        Codul studentului (limba inferată):
        ```code
        #include <cstdio>
#include <cstring>
#include <utility>
#include <vector>
#include <queue>
#include <algorithm>

struct node {
    int x, y, came_from, dist;

    node(int x, int y, int came_from, int dist) :
            x(x), y(y), came_from(came_from), dist(dist) {}
};

int n, m, i, j;
char table[10000][10000];
int visited[10000][10000];
int vis[10000][10000];

struct compareFunc {
    bool operator()(node const &n1, node const &n2) {
        int x1 = n1.x;
        int y1 = n1.y;
        int x2 = n2.x;
        int y2 = n2.y;

        return visited[x1][y1] > visited[x2][y2];
    }
};

std::pair<int, int> start;
std::pair<int, int> finish;

int dx[] = {-1, 0, 1, 0};  // up, right, down, left --> 0, 1, 2, 3
int dy[] = {0, 1, 0, -1};

bool reachable(int x, int y) {
    bool res =  (0 <= x && x < n) &&
                (0 <= y && y < m) &&
                table[x][y] != 'W';

    return res;
}

int getResult() {
    int new_x, new_y;
    std::priority_queue<node, std::vector<node>, compareFunc> q;

    int i = start.first;
    int j = start.second;

    visited[i][j] = 0;
    q.push({i, j, -1, 0});

    while (!q.empty()) {
        node n = q.top();
        q.pop();

        int i = n.x;
        int j = n.y;
        int dir = n.came_from;
        int dist = n.dist;

        if (i == finish.first && j == finish.second)
            return visited[i][j];

        for (int k = 0; k < 4; ++k) {
            new_x = i + dx[k];
            new_y = j + dy[k];

            if (reachable(new_x, new_y)) {
                if ((dir == -1) || (dir == k)) {
                    if (visited[new_x][new_y] > dist) {
                        visited[new_x][new_y] = dist;
                        q.push(node(new_x, new_y, k, dist));
                    }
                } else if (abs(k - dir) != 2) {
                    if (visited[new_x][new_y] > dist + 1) {
                        visited[new_x][new_y] = dist + 1;
                        q.push(node(new_x, new_y, k, dist + 1));
                    }
                }
            }
        }
    }

    return -1;
}

int main() {
    freopen("beamdrone.in", "r", stdin);
    freopen("beamdrone.out", "w", stdout);

    scanf("%d %d", &n, &m);
    scanf("%d %d %d %d\n", &start.first, &start.second,
                            &finish.first, &finish.second);

    for (i = 0; i < n; ++i) {
        for (j = 0; j < m; ++j) {
            int ch = getchar();
            if (ch == '\n' || ch == EOF)
                break;
            table[i][j] = (char) ch;
        }

        if (j == m)
            getchar();
    }

    for (i = 0; i < n; ++i) {
        for (j = 0; j < m; ++j) {
            visited[i][j] = __INT_MAX__;
        }
    }

    printf("%d\n", getResult());

    return 0;
}

