        ```code
        #include <fstream>
#include <climits>

using namespace std;

#define INF 2000000000
#define MAX_SIZE 100000000

struct Pair {
	int x, y;
};

struct Tuple {
	int costU, costD, costL, costR;
};

bool isInside(int x, int y, int n, int m) {
	return x >= 0 && y >= 0 && x < n && y < m;
}

int main() {
	int n, m;
	int startX, startY;
	int endX, endY;
	int li = 0, lf = 0;

	Tuple* v = NULL;
	Pair* q = NULL;

	ifstream fin("beamdrone.in");
	ofstream fout("beamdrone.out");

	fin >> n >> m;
	fin >> startX >> startY;
	fin >> endX >> endY;

	v = new Tuple[n * m];
	q = new Pair[MAX_SIZE];

	for (int i = 0; i < n; i++)
		for (int j = 0; j < m; j++) {
			char c;

			fin >> c;

			if (c == '.')
				v[i * m + j] = {INF, INF, INF, INF};
			else
				v[i * m + j] = {-INF, -INF, -INF, -INF};
		}

	q[lf++] = {startX, startY};
	v[startX * m + startY] = {0, 0, 0, 0};

	while (li <= lf) {
		int x = q[li].x;
		int y = q[li].y;

		Tuple* tuple = v + x * m + y;

		int costU = tuple->costU;
		int costD = tuple->costD;
		int costL = tuple->costL;
		int costR = tuple->costR;

		// Coming from top
		if (isInside(x + 1, y, n, m) && v[(x + 1) * m + y].costU != -INF) {
			int minCost = costU;

			if (costD + 1 < minCost)
				minCost = costD + 1;

			if (costL + 1 < minCost)
				minCost = costL + 1;

			if (costR + 1 < minCost)
				minCost = costR + 1;

			if (minCost < v[(x + 1) * m + y].costU) {
				v[(x + 1) * m + y].costU = minCost;
				q[lf++] = {x + 1, y};
			}
		}

		// Coming from bottom
		if (isInside(x - 1, y, n, m) && v[(x - 1) * m + y].costD != -INF) {
			int minCost = costD;

			if (costU + 1 < minCost)
				minCost = costU + 1;

			if (costL + 1 < minCost)
				minCost = costL + 1;

			if (costR + 1 < minCost)
				minCost = costR + 1;

			if (minCost < v[(x - 1) * m + y].costD) {
				v[(x - 1) * m + y].costD = minCost;
				q[lf++] = {x - 1, y};
			}
		}

		// Coming from left
		if (isInside(x, y + 1, n, m) && v[x * m + y + 1].costL != -INF) {
			int minCost = costL;

			if (costU + 1 < minCost)
				minCost = costU + 1;

			if (costD + 1 < minCost)
				minCost = costD + 1;

			if (costR + 1 < minCost)
				minCost = costR + 1;

			if (minCost < v[x * m + y + 1].costL) {
				v[x * m + y + 1].costL = minCost;
				q[lf++] = {x, y + 1};
			}
		}

		// Coming from right
		if (isInside(x, y - 1, n, m) && v[x * m + y - 1].costR != -INF) {
			int minCost = costR;

			if (costU + 1 < minCost)
				minCost = costU + 1;

			if (costD + 1 < minCost)
				minCost = costD + 1;

			if (costL + 1 < minCost)
				minCost = costL + 1;

			if (minCost < v[x * m + y - 1].costR) {
				v[x * m + y - 1].costR = minCost;
				q[lf++] = {x, y - 1};
			}
		}

		li++;
	}

	fout << min(min(v[endX * m + endY].costU, v[endX * m + endY].costD),
				min(v[endX * m + endY].costL, v[endX * m + endY].costR)) << "\n";

	fin.close();
	fout.close();

	delete[] v;
	delete[] q;

	return 0;
}

