		boolean[][] visited = new boolean[M][N];


		// Adăugăm punctele în coadă pentru BFS sortate după numărul de întoarceri
		Queue<Point> q = new PriorityQueue<>(Comparator.comparingInt(p -> p.turns));

		q.add(source);

		// Pornim o percurgere BFS din sursă
		while (!q.isEmpty()) {
			Point pt = q.peek();

			// ne oprim dacă am ajuns la destinație
			// și returnăm numărul de întoarceri
			if (pt.x == dest.x && pt.y == dest.y) {
				return pt.turns;
			}

			// altfel scoatem punctul din coadă și adăugăm vecinii săi
			q.remove();

			for (int i = 0; i < 4; i++) {
				int row = pt.x + rowNum[i];
				int col = pt.y + colNum[i];

				// adăugăm punctul în coadă dacă e valid, liber și nevizitat
				if (isValid(row, col)
						&& mat.get(row).charAt(col) == '.'
						&& !visited[row][col]) {

					// am considerat un punct ca vizitat la întoarcerea în el
					if (Math.abs(i - pt.orientation) == 2) {
						visited[row][col] = true;
					}

					// dacă diferența dintre orientări e impară și nu suntem în sursă
					// avem întoarcere
					// i dă noua orientare
					if (Math.abs(i - pt.orientation) % 2 == 1 && pt.orientation != -1) {
						q.add(new Point(row, col, pt.turns + 1, i));
					} else {
						q.add(new Point(row, col, pt.turns, i));
					}
				}
			}
		}

		// dacă nu se ajunge la destinație returnăm -1
		return -1;
	}

