        #include <fstream>
#include <iostream>
#include <queue>
#include <algorithm>

#define MAX 1000

using namespace std;

ifstream fin("beamdrone.in");
ofstream fout("beamdrone.out");

// structura pentru patrat
struct Tile {
    int x, y;
    Tile operator+(Tile other) {
        return {x + other.x, y + other.y};
    }
    bool operator==(Tile other) {
        return x == other.x && y == other.y;
    }
};

// structura pentru elementul din queue
struct QElem {
    Tile old;
    Tile curr;
    int weight;
};

// directiile pe care le pot avea pe ambele axe dx-dy
constexpr Tile dir[]{
    {0, 1},
    {0, -1},
    {1, 0},
    {-1, 0},
};

int N, M;
char a[MAX][MAX];
Tile drone, finish;

int BFS() {
    // cmp - lambda pentru a returna weight-ul elementului
    auto cmp = [](QElem& a, QElem& b) {
        return a.weight > b.weight;
    };
    // imi construiesc un pqueue
    std::priority_queue<QElem, std::vector<QElem>, decltype(cmp)> Q(cmp);
    // pushez in coada drona
    Q.push({drone, drone, 0});
    while (!Q.empty()) {
        // iau primul element
        QElem el = Q.top();
        Q.pop();
        // daca elementul curent este . -> continui
        if (a[el.curr.y][el.curr.x] != '.') {
            continue;
        }
        // marchez locatia curenta cu O - obstacol
        a[el.curr.y][el.curr.x] = 'O';
        // daca ajung la final returnez weight-ul dorit
        if (el.curr == finish) {
            return el.weight;
        }
        // parcurg directiile
        for (int i = 0; i < 4; ++i) {
            // ma mut pe directie
            Tile newPos = el.curr + dir[i];
            // bordez matricea
            if (newPos.x < 0 || newPos.x >= M ||
                newPos.y < 0 || newPos.y >= N) {
                continue;
            }
            // daca pozitia noua e diferita de punct - continue
            if (a[newPos.y][newPos.x] != '.') {
                continue;
            }
            // pushez in coada si cresc costul daca am facut
            // o rotire la 90 de grade
            Q.push({el.curr, newPos, el.weight + (
                el.old.x != newPos.x && el.old.y != newPos.y)
            });
        }
    }
    return -1;
}

int main() {
    // fac citirile si afisez bfs-ul
    fin >> N >> M;
    fin >> drone.y >> drone.x;
    fin >> finish.y >> finish.x;
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            fin >> a[i][j];
        }
    }
    fout << BFS();
}

