void generate_Graf() {
    inputFile >> N >> M;
    for (int i = 1; i <= N; ++i) {
        char *linie = (char *) malloc(M + 10);
        if (!linie) {
            perror("Eroare la alocare!\n");
            exit(-1);
        }
        inputFile >> linie;
        for (int j = 0; j < M; ++j) {
            switch (linie[j]) {
                case 'X':
                    break;
                case '.':
                    noduri.insert((i - 1) * M + j + 1);
                    break;
                case 'R':
                    poz_start.push_back({i, j + 1});
                    noduri.insert((i - 1) * M + j + 1);
                    break;
                case 'S':
                    poz_murdare.push_back({i, j + 1});
                    noduri.insert((i - 1) * M + j + 1);
                    break;
                default:
                    break;
            }
        }
        free(linie);
    }

    /* 
        Pentru fiecare nod liber ii generez vecinii si fac
        muchiile cu ei daca nu sunt blocati.
    */
    for (auto nod : noduri) {
        int vecin_E, vecin_V, vecin_N, vecin_S;
        int l = nod / M + 1, c = nod % M;
        if (nod % M == 0) l -= 1, c = M;
        if (l > 1) {
            vecin_N = nod - M;
            add_edge(nod, vecin_N);
        }
        if (l < N) {
            vecin_S = nod + M;
            add_edge(nod, vecin_S);
        }
        if (c < M) {
            vecin_E = nod + 1;
            add_edge(nod, vecin_E);
        }
        if (c > 1) {
            vecin_V = nod - 1;
            add_edge(nod, vecin_V);
        }
    }
}

void generate_2nd_graf(vector<pair<int, int>> g[]) {
    for (int nod = 1; nod < dim; ++nod) {
