int BFS(int s, int d) {
    vector<bool> visited(N * M, false);
    vector<int> dist(N * M);
    queue<int> q;

    visited[s] = true;
    dist[s] = 0;
    q.push(s);
    if (s != d) {
        while (!q.empty()) {
            s = q.front();
            q.pop();

            for (int i = 0; i < adj[s].size(); ++i) {
                if (!visited[adj[s][i]]) {
                    visited[adj[s][i]] = true;
                    dist[adj[s][i]] = dist[s] + 1;
                    q.push(adj[s][i]);
                    if (adj[s][i] == d) {
                        return dist[adj[s][i]];
                    }
                }
            }
        }
    }

    return 0;
}

void compute_min_distances(vector<pair<int, int>> g[]) {
    int index_pozitii_murdare = 1 + nr_roboti;
    int linie, coloana;
    set<pair<int, int>> set;
    for (int i = 1; i < dim; ++i) {
        for (int j = 1; j < dim; ++j) {
            if (i < index_pozitii_murdare && j < index_pozitii_murdare) {
                continue;
            }
            int x;
            if (i < index_pozitii_murdare) {
                x = i - 1;
                linie = poz_start[x].first;
                coloana = poz_start[x].second;
            } else {
                x = i - index_pozitii_murdare;
                linie = poz_murdare[x].first;
                coloana = poz_murdare[x].second;
            }

            int sursa = (linie - 1) * M + coloana;

            if (j < index_pozitii_murdare) {
                x = j - 1;
                linie = poz_start[x].first;
                coloana = poz_start[x].second;
            } else {
                x = j - index_pozitii_murdare;
                linie = poz_murdare[x].first;
                coloana = poz_murdare[x].second;
            }

            int dest = (linie - 1) * M + coloana;

            if (set.find({sursa, dest}) == set.end()) {
                int min_dist = BFS(sursa, dest);
                set.insert(make_pair(sursa, dest));
                set.insert(make_pair(dest, sursa));
                g[i][j - 1].second = min_dist;
                g[j][i - 1].second = min_dist;
            }
        }
    }
}

