int helper(int **arr, int n, int m, vector<pair<int, int>> robots, int cleaning_points, map<int, vector<pair<int, int>>> cleaning, int cleaning_time) {
    if(cleaning_points == 0) {
        return cleaning_time - 1;
    }
    for(int i = 0; i < robots.size(); i++) {
        int size = cleaning[i].size();
        for(int j = 0; j < size; j++) {
            int x = cleaning[i][0].first;
            int y = cleaning[i][0].second;
            cleaning[i].erase(cleaning[i].begin());

            if(x > 0 && arr[x-1][y] == 0) {
                arr[x-1][y] = cleaning_time;
                cleaning[i].push_back(make_pair(x-1, y));
            } else if (x > 0 && arr[x-1][y] == -2) {
                arr[x-1][y] = cleaning_time;
                cleaning_points--;
            }

            if(x < n - 1 && arr[x+1][y] == 0) {
                arr[x+1][y] = cleaning_time;
                cleaning[i].push_back(make_pair(x+1, y));
            } else if (x < n - 1 && arr[x+1][y] == -2) {
                arr[x+1][y] = cleaning_time;
                cleaning_points--;
            }

            if(y > 0 && arr[x][y-1] == 0) {
                arr[x][y-1] = cleaning_time;
                cleaning[i].push_back(make_pair(x, y-1));
            } else if(y > 0 && arr[x][y-1] == -2) {
                arr[x][y-1] = cleaning_time;
                cleaning_points--;
            }

            if(y < m - 1 && arr[x][y+1] == 0) {
                arr[x][y+1] = cleaning_time;
                cleaning[i].push_back(make_pair(x, y+1));
            } else if (y < m-1 && arr[x][y+1] == -2) {
                arr[x][y+1] = cleaning_time;
                cleaning_points--;
            }
        }
    }

    return helper(arr, n, m, robots, cleaning_points, cleaning, cleaning_time + 1);
}

int makeClean(int **arr, int n, int m, vector<pair<int, int>> robots, int cleaning_points, map<int, vector<pair<int,int>>> cleaning) {
    int cleaning_time = 0;
    cleaning_time = helper(arr, n, m, robots, cleaning_points, cleaning, 1);
    return cleaning_time;
}

int main() {
    ifstream fin("curatare.in");
    ofstream fout("curatare.out");

    int n, m;
