            }
        }
    }

    for(int i = 0; i < robots.size(); i++) {
        vector <pair<int, int>> vec;
        vec.push_back(robots[i]);
        cleaning[i] = vec;
    }

    fout << makeClean(arr, n, m, robots, cleaning_points, cleaning) << "\n";

    return 0;
