				M[i] = sc.nextLine().toCharArray();
				for (int j = 0; j < m ; j++) {
					if (M[i][j] == 'R') {
						q.add(new Pair(i, j, 0));
						viz[i][j] = 1;
					} else if (M[i][j] == 'S') {
						sources += 1;
					}
				}
			}
			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

