// Computes minimum distance to each cell using Dijkstra's algorithm.
vector<int> Dijkstra(int Xs, int Ys, int N, int M, vector<vector<char>> harta) {
    vector<int> d(N*M + 1, INF);
    // The implementation uses a set instead of a priority queue.
    // The elements will be stored with respect to distance
    // in ascending order.
    set<pair<int, pair<int, int>>> myPriority;
    vector<int> dl = {-1, 0, 1, 0};
    vector<int> dc = {0, 1, 0, -1};

    int start = (Xs - 1) * M + Ys;

    d[start] = 0;

    myPriority.insert({0, {Xs, Ys}});

    while (!myPriority.empty()) {
        auto top = myPriority.begin();
        const auto[_, coords] = *top;
        myPriority.erase(top);
        int x = coords.first;
        int y = coords.second;
        int node1 = (x - 1) * M + y;

        for (int i = 0; i < 4; i ++) {
            int xx = x + dl[i];
            int yy = y + dc[i];

        if (pozitie_corecta(xx, yy, N, M) && harta[xx][yy] != 'X') {
            int node2 = (xx - 1) * M + yy;
            if (d[node2] > d[node1] + 1) {
                myPriority.erase({d[node2], {xx, yy}});
                d[node2] = d[node1] + 1;
                myPriority.insert({d[node2], {xx, yy}});
	    }
	  }
    }
  }
    return d;
}

