		for (int j : v) {
			if (j < min) {
				min = j;
			}
		}
		return min;
	}

	static class Point {
		int x;
		int y;

		public Point(int x, int y) {
			this.x = x;
			this.y = y;
		}
	}

	static class Node {
		Point point;
		int dist;

		public Node(Point point, int dist) {
			this.point = point;
			this.dist = dist;
		}
	}

	static boolean isValid(int row, int col) {
		return (row >= 0) && (row < n) && (col >= 0) && (col < m);
	}

	static int bfs(int [][]mat, Point src, Point dest) {

		int []rowNum = {-1, 0, 0, 1};
		int []colNum = {0, -1, 1, 0};

		boolean [][]visited = new boolean[n][m];

		visited[src.x][src.y] = true;

		Queue<Node> q = new LinkedList<>();

		q.add(new Node(src, 0));

		while (!q.isEmpty()) {
			Node curr = q.poll();
			Point point = curr.point;

			if (point.x == dest.x && point.y == dest.y) {
				return curr.dist;
			}

			for (int i = 0; i < 4; i++) {
				int row = point.x + rowNum[i];
				int col = point.y + colNum[i];

				if (isValid(row, col) && mat[row][col] == 1 && !visited[row][col]) {
					visited[row][col] = true;
					q.add(new Node(new Point(row, col), curr.dist + 1));
				}
			}
		}
		return -1;
	}


