vector<vector<int>> adj(NMAX, vector<int>(NMAX, 0));
// coords of robots and dirty spots
vector<pair<int, int>> robots, d_spots;
// distances from robots to dirty spots
vector<vector<int>> dist;
// distances from dirty spots to other dirty spots
vector<vector<int>> d2d_dist;
int N, M, R, S;

vector<pair<int, int>> neighs = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
vector<int> bfs(pair<int, int> source) {
    vector<vector<int>> d(N + 1, vector<int>(M + 1, INF));
    vector<int> dist_to_dirty_spots;
    queue<pair<int, int>> q;

    q.push(source);
    d[source.first][source.second] = 0;

    int neigh_x, neigh_y;
    while (!q.empty()) {
        pair<int, int> node = q.front();
        q.pop();
        // if occupied spot, skip
        if (adj[node.first][node.second] == 1) continue;

        for (auto& offs : neighs) {
            neigh_x = node.first + offs.first;
            neigh_y = node.second + offs.second;
            // if out of bounds, skip
            if (neigh_x < 1 || neigh_x > N ||
                neigh_y < 1 || neigh_y > M)
                continue;

            if (d[node.first][node.second] + 1 < d[neigh_x][neigh_y]) {
                d[neigh_x][neigh_y] = d[node.first][node.second] + 1;
                q.push({neigh_x, neigh_y});
            }
        }
    }

    dist_to_dirty_spots.push_back(INF);  // index 0 is not used
    for (auto& d_spot : d_spots) {
        dist_to_dirty_spots.push_back(d[d_spot.first][d_spot.second]);
    }

    return dist_to_dirty_spots;
}

vector<int> path[RMAX];
int min_cost = INF;
void compute_solution() {
    int local_max_cost = 0;  // max cost of each robot's path
    for (int i = 1; i <= R; i++) {
        if (path[i].size() == 0) continue;

        // init cost with cost from ith robot to first dirty spot in its path
        int cost = dist[i][path[i][0]];
        auto& p = path[i];
        int prev = -1;
        // add costs to reach the dirty spots in the order they are in the path
        for (auto& node : p) {
            if (prev != -1)
                cost += d2d_dist[prev][node];
            prev = node;
        }

        if (cost > local_max_cost)
            local_max_cost = cost;
    }

    if (local_max_cost < min_cost)
        min_cost = local_max_cost;
}

int visited[RMAX];
void bt(int d_i) {
    if (d_i == S + 1) {
        compute_solution();
        return;
    }

    for (int i = d_i; i <= S; ++i) {
        if (visited[i] == 1)
            continue;
        visited[i] = 1;
        for (int j = 1; j <= R; ++j) {
            path[j].push_back(i);
            bt(d_i + 1);
            path[j].pop_back();
        }
        visited[i] = 0;
    }
}

