        mountain[j - 1] = mountain[j];
        j--;
      } else {
        cost += mountain[i + 1] - mountain[i];
        mountain[i + 1] = mountain[i];
        i++;
      }
    }

    if (i_nex == false && j_nex) {
      cost += mountain[j - 1] - mountain[j];
      mountain[j - 1] = mountain[j];
      j--;
    }

    if (i_nex && j_nex == false) {
      cost += mountain[i + 1] - mountain[i];
      mountain[i + 1] = mountain[i];
      i++;
    }
  }
  out << cost;
  out.close();
  file.close();
  return 0;
