            sum += v[i] - minim;
            v[i] = minim;
        }
    }

    // pornim de la idx=1 pana la left
    for (int i = 1; i < left; ++i) {
        if (v[i] > v[i - 1]) {
            sum += v[i] - v[i - 1];
            v[i] = v[i - 1];
        }
    }

    // pornim de la idx=n-2 pana la right
    for (int i = n-2; i > right; --i) {
        if (v[i] > v[i + 1]) {
            sum += v[i] - v[i + 1];
            v[i] = v[i + 1];
        }
    }

    if (isFirst) {
        sum += v[1] - minim;
    }

    if (isLast) {
        sum += v[v.size() - 2] - minim;
    }

    out << sum;

    // inchidem fisierele
    in.close();
    out.close();

    return 0;
}

