				reader.close();
			} catch (FileNotFoundException e) {
				throw new RuntimeException(e);
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(long result) {
			try {
				PrintWriter pw = new PrintWriter(new File(outputFile));
				pw.printf("%d\n", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private long getResult() {
			long sol = 0;
			int mid = 1;

			//Gasirea mijlocului, deoarece cel mai convenabil este ca mijlocul sa fie
			//cel mai mic numar din tot array-ul
			for (int i = 2; i <= n - 2; i++) {
				if (val[mid] > val[i]) {
					mid = i;
				}
			}

			//Actualizarea prefixului, daca valoarea de pe pozitia i este mai mare decat cea
			//de dinainte, atunci adun la solutie diferenta dintre ei si il actualizez pe cel
			//de pe pozitia i cu valoarea celui de dinainte
			for (int i = 1; i <= mid; i++) {
				if (val[i] > val[i - 1]) {
					sol += (val[i] - val[i - 1]);
					val[i] = val[i - 1];
				}
			}

			//Actualizarea sufixului, daca valoarea de pe pozitia i este mai mare decat cea
			//de dupa el, atunci adun la solutie diferenta dintre ei si il actualizez pe cel
			//de pe pozitia i cu valoarea celui de dupa el
			for (int i = n - 2; i >= mid; i--) {
				if (val[i] > val[i + 1]) {
					System.out.println(val[i] - val[i + 1]);
					sol += (val[i] - val[i + 1]);
					val[i] = val[i + 1];
				}
			}

			return sol;
		}
	}

