        #include <bits/stdc++.h>
#include <fstream>

using namespace std;

int main() {
    unsigned int N, i;

    ifstream in("valley.in");
    in >> N;
    vector<long long> v(N);

    in >> v[0];

    long long min = v[0];
    long long index = 0;
    long long nr_of_occur = 1;
    for (i = 1; i < N; ++i) {
        in >> v[i];
        if (v[i] == min) {
            index = i;
            ++nr_of_occur;
        } else if (v[i] < min) {
            min = v[i];
            index = i;
            nr_of_occur = 1;
        }
    }
    in.close();

    ofstream out("valley.out");
    long long count = 0;
    // corner cases
    if ((index == 0) && (nr_of_occur == 1)) {
        out << v[1] - v[0];
    } else if ((index == N - 1) && (nr_of_occur == 1)) {
        out << v[N - 2] - v[N - 1];
    } else {
        long long first, last;
        // prefix
        for (i = 0; i < N; ++i) {
            if (v[i] == min) {
                first = i;
                break;
            } else if (v[i + 1] > v[i]) {
                count += v[i + 1] - v[i];
                v[i + 1] = v[i];
            }
        }

        // sufix
        for (i = N - 1; i >= 0; --i) {
            if (v[i] == min) {
                last = i;
                break;
            } else if (v[i - 1] > v[i]) {
                count += v[i - 1] - v[i];
                v[i - 1] = v[i];
            }
        }

        // median
        for (i = first + 1; i < last; ++i) {
            count += v[i] - min;
        }

        out << count;
    }
    out.close();

    return 0;
}

