        #include <iostream>

using namespace std;

const auto MOD = 1000000007;

/* ma folosesc de aceasta proprietate matematica:
 a/b % MOD=((a % MOD)∗(b^(MOD−2) % MOD)) % MOD) */

/* in aceasta functie calculez in timp logaritmic b^(MOD - 2) ->
complexitate temporala O(logMOD) */
unsigned long long inversModular(unsigned long long base) {
    unsigned long long exponent = MOD - 2;
    unsigned long long result = 1;
    while (exponent != 1) {
        if (exponent % 2 == 0) {
            base = ((base % MOD) * (base % MOD)) % MOD;
			exponent /= 2;
        } else {
			result = (result * (base % MOD)) % MOD;
			exponent--;
		}
    }
    return (result * base) % MOD;
}

/* in aceasta functie calculez coeficientul binomial */
int C(int n, int k) {
	/* combinari de n luate cate k = combinari de n luate cate (n - k) */
	/* pentru a avea o complexitate temporala mai mica, iau k ca fiind
	minumul dintre k si n - k */
    if (k > n - k) {
        k = n - k;
    }

    unsigned long long a = 1LL;
    unsigned long long b = 1LL;

	/* C(n, k) = n! / (k! * (n - k)!) = ((n - k + 1) * ... * n) / k! */

	/* complexitate temporala O(k) -> k este maxim n / 2 ->
	O(k) e aproximativ O(n) */
    for (int i = 0; i < k; i++) {
		/* in a calculez ((n - (k - 1)) * ... * n) */
        a = ((a % MOD) * ((n - i) % MOD)) % MOD;
		/* in b calculez k! */
        b = ((b % MOD) * ((i + 1) % MOD)) % MOD;
    }

    unsigned long long invers_b = inversModular(b);

    return (a * invers_b) % MOD;
}

int type1(int x, int y) {
	/*
	- pentru a nu avea 2 biti de 1 consecutivi, trebuie sa
	punem mereu minim un 0 intre ei
	- daca avem x = 3 , y = 2
	_0_0_0_ -> daca avem 3 de 0, noi putem aseza un bit de 1
	in oricare dintre cele 3 + 1 spatii goale
	- daca _ ar fi inlocuit cu numere de la 1 la (1 + 3)
	_0_0_0_
	1 2 3 4 -> atunci combinari de x + 1 luate cate y (toate combinarile de pozitii
	in care putem pune biti de 1) -> C(4,2) :
	1 2 -> 10100 (punem biti de 1 pe pozitiile 1 si 2 unde aveam _)
	1 3 -> 10010
	1 4 -> 10001
	2 3 -> 01010
	2 4 -> 01001
	3 4 -> 00101
	*/

	if (x + 1 < y) {
		/* nu are sens sa calculam C(n, k) (n>=k) */
		return 0;
	}
    /* complexitate temporala totala ar fi O(x + 1) + O(logMOD)
	logMOD e aprox 30 (un nr foarte mic comparativ cu x), MOD e o constanta
	O(x + 1) + O(logMOD) aprox O(x) */
    return C(x + 1, y);
}

unsigned long long type2(int x, int y) {
	/* de cate ori intra 2 in numarul y */
	int div = y / 2;
	unsigned long long sum = 0LL;
	for (int i = y - div ; i <= y ; i++) {
		/* cat timp are sens sa calculam C(n, k) (n>=k) */
		/* i reprezinta cate grupuri de 1 avem in semnal,
		un grup putand fi de forma 1 sau 11 */
		if (x + 1 >= i) {
			sum = (sum + (1LL * C(i, (y - i)) * C(x + 1, i)) % MOD) % MOD;
		}
	}
    return sum;
}

