        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

class Semnale {

	static int sig_type, x, y;
	static final int  mod = 1000000007;

	Semnale(){}

	/* Semnalul nu poate contine 2 biti consecutivi de 1 */
	static int type1() {
		/* Vector cu 3 dimensiuni.
		   Prima dimensiune reprezinta numarul de biti de "0".
		   A doua dimensiune reprezinta numarul de biti de "1".
		   A treia dimensiune specifica daca semnalul se termina in "0" sau in "1" */
		int[][][] dp = new int[x + 1][y + 1][2];

		/* Cazuri de baza */
		dp[1][0][0] = 1; /* Semnalul "0" */
		dp[0][1][1] = 1; /* Semnalul "1" */

		/* Cazuri generale */
		for (int i = 1; i <= x; i++) {
			dp[i][0][0] = 1;	
			/* Umplu coloana pentru semnalele formate din oricati biti "0" si
			   niciun bit "1" cu 1 */

			for (int j = 1; j <= y; j++) {
				/* Semnalele care se termina in "0" pot fi formate prin adaugarea
				   lui "0" la semnalele care se termina in "0" sau "1" si au un 0
				   mai putin */
				dp[i][j][0] = (dp[i - 1][j][0] + dp[i - 1][j][1]) % mod;

				/* Semnalele care se termina in "1" pot fi formate prin adaugarea
				   lui "1" la semnalele care se termina in "0" si au un 1 mai putin */
				dp[i][j][1] = (dp[i][j - 1][0]) % mod;
			}
		}

		return (dp[x][y][0] + dp[x][y][1]) % mod;
	}

	/* Semnalul nu poate contine 3 biti consecutivi de 1 */
	static long type2() {
		/* Vector cu 3 dimensiuni.
		   Prima dimensiune reprezinta numarul de biti de "0".
		   A doua dimensiune reprezinta numarul de biti de "1".
		   A treia dimensiune specifica daca semnalul se termina in
		   "0", in "1" sau in "11" */
		long[][][] dp = new long[x + 1][y + 1][3];

		/* Cazuri de baza */
		dp[1][0][0] = 1; /* Semnalul "0" */
		dp[0][1][1] = 1; /* Semnalul "1" */
		dp[0][2][2] = 1; /* Semnalul "11" */

		/* Cazuri generale */
		for (int i = 1; i <= x; i++) {
			/* Umplu coloana pentru semnalele formate din oricati biti de "0"
			si niciun bit "1" cu 1 */
			dp[i][0][0] = 1;

			/* Umplu linia pentru semnalele formate din oricati biti de "0"
			   si 2 biti de "1" cu 1 */
			dp[i][2][2] = 1;

			for (int j = 1; j <= y; j++) {
				/* Semnalele care se termina in "0" pot fi formate prin adaugarea
				   lui "0" la semnalele care se termina in "0", "1" sau in "11" si
				   au un 0 mai putin */
				dp[i][j][0] = (dp[i - 1][j][0] + dp[i - 1][j][1] + dp[i - 1][j][2]) % mod;

				/* Semnalele care se termina in "1" pot fi formate prin adaugarea
				   lui "1" la semnalele care se termina in "0" si au un 1 mai putin */
				dp[i][j][1] = (dp[i][j - 1][0]) % mod;

				/* Nu exista semnale care sa se termine in "11" si sa aiba mai
				   putin de 2 biti de "1" */
				if (j >= 2) {
					/* Semnalele care se termina in "11" pot fi formate prin adaugarea
					   lui "1" la semnalele care se termina in "1" si au un 1 mai putin */
					dp[i][j][2] = (dp[i][j - 1][1]) % mod;
				}
			}
		}

		return (dp[x][y][0] + dp[x][y][1] + dp[x][y][2]) % mod;
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("semnale.in"));

			sig_type = sc.nextInt();
			x = sc.nextInt();
			y = sc.nextInt();

			long ans;
			switch (sig_type) {
				case 1:
					ans = Semnale.type1();
					break;
				case 2:
					ans = Semnale.type2();
					break;
				default:
