					(Inversa(factorial(1, v011)) % mod)) % mod;
			if (v01 - 1 >= v011)
				s = ((s % mod) + ((a % mod) * (C1 % mod)) % mod) % mod;
			else
				s = ((s % mod) + ((a % mod) * (C2 % mod)) % mod) % mod;
		}
		if (v011 > 0) {
		    C1 = ((factorial(v01 + 1, v01 + v011 - 1) % mod) *
					(Inversa(factorial(1, v011 - 1)) % mod)) % mod;  // C x+y-1 x-1
            // C x+y y
            C2 = ((factorial(v01 + 1, v01 + v011 - 1) % mod) *
					(Inversa(factorial(1, v011 - 1)) % mod)) % mod;
			if (v01 >= v011 - 1)
				s = ((s % mod) + ((a % mod) * (C1 % mod))% mod) % mod;
			else
				s = ((s % mod) + ((a % mod) * (C2 % mod)) % mod) % mod;
		}
		v011 = v011 + 1;
	}
	return s;
    return 0;
}  // am notat v01 si v011 ca fiind numarul de secvente
// de 01 biti si 011 biti. Q reprezinta numarul de 0 din combinari, acesta
// se afla prin formula Q = x - v01 - v011

int main() {
    freopen("semnale.in", "r", stdin);
	freopen("semnale.out", "w", stdout);

	int sig_type, x, y;

	cin >> sig_type >> x >> y;

    switch (sig_type) {
		case 1:
			cout << type1(x, y);;
			break;
		case 2:
			cout << type2(x, y);
			break;
		default:
			cout << "wrong task number" << endl;
	}

    return 0;
}

