import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;
import java.util.Arrays;
import java.util.StringTokenizer;

public class Nostory {
	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("nostory.in"));

		var task = scanner.nextInt();
		var n = scanner.nextInt();
		var moves = task == 2 ? scanner.nextInt() : 0;

		long[] a = new long[n];
		for (var i = 0; i < n; i += 1) {
			a[i] = scanner.nextLong();
		}

		long[] b = new long[n];
		for (var i = 0; i < n; i += 1) {
			b[i] = scanner.nextLong();
		}

		try (var printer = new PrintStream("nostory.out")) {
			if (task == 1) {
				printer.println(solveTask1(a, b));
			} else {
				printer.println(solveTask2(a, b, moves));
			}
		}
	}

	// function for building an array with the biggest n numbers from both a and b 
	private static long[] getNMaxNumbers(long[] a, long[] b) {
		long[] aux = new long[2 * a.length];

		//copying both arrays in aux
		System.arraycopy(a, 0, aux, 0, a.length);
		System.arraycopy(b, 0, aux, a.length, b.length);

		Arrays.sort(aux);

		long[] maxNumbers = new long[a.length];

		int idx = 0;

		for (int i = 2 * a.length - 1; i >= a.length; i--) {
			maxNumbers[idx] = aux[i];
			idx++;
		}

		return maxNumbers;
	}

	private static long solveTask1(long[] a, long[] b) {
		long[] aux = new long[2 * a.length];

		//copying both arrays in aux
		System.arraycopy(a, 0, aux, 0, a.length);
		System.arraycopy(b, 0, aux, a.length, b.length);

		// sorting aux
		for (int i = 0; i < 2 * a.length - 1; i++) {
			for (int j = i + 1; j < 2 * a.length; j++) {
				if (aux[i] < aux[j]) {
					long currentAux = aux[i];
					aux[i] = aux[j];
					aux[j] = currentAux;
				}
			}
		}
		long s = 0;

		// if we can make unlimited moves, the sum will always be built from the biggest numbers
		for (int i = 0; i < a.length; i++) {
			s = s + aux[i];
		}

		return s;
	}

	private static long solveTask2(long[] a, long[] b, int moves) {
		//getting the biggest n numbers from both a and b 
		long[] maxNumbers = getNMaxNumbers(a, b);

		long finalSum = 0;

		// number of elements added to the sum
		int count = 0;

		long[] unusedMax = new long[a.length];
		int unusedMaxIndex = 0;

		// keeping the smaller maximums from a pair
		for (int i = 0; i < a.length; i++) {
			if (a[i] >= maxNumbers[maxNumbers.length - 1] 
				&& b[i] >= maxNumbers[maxNumbers.length - 1]) {
				unusedMax[unusedMaxIndex] = Math.min(a[i], b[i]);
				unusedMaxIndex++;
			}
		}

		// sorting them
		Arrays.sort(unusedMax);

		// add to the finalSum the maximums from the pairs that are also in the maxNumbers
		for (int i = 0; i < a.length; i++) {
			long elem = Math.max(a[i], b[i]);
			if (elem >= maxNumbers[a.length - 1]) {
				finalSum = finalSum + elem;
				count++;
			}
		}

		// get the maximums between two elements
		long[] maxBetweenNumbers = new long[a.length];

		for (int i = 0; i < a.length; i++) {
			maxBetweenNumbers[i] = Math.max(a[i], b[i]);
		}

		Arrays.sort(maxBetweenNumbers);

		// the first position of maxBetweenNumbers
		int start = 0;

		// adding to the sum moves numbers from unusedMax
		for (int i = a.length - 1; i >= 0; i--) {
			if (moves > 0) {
				finalSum = finalSum + unusedMax[i];
				// we used another move
				moves--;
				count++;
				// increasing start so that we skip some of the minimim maximums that we already 
				// replaced 
				start++;
			}
		}

		for (int i = start; i < maxBetweenNumbers.length; i++) {
			// if we ran out of moves, we add the rest of the maximums
			if (moves == 0) {
				if (count < a.length) {
					finalSum = finalSum + maxBetweenNumbers[i];
					count++;
				}
			}
		}
		return finalSum;
	}

	/**
	 * A class for buffering read operations, inspired from here:
	 * https://pastebin.com/XGUjEyMN.
