#include <bits/stdc++.h>

#include <cstdint>
#include <fstream>
#include <vector>

using namespace std;

int64_t SolveTask1(const vector<int>& a, const vector<int>& b) {
    // primesc cei 2 vectori ordonati descrescator
    // avand mutari nelimitate adaugam cele mai mari n numere
    int j = 0, k = 0;  // j contor pt termenul actual din a, k contor pt b
    int64_t sum = 0;
    for (int i = 0; i < a.size(); i++) {
        // daca termenul din a e mai mare il adaugam la suma si trecem la
        // urmatorul element din a
        if (a[j] > b[k]) {
            sum += a[j];
            j++;
        }
        // analog b
        else {
            sum += b[k];
            k++;
        }
    }
    // in sum se afla suma celor mai mari n numere din ambii vectori
    return sum;
}

int64_t SolveTask2(const vector<int>& a, const vector<int>& b, int moves,
                   const vector<int>& compareA, const vector<int>& compareB) {
    // la fel ca la 1 dar tinem cont de nr de mutari
    int j = 0, k = 0, contorMoves = 0;
    int64_t sum = 0;
    for (int i = 0; i < a.size(); i++) {
        if (a[j] > b[k]) {
            // daca termenului j ii corespunde 0 inseamna ca initial
            // termenul de pe poz j din vectorul A era mai mare decat termenul
            // din B deci nu este nevoie sa folosim o mutare
            if (compareA[j] == 0) {
                sum += a[j];
            } else {
                // mai avem mutari disponibile
                if (contorMoves < moves) {
                    sum += a[j];
                    contorMoves++;
                } else
                    // nu am mai avut mutari disponibile deci nu am adaugat un
                    // element micsoram i-ul care este contorul de numere
                    // adaugate in suma care se incrementa automat din for
                    i--;
            }
            // trecem la urmatorul element din a
            j++;
        } else {
            // daca termenului k ii corespunde 1 inseamna ca initial
            // termenul de pe poz k din vectorul B era mai mare decat termenul
            // din A deci nu este nevoie sa folosim o mutare
            if (compareB[k] == 1) {
                sum += b[k];
            } else {
                // analog a
                if (contorMoves < moves) {
                    sum += b[k];
                    contorMoves++;
                } else
                    i--;
            }
            k++;
        }
    }
    return sum;
}

