void merge_halves(vector<int>& v, vector<int>& g, int left, int right) {
    int mid = (left + right) / 2;
    vector<int> aux;
    vector<int> aux2;
    int i = left, j = mid + 1;

    while (i <= mid && j <= right) {
        if (v[i] > v[j]) {
            aux.push_back(v[i]);
            aux2.push_back(g[i]);
            i++;
        } else {
            aux.push_back(v[j]);
            aux2.push_back(g[j]);
            j++;
        }
    }

    while (i <= mid) {
        aux.push_back(v[i]);
        aux2.push_back(g[i]);
        i++;
    }
    while (j <= right) {
        aux.push_back(v[j]);
        aux2.push_back(g[j]);
        j++;
    }
    for (int k = left; k <= right; k++) {
        v[k] = aux[k - left];
        g[k] = aux2[k - left];
    }
}

void merge_sort(vector<int>& v, vector<int>& g, int left, int right) {
    if (left >= right) return;
    int mid = left + (right - left) / 2;

    merge_sort(v, g, left, mid);
    merge_sort(v, g, mid + 1, right);
    merge_halves(v, g, left, right);
}

