	public static long largestNNumbers(int[] arr1, int[] arr2, int n) {
		int[] mergedArr = new int[2 * n];

		long sum = 0;
		int len = 2 * n;

		for (int i = 0; i < n; i++) {
			mergedArr[i] = arr1[i];
			mergedArr[i + n] = arr2[i];
		}

		Arrays.sort(mergedArr);

		for (int i = 1; i <= n; i++) {
			sum += mergedArr[len - i];
		}
		return sum;
	}

	private static long solveTask1(int[] a, int[] b) {
		return largestNNumbers(a, b, a.length);
	}

	public static long maxKSwaps(int[] arr1, int[] arr2, int k) {
		List<int[]> pairsA = new ArrayList<>(), pairsB = new ArrayList<>();
		Set<Integer> visited = new HashSet<>();

		long sum = 0;
		int N = arr1.length;

		for (int i = 0; i < N; i++) {
			pairsA.add(new int[] { i, arr1[i] });
			pairsB.add(new int[] { i, arr2[i] });
		}

		List<int[]> pairsFull = new ArrayList<>(pairsA);
		pairsFull.addAll(pairsB);

		Collections.sort(pairsFull, new Comparator<int[]>() {
			@Override
			public int compare(int[] p1, int[] p2) {
				return Integer.compare(p2[1], p1[1]);
			}
		});

		for (int[] pair : pairsFull) {
			int index = pair[0];
			int number = pair[1];

			if (N == 0) {
				break;
			}

			if (visited.contains(index) && k > 0) {
				sum += number;
				N--;
				k--;
			} else if (!visited.contains(index)) {
				visited.add(index);
				sum += number;
				N--;
			}
		}

		return sum;
	}

	private static long solveTask2(int[] A, int[] B, int K) {
		return maxKSwaps(A, B, K);
	}

