#include <vector>


using namespace std;

int compare(int a, int b) {
    return a > b;
}

/* function by which we find the largest sum of
the maxima at position i from the two vectors */
int64_t SolveTask1(vector<int> &a, vector<int> &b) {
    a.insert(end(a), begin(b), end(b));
    sort(a.begin(), a.end(), compare);
    // the sum of the first n biggest numbers
    long long sum = 0;
    for (int i = 0; i < (signed)a.size() / 2; i++) {
        sum += a[i];
    }
    return sum;
}

/* function by which we find the sum of the current maxima */
int current_sum(vector<int> &a, vector<int> &b) {
    int score = 0;
    for (int i = 0; i < (signed)a.size(); i++) {
        score += max(a[i], b[i]);
    }
    return score;
}

/* to find out the maximum amount obtained in n moves, we use a for that counts the number of moves made,
and inside this for we do repeated tests by making exchanges
between an element of vector a and all other elements of a and b,
we keep in two auxiliary vectors auxa and auxb the combination with the best current maximum amount per move */
int64_t SolveTask2(vector<int> &a, vector<int> &b, int moves) {
    long long sum = current_sum(a, b);
    // auxiliary vectors which store the best solution for one move
    vector<int> auxa, auxb;
    auxa.assign(a.begin(), a.end());
    auxb.assign(b.begin(), b.end());

    for (int k = 0; k < moves; k++) {
        for (int i = 0; i < (signed)a.size(); i++) {
            for (int p = 0; p < (signed)a.size(); p++) {
                // auxiliary vectors which store the current possible move
                vector<int> vecta, vectb;

                vecta.assign(a.begin(), a.end());
                vectb.assign(b.begin(), b.end());

                vecta[i] = a[p];
                vecta[p] = a[i];
                /* check the current sum if it is greater 
                than the previous we save it */
                int sum_current = current_sum(vecta, vectb);
                if (sum_current > sum) {
                    sum = sum_current;
                    auxa.assign(vecta.begin(), vecta.end());
                    auxb.assign(vectb.begin(), vectb.end());
                }

                vecta[i] = b[p];
                vectb[p] = a[i];
                /* check the current sum if it is greater 
                than the previous we save it */
                int sum_current2 = current_sum(vecta, vectb);
                if (sum_current2 > sum) {
                    sum = sum_current;
                    auxa.assign(vecta.begin(), vecta.end());
                    auxb.assign(vectb.begin(), vectb.end());
                }
            }
        }
        a.assign(auxa.begin(), auxa.end());
        b.assign(auxb.begin(), auxb.end());
    }

    return sum;
}

vector<int> ReadVector(istream &is, int size) {
    vector<int> vec(size);
    for (auto &num : vec) {
