import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;
import java.util.Arrays;
import java.util.StringTokenizer;


public class Nostory {
	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("nostory.in"));

		var task = scanner.nextInt();
		var n = scanner.nextInt();
		var moves = task == 2 ? scanner.nextInt() : 0;

		var a = new int[n];
		for (var i = 0; i < n; i += 1) {
			a[i] = scanner.nextInt();
		}

		var b = new int[n];
		for (var i = 0; i < n; i += 1) {
			b[i] = scanner.nextInt();
		}

		try (var printer = new PrintStream("nostory.out")) {
			if (task == 1) {
				printer.println(solveTask1(a, b));
			} else {
				printer.println(solveTask2(a, b, moves));
			}
		}
	}

	private static long solveTask1(int[] a, int[] b) {
		long result = 0;

		/*
		 * sortez cei doi vectori crescator,
		 * iar ulterior compar valorile corespunzatoare
		 * acelorasi pozitii din cei doi vectori si salvez
		 * valorile mai mari intr-unul din vectori, iar pe 
		 * cele mai mici le mut in celalalt, astfel
		 * incat la final toate valorile maxime vor fi 
		 * intr-un singur vector, iar pentru a obtine
		 * scorul maxim calculez suma tuturor elementelor
		 * din acesta 
		 */
		Arrays.sort(a);
		Arrays.sort(b);
		int aux;
		for (int i = 0; i < a.length; i++) {
			if (a[i] < b[b.length - 1 - i]) {
				aux = a[i];
				a[i] = b[b.length - 1 - i];
				b[b.length - 1 - i] = aux;
			}
			result += a[i];
		}
		return result;
	}

	/*
	 * functia care, atata timp cat mai exista
	 * mutari posibile, interschimba, daca acest 
	 * lucru este profitabil, cele mai mici valori 
	 * din vectorul de elemente maxime cu cele mai 
	 * mari valori din vectorul de elemente minime,
	 * actualizand suma maxima, pe care la final o 
	 * returneaza 
	 */
	private static long get_result(int [] added, int [] not_added, int moves, 
		long possible_result) {
		int counter = 0;
		while (counter < added.length) {
			if (moves > 0  && added[counter] < not_added[not_added.length - 1 - counter]) {
				int aux = added[counter];
				added[counter] = not_added[not_added.length - 1 - counter];
				not_added[not_added.length - 1 - counter] = aux;
				possible_result = possible_result - aux + added[counter];
				moves--;
			}
			counter++;
		}
		return possible_result;
	}

	private static long solveTask2(int[] a, int[] b, int moves) {
		long possible_result = 0;
		/*
		 * creez un vector in care adaug elementele cuprinse
		 * in suma initiala considerata ca fiind maxima, 
		 * pe care o obtin adunand elementele mai mari rezultate
		 * din compararea elementelor de pe aceleasi pozitii ale
		 * celor doi vectori a si b, precum si un alt vector in 
		 * care salvez elementele pe care nu le adaug la suma
		 * initiala, adica minimele obtinute din comparare
		 */
		int [] added = new int [a.length];
		int [] not_added = new int [b.length];


		for (int i = 0 ; i < a.length; i++) {
			if (a[i] > b[i]) {
				possible_result += a[i];
				added[i] = a[i];
				not_added[i] = b[i];
			} else {
				possible_result += b[i];
				added[i] = b[i];
				not_added[i] = a[i];
			}
		}
		/*
		 * realizez o sortare intermediara a celor doi vectori,
		 * care sa imi asigure accesul optim la valorile cele 
		 * mai mici din vectorul de elemente maxime si la
		 * valorile cele mai mari din vectorul de elemente minime 
		 */
		Arrays.sort(added);
		Arrays.sort(not_added);

		long result = get_result(added, not_added, moves, possible_result);
		return result;
	}

