int64_t SolveTask2(vector<int>& a, vector<int>& b, int moves, int n) {
	for (int i = 0; i < n; i++) {
		if (a[i] > b[i])
			swap(a[i], b[i]);
			//  Se compară elementele de pe aceleași poziții din a și b,
			//  iar dacă a[i] > b[i], se efectuează o schimbare
			//  între ele folosind funcția swap()
	}
	sort(a.begin(), a.end());
