int64_t SolveTask1(vector<int>& a, vector<int>& b) { 

    int n = b.size();
    int max_val = 0, min_val = 0;
    int max_ind = 0, min_ind = 0;

// salvez elementele cele mai mari in b si elementele cele mai mici in a
     while(1) {

        auto max_it = max_element(a.begin(), a.end());
        auto min_it = min_element(b.begin(), b.end());

        max_val = *max_it;
        min_val = *min_it;
        max_ind = distance(a.begin(), max_it);
        min_ind = distance(b.begin(), min_it);

        if(max_val > min_val && max_ind != min_ind) {

            a[max_ind] = min_val;
            b[min_ind] = max_val;
        }
        else if(max_val <= min_val)
            break;
     }

    int64_t sum = 0;

// pentru ca in b am salvat toate elementele maxime, nu mai are rost compararea cu cele din a
// asa ca suma maxima va fi suma el. din b
    for(int i = 0; i < n; i++) {
        sum += b[i];
    }
    return sum;
}

// functie care calculeaza suma maximelor 
int64_t summ(vector<int>& a, vector<int>& b) {

    int n = a.size();
    int64_t sum_max = 0;

    for(int i = 0; i < n; i++) {
        int64_t max_num = max(a[i], b[i]);
        sum_max += max_num;
    }
    return sum_max;
}

int64_t SolveTask2(vector<int>& a, vector<int>& b, int moves) { 

    int n = a.size();
    int64_t sum = summ(a, b);
    int64_t max_sum = sum;
    int64_t rezultat = sum;
    int i_sec = 0, j_sec = 0;
    int k = 0; //moves

    while (k < moves) {

        for(int i = 0; i < n; i++) {
            for(int j = 0; j < n; j++) {

                if(i != j) {
                    int64_t new_sum = sum - max(a[i], b[i]) - max(a[j], b[j]) + max(a[i], b[j]) + max(a[j], b[i]);

                    // verifica daca schimbarea produce un nou maxim
                    if(new_sum > max_sum) {
                        max_sum = new_sum;
                        i_sec = i;   //retin indexul i pt swap
                        j_sec = j;  //retin indexul j pt swap
                    }
                }
            }
        }

        // fac swap intre numerele care produc cel mai mare maxim
            swap(a[i_sec], b[j_sec]);
            sum = max_sum;
            rezultat = max(rezultat, sum);
            max_sum = sum; 
            k++;
    }    
    return rezultat;
}

vector<int> ReadVector(istream& is, int size) {
    vector<int> vec(size);
    for (auto& num : vec) {
        is >> num;
    }
    return vec;
}

