public class Nostory {
	void mergesort(int st, int dr, int[] v, int[] sorted) {
		if (st < dr) {
			int m = (st + dr) / 2;
			mergesort(st, m, v, sorted);
			mergesort(m + 1, dr, v, sorted);

			// sortam elementele
			int i = st, j = m + 1, k = 0;
			while (i <= m && j <= dr) {
				if (v[i] <= v[j]) {
					sorted[k++] = v[i++];

				} else if (v[i] > v[j]) {
					sorted[k++] = v[j++];
				}

			}
			while (i <= m) {
				sorted[k++] = v[i++];
			}
			while (j <= dr) {
				sorted[k++] = v[j++];
			}
			for (i = st, j = 0; i <= dr; i++, j++) {
				v[i] = sorted[j];
			}
		}
	}

	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("nostory.in"));

