		int[] c = new int[N];
		int[] freq = new int[N];
		Map<Integer, Integer> unsorted = new HashMap<>();

		var a = new int[n];
		for (var i = 0; i < n; i += 1) {
			a[i] = scanner.nextInt();
			c[i] = a[i]; // ne punem toate elem intr-un vector mare
			unsorted.put(a[i], i); // avem valoare->indice in hashmap
		}

		var b = new int[n];
		for (var i = 0; i < n; i += 1) {
			b[i] = scanner.nextInt();
			c[n + i] = b[i]; // pun toate elem intr-un vector mare
			unsorted.put(b[i], n + i); // valoare->indice in hashmap

			if (b[i] > a[i]) { // elem mai mare de pe ac pozitie
				freq[n + i] = 1; // va fi marcat in vectorul
			} else { // de frecventa prin indicele lui
				freq[i] = 1;
			}

		}
		// System.out.println(sorted);
		try (var printer = new PrintStream("nostory.out")) {
			if (task == 1) {
