	private static long solveTask1(int[] c, int n) {
		int N = 2 * n;
		int[] sorted = new int[N];

		Nostory ex1 = new Nostory();
		ex1.mergesort(0, N - 1, c, sorted); // sortez vectorul mare
		long score = 0;
		// iau ultimele n elemente cele mai mari
		for (int i = N - 1; i >= n; i--) {
			score += c[i];
		}

		return score;
	}

	private static long solveTask2(Map unsorted, int n, int[] freq, int moves) {
		int N = 2 * n;

		Nostory ex1 = new Nostory();

		ArrayList<Map.Entry<Integer, Integer>> sorted = new ArrayList<>(unsorted.entrySet());
		// imi sortez hashmapul in functie de valoarea din vectorii a/b
		Collections.sort(sorted, new Comparator<Map.Entry<Integer, Integer>>() {
			public int compare(Map.Entry<Integer, Integer> e1, Map.Entry<Integer, Integer> e2) {
				return e1.getKey() - e2.getKey();
			}
		});

		long score = 0;
		int made_moves = 0;
		int n1 = n - 1;
		int i = freq.length - 1;
		while (n1 >= 0 && i >= 0) {
			// System.out.println(sorted.get(i));
			int value = sorted.get(i).getValue();
			int key = sorted.get(i).getKey();
			if (freq[value] == 1) {
				// daca valoarea din hashmap e marcata in vectorul de frecventa
				// =>il adaug la scor
				score += key;
				n1--;
			} else {
				if (made_moves < moves) {
					// daca valoarea nu e marcata in vect de frecventa
					// fac o mutare
					freq[value] = 1;
					made_moves++;
					score += key;
					n1--;
				}
			}
			i--;
		}
		return score;
	}

