        priority_queue<pair<int, int>> q;

        for (int i = 0; i <= n; i++) {
            d[i] = INF;
            p[i] = 0;
        }

        d[source] = 0;
        q.push({source, d[source]});

        while (!q.empty()) {
            pair<int, int> node = q.top();
            q.pop();

            for (auto neigh : adj[node.first]) {
                if (find(barbari.begin(),
                        barbari.end(),
                        neigh.first) != barbari.end()) {
                        continue;
                }

                if (neigh.second > d[neigh.first]) {
                    continue;
                }

                if (d[node.first] + neigh.second < d[neigh.first]) {
                    d[neigh.first] = d[node.first] + neigh.second;
                    p[neigh.first] = node.first;
                    q.push({neigh.first, d[neigh.first]});
                }
            }
        }

        return {d, p};
    }

    // find minimum time for barbarians to reach capital
    int generate_cost_vector(vector<unsigned long long> d) {
        vector<unsigned long long> res;

        // create vector with all times for each barbarians to reach capital
        for (auto barbar : barbari) {
            vector<pair<int, unsigned long long>> neighs = adj[barbar];
            for (auto neigh : neighs) {
                res.push_back(neigh.second + d[neigh.first]);
            }
        }

        // sort to keep minimum value on position 0
        sort(res.begin(), res.end());

        // start puting towers
        int j = 0;
        for (int i = 0; i < k; i++) {
            if (!j) {
                while (res[j] == res[0] && j != res.size()) {
                    j++;
                }
            }
            res[--j]++;
        }

        // return minimum value
        return res[0];
    }

    // functionality
    int find_minimum_cost() {
        Dijkstra solution = minimum_length();
        return generate_cost_vector(solution.d);
    }

    // output
    void print_out(ofstream &out) {
        out << find_minimum_cost();
    }

