		private DijkstraResult dijkstra(int source) {
			List<Integer> d = new ArrayList<>();
			List<Integer> p = new ArrayList<>();
			List<Integer> visited = new ArrayList<>();

			// Initializare distante cu infinit
			for (int node = 0; node <= N; node++) {
				d.add(Integer.MAX_VALUE);
				p.add(0);
				visited.add(-1);
			}

			PriorityQueue<Pair> pq = new PriorityQueue<>();

			// Inserare nod sursa in pq si setare distanta 0
			d.set(source, 0);
			pq.add(new Pair(source, 0));

			while (!pq.isEmpty()) {
				// Extragere din capatul cozii
				int cost = pq.peek().cost;
				int node = pq.poll().destination;
				visited.set(node, 1);

				if (cost > d.get(node)) {
					continue;
				}

				// Parcurgere vecini
				for (int neigh = 1; neigh <= N; neigh++) {
