void dijkstra(int source, int n) {
    // Initializam vectorul de distante cu distante infinite.
    fill_n(&dj[0], n + 1, MAX_NO);
    int i;
    dj[source] = 0;
    priority_queue<pair<long long, int>,
                    vector <pair <long long, int>>,
                    greater <pair <long long, int> >> pq;
    pq.push(make_pair(0, source));
    dj[source] = 0;
    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();
        for (i = 0; i < (int) adj[u].size(); i++) {
            int v = adj[u][i].first;
            long long w = adj[u][i].second;
            // Daca nu este barbar, algoritmul continua normal
            if (isBarbar[v] == 0) {
                if (dj[v] > dj[u] + w) {
                    dj[v] = dj[u] + w;
                    pq.push(make_pair(dj[v], v));
                }
            } else {
                // Avem nod marginal (vecin cu unul barbar)
                margins.insert(u);
            }
        }
    }
}

