        isBarbar[x] = 1;
    }
    for (i = 0; i < m; i++) {
        fin >> x >> y >> dist;
        // graf neorientat
        adj[x].push_back(make_pair(y, dist));
        adj[y].push_back(make_pair(x, dist));
    }
    // Aplicam dijkstra din capitala pana in toate cetatile
    dijkstra(1, n);

    for (auto& cetate : margins) {
        for (i = 0; i < (int) adj[cetate].size(); i++) {
            // Daca vecinul este barbar
            if (isBarbar[adj[cetate][i].first]) {
                long long cost = dj[cetate] + adj[cetate][i].second;
                barbare.push_back(cost);
            }
