vector<pair<long long, long long>> v[100001];

// coada de prioritate pentru algoritmul lui Dijkstra
priority_queue<pair<long long, long long>, vector<pair<long long, long long>>,
               greater<pair<long long, long long>>>
    pq;

// functie pentru verificarea unui numar dist astfel incat barbarii pot fi
// opriti cel putin dist, folosind algoritmul lui Dijkstra
bool possible(long long dist) {
    // pregateste structurile de date pentru algoritmul lui Dijkstra
    dist += 1;

    // goleste vectorul de distanta
    memset(d, 0, sizeof(d));

    // remaining este numarul de fortificatii ramaase
    long long remaining = k;

    // adauga in coada de prioritate capitala
    pq.push(make_pair(1, 1));

    // incepe algoritmul lui Dijkstra
    while (!pq.empty()) {
        pair<long long, long long> nodePair = pq.top();
        pq.pop();
        long long nodeDistance = nodePair.first;
        long long node = nodePair.second;

        // continua daca nodul a fost deja vizitat
        if (d[node]) continue;

        // daca nodul este mai mare decat dist inseamna ca dist este o solutie
        if (nodeDistance >= dist) return true;

        // seteaza distanta pentru node
        d[node] = nodeDistance;

        // incearca actualizarea pentru toate nodurile adiacente
        for (auto it : v[node])
            // verifica daca nodul nu a fost deja vizitat
            if (!d[it.second]) {
                long long dn = nodeDistance + it.first;
                long long nn = it.second;

                // daca nodul adiacent este un oras barbaric, atunci verificam
                // daca trebuie folosite fortificatii pentru acest traseu
                if (barbar[nn] && dn < dist) {
                    long long delta = dist - dn;

                    // daca ramanem fara fortificatii inseamna ca dist nu
                    // este o solutie posibila
                    if (remaining < delta)
                        return false;
                    else
                        remaining -= delta;  // consuma fortificatiile necesare
                } else {
                    // adauga nodul nou in coada de prioritate
                    pq.push(make_pair(dn, nn));
                }
            }
    }
    return true;
}

