        barbar[x] = true;
    }

    for (int i = 0; i < m; i++) {
        int x, y, z;
        fin >> x >> y >> z;
        v[x].push_back(make_pair(z, y));
        v[y].push_back(make_pair(z, x));
    }

    // cauta binar solutia si verifica folosind algoritmul lui Dijkstra
    long long l = 0, r = LLONG_MAX, ans;
    while (l <= r) {
        long long mid = l + (r - l) / 2;

        if (possible(mid)) {
            // am gasit o solutia posibila, deci o salvam si cautam una mai mare
            ans = mid;
            l = mid + 1;
        } else {
            r = mid - 1;  // m nu este o solutie, deci cauta un mid mai mic
        }
    }
    fout << ans;
    return 0;
