    string src, dest;
    getline(infile, src, ' ');
    getline(infile, dest);

    // reading the number of routes from the file
    long long nrRoutes;
    nrCities = 0;
    infile >> nrRoutes;
    infile.ignore(numeric_limits<streamsize>::max(), '\n');
    long long i;
    map<string, city> cityInfo;

    // reading routes from file and creating the graph matrix
    for (i = 0; i < nrRoutes; i++) {
        string city1, city2;
        getline(infile, city1, ' ');
        getline(infile, city2);

        // adding city to hashmap if it's not already a key
        if (cityInfo.find(city1) == cityInfo.end()) {
            cityInfo[city1] = city();
            nrCities++;
        }

        if (cityInfo.find(city2) == cityInfo.end()) {
            cityInfo[city2] = city();
            nrCities++;
        }

        // adding route to the list
        cityInfo[city1].neighbours.push_back(city2);
    }
    infile.close();
    long long mostCities = 0;

    // performing dfs on graph to sort nodes topologically
    vector<string> topoSort;
    dfs(cityInfo, topoSort, src);
    reverse(topoSort.begin(), topoSort.end());

    // calculating distances
    cityInfo[src].distance = 0;
    for (i = 0; i < topoSort.size(); i++) {
        string crnt = topoSort[i];
        if (cityInfo[crnt].distance != INT_MIN) {
            for (long long k = 0; k < cityInfo[crnt].neighbours.size(); k++) {
                string neighCity = cityInfo[crnt].neighbours[k];
                if (cityInfo[neighCity].distance <
                 cityInfo[crnt].distance + 1) {
                    cityInfo[neighCity].distance = cityInfo[crnt].distance + 1;
                }
            }
        }
    }

    // printing the result
    mostCities = cityInfo[dest].distance + 1;
    outfile << mostCities;
    outfile.close();
    return 0;
}

