        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Stack;
import java.util.StringTokenizer;

public class Trenuri {

	//adjacency list for the cities/for the graph
	static Map<String, List<String>> adjListCity = new HashMap<>();
	//hashmap to mark visited cities
	static Map<String, Boolean> visitedCities = new HashMap<>();
	//hashmap to store the distances from the start city to other
	static Map<String, Integer> dist = new HashMap<>();
	//stack used for topological sort like the first problem
	static Stack<String> topoStack = new Stack<>();
	static String startCity, endCity;
	static int M;

	//DFS algo modified to use streams and to obtain a topological sort
	public static void dfs(String node) {
		visitedCities.put(node, true);

		adjListCity.getOrDefault(node, Collections.emptyList())
			.stream()
			.filter(neighbor -> !visitedCities.getOrDefault(neighbor, false))
			.toList()
			.forEach(Trenuri::dfs);

		topoStack.push(node);
	}


	//initialize the distances
	public static void initializeDistances() {
		for (String key : visitedCities.keySet()) {
			dist.put(key, Integer.MIN_VALUE);
		}
		dist.put(startCity, 0);
	}


	public static int processTopologicalOrder() {
		// process the topological order by checking the neighbors of each node from the stack
		// and recalculating the distance with merge function
		while (!topoStack.isEmpty()) {
			String node = topoStack.pop();

			if (dist.get(node) != Integer.MIN_VALUE) {
				adjListCity.getOrDefault(node, Collections.emptyList())
					.forEach(neighbor ->
						dist.merge(neighbor, dist.get(node) + 1, Math::max));
			}
		}

		var result = dist.getOrDefault(endCity, Integer.MIN_VALUE) + 1;

		return result;
	}

	public static void readEdges(BufferedReader reader) throws IOException {
		List<String> lines = reader.lines().limit(M).toList();

		// read the edges and store them in the adjacency list
		lines.forEach(line -> {
			StringTokenizer st = new StringTokenizer(line);
			String x = st.nextToken();
			String y = st.nextToken();
			adjListCity.computeIfAbsent(x, k -> new ArrayList<>()).add(y);
			visitedCities.putIfAbsent(x, false);
			visitedCities.putIfAbsent(y, false);
		});
	}


	public static void main(String[] args) {
		try (BufferedReader reader = new BufferedReader(new FileReader("trenuri.in"))) {
			StringTokenizer st = new StringTokenizer(reader.readLine());
			startCity = st.nextToken();
			endCity = st.nextToken();
			M = Integer.parseInt(reader.readLine());
			readEdges(reader);
		} catch (IOException e) {
			System.err.println("Error opening file: trenuri.in");
		}

		// DFS to get the topological order
		for (String key : visitedCities.keySet()) {
			if (!visitedCities.get(key)) {
				dfs(key);
			}
		}

		// initialize the distances and process the topological order
		initializeDistances();
		var result = processTopologicalOrder();

		try (PrintWriter writer = new PrintWriter(new FileWriter("trenuri.out"))) {
			writer.println(result);
		} catch (IOException e) {
			System.err.println("Error opening output file: " + "trenuri.out");
		}
	}
}

