    vector<string> sorted;
    queue<string> q;

    for (const auto& entry : indegree) {
        if (entry.second == 0) {
            q.push(entry.first);
        }
    }

    while (!q.empty()) {
        string current = q.front();
        q.pop();
        sorted.push_back(current);

        if (adj.find(current) != adj.end()) {
            for (const string& neighbor : adj.at(current)) {
                indegree[neighbor]--;
                if (indegree[neighbor] == 0) {
                    q.push(neighbor);
                }
            }
        }
    }

    return sorted;
}

// gasirea drumului cel mai lung
int findLongestPath(const string& start, const string& end,
const vector<string>& sorted, const map<string, vector<string>>& adj) {
    map<string, int> longest;
    longest[start] = 1;

    for (const string& city : sorted) {
        if (longest.find(city) != longest.end()) {
            if (adj.find(city) != adj.end()) {
                for (const string& neighbor : adj.at(city)) {
                    if (longest[city] + 1 > longest[neighbor]) {
                        longest[neighbor] = longest[city] + 1;
                    }
                }
            }
        }
    }

    return (longest.find(end) == longest.end()) ? 0 : longest[end];
}

int main() {
    ifstream fin("trenuri.in");
    ofstream fout("trenuri.out");

    string start, end;
    fin >> start >> end;

    int M;
    fin >> M;

    map<string, vector<string>> adj;  // lista de adiacenta pentru graf
    map<string, int> indegree;  // gradul de intrare pentru fiecare oras

    string u, v;
    while (M--) {
        fin >> u >> v;
        adj[u].push_back(v);  // adaugarea muchiei de la u la v
        indegree[v]++;  // cresterea gradul de intrare pentru v
        if (indegree.find(u) == indegree.end()) {
            indegree[u] = 0;
        }
    }

    vector<string> sorted = topologicalSort(adj, indegree);
    int result = findLongestPath(start, end, sorted, adj);

    fout << result << endl;

    fin.close();
    fout.close();
    return 0;
}

