            st.pop();

            if (dp[current] != -1) {
                for (string neigh : adj[current]) {
                    if (dp[neigh] < dp[current] + 1) {
                        dp[neigh] = dp[current] + 1;
                    }
                }
            }
        }

        return dp[end] + 1;
    }
};

