        #include <algorithm>
#include <fstream>
#include <iostream>
#include <stack>
#include <unordered_map>
#include <vector>
using namespace std;

// Structura de nod pentru graful neorientat
struct Node {
	vector<int> neighbors;  // Lista vecinilor
};

// Funcția pentru calculul lungimii celui mai lung drum într-un graf
int longestPathLength(const vector<Node> &graph, int source, int destination) {
	int n = graph.size();
	vector<int> dist(n, -1);  // Vector pentru a stoca distanțele minime de la
							  // sursă la fiecare nod
	vector<int> pred(n, -1);  // Vector pentru a reține predecesorii în cadrul
							  // drumului cel mai lung

	dist[source] = 0;  // Lungimea drumului de la sursă la sursă este 0

	stack<int> dfsStack;			 // Stivă pentru parcurgerea în adâncime
	vector<bool> visited(n, false);  // Vector pentru a marca nodurile vizitate

	// Funcția de parcurgere în adâncime pentru sortarea topologică a nodurilor
	function<void(int)> dfsTopo = [&](int node) {
		visited[node] = true;  // Marchează nodul ca vizitat
		for (int neighbor : graph[node].neighbors) {
			if (!visited[neighbor]) {  // Dacă vecinul nu a fost vizitat încă
				dfsTopo(neighbor);	   // Parcurge recursiv vecinul
			}
		}
		dfsStack.push(node);  // După ce a terminat parcurgerea în adâncime a
							  // vecinilor, adaugă nodul în stivă
	};

	// Parcurgerea grafului pentru a apela funcția de sortare topologică pentru
	// nodurile nevizitate
	for (int i = 0; i < n; ++i) {
		if (!visited[i]) {
			dfsTopo(i);
		}
	}

	// Calculul distanțelor minime de la sursă la fiecare nod folosind
	// sortarea topologică
	while (!dfsStack.empty()) {
		int node = dfsStack.top();
		dfsStack.pop();
		for (int neighbor : graph[node].neighbors) {
			if (dist[node] + 1 > dist[neighbor]) {  // Dacă distanța curentă
												    // este mai mare decât distanța
												    // înregistrată anterior
				dist[neighbor] = dist[node] + 1;    // Actualizează distanța
				pred[neighbor] = node;			    // Actualizează predecesorul
			}
		}
	}

	int longestPathLength = dist[destination];  // Lungimea celui mai lung drum
	                                            // până la destinație
	return longestPathLength;
}

int main() {
	ifstream fin("trenuri.in");
	ofstream fout("trenuri.out");

	// Harta pentru a măpa numele nodurilor la indicii lor în graf
	unordered_map<string, int> nodeIndexMap;
	// Contor pentru a asigura indici unici pentru fiecare nod
	int indexCounter = 0;

	string source, destination;
	fin >> source >> destination;

	int m;
	fin >> m;			    // Numărul de muchii în graf
	vector<Node> graph(m);  // Graf reprezentat ca un vector de noduri

	for (int i = 0; i < m; ++i) {
		string u, v;
		fin >> u >> v;  // Citirea unei muchii
		if (nodeIndexMap.find(u) == nodeIndexMap.end()) {
			// Adaugă un nou nod în hartă dacă nu există deja
			nodeIndexMap[u] = indexCounter++;
		}
		if (nodeIndexMap.find(v) == nodeIndexMap.end()) {
			// Adaugă un nou nod în hartă dacă nu există deja
			nodeIndexMap[v] = indexCounter++;
		}
		// Adaugă vecinul v la nodul u
		graph[nodeIndexMap[u]].neighbors.push_back(nodeIndexMap[v]);
	}

	// Calculul lungimii celui mai lung drum
	int longestPathLen =
	longestPathLength(graph, nodeIndexMap[source], nodeIndexMap[destination]);
	fout << longestPathLen + 1;

	fin.close();
	fout.close();

	return 0;
}

