// Functia care face sortarea topologica a grafului
void topologicalSort(const string &oras, unordered_map<string, bool> &visited, 
                     unordered_map<string, vector<string>> &graph, stack<string> &topo) {
    visited[oras] = true;
    for (const string &neighbor : graph[oras]) {
        if (!visited[neighbor]) {
            topologicalSort(neighbor, visited, graph, topo);
        }
    }
    topo.push(oras);
}

