    ofstream fout("trenuri.out");

    string inceput, destinatie;
    fin >> inceput >> destinatie;

    int M;
    fin >> M;

    string traseu_start, traseu_dest;

    // Citesc orasul de inceput si destinatia traseului
    for (int i = 0; i < M; ++i) {
        fin >> traseu_start >> traseu_dest;
        graph[traseu_start].push_back(traseu_dest);
        visited[traseu_start] = false;
        visited[traseu_dest] = false;
    }

    for (auto &entry : visited) {
        if (!entry.second) {
            topologicalSort(entry.first, visited, graph, topoOrder);
        }
    }

    // Initializez vectorul de orase vizitate cu 0
    for (auto &entry : visited) {
        orase_vizitate[entry.first] = 0;
    }

    // Parcurg graful in ordine
