            if (orase_vizitate[neighbor] < orase_vizitate[oras] + 1) {
                orase_vizitate[neighbor] = orase_vizitate[oras] + 1;
            }
        }
    }

    fout << orase_vizitate[destinatie] << endl;

    return 0;
