        #include <fstream>
#include <iostream>
#include <vector>
#include <map>
#include <queue>
#include <string>
#include <algorithm>

using namespace std;

vector<string> topologicalSort(const map<string, vector<string>>& graph) {
    map<string, int> inDegree;

    // initialized inDegree for all nodes to ensure they are accounted for
    for (const auto& pair : graph) {
        if (inDegree.find(pair.first) == inDegree.end()) {
            inDegree[pair.first] = 0;
        }
        for (const auto& v : pair.second) {
            inDegree[v]++;
        }
    }

    queue<string> queue;
    // push nodes with 0 in-degree into the queue
    for (const auto& pair : inDegree) {
        if (pair.second == 0) {
            queue.push(pair.first);
        }
    }

    vector<string> topOrder;
    while (!queue.empty()) {
        string u = queue.front();
        queue.pop();
        topOrder.push_back(u);

        if (graph.find(u) != graph.end()) {
            for (const auto& v : graph.at(u)) {
                if (--inDegree[v] == 0) {
                    queue.push(v);
                }
            }
        }
    }

    return topOrder;
}

int main() {
    ifstream fin("trenuri.in");
    ofstream fout("trenuri.out");

    string startEnd;
    getline(fin, startEnd);
    int pos = startEnd.find(" ");

    string startCity = startEnd.substr(0, pos);
    string endCity = startEnd.substr(pos + 1);

    int M;
    fin >> M;
    fin.ignore();

    map<string, vector<string>> graph;
    string line, from, to;
    // read routes and build the graph
    while (getline(fin, line)) {
        pos = line.find(" ");
        from = line.substr(0, pos);
        to = line.substr(pos + 1);
        graph[from].push_back(to);
    }

    // topological sort
    vector<string> topOrder = topologicalSort(graph);

    // created a map to get index of cities in topological order
    map<string, int> idx;

    for (int i = 0; i < topOrder.size(); i++) {
        idx[topOrder[i]] = i;
    }

    // Initialize distances to -1 (unreachable)
    vector<int> dist(topOrder.size(), -1);

    if (idx.find(startCity) != idx.end()) {
        dist[idx[startCity]] = 0;
    }

    // find longest paths
    for (const auto& city : topOrder) {
        if (dist[idx[city]] != -1 && graph.find(city) != graph.end()) {
            for (const auto& neighbor : graph[city]) {
                if (idx.find(neighbor) != idx.end()
                            && dist[idx[neighbor]] < dist[idx[city]] + 1) {
                    dist[idx[neighbor]] = dist[idx[city]] + 1;
                }
            }
        }
    }


    int result = -1;
    // determine the result based on the distance to the end city
    if (idx.find(endCity) != idx.end() && dist[idx[endCity]] != -1) {
        result = dist[idx[endCity]] + 1;
    }

    fout << result << endl;

    return 0;
}

