        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Trenuri {
	static Map<String, List<String>> graph;
	static Map<String, Integer> longestPathMemo;

	public static void main(String[] args) throws IOException {
		BufferedReader br = new BufferedReader(new FileReader("trenuri.in"));
		final PrintWriter pw = new PrintWriter(new FileWriter("trenuri.out"));

		// Read start and destination cities
		String[] firstLine = br.readLine().split(" ");
		final String start = firstLine[0];
		final String destination = firstLine[1];

		int M = Integer.parseInt(br.readLine());
		graph = new HashMap<>();
		longestPathMemo = new HashMap<>();

		// Building the graph from input
		for (int i = 0; i < M; i++) {
			String[] route = br.readLine().split(" ");
			graph.computeIfAbsent(route[0], k -> new ArrayList<>()).add(route[1]);
		}

		// Calculate the longest path from the start city to the destination
		int maxCities = dfs(start, destination) + 1;

		// Writing the result
		pw.println(maxCities);
		pw.close();
		br.close();
	}

	private static int dfs(String current, String destination) {
		if (current.equals(destination)) {
			return 0;
		}

		// If the result was already computed for this city, return it
		if (longestPathMemo.containsKey(current)) {
			return longestPathMemo.get(current);
		}

		int max = 0;
		List<String> neighbours = graph.get(current);
		if (neighbours != null) {
			for (String neighbour : neighbours) {
				int candidate = dfs(neighbour, destination);
				if (candidate > max) {
					max = candidate;
				}
			}
		}

		// Memoize the longest path found from this city, plus one for the current city
		// itself
		longestPathMemo.put(current, max + 1);
		return max + 1;
	}
}

