class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    // Maximum number of nodes
    static constexpr int NMAX = (int)1e5 + 5;

    // Number of nodes and edges
    int N, M;

    // Graph as an adjacency list
    vector<Node> adj[NMAX];

    // Data sets and in degrees for each node
    vector<int> data_set;
    vector<int> in_degree;

    void read_input() {
        ifstream fin("supercomputer.in");
        fin >> N >> M;

        data_set = vector<int>(N + 1, 0);
        in_degree = vector<int>(N + 1, 0);

        // Read data set for each node
        for (int i = 1; i <= N; i++) {
            fin >> data_set[i];
        }

        // Read adjacency list and in degrees
        for (int i = 1, x, y; i <= M; i++) {
            fin >> x >> y;
            adj[x].push_back({y, data_set[y]});
            in_degree[y]++;
        }

        fin.close();
    }

    int get_result() {
        return solve_bfs();
    }

    // Order the vector in ascending order
    static bool comp_asc(Node a, Node b) {
        return a.data_set < b.data_set;
    }

    // Order the vector in descending order
    static bool comp_desc(Node a, Node b) {
        return a.data_set > b.data_set;
    }

    int solve_bfs() {
        int count = 0, last_data_set;

        // Vector for the topological sort
        vector<int> topsort(N + 1, 0);

        // Queue for the nodes to be visited
        queue<int> q;

        // Add all 0 in degree nodes to the queue to be visited
        for (int node = 1; node <= N; ++node) {
            if (in_degree[node] == 0) {
                q.push(node);
                count++;

                // Save first node to be visited's data set
                if (count == 1) last_data_set = data_set[node];
            }
        }

        // Do a BFS on the graph
        int idx = 1;
        while (!q.empty()) {
            int node = q.front();
            q.pop();

            // Add the current node to the sorted vector
            topsort[idx++] = node;

            // Sort nodes in the adjacency list
            // ASC -> last data set was a 1
            // DESC -> last data set was a 2
            if (last_data_set == 1) {
                sort(adj[node].begin(), adj[node].end(), comp_asc);
            } else {
                sort(adj[node].begin(), adj[node].end(), comp_desc);
            }

            for (const auto& [neigh, set] : adj[node]) {
                // Erase edge node->neigh
                in_degree[neigh]--;

                // If neigh has no more dependencies
                // it is added to the queue
                if (in_degree[neigh] == 0) {
                    q.push(neigh);
                    last_data_set = data_set[neigh];
                }
            }
        }

        // If there are still edges in the graph,
        // the topological sort is not valid
        bool is_valid = true;
        for (int node = 1; node <= N; ++node) {
            if (in_degree[node] > 0) {
                return -1;
            }
        }

        // If the topological sort is valid, return
        // the number of switches
        int result = 0, curr_set = data_set[topsort[1]];

        for (int i = 2; i <= N; i++) {
            if (data_set[topsort[i]] != curr_set) {
                curr_set = data_set[topsort[i]];
                result++;
            }
        }

        return result;
    }

    void print_output(int result) {
        ofstream fout("supercomputer.out");
        fout << result << '\n';
        fout.close();
    }
};

int main() {
