			writer.println(result);
			writer.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}

	private static int compute() {

		Queue<Integer> queue = new LinkedList<>();
		Queue<Integer> auxQueue = new LinkedList<>();
		int numSwitches = 0;

		int[] inDegree = new int[numTasks + 1];
		for (int i = 1; i <= numTasks; i++) {
			for (int dependency : dependencies.get(i)) {
				inDegree[dependency]++;
			}
		}

		for (int i = 1; i <= numTasks; i++) {
			if (inDegree[i] == 0) {
				queue.add(i);
			}
		}

		while (!queue.isEmpty()) {
			int task = queue.poll();
			for (int dependency : dependencies.get(task)) {
				inDegree[dependency]--;
				if (inDegree[dependency] == 0) {
					if (datasets[dependency - 1].equals(datasets[task - 1])) {
						queue.add(dependency);
					} else {
						auxQueue.add(dependency);
					}
				}
			}
			if (queue.isEmpty()) {
				if (!auxQueue.isEmpty()) {
					numSwitches++;
					queue = auxQueue;
					auxQueue = new LinkedList<>();
				}
			}
		}

		return numSwitches;
	}


	public static void main(String[] args) {
		readInput();
		int result = compute();
		writeOutput(result);
	}

}
