import java.util.ArrayList;
import java.util.Arrays;
import java.util.LinkedList;
import java.util.Queue;
import java.util.StringTokenizer;


public class Supercomputer {

	private static int n;

	private static int m;

	private static ArrayList<ArrayList<Integer>> adj;

	private static int[] grades;

	private static boolean[] used;

	private static int[] neededTasks;



	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("supercomputer.in"));

		n = scanner.nextInt();
		m = scanner.nextInt();

		neededTasks = new int[n + 1];
		grades = new int[n + 1];
		used = new boolean[n + 1];



		int switches = 0;

		for (int i = 1; i <= n; i++) {
			neededTasks[i] = scanner.nextInt();
		}

		adj = new ArrayList<>();

		for (int i = 0; i < n; i++) {
			adj.add(new ArrayList<>());
		}

		for (int i = 0; i < m; i++) {
			int x = scanner.nextInt();
			int y = scanner.nextInt();

			// adaugam nodurile cu acelasi task pe prima pozitie in lista
			// pentru a le prioritiza in cadrul toposortului
			if (neededTasks[y] == neededTasks[x]) {
				adj.get(x - 1).add(0, y);
			} else {
				adj.get(x - 1).add(y);
			}

			grades[y]++;

		}

		// efectuam toposort
		ArrayList<Integer> toposort = solveDfs();

		// calculam switch-urile necesare pe baza
		// rezultatului toposortului
		int loadedTask = neededTasks[toposort.get(0)];

		for (int i = 1; i < toposort.size(); i++) {


			if (neededTasks[toposort.get(i)] != loadedTask) {
				loadedTask = neededTasks[toposort.get(i)];
				switches++;
			}

		}

		try (var printer = new PrintStream("supercomputer.out")) {

			printer.println(switches);

		}
	}


	private static ArrayList<Integer> solveDfs() {
		// vectorul rezultat (in final contine o permutare pentru 1, 2, ... n)
		ArrayList<Integer> topsort = new ArrayList<>();


		// pentru fiecare nod
		for (int node = n; node >= 1; node--) {

			// daca nodul nu a fost vizitat, pornim o parcurgere DFS
			if (!used[node] && grades[node] == 0) {
				dfs(node, used, topsort);
			}
		}


		return topsort;
	}

	// porneste o parcurgere DFS din node
	// foloseste vectorul used pentru a marca nodurile vizitate
	private static void dfs(int node, boolean[] used, ArrayList<Integer> topsort) {

		topsort.add(node);
		for (Integer neigh : adj.get(node - 1)) {
			grades[neigh]--;
		}

		used[node] = true;

		for (int i = 0; i < adj.get(node - 1).size(); i++) {
			int neigh = adj.get(node - 1).get(i);

			if (!used[neigh] && grades[neigh] == 0) {

				dfs(neigh, used, topsort);

			}
		}
	}



