import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;

public class Supercomputer {

	// Variabile statice pentru stocarea informațiilor necesare
	static int noTaskuri; // Numărul de task-uri
	static int noDeependencies; // Numărul de dependențe
	static int actualElement; // Task-ul curent în procesare
	static int visitedTasks = 0; // Numărul de task-uri vizitate
	static int actualSet; // Setul curent în procesare
	static int lastSet; // Setul anterior în procesare
	static int noSetSwaps; // Numărul de schimbări de seturi
	// Lista de dependențe pentru fiecare task
	static List<LinkedList<Integer>> dependenciesList = new ArrayList<>();
	// Coada de task-uri pentru fiecare set
	static HashMap<Integer, LinkedList<Integer>> setQueue = new HashMap<>();

	public static void main(String[] args) throws IOException {
		String inputFile = "supercomputer.in";
		String outputFile = "supercomputer.out";

		try (BufferedReader reader = new BufferedReader(new FileReader(inputFile));
				BufferedWriter writer = new BufferedWriter(new FileWriter(outputFile))) {


			// Citirea numărului de task-uri și al dependențelor
			String line = reader.readLine();
			String[] parts = line.split(" ");

			noTaskuri = Integer.parseInt(parts[0]);
			noDeependencies = Integer.parseInt(parts[1]);

			// Citirea setului cerut pentru fiecare task
			line = reader.readLine();
			parts = line.split(" ");

			int[] setEachTask = new int[noTaskuri + 1];

			int i;
			for (i = 1; i <= noTaskuri; i++) {
				setEachTask[i] = Integer.parseInt(parts[i - 1]);
			}

			actualSet = 1;
			lastSet = 1;

			// Inițializarea cozilor de task-uri pentru fiecare set
			setQueue.put(1, new LinkedList<>());
			setQueue.put(2, new LinkedList<>());

			// Inițializarea listei de dependențe pentru fiecare task
			for (i = noTaskuri; i-- >= 0; ) {
				dependenciesList.add(new LinkedList<>());
			}

			// Citirea dependențelor dintre task-uri și adăugarea lor în graf
			line = reader.readLine();
			for (i = 1; i <= noDeependencies; i++) {
				parts = line.split(" ");

				int u = Integer.parseInt(parts[0]);
				int v = Integer.parseInt(parts[1]);

				dependenciesList.get(v).add(u);
				line = reader.readLine();
			}

			// Adăugarea task-urilor fără dependențe în coada corespunzătoare
			for (i = 1; i <= noTaskuri; i++) {
				if (dependenciesList.get(i).isEmpty()) {
					setQueue.get(setEachTask[i]).add(i);
				}
			}

			// Determinarea setului cu mai multe task-uri în coadă
			if (setQueue.get(2).size() > setQueue.get(1).size()) {
				++ actualSet;
				++ lastSet;
			}

			// Extrage primul task din coada setului curent și îl marchează ca vizitat
			++ visitedTasks;
			actualElement = setQueue.get(actualSet).removeFirst();


			// Procesarea task-urilor în ordinea dependențelor
			do {
				// Verificarea dependențelor fiecărui task
				for (i = 1; i <= noTaskuri; i++) {
					// Dacă task-ul nu mai are dependențe, este adăugat în coada setului aferent
					if (dependenciesList.get(i).remove((Integer) actualElement)) {
						if (dependenciesList.get(i).isEmpty()) {
							setQueue.get(setEachTask[i]).add(i);
						}
					}
				}

				// Verificarea dacă coada setului anterior este goală
				if (setQueue.get(lastSet).isEmpty()) {
					// Actualizarea setului curent și incrementarea contorului de schimbări de set
					if (lastSet == 1) {
						actualSet = 2;
					} else {
						actualSet = 1;
					}

					if (!(setQueue.get(2).isEmpty() && setQueue.get(1).isEmpty())) {
						noSetSwaps++;
					}
				}

				// Extrage următorul task din coada setului curent și îl marchează ca vizitat
				++ visitedTasks;
				lastSet = actualSet;
				actualElement = setQueue.get(lastSet).removeFirst();

			} while (visitedTasks != noTaskuri);

			// Scrie rezultatul în fișierul de ieșire
			writer.write(String.valueOf(noSetSwaps));
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

