        #include <bits/stdc++.h>
using namespace std;
int n, m, sum;
vector<pair<int, int>> v[100001];
int tasks[100001];
int ingrade[100001];
bool visited[100001];

void topologicalSort() {
    deque<int> dq;
    queue<int> q;
    // all the given nodes with 0 indegree
    for (int i = 1; i <= n; i++) {
        if (ingrade[i] == 0) {
            q.push(i);
        }
    }
    while (!q.empty()) {
        int u = q.front();
        sum = 0;
        q.pop();
        dq.push_back(u);
        // for each node with 0 indegree, start a topsort
        while (!dq.empty()) {
            int z = dq.front();
            visited[z] = true;
            dq.pop_front();
            for (auto itr = v[z].begin();
                itr != v[z].end(); itr++) {
                if (--ingrade[itr->first] == 0) {
                    if (itr->second) {
                        // the ones with 0 cost get priority
                        dq.push_back(itr->first);
                            if (!visited[itr->first]) {
                                sum++;
                            }
                    } else {
                        dq.push_front(itr->first);
                    }
                }
            }
        }
    }
}


int main() {
    ifstream fin("supercomputer.in");
    ofstream fout("supercomputer.out");
    fin >> n >> m;
    for (int i = 1; i <= n; i++) {
        fin >> tasks[i];
    }
    int a, b;
    for (int i = 0; i < m; i++) {
        fin >> a >> b;
        if (tasks[a] != tasks[b]) {
            v[a].push_back({b, 1});
            ingrade[b]++;
        } else {
            v[a].insert(v[a].begin(), {b, 0});
            ingrade[b]++;
        }
    }
    topologicalSort();
    fout << sum << "\n";
