using namespace std;

vector<int> indegree;
vector<vector<int>> adj;

int supercomputer(int N, vector<int>& datasets, vector<pair<int,
                    int>>& dependencies) {
    indegree.assign(N + 1, 0);
    adj.assign(N + 1, vector<int>());

    for (auto& dependency : dependencies) {
        int u = dependency.first;
        int v = dependency.second;
        adj[v].push_back(u);
        indegree[u]++;
    }

    queue<int> q;
    for (int i = 1; i <= N; i++) {
        if (indegree[i] == 0) {
            q.push(i);
        }
    }

    int contextSwitches = 0;
    int prevDataset = datasets[q.front()];

    while (!q.empty()) {
        int u = q.front();
        q.pop();

        int currDataset = datasets[u];
        if (currDataset != prevDataset) {
            contextSwitches++;
            prevDataset = currDataset;
        }

        for (int v : adj[u]) {
            indegree[v]--;
            if (indegree[v] == 0) {
                q.push(v);
            }
        }
    }

    return contextSwitches;
}

int main() {
    ifstream fin("supercomputer.in");
    ofstream fout("supercomputer.out");

    int N, M;
    fin >> N >> M;

    vector<int> datasets(N + 1);
    for (int i = 1; i <= N; i++) {
        fin >> datasets[i];
    }

    vector<pair<int, int>> dependencies(M);
    for (int i = 0; i < M; i++) {
        int u, v;
        fin >> u >> v;
        dependencies[i] = {u, v};
    }

    int result = supercomputer(N, datasets, dependencies);

    fout << result << endl;

    fin.close();
    fout.close();

    return 0;
}

