	private static long solveTask(int N, int[] dataSets, TopologicalSort topologicalSort) {
		List<List<Integer>> allTopologicalSorts = topologicalSort.getAllTopologicalSorts();
		System.out.println(allTopologicalSorts);
		// get the topological sort with the minimum context switches
		int minContextSwitches = Integer.MAX_VALUE;
		for (List<Integer> topologicalSort2 : allTopologicalSorts) {
			int contextSwitches = 0;
