				int next = topologicalSort2.get(i + 1);
				if (dataSets[current] != dataSets[next]) {
					contextSwitches += 1;
				}
			}
			minContextSwitches = Math.min(minContextSwitches, contextSwitches);
		}
		System.out.println(minContextSwitches);
		return minContextSwitches;
	}

