        #include <iostream>
#include <fstream>
#include <vector>
#include <queue>

using namespace std;

// variabila pentru initializare vector de distante
#define MAX 20000000000

// structura pentru muchii
struct Edge {
    int dest;
    long long weight;

    // perioada in care se poate transporta (0 daca nu e cazul)
    long long period;
};

// Algoritmul lui Dijkstra pentru cel mai scurt drum
vector<long long> dijkstra(int N, const vector<vector<Edge>>& graph) {
    /* vector pentru cele mai mici distante 
    (initializat cu cea mai mare dist posibila) */
    vector<long long> dist(N + 1, MAX);
    // noduri vizitate
    vector<bool> visited(N + 1, false);
    // priority queue pentru eficienta
    priority_queue<pair<long long, int>,
    vector<pair<long long, int>>, greater<pair<long long, int>>> priorityQueue;

    // distanta este 0 initial pentru nodul sursa
    dist[1] = 0;
    priorityQueue.push(make_pair(0, 1));

    while (!priorityQueue.empty()) {
        // aleg nodul cu cea mai mica distanta
        int u = priorityQueue.top().second;
        long long d = priorityQueue.top().first;
        priorityQueue.pop();

        // sar peste nodurile pe care le-am vizitat deja
        if (visited[u]) {
            continue;
        }

        visited[u] = true;

        // Procesez toate nodurile adiacente lui u
        for (Edge edge : graph[u]) {
            int v = edge.dest;
            long long weight = edge.weight;
            long long period = edge.period;

            // daca este nod de teleportare
            if (period > 0) {
                // calculez urmatorul timp in care ma pot teleporta
                long long time = (d + period - 1) / period * period + weight;

                // actualizez distanta daca e mai mica decat timpul curent
                if (time < dist[v]) {
                    dist[v] = time;

                    // adaug nodul si dist actualizata in coada de prioritati
                    priorityQueue.push(make_pair(dist[v], v));
                }
            } else {
                /* verific daca se merita adaugat nodu-ul normal , 
                in functie de weight */
                if (d + weight < dist[v]) {
                    dist[v] = d + weight;

                    /* adaug nodul si distanta actualizata 
                    in coada de prioritati */
                    priorityQueue.push(make_pair(dist[v], v));
                }
            }
        }
    }

    // returnez un vector de distante minime pentru fiecare nod
    return dist;
}

int main() {
    ifstream inputFile("teleportare.in");
    ofstream outputFile("teleportare.out");

    int N, M, K, x, y;
    long long weight, period;
    inputFile >> N >> M >> K;

    // lista de adiacenta graf
    vector<vector<Edge>> graph(N + 1);

    // citesc muchiile normale
    for (int i = 0; i < M; ++i) {
        inputFile >> x >> y >> weight;
        // adaug muchia
        graph[x].push_back(Edge{y, weight, 0});
        // adaug muchia invers
        graph[y].push_back(Edge{x, weight, 0});
    }

    // muchiile de teleportare
    for (int i = 0; i < K; ++i) {
        inputFile >> x >> y >> period;
        // adaug muchia de transport
        graph[x].push_back(Edge{y, 1, period});
        // adaug si invers
        graph[y].push_back(Edge{x, 1, period});
    }

    // algoritmul lui Dijkstra pentru cel mai mic drum pentru fiecare nod
    vector<long long> shortestDistances = dijkstra(N, graph);

    // cel mai mic drum pt nodul N
    long long shortestPath = shortestDistances[N];

    outputFile << shortestPath << "\n";

    inputFile.close();
    outputFile.close();

    return 0;
}

