int bfs(list<Node> *graph, int n, int start, int end, int **visited, int max) {
  priority_queue<pair<int, int>, vector<pair<int, int>>,
                 std::greater<pair<int, int>>>
      q;
  q.push(std::make_pair(0, start));

  while (!q.empty()) {
    pair<int, int> p = q.top();
    q.pop();
    int node = p.second;
    int cost = p.first;
    if (node == end) {
      return cost;
    }
    for (auto it = graph[node].begin(); it != graph[node].end(); it++) {
      if (it->temp && cost % it->cost != 0)
        continue;
      int new_dist;
      if (it->temp)
        new_dist = cost + 1;
      else
        new_dist = cost + it->cost;
      if (visited[it->n][new_dist % max] > new_dist ||
          visited[it->n][new_dist % max] == -1) {
        visited[it->n][new_dist % max] = new_dist;
        q.push(std::make_pair(new_dist, it->n));
      }
    }
  }
  return -1;
}

