        #include <bits/stdc++.h>

using namespace std;
ifstream fin("teleportare.in");
ofstream fout("teleportare.out");

long long N;		// number of nodes
long long M;		// number of normal edges
long long K;		// number of teleportation edges
long long TMAX;		// the period of the graph

/* Returns the biggest common divisor of a and b */
long long cmmmd(long long a, long long b) {
    long long r;

    while (b != 0) {
        r = a % b;
        a = b;
        b = r;
    }

    return a;
}

int main() {
	fin >> N >> M >> K;

	// the time needed to travel
	vector<pair<long long, long long>> cost[N + 1];

	// the period of the teleportation
	vector<pair<long long, long long>> magic[N + 1];

	/* Read the normal edges with their cost */
	for (int i = 1; i <= M; ++i) {
		long long X, Y;
		long long T;

		fin >> X >> Y >> T;

		cost[X].push_back({Y, T});
		cost[Y].push_back({X, T});
	}

	TMAX = 1;
	/* Read the teleportation edges with their period */
	for (int i = 1; i <= K; ++i) {
		long long X, Y, P;

		fin >> X >> Y >> P;

		magic[X].push_back({Y, P});
		magic[Y].push_back({X, P});

		/* Calculate the CMMMC of all the periods - period of graph */
		TMAX = TMAX * P / cmmmd(TMAX, P);
	}

	vector<vector<long long>> d(TMAX, vector<long long>(N + 1, LONG_MAX));
	d[0][1] = 0;

    priority_queue<pair<long long, long long>,
					vector<pair<long long, long long>>,
					greater<pair<long long, long long>>> pq;
    pq.push({0, 1});

    while (!pq.empty()) {
		long long old_dist = pq.top().first;
        long long node = pq.top().second;
        pq.pop();

		if (node == N) {
			fout << old_dist << '\n';
			return 0;
		}

		if (old_dist > d[old_dist%TMAX][node])
            continue;

        for (const auto& neigh : cost[node]) {
			long long v = neigh.first;
			long long w = neigh.second;

			long long new_d = d[old_dist%TMAX][node] + w;
			if (new_d < d[(old_dist + w)%TMAX][v]) {
				d[(old_dist + w)%TMAX][v] = new_d;
				pq.push({new_d, v});
			}
        }

		for (const auto& neigh : magic[node]) {
			long long v = neigh.first;
			long long w = neigh.second;

			if (old_dist % w == 0) {
				long long new_d = d[old_dist%TMAX][node] + 1;
				d[(old_dist + 1)%TMAX][v] = new_d;
				pq.push({new_d, v});
			}
		}
    }

	return 0;
}

