import java.util.Arrays;
import java.util.Comparator;
import java.util.PriorityQueue;

public class Teleportare {
	static class Edge {
		int source;
		int destination;
		int time;
		boolean isTeleportation;
		int teleportationPeriod;

		public Edge(int source, int destination, int time,
					boolean isTeleportation, int teleportationPeriod) {
			this.source = source;
			this.destination = destination;
			this.time = time;
			this.isTeleportation = isTeleportation;
			this.teleportationPeriod = teleportationPeriod;
		}
	}

	private static int n, m, k;
	private static ArrayList<ArrayList<Edge>> graph;

	private static void write_output(int result) {
		try {
			FileWriter fileWriter = new FileWriter("../teleportare.out");
			BufferedWriter bufferedWriter = new BufferedWriter(fileWriter);

			bufferedWriter.write(String.valueOf(result));
			bufferedWriter.close();
			fileWriter.close();

		} catch (Exception e) {
			throw new RuntimeException(e);
		}
	}

	private static int minimumDuration() {
		int[] dist = new int[n + 1];
		Arrays.fill(dist, Integer.MAX_VALUE);
		dist[1] = 0;

		// declar o coada de prioritate in care vor fi stocate
		// muchiile in ordine crescatoare al timpului de parcurgere
		PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingInt(e -> e.time));
		pq.offer(new Edge(1, 1, 0, false, 0));

		while (!pq.isEmpty()) {
			Edge curr = pq.poll();
			int currNode = curr.destination;
			int currTime = curr.time;

			if (currTime > dist[currNode]) {
				continue;
			}

			// parcurg fiecare muchie adiacenta
			// nodului destinatie extras din stiva
			for (Edge neighbor : graph.get(currNode)) {
				int nextNode = neighbor.destination;
				int nextTime = currTime + neighbor.time;
				boolean isTeleportation = neighbor.isTeleportation;
				int teleportationPeriod = 0;

				// in cazul in care muchia este de teleportare,
				// verific daca poate fi parcursa
				if (isTeleportation) {
					teleportationPeriod = neighbor.teleportationPeriod;
					int waitTime = (currTime % teleportationPeriod == 0)
							? 0 : (teleportationPeriod - currTime % teleportationPeriod);
					nextTime += waitTime;
				}

				if (nextTime < dist[nextNode]) {
					dist[nextNode] = nextTime;
					pq.offer(new Edge(currNode, nextNode, nextTime,
							isTeleportation, teleportationPeriod));
				}
			}
		}

		return dist[n];
	}

