constexpr long INFTY = (long)1e16;

int lcm(int a, int b) {
    // Calculeaza CMMMC al celor doua numere prin impartirea produsului acestora
    // la CMMDC al lor, calculat folosind algoritmul lui Euclid
    int a_copy = a, b_copy = b, r;
    if (a_copy < b_copy) {
        r = a_copy;
        b_copy = r;
        a_copy = b_copy;
    }

    r = a_copy % b_copy;

    while (r) {
        a_copy = b_copy;
        b_copy = r;
        r = a_copy % b_copy;
    }

    return a * b / b_copy;
}

struct Destination {
    int node;
    long dist;

    Destination(int node, long dist): node(node), dist(dist) {}

    bool operator<(const Destination &other) const {
        return dist < other.dist;
    }

    bool operator>(const Destination &other) const {
        return dist > other.dist;
    }
};

struct Node {
    std::vector<Destination> edges;
    std::vector<Destination> teleports;
};

using Graph = std::vector<Node>;

int main() {
    int nodes, edges, teleports;

    std::ifstream in("teleportare.in");
    std::ofstream out("teleportare.out");

    in >> nodes >> edges >> teleports;
    int period_lcm = 1;

    // Construieste graful
    Graph graph(nodes);

    for (int i = 0; i < edges; i++) {
        int x, y, w;
        in >> x >> y >> w;

        graph[x - 1].edges.push_back(Destination(y - 1, w));
        graph[y - 1].edges.push_back(Destination(x - 1, w));
    }

    for (int i = 0; i < teleports; i++) {
        int x, y, period;
        in >> x >> y >> period;

        // Calculeaza si CMMMC al tuturor perioadelor simultan cu construirea
        // grafului
        period_lcm = lcm(period_lcm, period);

        graph[x - 1].teleports.push_back(Destination(y - 1, period));
        graph[y - 1].teleports.push_back(Destination(x - 1, period));
    }

    in.close();

    std::priority_queue<
        Destination,
        std::vector<Destination>,
        std::greater<Destination>> pq;

    std::vector<std::vector<long>>
    dist(nodes, std::vector<long>(period_lcm, INFTY));

    pq.push(Destination(0, 0));

    // Ruleaza algoritmul lui Dijkstra, parcurgand toate nodurile in toate
    // configuratiile posibile ale cooldown-urilor teleportoarelor
    while (!pq.empty()) {
        auto &dest = pq.top();
        long time = dest.dist;
        int node = dest.node;
        pq.pop();

        int period_moment = time % period_lcm;
        if (dist[node][period_moment] <= time)
            continue;

        // Avem cel mai bun timp pentru nodul curent in configuratia curenta
        // a contoarelor de teleportare
        dist[node][period_moment] = time;

        // Adauga nodurile vecine "normale"
        for (auto &neigh : graph[node].edges)
            pq.push(Destination(neigh.node, time + neigh.dist));

        // Adauga nodurile vecine prin muchie de teleportare
        for (auto &teleport : graph[node].teleports) {
            if (time % teleport.dist != 0)
                continue;

            pq.push(Destination(teleport.node, time + 1));
        }
    }

    // Extrage timpul minim necesar ajungerii in nodul final, in oricare
    // dintre configuratiile timpilor de teleportare
    auto &dest_times = dist[nodes - 1];
    long result = INFTY;
    for (auto final_time : dest_times)
        result = std::min(final_time, result);

    out << result << "\n";
    out.close();
    return 0;
}

