        #include <bits/stdc++.h>

using namespace std;

ifstream fin("teleportare.in");
ofstream fout("teleportare.out");

long long Dijkstra(int N, vector<pair<int, int>> adj[],
                   vector<pair<int, int>> tunnel[], int cmmmc) {
    // Distances matrix
    // d[K][modTime] = shortest time taken to travel from node 1 to node K,
    // where time must be a multiple of modTime.
    // modTime can be at most CMMMC(all periods from input taken once)
    // if all periods 1-8 are given as input, CMMMC is max 840
    // Used to compute multiple possible paths from 1 to K, with different
    // time costs, so that, upon meeting a tunnel, to be able to check for
    // every possibility whether the tunnel can be enetered
    vector<vector<long long>> d(N + 1, vector<long long>(cmmmc, LONG_MAX));

    // Priority queue as min heap for storing shortest paths first
    priority_queue<pair<long long, int>, vector<pair<long long, int>>,
                   greater<pair<long long, int>>> pq;

    // Add node source node 1 with starting distance = 0
    d[1][0] = 0;
    pq.push({d[1][0], 1});

    while (!pq.empty()) {
        // Extract top element from pq
        long long time = pq.top().first;
        int node = pq.top().second;
        pq.pop();

        // We found shortest path to destination
        if (node == N)
            return time;

        // Check all paths to neighbor nodes
        for (unsigned int i = 0; i < adj[node].size(); i++) {
            int next = adj[node][i].first;
            int cost = adj[node][i].second;
            // new_cost = time taken from 1 to node + time from node to neighbor
            long long new_cost = time + cost;

            // if new cost < old cost
            if (new_cost < d[next][(time + cost) % cmmmc]) {
                // update old cost and add (new cost, next) to pq
                d[next][(time + cost) % cmmmc] = new_cost;
                pq.push({d[next][(time + cost) % cmmmc], next});
            }
        }

        // Check all paths to nodes connected by a tunnel
        for (unsigned int i = 0; i < tunnel[node].size(); i++) {
            int next = tunnel[node][i].first;
            int period = tunnel[node][i].second;
            // new_cost = time taken from 1 to node + 1 (teleportation cost)
            long long new_cost = time + 1;

            // if cost from 1 to node is a multiple of tunnel period
            // and new cost < old cost
            if (time % period == 0 && new_cost < d[next][(time + 1) % cmmmc]) {
                // update old cost and add (new cost, next) to pq
                d[next][(time + 1) % cmmmc] = new_cost;
                pq.push({d[next][(time + 1) % cmmmc], next});
            }
        }
    }
}

int cmmdc(int a, int b) {
    int r;
    while (b) {
        r = a % b;
        a = b;
        b = r;
    }
    return a;
}

int main() {
    int N, M, K;
    fin >> N >> M >> K;

    vector<pair<int, int>> adj[N + 1];
    vector<pair<int, int>> tunnel[N + 1];

    // Create adjacency list for normal paths
    while (M--) {
        int i, j, t;
        fin >> i >> j >> t;
        adj[i].push_back({j, t});
        adj[j].push_back({i, t});
    }

    // Add all periods from input in this set
    // (they are added only once)
    unordered_set<int> periods_set;

    // Create adjacency list for teleportation tunnels
    while (K--) {
        int i, j, t;
        fin >> i >> j >> t;
        tunnel[i].push_back({j, t});
        tunnel[j].push_back({i, t});
        periods_set.insert(t);
    }

    // Compute CMMMC of all periods given in input
    // (count only one apparition)
    int cmmmc = 1;

    if (periods_set.size() == 1)
        cmmmc = *periods_set.begin();

    if (periods_set.size() >= 2) {
        // Transform set to vector
        vector<int> periods_vector(periods_set.begin(), periods_set.end());

        // Compute cmmmc of all periods
        int a = cmmdc(periods_vector[0], periods_vector[1]);
        cmmmc = periods_vector[0] * periods_vector[1] / a;
        for (unsigned int i = 2; i < periods_vector.size(); i++) {
            a = cmmdc(cmmmc, periods_vector[i]);
            cmmmc = cmmmc * periods_vector[i] / a;
        }
    }

    // Compute shortest path from 1 to N using both normal paths
    // and teleportation tunnels
    fout << Dijkstra(N, adj, tunnel, cmmmc);
}

