        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.PriorityQueue;
import java.util.StringTokenizer;

public class Teleportare {
	private static class Pair implements Comparable<Pair> {
		long first;
		long second;

		public Pair(long first, long second) {
			this.first = first;
			this.second = second;
		}

		@Override
		public int compareTo(Pair other) {
			return Long.compare(this.first, other.first);
		}
	}

	static class Graph {
		private ArrayList<Pair>[] AdjList; // Lista de adiacenta pentru nodurile grafului

		public Graph(int N) {
			AdjList = new ArrayList[N + 1];
			for (int i = 0; i <= N; i++) {
				AdjList[i] = new ArrayList<>();
			}
		}

		public void addEdge(int u, int v, int w) {
			// Adaugare muchie intre nodurile u si v cu costul w
			AdjList[u].add(new Pair(v, w));
			// Adaugare muchie inversa intre nodurile v si u cu acelasi cost w
			AdjList[v].add(new Pair(u, w)); 
		}

		public ArrayList<Pair> getNeighbors(int u) {
			return AdjList[u]; // Returneaza lista de vecini ai nodului u
		}

		public long[] dijkstra(int s) {
			long[] dist = new long[AdjList.length];
			Arrays.fill(dist, (long) 1e18);
			dist[s] = 0;

			PriorityQueue<Pair> pq = new PriorityQueue<>();
			pq.add(new Pair(0, s));

			while (!pq.isEmpty()) {
				Pair front = pq.poll();
				long d = front.first, u = front.second;

				if (d == dist[(int) u]) {
					ArrayList<Pair> neighbors = getNeighbors((int) u);
					for (Pair v : neighbors) {
						if (dist[(int) u] + v.second < dist[(int) v.first]) {
							dist[(int) v.first] = dist[(int) u] + v.second;
							pq.add(new Pair(dist[(int) v.first], v.first));
						}
					}
					if (teleport[(int) u] != -1 && T[(int) u] != -1) {
						long wait = ((dist[(int) u] + T[(int) u] - 1)
							/ T[(int) u]) * T[(int) u] + 1;
						if (wait < dist[(int) teleport[(int) u]]) {
							dist[(int) teleport[(int) u]] = wait;
							pq.add(new Pair(dist[(int) teleport[(int) u]], teleport[(int) u]));
						}
					}
				}
			}

			return dist;
		}
	}

	static long[] teleport, T;

	public static void main(String[] args) throws IOException {
		BufferedReader fin = new BufferedReader(new FileReader("teleportare.in"));
		final PrintWriter fout = new PrintWriter(new FileWriter("teleportare.out"));

		StringTokenizer st = new StringTokenizer(fin.readLine());
		final int N = Integer.parseInt(st.nextToken());
		final int M = Integer.parseInt(st.nextToken());
		final int K = Integer.parseInt(st.nextToken());

		teleport = new long[N + 1];
		T = new long[N + 1];

		Arrays.fill(teleport, -1);
		Arrays.fill(T, -1);

		Graph graph = new Graph(N); // Crearea grafului cu N noduri

		// Citirea muchiilor
		for (int i = 0; i < M; i++) {
			st = new StringTokenizer(fin.readLine());
			int u = Integer.parseInt(st.nextToken());
			int v = Integer.parseInt(st.nextToken());
			int w = Integer.parseInt(st.nextToken());
			// Adaugarea muchiei intre nodurile u si v cu costul w in graful G
			graph.addEdge(u, v, w); 
		}

		// Citirea teleportarilor
		for (int i = 0; i < K; i++) {
			st = new StringTokenizer(fin.readLine());
			int u = Integer.parseInt(st.nextToken());
			int v = Integer.parseInt(st.nextToken());
			int w = Integer.parseInt(st.nextToken());

			teleport[u] = v; // Teleportarea nodului u la nodul v
			T[u] = w; // Timpul necesar pentru teleportarea din nodul u in nodul v
		}

		long[] dist = graph.dijkstra(1); // Calcularea distantei minime de la nodul 1 la nodul N
		fout.println(dist[N]); // Scrierea rezultatului in fisierul de iesire

		fin.close();
		fout.close();
	}
}


