#include <iostream>
#include <vector>
#include <fstream>
#include <queue>

using namespace std;

// Numarul maxim de noduri din graf
const int NMAX = 1e4 + 5;
// Valoarea infinitului pentru dijkstra
const int INF = 1e9 + 5;

// Vectorul de adiacenta al grafului
vector<pair<int, int>> graph[NMAX];
// Vectorul de teleportari
vector<pair<int, int>> teleport[NMAX];

// Distanta minima de la nodul de start la fiecare nod
int dist[NMAX];
// Numarul de noduri
int n;

// Structura pentru nodul din heap
struct Node {
    // Nodul
    int node;
    // Distanta
    int dist;

    // Constructor pentru structura Node (nod, distanta)
    Node(int node, int dist) : node(node), dist(dist) {}

    // Operatorul < pentru structura Node (pentru heap) (distanta)
    bool operator<(const Node &rhs) const {
        return dist > rhs.dist;
    }
};

// Coada de prioritati pentru dijkstra
priority_queue<Node> pq;

void dijkstra() {
    // Se parcurge fiecare nod
    for (int i = 1; i <= n; ++i) {
        // Se initializeaza distantele cu infinit pentru fiecare nod
        dist[i] = INF;
    }

    // Se seteaza distanta nodului de start cu 0
    dist[1] = 0;
    // Se adauga nodul de start in coada de prioritati
    pq.push(Node(1, 0));

    // Cat timp coada de prioritati nu este goala
    while (!pq.empty()) {
        // Se extrage nodul cu distanta minima
        Node node = pq.top();
        // Se elimina nodul din coada de prioritati
        pq.pop();

        // Daca distanta nodului din coada nu mai este cea mai mica
        // distanta, se trece la urmatorul nod
        if (node.dist != dist[node.node]) {
            continue;
        }

        // Se parcurg vecinii nodului si se actualizeaza distantele
        // pentru fiecare vecin al nodului curent
        for (auto &it : graph[node.node]) {
            if (dist[it.first] > dist[node.node] + it.second) {
                dist[it.first] = dist[node.node] + it.second;
                pq.push(Node(it.first, dist[it.first]));
            }
        }

        // Se parcurg teleportarile si se actualizeaza distantele pentru
        // fiecare teleportare al nodului curent
        // (se calculeaza distanta pana la urmatorul teleport)
        for (auto &it : teleport[node.node]) {
            int t = node.dist % it.second;
            if (t == 0) {
                if (dist[it.first] > dist[node.node] + 1) {
                    dist[it.first] = dist[node.node] + 1;
                    pq.push(Node(it.first, dist[it.first]));
                }
            } else {
                if (dist[it.first] > dist[node.node] + it.second - t + 1) {
                    dist[it.first] = dist[node.node] + it.second - t + 1;
                    pq.push(Node(it.first, dist[it.first]));
                }
            }
        }
    }
}

