vector<int> parent;
vector<int> sorted_nodes;
vector<int> found;
vector<int> low_link;
stack<int> nodes_stack;
vector<bool> in_stack;
vector<bool> critical_points;

void read_input() {
    int node1, node2;
    ifstream fin("retea.in");
    fin >> N >> M;
    adj.resize(N+1);
    for (int i = 0; i < M; ++i) {
        fin >> node1 >> node2;
        adj[node1].push_back(node2);
        adj[node2].push_back(node1);
    }
    fin.close();
}

void dfs(int node, int& timestamp, vector<vector<int>>& all_sccs,
 vector<bool> &critical_points, int deleted) {
    if (node != deleted) {
        // a new node is visited - increment the timestamp
        found[node] = ++timestamp;  // the timestamp when node was found
        low_link[node] = found[node];  // node only knows its timestamp
        nodes_stack.push(node);  // add node to the visiting stack
        in_stack[node] = true;
        int children = 0;
        // visit each neighbour
        for (auto neigh : adj[node]) {
            // check if neigh is already visited
            if (parent[neigh] != -1) {
                // update low_link[node] with information gained through neigh
                // note: neigh is in the same SCC with node only if it's in the
                // visiting stack;
                // otherwise, neigh is from other SCC, so it should be ignored
                if (in_stack[neigh]) {
                    low_link[node] = min(low_link[node], found[neigh]);
                }
                continue;
            }
            // save parent
            parent[neigh] = node;
            ++children;  // count child
            // recursively visit the child subree
            dfs(neigh, timestamp, all_sccs, critical_points, deleted);

            // update low_link[node] with information gained through neigh
            low_link[node] = min(low_link[node], low_link[neigh]);
            if (parent[node] != node && low_link[neigh] >= found[node]) {
                // critical_points.push_back(node);
                critical_points[node] = true;
            }
        }
        if (parent[node] == node && children > 1) {
            // critical_points.push_back(node);
            critical_points[node] = true;
        }
        // node is root in a SCC if low_link[node] == found[node]
        // (there is no edge from a descendant to an ancestor)
        if (low_link[node] == found[node]) {
            // pop all elements above node from stack => extract the SCC where
            // node is root
            vector<int> scc;
            do {
                auto x = nodes_stack.top();
                nodes_stack.pop();
                in_stack[x] = false;

                scc.push_back(x);
            } while (scc.back() != node);
            // stop when node was popped from the stack

                all_sccs.push_back(scc);
            }
        }
    }
vector<vector<int>> tarjan_scc() {
    // initialize result
    parent = vector<int>(N + 1, -1);
    found = vector<int>(N + 1, -1);
    low_link = vector<int>(N + 1, -1);
    in_stack = vector<bool>(N + 1, false);

    // visit all nodes
    vector<vector<int>> all_sccs;
    critical_points = vector<bool>(N + 1, false);
    int timestamp = 0;  // global timestamp
    for (int node = 1; node <= N; ++node) {
        if (parent[node] == -1) {  // node not visited
            parent[node] = node;  // convention: the parent of the root
            // is actually the root
            // start a new DFS traversal this subtree
            dfs(node , timestamp, all_sccs, critical_points, -1);
        }
    }
    return all_sccs;
}

int main() {
    read_input();

    ofstream fout("retea.out");
    std::vector<vector<int>> all_sccs = tarjan_scc();
    vector<bool> aux_critical(N+1, false);
    int timestamp = 0;
    parent = vector<int>(N + 1, -1);
    for (int i = 1; i <= N; i++) {
        all_sccs.clear();

        if (critical_points[i] == true) {
        timestamp = 0;
        int nr = N - 1;
        for (int node = 1; node <= N; ++node) {
            if (parent[node] == -1) {
                parent[node] = node;
                dfs(node , timestamp, all_sccs, aux_critical, i);
            }
        }
        for (const auto& scc : all_sccs) {
            nr += scc.size() * (N - scc.size());
        }
        fout << nr << endl;
        parent = vector<int>(N + 1, -1);
        } else {
            fout << 2 * (N - 1) << endl;
        }
    }

    fout.close();
    return 0;
}

