        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;

public class Retea {
	private static boolean[] parse_nodes(GraphNode[] nodes, GraphNode v, boolean[] visited) {
		//Consider nodul curent vizitat
		visited[v.getNode()] = true;

		for (Integer i: v.getAdjacentNodes()) {
			GraphNode new_node = nodes[i];
			if (!visited[i]) {
				visited = parse_nodes(nodes, new_node, visited);
			}
		}

		return visited;
	}

	private static boolean[] dfs(GraphNode[] nodes, GraphNode v, int nodes_count) {
		boolean[] visited = new boolean[nodes_count];
		visited = parse_nodes(nodes, v, visited);

		return visited;
	}

	public static void main(String[] args) {
		int N = 0, M;
		GraphNode[] graph_nodes = new GraphNode[1];

		try {
			BufferedReader bf = new BufferedReader(new FileReader("retea.in"));
			String[] line = bf.readLine().split(" ");

			N = Integer.parseInt(line[0]);
			M = Integer.parseInt(line[1]);
			graph_nodes = new GraphNode[N + 1];

			//Creez nodurile
			for (int i = 0; i < N; i++) {
				graph_nodes[i + 1] = new GraphNode(i + 1);
			}

			for (int i = 0; i < M; i++) {
				line = bf.readLine().split(" ");

				int node1 = Integer.parseInt(line[0]);
				int node2 = Integer.parseInt(line[1]);

				//Construiesc listele de adiacenta
				graph_nodes[node1].addAdjacentNode(node2);
				graph_nodes[node2].addAdjacentNode(node1);
			}

		} catch (IOException ex) {
			ex.printStackTrace();
		}

		GraphNode[] graph_nodes_after_removal = new GraphNode[N + 1];
		ArrayList<Integer> remaining_connections = new ArrayList<>();
		int initial_connections = N * (N - 1);

		//Elimin pe rand nodurile
		for (int i = 1; i <= N; i++) {
			int after_removal_connections = 0;

			//Refac lista de adiacenta dupa eliminarea nodului curent
			for (int j = 1; j <= N; j++) {
				graph_nodes_after_removal[j] = new GraphNode(j);

				if (j != i) {
					graph_nodes_after_removal[j].getAdjacentNodes()
							.addAll(graph_nodes[j].getAdjacentNodes());

					for (Integer n : graph_nodes[j].getAdjacentNodes()) {
						if (n == i) {
							graph_nodes_after_removal[j].getAdjacentNodes().remove(n);
						}
					}
				}
			}

			for (int j = 1; j < N + 1; j++) {
				//Daca e chiar nodul eliminat, il ignor
				if (i == j) {
					continue;
				}

				int count = 0;
				boolean[] visited = dfs(graph_nodes_after_removal,
						graph_nodes_after_removal[j], N + 1);

				for (int k = 1; k < N + 1; k++) {
					if (k == j) {
						continue;
					}

					if (visited[k]) {
						count++;
					}
				}

				after_removal_connections += count;
			}

			remaining_connections.add(initial_connections - after_removal_connections);
		}

		try {
			FileWriter w = new FileWriter("retea.out");
			for (int i = 0; i < remaining_connections.size(); i++) {
				w.write(remaining_connections.get(i) + "\n");
			}
			w.close();
		} catch (IOException e) {
			e.printStackTrace();
		}

	}
}

class GraphNode {                        
	private int node;
	private ArrayList<Integer> adjacentNodes = new ArrayList<>();

	public GraphNode(int node) {
		this.node = node;
	}

	public int getNode() {
		return node;
	}

	public void setNode(int node) {
		this.node = node;
	}

	public ArrayList<Integer> getAdjacentNodes() {
		return adjacentNodes;
	}

	public void addAdjacentNode(int new_node) {
		adjacentNodes.add(new_node);
	}
}
