#define INF 20000

class Graph {
 public:
    /* Membrii */
    int V;
    std::vector<std::list<int>> adjList;

    /* Functii */
    // Adauga muchia de la u la v
    void addEdge(int u, int v);

    /* Constructor / destructor */
    explicit Graph(std::string& fileName);
    ~Graph();
};

Graph::Graph(std::string& fileName) {
    std::ifstream inFile;
    inFile.open(fileName);

    int E;

    inFile >> V >> E;

    adjList.resize(V);

    for (int i = 0; i < E; i++) {
        int u;
        int v;
        inFile >> u >> v;

        // Ca sa inceapa de la 0
        u--; v--;

        // Adaugam muchia u-v
        addEdge(u, v);
    }
}

Graph::~Graph() {
}

void Graph::addEdge(int u, int v) {
    // Graf neorientat
    adjList[u].push_back(v);
    adjList[v].push_back(u);
}

// BFS modificat pt a ignora nodul dat ca parametru
// Intoarce nr de apeluri pentru nodul source care vor disparea in urma
// scoaterii nodului nodeToRemove din graf
int BFS(const Graph& g, int source, int nodeToRemove) {
    // Vectori pt vizitati si distante
    int *visited = new int[g.V];
    int *dist = new int[g.V];
    for (int i = 0; i < g.V; i++) {
        visited[i] = 0;
        dist[i] = INF;
    }

    // Coada in care vom introduce nodurile
    std::queue<int> q;

    // Pentru nodul sursa
    dist[source] = 0;
    visited[source] = 1;
    q.push(source);

    while (!q.empty()) {
        int u;
        u = q.front();
        q.pop();

        // Daca nodul este cel care e de eliminat, il ignoram
        if (u == nodeToRemove) {
            continue;
        }

        auto it = g.adjList[u].begin();
        while (it != g.adjList[u].end()) {
            if (!visited[*it] && *it != nodeToRemove) {
                visited[*it] = 1;
                dist[*it] = dist[u] + 1;
                q.push(*it);
            }
            it++;
        }
    }

    // Numaram la cate noduri NU mai avem cale in urma eliminarii nodului dat
    // din graf
    int count = 0;
    for (int i = 0; i < g.V; i++) {
        if (dist[i] == INF) {
            count++;
        }
    }

    // Eliberam memoria
    delete[] visited;
    delete[] dist;

    // Returnam numarul calculat
    return count;
}

// Aplica BFS-ul modificat pentru fiecare nod din graful din care scoatem nodul
// nodeToRemove
int BFS_wrp(const Graph& g, int nodeToRemove) {
    // Suma nodurilor catre care nu vor mai fi cai
    int sum = 0;

    // Aplica BFS pe toate nodurile
    for (int i = 0; i < g.V; i++) {
        // N-are sens sa mai fac BFS si pe el -> va avea automat |V| - 1
        // (deoarece stim din enunt ca graful initial e conex)
        if (i == nodeToRemove) {
            sum += g.V - 1;
        } else {
            sum += BFS(g, i, nodeToRemove);
        }
    }
    return sum;
}

// Aplica BFS_wrp cu fiecare nod ca "nodeToRemove"
// Scrie in fisierul de output rezultatul (cfm enuntului)
void solve(const Graph& g, const std::string& fileName) {
    std::ofstream out;
    out.open(fileName);

    for (int i = 0; i < g.V; i++) {
        int nr;
        nr = BFS_wrp(g, i);
        out << nr << "\n";
    }

    out.close();
}

int main() {
    // Citim graful
    std::string inFileName = "retea.in";
    Graph g(inFileName);

    // Rezolvam problema
    std::string outFileName = "retea.out";
    solve(g, outFileName);

    return 0;
}

