        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.Stack;

public class Retea {
	private static int N, M;
	private static List<List<Integer>> graph;
	private static boolean[] viz;
	private static int[] nodeLevel;

	public static void main(String[] args) throws Exception {
		BufferedReader reader = new BufferedReader(new FileReader("retea.in"));
		String line = reader.readLine().trim();
		String[] tocks = line.split(" ");
		N = Integer.parseInt(tocks[0]);
		M = Integer.parseInt(tocks[1]);

		nodeLevel = new int[N + 1];
		graph = new ArrayList<>(N + 1);
		for (int i = 0; i <= N; i++) {
			nodeLevel[i] = 0;
			graph.add(new ArrayList<>());
		}

		for (int i = 0; i < M; i++) {
			line = reader.readLine().trim();
			tocks = line.split(" ");
			int x = Integer.parseInt(tocks[0]);
			int y = Integer.parseInt(tocks[1]);
			graph.get(x).add(y);
			graph.get(y).add(x);
			nodeLevel[x]++;
			nodeLevel[y]++;
		}

		BufferedWriter writer = new BufferedWriter(new FileWriter("retea.out"));
		for (int i = 1; i <= N; i++) {
			int d = solveForNode(i);
			writer.write("" + d + "\n");
		}
		writer.close();
	}

	public static int solveForNode(int nodeToIgnore) {
		viz = new boolean[N + 1];
		for (int node = 1; node <= N; node++) {
			viz[node] = false;
		}

		if (nodeLevel[nodeToIgnore] == 1) {
			return 2 * (N - 1);
		}

		int result = N * (N - 1);
		for (int node = 1; node <= N; node++) {
			if (node == nodeToIgnore) {
				continue;
			} else {
				if (!viz[node]) {
					int tmp = bfs(node, nodeToIgnore);
					result = result - tmp * (tmp - 1);
				}
			}
		}

		return result;
	}

	public static int bfs(int node, int nodeToIgnore) {
		int nrNodes = 0;
		Stack<Integer> stack = new Stack<>();
		stack.add(node);

		while (!stack.isEmpty()) {
			int u = stack.pop();
			if (viz[u]) {
				continue;
			}
			viz[u] = true;
			nrNodes++;

			for (int v : graph.get(u)) {
				if (v != nodeToIgnore && !viz[v]) {
					stack.add(v);
				}
			}
		}

		return nrNodes;
	}
}

