import java.util.Vector;

public class Retea {
	static int nrOfNodes;
	static int nrOfVertices;
	static ArrayList<ArrayList<Integer>> adjacencyList;
	static ArrayList<ArrayList<Integer>> connectedComponents;
	static ArrayList<Integer> componentArrayList;
	static int[] parent;
	static String[] color;


	static void dfs() {
		for (int i = 1; i <= nrOfNodes; i++) {
			if (parent[i] == -1 && color[i].equals("white")) {
				dfsRecursive(i);

				ArrayList<Integer> new_vect = (ArrayList<Integer>) componentArrayList.clone();
				connectedComponents.add(new_vect);
				componentArrayList.clear();
			}
		}
	}

	static void dfsRecursive(int node) {
		componentArrayList.add(node);

		color[node] = "grey";

		for (Integer x : adjacencyList.get(node)) {
			if (parent[x] == -1 && color[x].equals("white")) {
				parent[x] = node;

				dfsRecursive(x);
			}
		}

		color[node] = "black";
	}

	public static void main(String[] args) throws IOException {
		//citim din fisierul de intrare "retea.in"
		BufferedReader br = new BufferedReader(new FileReader("retea.in"));
		String[] firstLine = br.readLine().split(" ", 2);

		nrOfNodes = Integer.parseInt(firstLine[0]);
		nrOfVertices = Integer.parseInt(firstLine[1]);
		adjacencyList = new ArrayList<>();
		connectedComponents = new ArrayList<>();
		componentArrayList = new ArrayList<>();
		parent = new int[nrOfNodes + 1];
		color = new String[nrOfNodes + 1];

		for (int i = 0; i <= nrOfNodes; i++) {
			adjacencyList.add(new ArrayList<>());
		}

		Arrays.fill(parent, -1);
		Arrays.fill(color, "white");

		for (int i = 0; i < nrOfVertices; i++) {
			String[] line = br.readLine().split(" ", 2);
			int firstNode = Integer.parseInt(line[0]);
			int secondNode = Integer.parseInt(line[1]);

			adjacencyList.get(firstNode).add(secondNode);
			adjacencyList.get(secondNode).add(firstNode);
		}

		br.close();

		int totalSum = nrOfNodes * (nrOfNodes - 1);

		//scriem in fisierul de iesire "retea.out"
		BufferedWriter bw = new BufferedWriter(new FileWriter("retea.out"));

		for (int i = 1; i <= nrOfNodes; i++) {
			ArrayList<ArrayList<Integer>> adjacencyListCopy = new ArrayList<>();
			adjacencyListCopy = (ArrayList<ArrayList<Integer>>) adjacencyList.clone();

			adjacencyList.remove(adjacencyList.get(i));
			adjacencyList.add(i, new ArrayList<>());

			for (int j = 1; j < adjacencyList.size(); j++) {
				ArrayList<Integer> arr = (ArrayList<Integer>) adjacencyList.get(j).clone();

				adjacencyList.remove(j);
				Integer x = i;
				arr.remove(x);
				adjacencyList.add(j, arr);
			}

			Arrays.fill(parent, -1);
			Arrays.fill(color, "white");

			connectedComponents.clear();

			dfs();
			int partialSum = 0;

			for (ArrayList<Integer> arr : connectedComponents) {
				partialSum += arr.size() * (arr.size() - 1);
			}

			bw.write(totalSum - partialSum + "\n");

			adjacencyList = adjacencyListCopy;
		}

		bw.close();
	}
}

