        #include <bits/stdc++.h>

using namespace std;

class Task {
	int n;
	int m;
	int time;
	vector<vector<int>> graph;
	vector<int> discover;
	vector<int> lowlink;

	vector<int> solution;

	void read() {
		ifstream in("retea.in");

		in >> n >> m;

		// indexing from 1
		graph.resize(n + 1);

		for (int i = 0, x, y; i < m; ++i) {
			in >> x >> y;

			graph[x].push_back(y);
			graph[y].push_back(x);
		}

		in.close();

		// indexing from 1
		discover.resize(n + 1, -1);
		lowlink.resize(n + 1);
		solution.resize(n + 1, 2 * (n - 1));

		time = 0;
	}

	// tarjan
	int dfs(int node, int parent) {
		discover[node] = time++;
		lowlink[node] = discover[node];

		int num_children = 0;

		// avoid counting twice
		int curr_n = n;

		for (auto &e : graph[node]) {
			if (e == parent) {
				continue;
			}

			if (discover[e] == -1) {
				int tmp;
				tmp = dfs(e, node);

				num_children += tmp + 1;

				if (lowlink[e] > discover[node]) {
					solution[node] += 2 * (tmp + 1) * (curr_n - tmp - 2);

					curr_n -= tmp + 1;
				}

				lowlink[node] = min(lowlink[node], lowlink[e]);

				continue;
			}

			lowlink[node] = min(lowlink[node], discover[e]);
		}

		return num_children;
	}

	void solve() {
		ofstream out("retea.out");

		dfs(1, -1);

		for (int i = 1; i <= n; ++i) {
			out << solution[i] << endl;
		}

		out.close();
	}

 public:
	void run() {
		read();
		solve();
	}
};


int main() {
	Task task;

	task.run();

	return 0;
}

