		void dfs(int node, int[] parent, int timestamp, int[] found, int[] low_link,
			Stack<Integer> nodes_stack) {
			found[node] = ++ timestamp;
			low_link[node] = found[node];
			nodes_stack.push(node);

			//visit each neighbour
			ArrayList<Integer> adj = nodes.get(node - 1).adj;
			for (int i = 0; i < adj.size(); i++) {
				int adjNode = adj.get(i);
				if (parent[adjNode] != 0) {
					if (nodes_stack.contains(adjNode)) {
						int min;
						if (low_link[node] < found[adjNode]) {
							min = low_link[node];
						} else {
							min = found[adjNode];
						}
						low_link[node] = min;
					}
					continue;
				}
				parent[adjNode] = node;
				dfs(adjNode, parent, timestamp, found, low_link, nodes_stack);
				int min2;
				if (low_link[node] < low_link[adjNode]) {
					min2 = low_link[node];
				} else {
					min2 = low_link[adjNode];
				}
				low_link[node] = min2;
			}
			if (low_link[node] == found[node]) {
				int nr = 0;
				int x;
				do {
					x = nodes_stack.pop();
					nr++;
				} while (x != node);

				//calculate missing connexions
				lost_conections = lost_conections + nr * (n - nr);
			}
		}
		//returns and eliminates the edges which contain the node i

		private int[] getResult() {
			int[] result = new int[n];
			for (int i = 0; i < n; i++) {
				lost_conections = 0;
				//eliminate node i's edges
				final ArrayList<Integer> n = nodes.get(i).adj;
				nodes.get(i).adj = new ArrayList<Integer>();
				tarjanScc();
				result[i] = lost_conections;
				nodes.get(i).adj.addAll(n);
			}
			return result;
		}
	}

