public class Stocks {
	//THE BUDGET OF BUYING STOCKS
	Integer budget;
	//MAXIMUM LOSS ACCEPTED
	Integer loss;
	//NUMBER OF SHARES
	Integer numberOfShares;
	//LIST WITH THE SHARES WITH THEIR DETAILS THE PRICE AT THE BUY TIME THE LOSS THAT CAN BE
	// OBTAINED IN WORST CASE AND THE BEST PROFIT
	ArrayList<Investments> investmentsList = new ArrayList<>();

	public static void main(String[] args) throws IOException {

		Stocks stocks = new Stocks();

		BufferedReader bufferedReader = new BufferedReader(new FileReader(
			"stocks.in"));

		String currentLine = bufferedReader.readLine();
		// IN ORDER NOT TO SPLIT THE CURRENT LINE EVERYTIME WE DO IT FROM
		// BEGINNING AND STORE IT IN AN ARRAY
		String[] splitLine = currentLine.trim().split(" ");
		// WE HAVE TO CONVERT FROM STRING TO INTEGER
		stocks.numberOfShares = Integer.parseInt(splitLine[0]);
		stocks.budget = Integer.parseInt(splitLine[1]);
		stocks.loss = Integer.parseInt(splitLine[2]);

		for (int i = 0; i < stocks.numberOfShares; i++) {
			currentLine = bufferedReader.readLine();
			splitLine = currentLine.trim().split(" ");
			// WE STORE IN THE ARRAYLIST THE SHARES
			int currentBudget = Integer.parseInt(splitLine[0]);
			// WE STORE IT IN ARRAYLIST LIKE THIS: THE BUDGET TO BUY A SHARE, NEXT WE HAVE THE
			// PROFIT THAT GIGEL CAN MAKE BUYING THAT SHARE, AND THE LAST FIELD IS THE LOSS THAT CAN
			// BE OPTAINED BUYING THAT SHARE WE DO THIS FROM THE READING IN ORDER TO CREATE A MATRIX
			// WITH INTEGERS NOT WITH OBJECTS OF TYPE INVESTMENTS IN ORDER TO GET A MORE EFFICIENT
			// CODE.
			stocks.investmentsList.add(new Investments(currentBudget,
				currentBudget - Integer.parseInt(splitLine[1]),
				Integer.parseInt(splitLine[2]) - currentBudget));

		}

		PrintWriter printWriter = new PrintWriter("stocks.out");
		printWriter.println(stocks.bestStocks());
		printWriter.close();
		bufferedReader.close();
	}

	/**
	 * The problem is very similar to a well known problem, Knapsack Problem, and we know this
	 * can be more efficiently solved by using dynamic programming. The problem is solved with a
	 * 2D array because it has only one restrain(the weight), in our case we have 2 restrains
	 * one of them is that we can not exceed Gigel's budget and the other one we encounter is the
	 * fact that we can only accept losses when buying stocks less then the limit loss so we have
	 * to use a 3D array. So we build the matrix like this
	 * [numberOfShares + 1][budget + 1][loss + 1] where numberOfShares is the number of Shares
	 * that Gigel can buy, budget can be correlated with the space of the sack, in our case is
	 * the budget that Gigel has and loss is the maximum loss that Gigel can accept in the worst
	 * case. Then we iterate with i,j,k where we consider i is the i-th share , j denotes the
	 * current budget spent on shares and k denotes the loss that Gigel has until now. For each
	 * of our matrix states we have only 2 options the profit obtained by Gigel is greater than
	 * the previous state or no . In the first case our current state will be the same as the
	 * previous, in the second one our current state will be the state before plus our new
	 * share's profit . So after integrating through all the states we will get on the las
	 * position our biggest profit
	 *
	 * @return the maximum value that can be obtained by buying stocks without overpassing loss
	 */
	int bestStocks() {
		int[][][] stockMarket =
			new int[numberOfShares + 1][budget + 1][loss + 1];


		// FOR EACH SHARE WE HAVE
		for (int i = 0; i <= numberOfShares; i++) {
			// FOR EACH VALUE OF SHARES THAT WE CAN HAVE
			for (int j = 0; j <= budget; j++) {
				// FOR EACH TIME WHERE THE LOSS OF GIGEL BUYING THE SHARE IS LESS THEN THE MAXIM
				// LOSS ACCEPTED
				for (int k = 0; k <= loss; k++) {
					if (i != 0 && j != 0 && k != 0) {
						// IF THE CURRENT VALUE OF THE STOCKS THAT GIGEL BOUGHT IS LESS THAN HIS
						// BUDGET AND IF THE TOTAL LOSS THAT CAN BE ENCOUNTERED IS LESS THAN THE
						// K THAT IS LESS THAN MAXIMUM LOSS WE NEED TO SEE WHICH IS BETTER: THE
						// PREVIOUS VALUE OR THE NEW BUYING FORMAT SO IN THIS CASE WE WILL RETURN
						// THE MAXIMUM BETWEEN THE TWO
						// IN OTHER CASE THE BEST VALUE FOR GIGEL IS THE ONE ABOVE
						if (j >= investmentsList.get(i - 1).currentValue && k
							>= investmentsList.get(i - 1).minValue) {
							int worstLoss =
								k - investmentsList.get(i - 1).minValue;
							int prevValue = j
								- investmentsList.get(i - 1).currentValue;
							int maxMax =
								(stockMarket[i - 1][prevValue][worstLoss]
									+ investmentsList.get(i - 1).maxValue);
							stockMarket[i][j][k] =
								Math.max(stockMarket[i - 1][j][k], maxMax);
						} else {
							stockMarket[i][j][k] =
								stockMarket[i - 1][j][k];
						}
					}
				}
			}
		}
		//THE BEST BUYING FORMAT WIL
