        import java.io.*;
import java.util.ArrayList;
import java.util.Arrays;

public class Stocks implements TestInterface {
  Integer stocks;
  Integer max;
  ArrayList<Integer> profit;
  ArrayList<Integer> loss;
  ArrayList<Integer> buy;
  Integer maxLoss;
  Integer budget;

  @Override
  public void runTest(File input, File output) throws IOException {

    readProblemData(input);
    solve();
    writeAnswer(output);
  }

  private void writeAnswer(File outputFile) throws IOException {
    FileWriter writer = new FileWriter(outputFile);
    writer.write(String.valueOf(max));
    writer.close();
  }

  private void solve() {
    int i, w;
    int[][][] matrix = new int[stocks + 1][budget + 1][maxLoss + 1];
    for (i = 0; i <= stocks; i++) {
      for (w = 0; w <= budget; w++) {
        if (i == 0 || w == 0) {
          if (i == 0) {
            break;
          }
          continue;
        } else if (buy.get(i - 1) <= w) {
          if (loss.get(i - 1) <= maxLoss) {
            for (int j = 0; j <= maxLoss; j++) {
              if (loss.get(i - 1) <= j && matrix[i - 1][w][j] > 0) {
                matrix[i][w][j] =
                    Math.max(
                        profit.get(i - 1) + matrix[i - 1][w - buy.get(i - 1)][j - loss.get(i - 1)],
                        matrix[i - 1][w][j]);
                max = Math.max(matrix[i][w][j], max);
              } else if (loss.get(i - 1) <= j) {
                matrix[i][w][j] = Math.max(matrix[i - 1][w][j], profit.get(i - 1));
                max = Math.max(matrix[i][w][j], max);
              }
            }
          }
        } else {
          if (maxLoss + 1 >= 0) System.arraycopy(matrix[i - 1][w], 0, matrix[i][w], 0, maxLoss + 1);
        }
      }
    }
    System.out.println("Profit:" + max + "\n");
  }

  private void readProblemData(File input) throws IOException {
    FileReader reader = new FileReader(input);
    BufferedReader bufferedReader = new BufferedReader(reader);
    String line;
    profit = new ArrayList<>();
    loss = new ArrayList<>();
    buy = new ArrayList<>();
    max = 0;
    int i = 0;
    while ((line = bufferedReader.readLine()) != null) {
      int[] array = Arrays.stream(line.split(" ")).mapToInt(Integer::parseInt).toArray();
      if (i == 0) {
        stocks = array[0];
        budget = array[1];
        maxLoss = array[2];
        i = 1;
      } else {
        buy.add(array[0]);
        profit.add(array[2] - array[0]);
        loss.add(array[0] - array[1]);
      }
    }
  }
}

