				for (int i = 1; i <= n; i++) {
					int price, lose, win;
					price = sc.nextInt();
					lose = price - sc.nextInt();
					win = sc.nextInt() - price;
					stocks.add(new Plw(price, lose, win));
				}
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

