							int sol_aux = dp[i - 1][j - stocks.elementAt(i - 1).price][k
									- stocks.elementAt(i - 1).lose];
							sol_aux += stocks.elementAt(i - 1).win;
							if (sol_aux > dp[i][j][k]) {
								dp[i][j][k] = sol_aux;
							}
						}
					}
				}
			}
			return dp[n][budget][loss];
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

class Plw {
	public int price;
	public int lose;
	public int win;

	public Plw() {
		price = 0;
		lose = 0;
		win = 0;
	}

	public Plw(int price, int lose, int win) {
		this.price = price;
		this.lose = lose;
		this.win = win;
	}

	public Plw sum(Plw o) {
		this.price += o.price;
		this.lose += o.lose;
		this.win += o.win;
		return this;
	}

	public boolean verify(int budget, int loss) {
		if (this.price > budget) {
			return false;
		}
		if (this.lose > loss) {
			return false;
		}
		return true;
	}
}

