// Clasa pentru valorile stocului citit
class Stock {
	private int currValue;
	private int minValue;
	private int maxValue;

	public Stock(final int currValue, final int minValue, final int maxValue) {
		this.currValue = currValue;
		this.minValue = minValue;
		this.maxValue = maxValue;
	}

	public int getCurrValue() {
		return currValue;
	}

	public int getMinValue() {
		return minValue;
	}

	public int getMaxValue() {
		return maxValue;
	}

	public int getProfit() {
		return maxValue - currValue;
	}

	public int getLoss() {
		return currValue - minValue;
	}

	// returneaza profit/loss ratio
	public float getRatio() {
		return (float) getProfit() / getLoss();
	}

	@Override
	public String toString() {
		return currValue + " " + minValue + " " + maxValue;
	}
}

public class Stocks {

	static class Task {
		private List<Stock> stockList = new ArrayList<>();
		private int nrStocks;
		private int budget;
		private int maxLoss;
		private int maxProfit = 0;

		// citesc din fisier, construiesc lista, o sortez dupa best profit/loss ratio
		// si calculez maximul
		public void solve() {
			readInput();
			stockList.sort(Comparator.comparing(Stock::getRatio).reversed());
			getMaxProfit(stockList, budget, maxLoss);
			// elimin doar 1 element din lista incepand de la ultimul
			attemptList(stockList);
			writeOutput(String.valueOf(maxProfit));
		}

		// elimin doar 1 element din lista incepand de la ultimul si calculez
		// profitul maxim pe cele ramase
		private void attemptList(List<Stock> list) {
			List<Stock> copyList;
			for (int i = list.size() - 1; i >= 0; i--) {
				// refac lista initiala pentru a pastra ordinea
				copyList = new ArrayList<>(list);
				copyList.remove(i);
				getMaxProfit(copyList, budget, maxLoss);
			}
		}

		// parcurge fiecare element din lista data sortata si alege cele mai bune elemente
		private void getMaxProfit(List<Stock> list, int budget, int maxLoss) {
			int currProfit = 0;
			for (Stock stock : list) {
				if (stock.getCurrValue() <= budget && stock.getLoss() <= maxLoss) {
					// e bun deci il adaug
					budget -= stock.getCurrValue();
					maxLoss -= stock.getLoss();
					currProfit += stock.getProfit();
				}
			}
			if (maxProfit < currProfit) {
				maxProfit = currProfit;
			}
		}

		// functie ce realizeaza citirea
		private void readInput() {
			try (BufferedReader br = new BufferedReader(new FileReader("stocks.in"))) {
				// citesc prima linie sa scot cele 3 valori
				String input = br.readLine();
				String[] values = input.split(" ");
				nrStocks = Integer.parseInt(values[0]);
				budget = Integer.parseInt(values[1]);
				maxLoss = Integer.parseInt(values[2]);
				int currValue, minValue, maxValue;
				// citesc fiecare linie si folosesc clasa creata pentru a stoca valorile
				while ((input = br.readLine()) != null) {
					values = input.split(" ");
					currValue = Integer.parseInt(values[0]);
					minValue = Integer.parseInt(values[1]);
					maxValue = Integer.parseInt(values[2]);
					stockList.add(new Stock(currValue, minValue, maxValue));
				}
			} catch (IOException e) {
				throw new RuntimeException("This should never happen.", e);
			}
		}

		// functie ce realizeaza scrierea
		private void writeOutput(String result) {
			try (BufferedWriter out = new BufferedWriter(new FileWriter("stocks.out"))) {
				out.write(result);
			} catch (IOException e) {
				throw new RuntimeException("This should never happen", e);
			}
		}
	}

	public static void main(String[] args) {
		new Task().solve();

	}
}

