int n, b, mL;
int D[2][1000];  /// cost
int L[2][1000];  /// lose
int P[2][1000];  /// profit

bool CMP(stocks A, stocks B) {
    if (1.0 * A.prof / A.cDif > 1.0 * B.prof / B.cDif) return true;
    return false;
}

void Read() {
    fin >> n >> b >> mL;
    for (int i = 1; i <= n; i++) {
        fin >> a[i].cost >> a[i].mn >> a[i].mx;
        a[i].cDif = a[i].cost - a[i].mn;
        a[i].prof = a[i].mx - a[i].cost;
    }
    sort(a + 1, a + n + 1, CMP);
}

void DP() {
    int l = 0, l2 = 1;
    for (int i = 1; i <= n; i++) {
        for (int cp = 0; cp <= b; cp++) {
            // Mai intai nu punem obiectul i.
            if (a[i].cost > cp) {
                D[l2][cp] = D[l][cp];
                L[l2][cp] = L[l][cp];
                P[l2][cp] = P[l][cp];
            } else if (a[i].cDif + L[l][cp - a[i].cost] > mL) {
                // Daca acest lucru duce la o solutie curenta mai buna, adaugam
                // obiectul i la o solutie anterioara.
                D[l2][cp] = D[l][cp];
                L[l2][cp] = L[l][cp];
                P[l2][cp] = P[l][cp];
            } else {
                if (a[i].prof + P[l][cp - a[i].cost] > P[l][cp]) {
                    D[l2][cp] = a[i].cost + D[l][cp - a[i].cost];
                    L[l2][cp] = a[i].cDif + L[l][cp - a[i].cost];
                    P[l2][cp] = a[i].prof + P[l][cp - a[i].cost];
                } else if (a[i].prof + P[l][cp - a[i].cost] == P[l][cp] &&
                           a[i].cDif + L[l][cp - a[i].cost] < L[l][cp]) {
                    D[l2][cp] = D[l][cp];
                    L[l2][cp] = a[i].cDif + L[l][cp - a[i].cost];
                    P[l2][cp] = P[l][cp];
                } else {
                    D[l2][cp] = D[l][cp];
                    L[l2][cp] = L[l][cp];
                    P[l2][cp] = P[l][cp];
                }
            }
        }
        swap(l2, l);
    }
    int profM = 0;
    for (int i = 0; i <= b; i++)
        if (P[l][i] > profM) profM = P[l][i];
    fout << profM << "\n";
}

int main() {
    Read();
    DP();
    return 0;
}

