using namespace std;

struct Stock{
    int price, min , max;

    Stock(int price, int min, int max)
        : price(price), min(min), max(max)
    {}

    double loss() {
        return price - min;
    }

    double profit() {
        return max - price;
    }

    double profit_loss_ratio() {
        return profit() / loss();
    }

    void print() {
        cout << price << " " << loss() << " " << profit() << endl;
    }
};

bool compare(Stock a, Stock b) {
    if (a.profit_loss_ratio() != b.profit_loss_ratio()) {
        // stock with bigger RR has priority
        return a.profit_loss_ratio() > b.profit_loss_ratio();
    }
    if (a.price != b.price) {
        // cheaper stock has priority
        return a.price < b.price;
    }
    if (a.profit() != b.profit()) {
        // the stock which is more profitable has priority
        return a.profit() > b.profit();
    }
    // the stock with the lowest loss has priority
    return a.loss() < b.loss();
}

class StockSolver {
 public:
    void solve() {
        readData();
        printResult();
    }

 private:
    int nr, budget, max_loss;
    vector<Stock> v;
    vector<vector<vector<int>>> m;

    int max(int a, int b) {
        if (a > b) {
            return a;
        }
        return b;
    }

    void init_matrix() {
        m = vector<vector<vector<int>>> (nr+1);
        for (int i = 0; i <= nr; i++) {
            m[i] = vector<vector<int>> (budget + 1);
            for (int j = 0; j <= budget; j++) {
                m[i][j] = vector<int> (max_loss + 1);
            }
        }
    }

    void print_vector() {
        for (int i = 1; i <= nr; i++) {
            v[i].print();
        }
    }

    void readData() {
        ifstream fin("stocks.in");
        fin >> nr >> budget >> max_loss;

        // vector has (nr + 1) elements
        v.push_back(Stock(0, 0, 0));

        for (int i = 1; i <= nr; i++) {
            int cost, min, max;
            fin >> cost >> min >> max;
            v.push_back(Stock(cost, min, max));
        }

        sort(v.begin() + 1, v.end(), compare);
        fin.close();
    }

    int computeResult() {
        init_matrix();

        for (int i = 1; i <= nr; i++) {
            for (int cost = 0; cost <= budget; cost++) {
                for (int loss = 0; loss <= max_loss; loss++) {
                    if (cost - v[i].price >= 0 && loss - v[i].loss() >= 0) {
                        int x = m[i-1][cost - v[i].price][loss - v[i].loss()];
                        m[i][cost][loss] = max(m[i - 1][cost][loss],
                                            x + v[i].profit());
                    }
                }
            }
        }

        return m[nr][budget][max_loss];
    }

    void printResult() {
        ofstream fout("stocks.out");
        fout << computeResult();
        fout.close();
    }
};

int main() {
    auto* task = new (std::nothrow) StockSolver{};
    task->solve();
    delete task;
    return 0;
}

