public class Stocks {
	static int[][][] values;
	static int[] prices;
	static int[] losses;
	static int[] wins;

	static int budget;
	static int maxLoss;

	static int getAnswer(int i, int l, int p) {

		//if we verify first added element return 0
		if (i <= 0 || l <= 0 || p <= 0) {
			values[i][l][p] = 0;
			return 0;
		}

		//if no value was found on i-1 object position,
		//call function for that position.
		//We need it in any case
		if (values[i - 1][l][p] == -1) {
			values[i - 1][l][p] = getAnswer(i - 1,l,p);
		}

		//if we cant add current stock - don't add it
		//Otherwise get maximum profit
		if (losses[i] > l || prices[i] > p) {
			values[i][l][p] = values[i - 1][l][p];
			return getAnswer(i - 1, l, p);
		} else {
			if (values[i - 1][l - losses[i]][p - prices[i]] == -1) {
				values[i - 1][l - losses[i]][p - prices[i]]
						= getAnswer(i - 1,l - losses[i],p - prices[i]);
			}
			return Math.max(values[i - 1][l][p],
					values[i - 1][l - losses[i]][p - prices[i]] + wins[i]);
		}
	}

	public static void main(String[] args) throws FileNotFoundException {

		MyScanner scanner = new MyScanner("stocks.in");

		//initializing 3D-Array
		int num = scanner.nextInt();
		budget = scanner.nextInt();
		maxLoss = scanner.nextInt();

		//values should start from 1 because otherwise
		//we try to acces array with negative index
		values = new int[num + 1][maxLoss + 1][budget + 1];
		prices = new int[num + 1];
		losses = new int[num + 1];
		wins = new int[num + 1];

		for (int i = 0 ; i <= num ; i++) {
			for (int j = 0 ; j <= maxLoss ; j++) {
				for (int k = 0 ; k <= budget ; k++) {
					values[i][j][k] = -1;
				}
			}
		}

		for (int i = 1 ; i <= num ; i++) {
			prices[i] = scanner.nextInt();
			losses[i] = prices[i] - scanner.nextInt();
			wins[i] = scanner.nextInt() - prices[i];
		}



		PrintStream stream = new PrintStream(new File("stocks.out"));
		stream.println(getAnswer(num,maxLoss,budget));
	}
}

