#include <queue>
#include <algorithm>
#include <iostream>
#include <vector>

using namespace std;

int N, B, max_loss;

typedef struct stock {
    long price;
    long loss;
    long win;
} stock;

vector<stock> stocks;

bool compareByRatio(const stock &a, const stock &b) {
    if (a.win == b.win) {
        return a.loss < b.loss;
    }
    return a.win > b.win;
}

void read_file() {
    ifstream fin("stocks.in");

    fin >> N >> B >> max_loss;

    long current_value, min_value, max_value;
    for (int i = 0; i < N; i++) {
        fin >> current_value >> min_value >> max_value;

        if (current_value - min_value > max_loss) {
            continue;
        }

        if (current_value > B) {
            continue;
        }

        // Calculam pierderea in cel mai rau caz si castigul in cel mai bun caz
        stock new_stock;
        new_stock.price = current_value;
        new_stock.loss = current_value - min_value;
        new_stock.win = max_value - current_value;

        stocks.push_back(new_stock);
    }

    sort(stocks.begin(), stocks.end(), compareByRatio);
}

long solve() {
    vector<stock> sol;

    for (int i = 0; i <= B; i++) {
        stock empty_sol;
        empty_sol.price = 0;
        empty_sol.loss = 0;
        empty_sol.win = 0;
        sol.push_back(empty_sol);
    }

    for (int i = 0; i < stocks.size(); i++) {
        for (int budget = B; budget >= stocks[i].price; budget--) {
            long price = stocks[i].price;

            // Daca pretul actiunii este mai mare decat bugetul de la pasul
            // curent, continuam
            if (price > budget) {
                continue;
            }

            // Incercam sa construim o solutie optima ce include actiunea
            // curenta
            stock with_stock;
            with_stock.price = sol[budget - price].price + price;
            with_stock.loss = sol[budget - price].loss + stocks[i].loss;
            with_stock.win = sol[budget - price].win + stocks[i].win;

            if (with_stock.loss <= max_loss
                    && with_stock.win > sol[budget].win) {
                sol[budget] = with_stock;
            } else if (with_stock.loss <= sol[budget].loss
                    && with_stock.win >= sol[budget].win) {
                sol[budget] = with_stock;
            }
        }
    }

    return sol[B].win;
}

void write_result(long result) {
    ofstream fout("stocks.out");

    fout << result;

    fout.close();
}

int main() {
    read_file();

    if (stocks.empty()) {
        write_result(0);
        return 0;
    }

    write_result(solve());
    return 0;
}

