using namespace std;

vector<vector<int>> Adj;
vector<int> copii;
vector<int> visited;
vector<int> visitedOrder;

void DFS(int elem, int& order) {
    visited[elem] = order++;
    visitedOrder.push_back(elem);
    for (int i : Adj[elem]) {
        if (!visited[i]) {
            DFS(i, order);
        }
        copii[elem] += copii[i] + 1;
    }
}

int main() {
    ifstream fin("magazin.in");
    ofstream fout("magazin.out");
    int N, Q;
    fin >> N >> Q;

    Adj = vector<vector<int>>(N + 1);
    copii = vector<int>(N + 1);
    visited = vector<int>(N + 1, 0);

    for (int i = 0; i < N - 1; i++) {
        int elem;
        fin >> elem;
        Adj[elem].push_back(i + 2);
    }
    int counter = 1;
    visitedOrder.push_back(0);
    DFS(1, counter);
    for (int i = 0; i < Q; i++) {
        int D, E;
        fin >> D >> E;
        if (E > copii[D]) {
            fout << "-1\n";
        } else {
            fout << visitedOrder[visited[D] + E] << "\n";
        }
    }

    return 0;
}

