import java.util.StringTokenizer;

public class Magazin {

	static class Question {
		int D; // depozit
		int E; // nr expedieri

		public Question(int D, int E) {
			this.D = D;
			this.E = E;
		}

		@Override
		public String toString() {
			return "Question [D=" + D + ", E=" + E + "]";
		}
	}

	public static void main(String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("magazin.in"));
		var N = scanner.nextInt(); // numarul de depozite
		var Q = scanner.nextInt(); // numarul de intrebari

		int[] hierarchy = new int[N + 1];
		for (var i = 0; i < N - 1; i += 1) {
			hierarchy[i + 1] = scanner.nextInt();
		}
		ArrayList<Question> questions = new ArrayList<>();
		for (var i = 0; i < Q; i += 1) {
			questions.add(new Question(scanner.nextInt(), scanner.nextInt()));
		}
		try (var printer = new PrintStream("magazin.out")) {
			printer.println(solveTask(N, Q, hierarchy, questions));
		}
	}

	private static String solveTask(int nrDepozite, int nrIntrebari, int[] ierarhie,
									ArrayList<Question> questions) {
		ArrayList<ArrayList<Integer>> adjacencyList = new ArrayList<>();
		for (int i = 0; i <= nrDepozite; i++) {
			adjacencyList.add(new ArrayList<>());
		}
		// construim graful
		for (int i = nrDepozite; i >= 2; i--) {
			adjacencyList.get(ierarhie[i - 1]).add(i);
		}

		// calculam ordinea de vizitare a nodurilor
		ArrayList<ArrayList<Integer>> ordersForEveryNode = new ArrayList<>();
		for (int i = 0; i <= nrDepozite; i++) {
			ordersForEveryNode.add(new ArrayList<>());
		}
		for (int i = 1; i <= nrDepozite; i++) {
			ordersForEveryNode.get(i).addAll(calculateOrder(adjacencyList, i));
		}
		StringBuilder result = new StringBuilder();
		int n = 0;
		while (n < nrIntrebari) {
			int depozit = questions.get(n).D;
			int nrExpedieri = questions.get(n++).E;
			// cautam indexul depozitului in lista de ordine
			int index = ordersForEveryNode.get(depozit).indexOf(depozit);
			int newIndex = index + nrExpedieri;
			// daca depozitul nu are atatea noduri
			if (newIndex >= ordersForEveryNode.get(depozit).size()) {
				result.append("-1\n");
			} else {
				result.append(ordersForEveryNode.get(depozit).get(newIndex)).append("\n");
			}
		}
		return result.toString();
	}

	private static ArrayList<Integer> calculateOrder(ArrayList<ArrayList<Integer>> adjacencyList,
													int firstNode) {
		ArrayList<Integer> order = new ArrayList<>();
		// parcurgem graful in adancime
		Stack<Integer> stack = new Stack<>();
		// adaugam primul nod in stiva
		stack.push(firstNode);
		while (!stack.isEmpty()) {
			int node = stack.pop();
			order.add(node);
			// adaugam in stiva toti vecinii nodului
			for (int i = 0; i < adjacencyList.get(node).size(); i++) {
				stack.push(adjacencyList.get(node).get(i));
			}
		}
		return order;
	}

