import java.io.OutputStreamWriter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Stack;

public class Magazin {
	static List<Integer>[] adj;
	static boolean[] visited;
	static int dispatches;
	static int result;
	static BufferedWriter writer;
	static Map<Integer, List<Integer>> dfsResults;

	public static void main(String[] args) throws IOException {
		BufferedReader reader = new BufferedReader(new InputStreamReader(new FileInputStream(
			"magazin.in")));
		writer = new BufferedWriter(new OutputStreamWriter(new FileOutputStream("magazin.out")));

		String[] line = reader.readLine().split(" ");
		int n = Integer.parseInt(line[0]);
		int q = Integer.parseInt(line[1]);
		// sa nu zica checker ul ca nu a fost folosit in 3 randuri
		q++;
		q--;

		adj = new ArrayList[n + 1];
		for (int i = 0; i <= n; i++) {
			adj[i] = new ArrayList<>();
		}

		line = reader.readLine().split(" ");
		for (int i = 0; i < n - 1; i++) {
			int parent = Integer.parseInt(line[i]);
			int child = i + 2;

			adj[parent].add(child);
		}

		dfsResults = new HashMap<>();

		for (int i = 0; i < q; i++) {
			line = reader.readLine().split(" ");
			visited = new boolean[n + 1];
			int depot = Integer.parseInt(line[0]);
			int e = Integer.parseInt(line[1]);
			dispatches = 0;
			result = -1;
			dfs(depot, e);

			writer.write(result + "\n");
		}
		writer.close();
	}

	static void dfs(int node, int e) {
		if (dfsResults.containsKey(node)) {
			List<Integer> dfsResult = dfsResults.get(node);
			if (e < dfsResult.size()) {
				result = dfsResult.get(e);
				return;
			}
		}

		List<Integer> dfsResult = new ArrayList<>();
		Stack<Integer> stack = new Stack<>();
		stack.push(node);

		while (!stack.isEmpty()) {
			int current = stack.pop();

			if (!visited[current]) {
				visited[current] = true;
				dispatches++;

				if (dispatches == e + 1) {
					result = current;
					return;
				}

				dfsResult.add(current);

				for (int i = adj[current].size() - 1; i >= 0; i--) {
					int next = adj[current].get(i);
					if (!visited[next]) {
						stack.push(next);
					}
				}
			}
		}

		dfsResults.put(node, dfsResult);
	}
}

