        #include <iostream>
#include <vector>
#include <stack>
#include <fstream>
#include <climits>

using namespace std;

class Task {
 public:
    void solve() {
        read_input();

        get_result();

        print_output();
    }

 private:
    static constexpr int NMAX = (int)1e5 + 5;

    int n, q;

    vector<int> adj[NMAX];  // vector with the list of adjacency of each node

    vector<int> orderd;  // vector of toplogically ordered nodes
    vector<int> nr_children;  // number of children of the nodes
    vector<int> destinations;  // the resulting destinations
    vector<pair<int, int>> directions;  // stores the start and the steps

    void read_input() {
        ifstream fin("magazin.in");
        fin >> n >> q;

        nr_children.resize(n + 1);
        directions.resize(q + 1);

        // reading the edges
        for (int i = 1, x; i < n; i++) {
            fin >> x;
            adj[x].push_back(i + 1);
        }

        // reading the indications
        for (int i = 0; i < q; i++) {
            fin >> directions[i].first >> directions[i].second;
        }

        fin.close();
    }

    void get_result() {
        // only one DFS traversing is needed, because out of it we get
        // the nodes orderd topologically and how many nodes we can
        // reach from every node
        DFS(1);

        // we go trough all directions
        for (int i = 0, start, steps; i < q; i++) {
            start = directions[i].first;
            steps = directions[i].second;

            // if we have more steps then the node can actually reach
            // set the destination to -1
            if (steps > nr_children[start]) {
                destinations.push_back(-1);
                continue;
            }

            // we search for the positon of the node
            int poz;
            for (poz = 0; poz < n; poz++)
                if (orderd[poz] == start)
                    break;

            // set the destinantion
            destinations.push_back(orderd[poz + steps]);
        }
    }

    int DFS(int start_node) {
        int count = 0;  // counts how many descendats a node has

        // adding the node to the vector of topologically ordered nodes
        orderd.push_back(start_node);

        // we go trough all the children
        int nr_neigh = adj[start_node].size();
        for (int i = 0; i < nr_neigh; i++) {
            count ++;

            // we do not need to worry that a node may be visited more
            // than one time because we have a tree
            count += DFS(adj[start_node][i]);
        }

        // seting the number of children
        nr_children[start_node] = count;

        return count;
    }

    void print_output() {
        ofstream fout("magazin.out");

        for (int i = 0; i < q; i++)
            fout << destinations[i] << '\n';

        fout.close();
    }
};

int main() {
    auto task = new Task();
    task->solve();
    delete task;

    return 0;
}

