int dfsLimit(list<int> *tree, int root, int x, int *dp) {
  stack<int> stack;
  int counter = 0;

  stack.push(root);
  int node;

  while (!stack.empty() && counter <= x) {
    node = stack.top();
    stack.pop();
    counter++;

    // push children
    int nodeChildren = dp[node];
    if (counter + nodeChildren <= x) {
      counter += nodeChildren;
      continue;
    }
    for (auto it = tree[node].rbegin(); it != tree[node].rend(); it++) {
      stack.push(*it);
    }
  }

  if (counter <= x)
    return -1;
  else
    return node;
}

void count_descendants(list<int> *tree, int root, int *dp) {
  dp[root] = 0;
  for (auto it = tree[root].begin(); it != tree[root].end(); it++) {
    count_descendants(tree, *it, dp);
    dp[root] += dp[*it] + 1;
  }
}

