        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.io.Reader;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashSet;
import java.util.Set;
import java.util.Stack;
import java.util.StringTokenizer;
public class Magazin {

	public static class Pair {
		public int inceput;
		public int nr_expedieri;

		Pair(int _x, int _y) {
			inceput = _x;
			nr_expedieri = _y;
		}
	}

	public static void main(String[] args) throws IOException {

		var sc = new MyScanner(new FileReader("magazin.in"));

		var n = sc.nextInt();

		final var q = sc.nextInt();

		var a = new int[n + 1];

		for (var i = 2; i <= n; i++) {
			a[i] = sc.nextInt();
		}

		@SuppressWarnings("unchecked") ArrayList<Integer>[] adj = new ArrayList[n + 1];

		for (var i = 1; i <= n; i++) {
			adj[i] = new ArrayList<>();
		}

		for (var i = 2; i <= n; i++) {
			adj[a[i]].add(i);
		}

		ArrayList<Pair> perechi = new ArrayList<>();

		for (var i = 1; i <= q; i++) {
			var inceput = sc.nextInt();
			var nr_expedieri = sc.nextInt();
			perechi.add(new Pair(inceput, nr_expedieri));
		}

		//set de noduri vizitate, pentru a nu repeta noduri in parcurgere
		Set<Integer> vizitat = new HashSet<>();


		//apelam dfs o singura data pentru a obtine array-ul cu elementele
		//dorite in functie de perechea data
		ArrayList<Integer> sol = dfs_general(n, vizitat, perechi, adj);
		try (var printer = new BufferedWriter(new PrintWriter("magazin.out"))) {
			for (Integer integer : sol) {
				printer.write(String.valueOf(integer));
				printer.newLine();
			}

		} catch (IOException e) {
			e.printStackTrace();
		}


	}

	public static ArrayList<Integer> dfs_general(int n, Set<Integer> vizitat,
						ArrayList<Pair> perechi, ArrayList<Integer>[] adj) {

		//array-ul cu elementele dorite
		ArrayList<Integer> sol = new ArrayList<>();

		//array cu numarul total de muchii pe care fiecare nod le poate parcurge
		int[] nr_muchii_trecere = new int[n + 1];

		//parcurgerea in adancime
		ArrayList<Integer> parcurgere = new ArrayList<>();

		//stiva pentru parcurgerea in adancime
		Stack<Integer> stiva = new Stack<>();

		//incepem intodeauna cu nodul radacina 1
		stiva.push(1);

		while (!stiva.isEmpty()) {

			//scoatem nodul din stiva
			int nod = stiva.pop();

			//practic numarul de vecini ai nodului
			int edges = 0;

			//adaugam nodul in parcurgere
			parcurgere.add(nod);

			//daca nodul nu a fost vizitat, il vizitam
			if (!vizitat.contains(nod)) {
				vizitat.add(nod);

				//parcurgem vecinii nodului si ii adaugam in stiva
				//o parcugem in ordine inversa pentru a avea ordinea corecta
				for (int i = adj[nod].size() - 1; i >= 0; i--) {
					edges++;
					stiva.push(adj[nod].get(i));

				}

			}
			//adaugam numarul de vecini pe care ii poate parcurge nodul
			nr_muchii_trecere[nod] = edges;

		}

		//inversam parcurgerea pentru a calcula numarul total de muchii
		//pe care le poate parcurge fiecare nod
		//de ex: 1, 2, 3, 5, 7, 8, 6, 4 va fi 4, 6, 8, 7, 5, 3, 2, 1
		//cu numarul total de muchii pt fiecare: 0, 0, 0, 0, 2, 4, 0, 7
		Collections.reverse(parcurgere);

		//parcurg lista de adiacenta in ordinea parcurgerii inversate
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < adj[parcurgere.get(i)].size(); j++) {
				//adaug la numarul total de muchii pe care le are fiecare nod, numarul de muchii
				//pe care le au la randul lor, vecinii
				nr_muchii_trecere[parcurgere.get(i)] +=
						nr_muchii_trecere[adj[parcurgere.get(i)].get(j)];
			}

		}

		//restabiliesc ordinea initiala a parcurgerii
		Collections.reverse(parcurgere);

		//parcurg lista de perechi
		for (Pair pair : perechi) {
			//daca numarul de muchii pe care le poate parcurge nodul de inceput
			//este mai mic decat numarul de muchii pe care trebuie sa le parcurga
			//atunci nu exista solutie
			if (nr_muchii_trecere[pair.inceput] < pair.nr_expedieri) {
				sol.add(-1);
				continue;
			}

			//altfel, adaugam in solutie nodul de la indexul format indexul nodului de inceput
			//si numarul de muchii pe care trebuie sa le parcurga din lista de parcurgere dfs
			sol.add(parcurgere.get(parcurgere.indexOf(pair.inceput) + pair.nr_expedieri));

		}

		//astfel, reusesc sa utilizez doar o singura parcurgerea dfs pentru o optimizare a timpului
		return sol;
	}

	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}


	}

}
