        import java.io.BufferedReader;

import java.io.BufferedWriter;

import java.io.FileReader;

import java.io.FileWriter;

import java.io.IOException;

import java.io.PrintWriter;

import java.util.ArrayList;

import java.util.HashSet;

import java.util.List;

import java.util.Scanner;

import java.util.Set;

public class Magazin {
	private static final String INPUT_FILE = "magazin.in";
	private static final String OUTPUT_FILE = "magazin.out";
	private static final int NMAX = (int)1e5 + 1;
	private static int n;

	@SuppressWarnings("unchecked")
	private static final List<Integer>[] adj = new ArrayList[NMAX];
	private static final int[] topSort = new int[NMAX];
	@SuppressWarnings("unchecked")
	private static final Set<Integer>[] reachableNodes = new HashSet[NMAX];
	private static final int[] entriesTopSort = new int[NMAX];
	private static int count = 1;

	public static void main(String[] args) throws IOException {
		Scanner sc = new Scanner(new BufferedReader(new FileReader(INPUT_FILE)));

		n = sc.nextInt();

		for (int i = 1; i <= n; i++) {
			adj[i] = new ArrayList<>();
		}

		int q = sc.nextInt(), k;

		for (int i = 2; i <= n; i++) {
			k = sc.nextInt();
			adj[k].add(i);
		}

		dfs(1);

		PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(OUTPUT_FILE)));
		int d, e, idx, ahead;

		for (int i = 0; i < q; i++) {
			d = sc.nextInt();
			e = sc.nextInt();
			idx = entriesTopSort[d];

			if (e > n - idx) {
				pw.println(-1);
			} else {
				ahead = topSort[idx + e];

				if (reachableNodes[d].contains(ahead)) {
					pw.println(ahead);
				} else {
					pw.println(-1);
				}
			}
		}

		sc.close();
		pw.close();
	}

	private static void dfs(int startNode) {
		boolean[] visited = new boolean[n + 1];
		dfsRecursive(startNode, visited);
	}

	private static void dfsRecursive(int node, boolean[] visited) {
		visited[node] = true;
		topSort[count] = node;
		entriesTopSort[node] = count++;

		if (reachableNodes[node] == null) {
			reachableNodes[node] = new HashSet<>();
		}

		reachableNodes[node].add(node);

		for (int neigh : adj[node]) {
			if (!visited[neigh]) {
				dfsRecursive(neigh, visited);
				reachableNodes[node].addAll(reachableNodes[neigh]);
			}
		}
	}
}

