        #include <iostream>
#include <fstream>
#include <vector>

using namespace std;

// Returnează indexul primei apariții a unui număr într-un vector
// sau -1 dacă numărul nu a fost găsit
int indexOf(int D, const vector<int> &vec) {
    for (size_t i = 0; i < vec.size(); i++) {
        if (vec[i] == D) {
            return static_cast<int>(i);
        }
    }
    // Numărul nu a fost găsit
    return -1;
}

// Funcție recursivă pentru parcurgerea în adâncime a grafului
void dfsRecursive(int N, int node, vector<int> adj[], vector<int> &traversal,
                  vector<int> &parent, vector<int> &start, vector<int> &finish,
                  int &timestamp) {
    start[node] = ++timestamp;
    traversal.push_back(node);

    // Parcurgerea vecinilor nodului curent
    for (int neighbor : adj[node]) {
        if (parent[neighbor] == -1) {
            parent[neighbor] = node;
            dfsRecursive(N, neighbor, adj, traversal, parent, start,
                         finish, timestamp);
        }
    }
    finish[node] = ++timestamp;
}

// Parcurgerea în adâncime a întregului graf
void dfs(int N, vector<int> adj[], vector<int> &traversal,
         vector<int> &start, vector<int> &finish) {
    vector<int> parent(N + 1, -1);

    // Parcurgerea fiecărui nod nevizitat
    for (int i = 1; i <= N; i++) {
        if (parent[i] == -1) {
            parent[i] = i;
            int timestamp = 0;
            dfsRecursive(N, i, adj, traversal, parent, start,
                         finish, timestamp);
        }
    }
}

int main() {
    ifstream fin("magazin.in");
    ofstream fout("magazin.out");
    int N, Q;
    fin >> N >> Q;

    vector<int> adj[N + 1];
    vector<int> parent(N + 1, -1);
    vector<int> traversal;
    vector<int> start(N + 1);
    vector<int> finish(N + 1);

    // Citirea muchiilor grafului
    // Se pornește de la 2, deoarece nodul 1 este deja radacina arborelui
    for (int i = 2; i <= N; i++) {
        int x;
        fin >> x;
        adj[x].push_back(i);
    }

    // Parcurgerea în adâncime a grafului
    dfs(N, adj, traversal, start, finish);

    // Verific dacă există suficiente noduri în subarborele cu rădăcina D
    for (int i = 1; i <= Q; i++) {
        int D, E;
        fin >> D >> E;

        if ((finish[D] - start[D] - 1) / 2 >= E) {
            fout << traversal[indexOf(D, traversal) + E] << "\n";
        } else {
            fout << "-1\n";
        }
    }

    fin.close();
    fout.close();

    return 0;
}

