using namespace std;

#define NMAX (int)1e5 + 5
#define VECSIZE 100005

// dfs recursive
void dfs_recursive(int node, vector<int> adj[NMAX], int start[VECSIZE],
                   int finish[VECSIZE], int &timestamp,
                   vector<int> &vector_dfs_fmm) {
    start[node] = ++timestamp;
    vector_dfs_fmm.push_back(node);

    for (auto neigh : adj[node])
        dfs_recursive(neigh, adj, start, finish, timestamp, vector_dfs_fmm);

    finish[node] = ++timestamp;
}

// function to check if the path can be taken
int fct(int D, int E, int N, const vector<int> topsort, int index,
        int start[VECSIZE], int finish[VECSIZE]) {
    if (index + E > N)
        return -1;
    if (!(start[D] < start[topsort[index + E]] &&
        finish[D] > finish[topsort[index + E]]))
        return -1;

    return topsort[index + E];
}

int main() {
    ifstream fin("magazin.in");
    ofstream fout("magazin.out");

    int N, Q, D, E;
    // read N si Q
    fin >> N >> Q;
    vector<int> adj[N + 1];

    // k-th number represents the deposit which will receive parcels from
    // depot k + 1
    for (int i = 1, val; i <= N - 1; i++) {
        fin >> val;
        adj[val].push_back(i + 1);
    }

    vector<int> topsort;
    topsort.push_back(-1);
    // vector<int> start(N + 1, 0);
    // vector<int> finish(N + 1, 0);
    int start[N + 1];
    int finish[N + 1];
    int timestamp = 0;
    int map[N + 1];

    // first make a dfs for the root 1
    dfs_recursive(1, adj, start, finish, timestamp, topsort);
    // auxiliary structure to find necesary elements in O(1)
    for (int i = 1; i <= N; i++) {
        map[topsort[i]] = i;
    }

    // for every question read D and E and compute the answer
    for (int i = 1; i <= Q; i++) {
        fin >> D >> E;
        fout << fct(D, E, N, topsort, map[D], start, finish) << "\n";
    }

    return 0;
}

