static constexpr int NMAX = (int)1e5 + 5;

vector<int> adj[NMAX];


// basic DFS algorithm
void dfs(int src, vector<int> &start, vector<int> &finish,
        int &time, vector<int> &dfs_vector,
        vector<int> &posish, int &idx) {
    // keeping start time of the current node
    start[src] = ++time;

    // adding current node to DFS vector
    dfs_vector.push_back(src);

    // storing each node's position in the DFS vector
    posish[src] = idx++;

    for (auto &i : adj[src]) {
        dfs(i, start, finish, time, dfs_vector, posish, idx);
    }

    // keeping finish time of the current node
    finish[src] = ++time;
}

