				// caruia nu i-am scazut din nivel
				if ((mountains.get(i).height - j != mountains.get(i - 1).height)
						&& (mountains.get(i).height - j >= 0)
						&& (mountains.get(i - 1).height >= 0)) {
					minimum = dp[i - 1][0];
				}

				// Verific daca este diferit fata de nivelul anterior
				// caruia i-am scazut din nivel 1
				if ((mountains.get(i).height - j != mountains.get(i - 1).height - 1)
						&& (mountains.get(i).height - j >= 0)
						&& (mountains.get(i - 1).height - 1 >= 0)) {
					if (minimum == -1) {
						minimum = dp[i - 1][1];
					} else {
						minimum = Math.min(minimum, dp[i - 1][1]);
					}
				}

				// Verific daca este diferit fata de nivelul anterior
				// caruia i-am scazut din nivel 2
				if ((mountains.get(i).height - j != mountains.get(i - 1).height - 2)
						&& (mountains.get(i).height - j >= 0)
						&& (mountains.get(i - 1).height - 2 >= 0)) {
					if (minimum == -1) {
						minimum = dp[i - 1][2];
					} else {
						minimum = Math.min(minimum, dp[i - 1][2]);
					}
