int main() {
  int N, heights_vect[1000000], costs_vect[1000000];
  long long answer;

  f >> N;
  for (int i = 0; i < N; i++) {
    f >> heights_vect[i] >> costs_vect[i];
  }

  // Dp-table
  vector<vector<long long>> dp(N);
  for (int i = 0; i < N; i++) {
    dp[i].resize(3);
  }

  // Not increasing the first element
  dp[0][0] = 0;

  // Increasing the first element by 1
  dp[0][1] = costs_vect[0];

  // Increasing the first element by 2
  dp[0][2] = costs_vect[0] * 2;
  // dp[0][2] = cost[0] * 2;

  for (int i = 1; i < N; i++) {
    for (int j = 0; j < 3; j++) {
      long long minimum = 9223372036854775807;

      // Condition if current element
      // is not equal to previous
      // non-increased element
      if (heights_vect[i] - j != heights_vect[i - 1])
        minimum = min(minimum, dp[i - 1][0]);

      // Condition if current element
      // is not equal to previous element
      // after being increased by 1
      if (heights_vect[i] - j != heights_vect[i - 1] - 1)
        minimum = min(minimum, dp[i - 1][1]);

      // Condition if current element
      // is not equal to previous element
      // after being increased by 2
      if (heights_vect[i] - j != heights_vect[i - 1] - 2)
        minimum = min(minimum, dp[i - 1][2]);

      // Take the minimum from all cases
      dp[i][j] = j * costs_vect[i] + minimum;
    }
  }

  answer = 9223372036854775807;

  // Finding the minimum cost
  for (int i = 0; i < 3; i++) {
    answer = min(answer, dp[N - 1][i]);
  }

  g << answer;
  return 0;
}
