public class Ridge {
    private static FileWriter myWriter;
    private static Scanner scanner;
    private static Creasta[] creste;

    public static void main(String[] args) throws IOException {

        try {
            myWriter = new FileWriter("ridge.out");
            scanner = new Scanner(new File("ridge.in"));
        } catch (
                FileNotFoundException e) {
            e.printStackTrace();
        } catch (IOException e) {
            e.printStackTrace();
        }
        //citire din fisier
        int n = scanner.nextInt();
        creste = new Creasta[n];
        for (int i = 0; i < n; i++) {
            creste[i] = new Creasta(scanner.nextBigInteger(), scanner.nextBigInteger());
        }

        //rezolvare propiu-zisa

        // sume partiale de costuri (cand scad o creasta)
        BigInteger [][] dp = new BigInteger[n][3];
        // initializez vectorul de dp
        //nu scad deloc primul elemenet
        dp[0][0] = BigInteger.ZERO;
        // il scad cu o unitate
        dp[0][1] = creste[0].cost;
        // il scad cu 2 unitati
        dp[0][2] = creste[0].cost.multiply(BigInteger.TWO);

        // parcurg vectorul si iau mereu minumul din ultimele sume partiale din dp
        for (int i = 1; i < n; i++) {
            // merg pe fiecare caz (scad 0/1/2)
            for (int j = 0; j < 3; j++) {
                BigInteger min = BigInteger.valueOf(Long.MAX_VALUE);
                BigInteger aux = creste[i].creasta.subtract(BigInteger.valueOf(j));
                // verific sa nu dea sub 0
                if (aux.signum() < 0) {
                    dp[i][j] = creste[i].cost.multiply(BigInteger.valueOf(j)).add(min);
                    continue;
                }

                // daca crestele difera prin j
                if ( ! aux.equals(creste[i-1].creasta) )
                    // iau cazul in care nu mai scad i/i-i (care are val mai mica)
                    min = min.min(dp[i - 1][0]);

                BigInteger subtractOne = creste[i-1].creasta.subtract(BigInteger.ONE);
                if ( ! aux.equals(subtractOne) && subtractOne.signum() >= 0)
                    // cazul in care difera prin j-1
                    min = min.min(dp[i - 1][1]);

                BigInteger subtractTwo = creste[i-1].creasta.subtract(BigInteger.TWO);
                if ( ! aux.equals(subtractTwo) && subtractTwo.signum() >= 0)
                    // cazul in care difera prin j-2
                    min = min.min(dp[i - 1][2]);

                // verific care a fost substractia potrivita si o inmultesc cu costul
                dp[i][j] = creste[i].cost.multiply(BigInteger.valueOf(j)).add(min);
            }
        }
        // la final in dp voi avea minumul de scaderi si iau minimul din cele 3 dimensiuni
        Arrays.sort(dp[n-1]);
        myWriter.write(String.valueOf(dp[n-1][0]));
        myWriter.close();
    }
}

class Creasta {
    BigInteger creasta;
    BigInteger cost;

    Creasta(BigInteger creasta, BigInteger cost) {
        this.cost = cost;
        this.creasta = creasta;
    }
}













