void readData(int &N, vector< pair<long long, long long> > &relief) {
	ifstream in("ridge.in");

	in >> N;
	for (int i = 0; i < N; i++) {
		pair<long long, long long> point;
		in >> point.first >> point.second;
		relief.push_back(point);
	}

	in.close();
}

int main() {
	int N;
	vector< pair<long long, long long> > relief;
	readData(N, relief);

	long long **costs = (long long**)malloc(N * sizeof(long long*));

	for (int i = 0; i < N; i++) {
		costs[i] = (long long*)malloc(3 * sizeof(long long));
	}

	costs[0][0] = 0;
	costs[0][1] = relief[0].second;
	costs[0][2] = 2 * relief[0].second;

	for (int i = 1; i < N; i++) {
		for (int j = 0; j < 3; j++) {
			if (relief[i].first - j >= 0) {
				long long min = LLONG_MAX;

				if (relief[i].first - j != relief[i - 1].first) {
					if (costs[i - 1][0] < min) {
						min = costs[i - 1][0];
					}
				}

				if (relief[i].first - j != relief[i - 1].first - 1) {
					if (costs[i - 1][1] < min) {
						min = costs[i - 1][1];
					}
				}

				if (relief[i].first - j != relief[i - 1].first - 2) {
					if (costs[i - 1][2] < min) {
						min = costs[i - 1][2];
					}
				}

				costs[i][j] = j * relief[i].second + min;
			} else {
				costs[i][j] = costs[i - 1][j];
			}
		}
	}

	long long result = LLONG_MAX;
	for (int i = 0; i < 3; i++) {
		if (costs[N - 1][i] < result) {
			result = costs[N - 1][i];
		}
	}

	ofstream out("ridge.out");
	out << result;
	out.close();

	for (int i = 0; i < N; i++) {
		free(costs[i]);
	}
	free(costs);

	return 0;
}
