        import java.io.*;
import java.util.*;


public class Poduri {

    public static class Node{
        int x,y,dist;

        Node(int x, int y, int dist){
            this.x = x;
            this.y = y;
            this.dist = dist;
        }
    }

    private static int BFS(char[][] lake, int xGigel, int yGigel ){
        int n =lake.length;
        int m = lake[0].length;

        boolean[][] visited = new boolean[n][m];

        Queue<Node> q = new LinkedList<>();
        visited[xGigel][yGigel] = true;

        q.add(new Node(xGigel,yGigel,0));

        int min_dist = Integer.MAX_VALUE;

        while(!q.isEmpty()){
            Node node = q.poll();

            xGigel = node.x;
            yGigel = node.y;

            visited[xGigel][yGigel] = true;

            //char type = lake[xGigel][yGigel];
            int dist = node.dist;

            if(xGigel == n -1 || xGigel == 0 || yGigel == m - 1 || yGigel == 0 ){
                min_dist = dist;
                break;
            }

            switch (lake[xGigel][yGigel]){
                case 'D':
                    if(!visited[xGigel + 1][yGigel] && lake[xGigel + 1][yGigel] !='.')
                        q.add(new Node(xGigel + 1, yGigel,dist + 1));
                    if(!visited[xGigel][yGigel + 1] && lake[xGigel][yGigel + 1] !='.')
                        q.add(new Node(xGigel, yGigel + 1,dist + 1));
                    if(!visited[xGigel - 1][yGigel] && lake[xGigel - 1][yGigel] !='.')
                        q.add(new Node(xGigel - 1, yGigel,dist + 1));
                    if(!visited[xGigel][yGigel - 1] && lake[xGigel][yGigel - 1] !='.')
                        q.add(new Node(xGigel, yGigel - 1,dist + 1));
                    break;

                case 'V':
                    if(!visited[xGigel + 1][yGigel] && lake[xGigel + 1][yGigel] !='.')
                        q.add(new Node(xGigel + 1, yGigel,dist + 1));
                    if(!visited[xGigel - 1][yGigel] && lake[xGigel - 1][yGigel] !='.')
                    q.add(new Node(xGigel - 1, yGigel,dist + 1));
                    break;

                case 'O':
                    if(!visited[xGigel][yGigel + 1] && lake[xGigel][yGigel + 1] !='.')
                    q.add(new Node(xGigel, yGigel + 1,dist + 1));
                    if(!visited[xGigel][yGigel - 1] && lake[xGigel][yGigel - 1] !='.')
                    q.add(new Node(xGigel, yGigel - 1,dist + 1));
                    break;

                default:
                    break;
            }

        }

        if(min_dist != Integer.MAX_VALUE){
            return min_dist;
        }
        else
            return -1;

    }


    public static void main(String[] args) throws IOException {

        //The input file and reader
        PrintWriter writer = new PrintWriter("poduri.out");
        BufferedReader reader = new BufferedReader(new FileReader("poduri.in"));

        String[] input = reader.readLine().split(" ");

        //The size of the input matrix
        int n = Integer.parseInt(input[0]);
        int m = Integer.parseInt(input[1]);

        //The input matrix represented as a Node matrix
        char[][] lake = new char[n+2][m+2];

        input = reader.readLine().split(" ");

        //Starting position
        int xGigel = Integer.parseInt(input[0]);
        int yGigel = Integer.parseInt(input[1]);

        //Reading the matrix
        for(int i = 1; i <= n; i++){
            String line = reader.readLine();
            for(int j = 1; j <= m; j++){
                lake[i][j] = line.charAt(j-1);
            }
        }

        writer.write(String.valueOf(BFS(lake,xGigel,yGigel)));
        writer.close();

    }
}

