        #include <fstream>
#include <vector>
#include <string>
#include <queue>
#include <utility>

using namespace std;

ifstream fin("poduri.in");
ofstream fout("poduri.out");


vector<pair<int, int>> nextStep(vector<vector<string>> &grid, int x, int y) {
    vector<pair<int, int>> nextCell;

    if (!grid[x][y].compare("V")) {
        if (grid[x - 1][y].compare(".")) {
            pair<int, int> p(x - 1, y);
            nextCell.push_back(p);
        }

        if (grid[x + 1][y].compare(".")) {
            pair<int, int> p(x + 1, y);
            nextCell.push_back(p);
        }
    } else if (!grid[x][y].compare("O")) {
        if (grid[x][y - 1].compare(".")) {
            pair<int, int> p(x, y - 1);
            nextCell.push_back(p);
        }

        if (grid[x][y + 1].compare(".")) {
            pair<int, int> p(x, y + 1);
            nextCell.push_back(p);
        }
    } else if (!grid[x][y].compare("D")) {
        if (grid[x - 1][y].compare(".")) {
            pair<int, int> p(x - 1, y);
            nextCell.push_back(p);
        }

        if (grid[x + 1][y].compare(".")) {
            pair<int, int> p(x + 1, y);
            nextCell.push_back(p);
        }

        if (grid[x][y - 1].compare(".")) {
            pair<int, int> p(x, y - 1);
            nextCell.push_back(p);
        }

        if (grid[x][y + 1].compare(".")) {
            pair<int, int> p(x, y + 1);
            nextCell.push_back(p);
        }
    }
    grid[x][y] = ".";

    return nextCell;
}

int bfs(vector<vector<string>> grid, int startX, int startY) {
    pair<int, int> start;
    start.first = startX;
    start.second = startY;
    pair<pair<int, int>, int> nod;
    nod.first = start;
    nod.second = 1;
    queue<pair<pair<int, int>, int>> q;
    q.push(nod);

    while (!q.empty()) {
        vector<pair<int, int>> vecini;
        pair<pair<int, int>, int> nodDeVerificat = q.front();
        q.pop();
        vecini = nextStep(grid, nodDeVerificat.first.first,
                            nodDeVerificat.first.second);

        for (int i = 0; i < vecini.size(); i++) {
            pair<int, int> vecin = vecini[i];
            if (grid[vecin.first][vecin.second].compare("M") == 0) {
                return nodDeVerificat.second;
            } else {
                pair<pair<int, int>, int> nod(vecin,
                                            nodDeVerificat.second + 1);
                q.push(nod);
            }
        }
    }
    return -1;
}

int main() {
int n, m, x, y;

fin >> n >> m;
fin >> x >> y;

vector<vector<string>> grid(n + 2, vector<string>(m + 2, "M"));

for (int i = 1; i <= n; i++) {
    for (int j = 1; j <= m; j++) {
        char in;
        fin >> in;
        grid[i][j] = in;
    }
}

fin.close();

fout << bfs(grid, x, y);

fout.close();

return 0;
}

