using namespace std;

#define M 2050
#define N 2050

struct Node {
	int x, y, dist;
};

int row[] = { -1, 0, 0, 1 };
int col[] = { 0, -1, 1, 0 };

bool isValid(char **matrix, bool visited[][N], int row, int col, int n, int m) {
    if (row <= 0 || col <= 0 || row > n || col > m) {
        return true;
    }
    return !visited[row][col] && matrix[row][col] != '.';
}

int BFS(char **matrix, int i, int j, int n, int m) {
    bool visited[M][N];

    memset(visited, false, sizeof visited);

    queue<Node> q;

    visited[i][j] = true;
    q.push({i, j, 0});

    int min_dist = INT_MAX;

    while (!q.empty()) {
        Node node = q.front();
        q.pop();

        int i = node.x, j = node.y, dist = node.dist;

        if (i <= 0 || j <= 0 || i > n || j > m) {
            min_dist = dist;
            break;
        }

        if (matrix[i][j] == 'V') {
            for (int k = 0; k < 4; k += 3) {
                if (isValid(matrix, visited, i + row[k], j + col[k], n, m)) {
                    visited[i + row[k]][j + col[k]] = true;
                    q.push({ i + row[k], j + col[k], dist + 1 });
                }
            }
        } else if (matrix[i][j] == 'O') {
            for (int k = 1; k < 3; k++) {
                if (isValid(matrix, visited, i + row[k], j + col[k], n, m)) {
                    visited[i + row[k]][j + col[k]] = true;
                    q.push({ i + row[k], j + col[k], dist + 1 });
                }
            }
        } else if (matrix[i][j] == 'D') {
            for (int k = 0; k < 4; k++) {
                if (isValid(matrix, visited, i + row[k], j + col[k], n, m)) {
                    visited[i + row[k]][j + col[k]] = true;
                    q.push({ i + row[k], j + col[k], dist + 1 });
                }
            }
        } else {
            cout << "INVALID" << endl;
        }
    }

    if (min_dist != INT_MAX) {
		return min_dist;
    } else {
        return -1;
    }
}

int main() {
    ifstream file("poduri.in");

    int n, m, x, y;
    file >> n >> m;
    file >> x >> y;
    char **matrix;
    matrix = new char *[2050];
    for (int i = 0; i < 2050; i++) {
        matrix[i] = new char[2050];
    }

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            file >> matrix[i][j];
        }
    }
    file.close();

    int distance;
    distance = BFS(matrix, x, y, n, m);
    ofstream out("poduri.out");
    out << distance;
    out.close();

    return 0;
}

