		public final String outputFile = "poduri.out";

		int N, M, xStart, yStart;
		// graph 
		int[][] matrix;
		int[][] visited;
		// path vector for O, V
		int[] var = {1, -1};
		// path vector for D
		int[] var1 = {1, 0 , -1, 0};
		int[] var2 = {0, 1, 0, -1};

