				visited = new int[N + 2][M + 2];

				for (int i = 1; i <= N; i++) {
					String s = scan.next();
					for (int j = 1; j <= M; j++) {
						// no road
						if (s.charAt(j - 1) == '.') {
							matrix[i][j] = -1;
						// vertical case
						} else if (s.charAt(j - 1) == 'V') {
							matrix[i][j] = 1;
						// both direction case
						} else if (s.charAt(j - 1) == 'D') {
							matrix[i][j] = 2;
						// horizantal caze
						} else if (s.charAt(j - 1) == 'O') {
							matrix[i][j] = 3;
						}

