import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.LinkedList;
import java.util.Queue;

public class Poduri {

	// cea mai scurta distanta de la sursa la uscat
	static int getBestRoute(char[][]mat, int X, int Y, int N, int M, int []dist, boolean[]visited) {
		Queue<Character> q = new LinkedList<>(); // coada valorilor celulelor
		Queue<Integer> q1 = new LinkedList<>(); // coada pozitiilor pe linii a celulelor
		Queue<Integer> q2 = new LinkedList<>(); // coada pozitiilor pe coloane a celulelor

		// adauga atributele celulei curente in cozile specifice
		q.add(mat[X][Y]);
		q1.add(X);
		q2.add(Y);

		// cat timp mai sunt noduri de verificat
		while (!q.isEmpty()) {

			// extrage atributele celulei curente din cozi
			Character crt_node = q.remove();
			X = q1.remove();
			Y = q2.remove();

			// verifica daca podul curent e langa uscat si poate ajunge la el
			if ((X == 0 || X == N - 1) && (crt_node == 'V' || crt_node == 'D')) {
				return dist[X * M + Y] + 1;
			}

			if ((Y == 0 || Y == M - 1) && (crt_node == 'O' || crt_node == 'D')) {
				return dist[X * M + Y] + 1;
			}

			// daca podul curent e deja vizitat, il ignoram
			if (visited[X * M + Y]) {
				continue;
			}

			// daca nu a fost deja vizitat, il marcam ca fiind si verificam
			// cu ajutorul valorii celulei ce vecin nevizitati are pe care
			// ii putem adauga in coada
			visited[X * M + Y] = true;

			switch (crt_node) {
				case 'V' : {
					if (!visited[(X - 1) * M + Y]) {
						dist[(X - 1) * M + Y] = dist[X * M + Y] + 1;
						q.add(mat[X - 1][Y]);
						q1.add(X - 1);
						q2.add(Y);
					}

					if (!visited[(X + 1) * M + Y]) {
						dist[(X + 1) * M + Y] = dist[X * M + Y] + 1;
						q.add(mat[X + 1][Y]);
						q1.add(X + 1);
						q2.add(Y);
					}

					break;
				}

				case 'O' : {
					if (!visited[X * M + Y - 1]) {
						dist[X * M + Y - 1] = dist[X * M + Y] + 1;
						q.add(mat[X][Y - 1]);
						q1.add(X);
						q2.add(Y - 1);
					}
					if (!visited[X * M + Y + 1]) {
						dist[X * M + Y + 1] = dist[X * M + Y] + 1;
						q.add(mat[X][Y + 1]);
						q1.add(X);
						q2.add(Y + 1);
					}
					break;
				}

				case 'D' : {
					if (!visited[(X - 1) * M + Y]) {
						dist[(X - 1) * M + Y] = dist[X * M + Y] + 1;
						q.add(mat[X - 1][Y]);
						q1.add(X - 1);
						q2.add(Y);
					}
					if (!visited[(X + 1) * M + Y]) {
						dist[(X + 1) * M + Y] = dist[X * M + Y] + 1;
						q.add(mat[X + 1][Y]);
						q1.add(X + 1);
						q2.add(Y);
					}
					if (!visited[X * M + Y - 1]) {
						dist[X * M + Y - 1] = dist[X * M + Y] + 1;
						q.add(mat[X][Y - 1]);
						q1.add(X);
						q2.add(Y - 1);
					}
					if (!visited[X * M + Y + 1]) {
						dist[X * M + Y + 1] = dist[X * M + Y] + 1;
						q.add(mat[X][Y + 1]);
						q1.add(X);
						q2.add(Y + 1);
					}
					break;
				}
				default: { }
			}
		}

		// nu s-a putut ajunge de la podul-sursa la uscat
		return -1;
	}

	public static void main(String []args) throws IOException {
		BufferedReader reader = new BufferedReader(new FileReader("poduri.in"));
		String line = reader.readLine();
		String [] arg = line.split(" ");

		// citeste numarul de linii si de coloane
		int N = Integer.parseInt(arg[0]);
		int M = Integer.parseInt(arg[1]);

		line = reader.readLine();
		arg = line.split(" ");

		// citeste pozitia podului de start
		int startX = Integer.parseInt(arg[0]);
		int startY = Integer.parseInt(arg[1]);

		// matricea valorilor celulelor
		char [][]mat = new char[N][M];

		// vectorul distantelor de la podul-sursa la celule
		int []dist = new int[N * M];

		boolean []visited = new boolean[N * M];

		// citeste din fisier matricea de valori
		for (int i = 0; i < N; i++) {
			line = reader.readLine();
			for (int j = 0; j < M; j++) {
				char c = line.charAt(j);
				mat[i][j] = c;
				dist[i * M + j] = 0;
				visited[i * M + j] = false;
			}
		}

		// afla cea mai buna ruta de la podul-sursa la uscat
		int n = getBestRoute(mat, startX - 1, startY - 1, N, M, dist, visited);

		// afiseaza rezultatul obtinut
		PrintWriter myWriter = new PrintWriter("poduri.out");
		myWriter.println(n);
		myWriter.close();
	}
}

