							adj[idx].push_back(shore);
							adj[idx].push_back((i - 1) * M + j + 1);
						} else if (j == M) {
							adj[idx].push_back((i - 1) * M + j - 1);
							adj[idx].push_back(shore);
						} else {
							adj[idx].push_back((i - 1) * M + j - 1);
							adj[idx].push_back((i - 1) * M + j + 1);
						}
					}
				}
			}
		}
		hit_the_road_jack(adj);  // calculeaza folosind BFS drumul minim
	}
	void hit_the_road_jack(vector<vector<int>> adj) {
		vector<int> d(N * M + 2, INF);
		queue<int> q;
		q.push(source);
		d[source] = 0;
		while (!q.empty()) {
            int node = q.front();
            q.pop();
            for (auto& neigh : adj[node]) {
                if (d[node] + 1 < d[neigh]) {
                    d[neigh] = d[node] + 1;
                    q.push(neigh);
                }
            }
        }
		ofstream fout("poduri.out");
		if (d[shore] != INF) {
			fout << d[shore];
		} else {
			fout << -1;
		}
		fout.close();
	}
};
