int longestSequence(vector<int> arr, int size) {
    // set to 1 because all sequences are at least 1
    int currentSeq = 1;
    int maxSeq = 0;

    for (int i = 1; i < size; i++) {
        // skip repeated numbers
        if (arr[i] == arr[i-1])
            int continua = 1;
        else
        if (arr[i-1] == arr[i] - 1) {
            // check if index is 1 greater than last
            currentSeq++;
        } else {
            // if not reset and hold last sequence value as max
            // if the last index of the array was last in the sequence
            if (currentSeq > maxSeq) {
                maxSeq = currentSeq;
            }
            currentSeq = 1;
        }
    }
    // if the last index of the array was last in the sequence
    if (currentSeq > maxSeq) {
        maxSeq = currentSeq;
    }

    return maxSeq;
}

// Pas1: generez multimi de lungime n, cu valori mai mici decat k
// in solution am o multime de marime n,
// in care elementele sunt mai mici decat k
// solution.size = n
void back(int step, vector<int> &solution) {
    // vom verifica o solutie atunci cand
    // am adaugat deja n elemente in solutie,
    // adica step == stop
    if (step == n + 1) {
        // am gasit un subgrup de n elemente si verific sumele
        vector<int> verif(100000);
        int sum = 0;
        int nk = 0;
        int nn = n;
        int prev_nn = 0;
        // imi pun numerele de baza
        for (int j = 1; j <= n; j++) {
            verif[nk++] = solution[j];
        }
        for (int i = 1; i < t; i++) {
            for (int j = 1; j <= n; j++) {
                for (int p = prev_nn; p < nn; p ++) {
                    verif[nk++] = verif[p] + solution[j];
                }
            }
            prev_nn = n;
            nn = nn * (n + 1);
        }
        sort(verif.begin(), verif.begin() + nk);
        int longseq = longestSequence(verif, nk);
        if (longseq > maxim) {
            maxim = longseq;
            for (unsigned i = 1; i <= n; i++) {
                vmax[i] = solution[i];
            }
        }

        return;
    }

    unsigned i = solution[step - 1] + 1;
    for (; i <= k; i++) {
        solution[step] = i;
        back(step + 1, solution);
    }
}

