// vector where all the combinations that contain 1 will be stored
vector<int> combinations;

// recursive function to generate a combination
void generateComb(int *arr, int *sol_arr,
                  int first, int last,
                  int index, int k) {
    if (index == k) {
        if (sol_arr[0] != 1)
            return;
        // a solution is stored in combinations vector
        for (int j = 0; j < k; j++) {
            combinations.push_back(sol_arr[j]);
        }
        return;
    }
    // try generating the next solution
    for (int i = first; i <= last &&
    last - i + 1 >= k - index; i++) {
        sol_arr[index] = arr[i];
        generateComb(arr, sol_arr, i + 1,
                         last, index + 1, k);
    }
}

// function to generate all the combinations
void combination(int *arr, int k, int n) {
    // temporary vector where a solution will be stored
    int sol_arr[50];
    generateComb(arr, sol_arr, 0, k - 1, 0, n);
}


int main() {
    // input/output files
    ifstream f("lego.in");
    ofstream out("lego.out");
    // read input data
    int k, n, t;
    f >> k >> n >> t;
    int *arr = (int*)malloc(sizeof(int)*k);
    if (!arr)
        return -1;
    // initialize the array
    for (int i = 0; i < k; i++)
        arr[i] = i+1;
    // vars for the best length and the best combination
    int best = 0;
    vector<int> best_combo;
    // generate all combinations
    combination(arr, k, n);
    // var to check the length of a combination
    int ind = 0;
    // vector to store a combination
    vector<int> combo;
    for (int combination : combinations) {
        combo.push_back(combination);
        ind++;
        if (ind == n) {  // first combination is in "combo"
            // calculate the maximum sum that can be reached
            int start_best = 0;
            int max_sum = combo[combo.size() - 1] * t;
            vector<int> v_sum(max_sum + 1, -1);
            // the combination elements have value 1
            for (int i : combo)
                v_sum[i] = 1;
           // max_sum is traversed and we calculate
           // the numbers that can be formed
            for (int i = 1; i <= max_sum; i++) {
                // check if there is a number that hasn't been formed
                if (v_sum[i] == -1) {
                    int best_cost = max_sum;
                    // iterate through the combination's element and
                    // check if the number can be formed with a lower cost
                    for (int j : combo) {
                        // to form a number, the cost will be at least 1
                        int cost = 1;
                        // can't form a number with bigger elements
                        if (j < i) {
                            // check what remains after removing
                            // a combination element
                            int rmn = i - j;
                            // if the previous element is not formed, it
                            // means this one cannot be formed as well
                            if (v_sum[rmn] == -1)
                                goto end;
                            cost += v_sum[rmn];
                            // check if the cost is valid
                            if (cost <= t && cost <= best_cost) {
                                best_cost = cost;
                                v_sum[i] = cost;
                            }
                        }
                        end:
                        continue;
                    }
                }
                // if number i couldn't be formed or the end of
                // the vector is reached
                if (v_sum[i] == -1 || i == max_sum) {
                    // calculate the longest distance
                    if (i-start_best > best) {
                        best = i - start_best;
                        best_combo = combo;
                        if (start_best == 0 && i != max_sum)
                            best -= 1;
                    }
                    start_best = i;
                }
            }
            // restart the combo vector and the index
            ind = 0;
            combo.clear();
        }
    }
    // print the longest consecutive sequence of numbers
    // and the combination for it
    out << best << endl;
    for (int i : best_combo)
        out << i << " ";
}

