        #include <cstdio>
#include <vector>
#include <map>
#include <cstring>

const int KMAX = 50;
int sol[KMAX], v[KMAX];

const int INF = -2147483647;
int vn = 0, answer = INF;

int vectorSum(std::vector<int> v) {
    int sum = 0;
    for (int i = 0; i < v.size(); i++) {
        sum += v[i];
    }
    return sum;
}

int calcDim(int n, int k, int t) {
    std::map<int, std::pair<std::vector<int>, int>> dimensions;
    std::vector<int> aux(n + 1, 0);
    for (int i = 0; i < k; i++) {
        aux[v[i]] = 1;
        dimensions[v[i]] = {aux, 1};
        aux[v[i]] = 0;
    }

    int lastDim = 1;
    int dist = 0, maxDist = INF;
    for (auto it = dimensions.begin(); it != dimensions.end(); it++) {
        int sum = it->first;
        aux = it->second.first;
        if (sum > lastDim + 1) {
            maxDist = std::max(maxDist, dist);
            dist = 1;
        } else {
            dist++;
        }

        int vsum = it->second.second;
        if (vsum + 1 > t) {
            lastDim = sum;
            continue;
        }
        for (int i = 0; i < k; i++) {
            aux[v[i]]++;
            if (dimensions.count(sum + v[i])) {
                if (dimensions[sum + v[i]].second > vsum + 1) {
                    dimensions[sum + v[i]].first = std::vector<int>(aux);
                    dimensions[sum + v[i]].second = vsum + 1;
                }
            } else {
                dimensions[sum + v[i]] = {std::vector<int>(aux), vsum + 1};
            }
            aux[v[i]]--;
        }
        lastDim = sum;
    }
    maxDist = std::max(maxDist, dist);
    return maxDist;
}

void backtrack(int n, int k, int t) {
    if (vn == k - 1) {
        int nrDim = calcDim(n, k, t);
        if (nrDim > answer) {
            answer = nrDim;
            memcpy(sol, v, KMAX * sizeof(int));
        }
    } else {
        for (int i = v[vn] + 1; i <= n; i++) {
            v[vn + 1] = i;
            vn++;
            backtrack(n, k, t);
            vn--;
            v[vn + 1] = 0;
        }
    }
}

int main() {
    FILE *in = fopen("lego.in", "r");
    int n, k, t;
    fscanf(in, "%d %d %d", &n, &k, &t);
    fclose(in);

    v[0] = 1;
    backtrack(n, k, t);

    FILE *out = fopen("lego.out", "w");
    fprintf(out, "%d\n", answer);
    for (int i = 0; i < k; i++) {
        fprintf(out, "%d ", sol[i]);
    }

    fclose(out);
    return 0;
}

