        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.Iterator;
import java.util.List;

class Lego {
	static ArrayList<Integer> sumePosibile = new ArrayList<>();
	static ArrayList<ArrayList> solutiiPosibile = new ArrayList<>();

	//  functie pentru a calcula produsul carteZian a 2 vectori
	private static void product(int[] arr, List<Integer> combinatii) {
		int sum = 0;
		ArrayList<Integer> solutie = new ArrayList<>();
		for (int i = 0; i < combinatii.size(); i++) {
			sum += arr[i] * combinatii.get(i);
			solutie.add(arr[i]);
		}
		//adaug suma si solutia in vectorii aferenti
		sumePosibile.add(sum);
		solutiiPosibile.add(solutie);
	}

	// dublu backtracking pentru a genera toate posibilitatile de piese alese
	// respectiv toate posibilitatile de numere de piese din fiecare fel
	static void genSol(int n, int k, int len, int[] arr,
						int n1, int t1, int sum, List<Integer> combinatii) {
		if (len == k) {
			if (n1 == 0) {
				if (sum <= t1) {
					product(arr, combinatii);
				}
				return;
			}
			for (int i = 0; i <= t1; i++) {
				combinatii.add(i);
				genSol(n, k, len, arr, n1 - 1, t1, sum + i, combinatii);
				combinatii.remove(combinatii.size() - 1);
			}
			return;
		}
		int i = (len == 0) ? 1 : arr[len - 1] + 1;
		len++;

		arr[0] = 1;
		while (i <= n) {
			arr[len - 1] = i;
			genSol(n, k, len, arr, n1, t1, sum, combinatii);
			i++;
		}
	}


	public static void main(String[] args) throws IOException {
		PrintWriter outputFile = new PrintWriter("lego.out");
		try (BufferedReader br = new BufferedReader(new FileReader("lego.in"))) {
			String s = br.readLine();
			String[] ss = s.split(" ");
			// citesc valorile din fisier
			int k = Integer.parseInt(ss[0]);
			int n = Integer.parseInt(ss[1]);
			int t = Integer.parseInt(ss[2]);
			List<Integer> combinatii = new ArrayList<>();
			int[] arr = new int[n];
			int len = 0;
			// aplic functia de generare a tuturor posibilitatilor
			genSol(k, n, len, arr, n, t, 0, combinatii);
			// creeZ un set cu toate sumele posibile intre valorile de 0 obtinute in
			// arrayul sumePosibile( dupa fiecare 0 este tratata alta combinatie si
			// astfel parcurg toate combinatiile), dupa care aflu pentru ce combinatie
			// se obtine secventa maxima de numere consecutive
			HashSet<Integer> hashSol = new HashSet<>();
			int counter = 0;
			Iterator<Integer> it;
			int a = 0;
			int b;
			int counter1 = 0;
			int counter2 = 0;
			int counter3 = -1, counter4 = 0;
			while (counter < sumePosibile.size()) {
				while (counter < sumePosibile.size() && sumePosibile.get(counter) != 0) {
					hashSol.add(sumePosibile.get(counter));
					counter++;
				}
				counter3++;
				it = hashSol.iterator();
				if (it.hasNext()) {
					a = it.next();
				}
				while (it.hasNext()) {
					b = it.next();
					if (b - a > 1) {
						if (counter2 < counter1) {
							counter2 = counter1;
							counter4 = counter3;
						}
						counter1 = 1;
					} else {
						counter1++;
					}
					a = b;
				}
				if (counter2 < counter1) {
					counter2 = counter1;
					counter4 = counter3;
				}
				counter1 = 1;
				counter++;
				hashSol.clear();
			}
			// printeZ secventa maxima in fisierul de output(counter2)
			outputFile.print(counter2);
			System.out.println(counter2);
			int counter5 = 0;
			for (int p = 0; p < sumePosibile.size(); p++) {
				if (sumePosibile.get(p) != 0) {
					counter5++;
				} else {
					counter5 = 0;
				}
			}
			// cu formula din acest for aflu dupa al catelea 0 se afla solutia mea
			//solutiiPosibile va fi un array de solutii posibile in care fiecare combinatie
			//apare de counter5 ori.
			outputFile.print("\n");
			for (int r = 0; r < solutiiPosibile.get((counter5 + 1) * counter4 - 1).size(); r++) {
				outputFile.print(solutiiPosibile.get((counter5 + 1) * counter4 - 1).get(r) + " ");
			}
			outputFile.flush();
			outputFile.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}
