        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.Collections;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class Lego {

	private static int K, N, T;
	// K - dimensiunea maxima a pieselor
	// N - subset din cele N piese
	// T - numarul de piese folosite, dintre subsetul celor N
	private static List<List<Integer>> allSubsets = new ArrayList<>();

	private static int maxSum = -1;
	private static List<Integer> response = null;

	public static void main(String[] args) throws Exception {
		BufferedReader reader = new BufferedReader(new FileReader("lego.in"));
		String line = reader.readLine().trim();
		String[] tocks = line.split(" ");
		K = Integer.parseInt(tocks[0]);
		N = Integer.parseInt(tocks[1]);
		T = Integer.parseInt(tocks[2]);
		reader.close();

		generateAllSubsetsOfSize_N_From_K_Elements();

		for (List<Integer> dimensions : allSubsets) {
			// solve for dimensions
			generateAllTheSumConsecutive(dimensions);
		}

		BufferedWriter writer = new BufferedWriter(new FileWriter("lego.out"));
		writer.write("" + maxSum + "\n");
		for (int value : response) {
			writer.write("" + value + " ");
		}
		writer.close();
	}

	public static void generateAllSubsetsOfSize_N_From_K_Elements() {
		int[] subset = new int[N + 1];
		boolean[] alreadyUsed = new boolean[K + 1];

		for (int i = 1; i <= K; i++) {
			alreadyUsed[i] = false;
		}

		generateAllSubsets(1, 1, subset, alreadyUsed);
	}

	public static void generateAllTheSumConsecutive(List<Integer> values) {
		int[] subset = new int[T + 1];
		Set<Integer> sums = new HashSet<>();
		generateAllSums(1, subset, values, sums);

		List<Integer> ss = new ArrayList<>();
		ss.addAll(sums);
		Collections.sort(ss);

		int currentLen = 1;
		int maxLen = 1;
		for (int i = 1; i < ss.size(); i++) {
			if (ss.get(i - 1) + 1 == ss.get(i)) {
				currentLen++;
			} else {
				maxLen = currentLen > maxLen ? currentLen : maxLen;
				currentLen = 1;
			}
		}
		maxLen = currentLen > maxLen ? currentLen : maxLen;

		if (maxLen > maxSum) {
			maxSum = maxLen;
			response = values;
		}
	}

	public static void generateAllSums(int pos, int[] subset,
										List<Integer> values, Set<Integer> sums) {
		if (pos == T + 1) {
			return;
		}

		for (int value : values) {
			subset[pos] = value;
			int sum = consumeSubset(subset, pos);
			sums.add(sum);
			generateAllSums(pos + 1, subset, values, sums);
		}
	}

	public static int consumeSubset(int[] subset, int pos) {
		int sum = 0;
		for (int i = 1; i <= pos; i++) {
			sum = sum + subset[i];
		}
		return sum;
	}

	public static void generateAllSubsets(int pos, int startValue, 
											int[] subset, boolean[] alreadyUsed) {
		if (pos == N + 1) {
			List<Integer> list = new ArrayList<>();
			for (int i = 1; i <= N; i++) {
				list.add(subset[i]);
			}
			allSubsets.add(list);
			return;
		}

		if (pos == 1) {
			subset[pos] = 1;
			alreadyUsed[pos] = true;
			generateAllSubsets(pos + 1, 2, subset, alreadyUsed);
			return;
		}

		for (int i = startValue; i <= K; i++) {
			if (alreadyUsed[i]) {
				continue;
			}

			subset[pos] = i;
			alreadyUsed[i] = true;
			generateAllSubsets(pos + 1, i + 1, subset, alreadyUsed);
			alreadyUsed[i] = false;
		}
	}
}

