        fin >> k >> n >> t;
        fin.close();
    }

    FinalSolution get_result() {
        int i;
        std::vector<int> domain(k - 1);
        std::vector<int> solution(n - 1);

        // se oun numerele disponibile in domeniu
        for (i = 0; i < k - 1; i++) {
            domain[i] = i + 2;
        }

        // se genereaza combinarile posibile
        back(0, n - 1, domain, solution);

        // se adauga elementul 1 in fiecare sir de numere
        for (auto &it : options) {
