        for (int i = 0; i < stop; ++i) {
            number.base.push_back(domain[solution[i]]);
            number.freq[domain[solution[i]]] = 1;
            number.prevSums.insert(domain[solution[i]]);
        }

        number.sums = number.prevSums;
        options.push_back(number);
    }

    // se genereaza toate combinarile de k luate cate n
    void back(int step, int stop, std::vector<int> &domain,
              std::vector<int> &solution) {
        if (step == stop) {
            if (check()) {
                makeSolution(solution, domain, stop);
            }
            return;
        }

        unsigned i = step > 0 ? solution[step - 1] + 1 : 0;
        for (; i < domain.size(); ++i) {
            solution[step] = i;
            back(step + 1, stop, domain, solution);
        }
    }

