        #include <bits/stdc++.h>
using namespace std;

int dominant_char;

/**
 * Compares two vectors. The bigger one is the one where the difference
 * between the number of letters used aside from the dominant letter and
 * the number of dominant letters is higher.
 */
bool comp(vector<int> a, vector<int> b) {
  long int sum_a = a[26] - a[dominant_char];
  long int sum_b = b[26] - b[dominant_char];

  return sum_a - a[dominant_char] > sum_b - b[dominant_char];
}

class Task {
 public:
  void solve() {
    ifstream fin("statistics.in");
    ofstream fout("statistics.out");

    // Initialise total_letters
    for (int i = 0; i < 27; i++) {
      total_letters.push_back(0);
    }

    fin >> n;
    for (int i = 1; i <= n; i++) {
      string cuv;
      vector<int> letters(27);

      fin >> cuv;

      // For each letter, increment it's corresponding position in the vectors
      for (int j = 0; j < cuv.length(); j++) {
        letters.at(cuv.at(j) - 'a')++;
        total_letters.at(cuv.at(j) - 'a')++;
      }

      // At position 26 we keep the length of the word, as well as the total
      // length of all words in total_letters.
      letters.at(26) = cuv.length();
      total_letters.at(26) += cuv.length();

      words.push_back(letters);
    }
    fout << get_result() << '\n';
    fin.close();
    fout.close();
  }

 private:
  int n;
  vector<vector<int> > words;
  vector<int> total_letters;

  /**
   * Checks that the word given as argument respects
   * the rule of having a dominant letter.
   */
  bool check_answer(vector<int> word) {
    long int sum_all = word.at(26);
    long int sum_curr_let = 0;
    sum_curr_let = word.at(dominant_char);
    return sum_curr_let > sum_all / 2;
  }

  /**
   * Checks if the letter is ever used in the current list of words.
   */
  bool is_letter_present(int i) {
    return total_letters.at(i) != 0;
  }

  int get_result() {
    vector<int> maximum_sequence;
    int longest = 0;

    // Repeats the exercise for every letter in the alphabet.
    for (int i = 0; i < 26; i++) {
      // Skip if the current letter is never used in this list of words.
      if (!is_letter_present(i)) {
        continue;
      }

      dominant_char = i;
      sort(words.begin(), words.end(), comp);

      maximum_sequence = total_letters;

      // Go through each word and verify if the current sequence is valid.
      // If it is, stop and check if the current number of words used is
      // the highest we got until now and set it if so.
      // Otherwise, remove the word from the current sequence and continue.
      for (int j = 0; j < n; j++) {
        if (check_answer(maximum_sequence)) {
          if (n - j > longest) {
            longest = n - j;
          }
          break;
        }
        for (int k = 0; k < 27; k++) {
          maximum_sequence.at(k) -= words.at(j).at(k);
        }
      }

      // If the longest sequence is of size n, stop since there is no
      // bigger number that we could get.
      if (longest == n) {
        return longest;
      }
    }
    return longest == 0 ? -1 : longest;
  }
};

int main() {
  Task* task = new (nothrow) Task();
  if (!task) {
    return -1;
  }
  task->solve();
  delete task;
  return 0;
}

