} myPair;


int get_occur_number(string str, char c) {
    if (str.find(c) != std::string::npos) {
        int counter =  std::count(str.begin(), str.end(), c);
        return counter;
    }
    return 0;
}

bool comparator(myPair a, myPair b) {
    int c1 = a.lettter_occur * 2 - (a.word).length();
    int c2 = b.lettter_occur * 2 - (b.word).length();
    return (c1 > c2);
}

int main() {
    // open in file
    ifstream in;

    in.open("statistics.in");
    if (!in) {
        cerr << "ERROR: Couldn't open in file\n";
        exit(1);
    }

    int n;
    in >> n;

    string words[NMAX];
    myPair wordsList[NMAX];
    int i;
    // read words list
    getline(in, words[0]);
    for (i = 0; i <n; i++) {
        getline(in, wordsList[i].word);
    }
    in.close();

    int result = 0;
    for (char c = 'a'; c <= 'z'; c++) {
        for (i = 0; i < n; i++) {
            wordsList[i].lettter_occur = get_occur_number(wordsList[i].word, c);
        }

        sort(wordsList, wordsList + n, comparator);

        int len = 0;
        int counter = 0;
        int charNb = 0;
        int index = 0;
        int letter_occur = wordsList[index].lettter_occur;
        int word_len = wordsList[index].word.length();
        while (index < n && ((charNb + letter_occur) << 1) > len + word_len) {
            len += word_len;
            charNb = charNb + letter_occur;
            counter++;
            index++;
            letter_occur = wordsList[index].lettter_occur;
            word_len = wordsList[index].word.length();
        }

        if (index >= n && ((charNb << 1) < len)) {
            counter = 0;
        }

        if (counter > result) {
            result = counter;
        }
    }

    // open out file
    ofstream out;
    out.open("statistics.out");

    if (result == 0) {
        out << -1;
    } else {
        out << result;
    }
    out.close();

    return 0;
}

