	public int calculateCost(String word, char letter) {
		int cost = 0;
		for (char c : word.toCharArray()) {
			if (c == letter) {
				cost++;
			} else {
				cost--;
			}
		}
		return cost;
	}
	// Functie ce calculeaza numarul maxim de cuvinte ce pot fi concatenate
	public int countMaxWords(ArrayList<Integer> costsArray) {
		int positiveCost = 0;
		int words = 0;
		for (int i = 0; i < costsArray.size(); i++) {
			if (positiveCost + costsArray.get(i) > 0) {
				positiveCost += costsArray.get(i);
				words += 1;
			} else {
				return words;
			}
		}
		return -1;
	}
	// Functie in care adaugam in fiecare vector din matricea noastra de litere
