			lettersCostsMatrix.add(new ArrayList<>());
			for (String word : inputWords) {
				lettersCostsMatrix.get(i).add(calculateCost(word, (char)(97 + i)));
			}
			Collections.sort(lettersCostsMatrix.get(i), Collections.reverseOrder());
			scoreForEachLetter.add(countMaxWords(lettersCostsMatrix.get(i)));
		}
	}
	// Sortam vectorul final descrescator si obtinem cea mai buna situatie pe prima pozitie
