        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;

public class Badgpt {
	/**
	 * A class for buffering read operations, inspired from here:
	 * https://pastebin.com/XGUjEyMN.
	 */
	private static class MyScanner {
		private BufferedReader br;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}

	private static final long MOD = 1000000007;

	// functia inmulteste 2 matrici, le am scris de mana
	// inmultirile pentru ca prob e mai rapid
	static long[][] inmultireMat(long[][] a, long[][] b) {
		long[][] rasp = new long[2][2];
		rasp[0][0] = (a[0][0] * b[0][0] + a[0][1] * b[1][0]) % MOD;
		rasp[0][1] = (a[0][0] * b[0][1] + a[0][1] * b[1][1]) % MOD;

		rasp[1][0] = (a[1][0] * b[0][0] + a[1][1] * b[1][0]) % MOD;
		rasp[1][1] = (a[1][0] * b[0][1] + a[1][1] * b[1][1]) % MOD;

		return rasp;
	}

	// functia imi calculeaza toate matricile
	// pana la puterea 64 si le salveaza in
	// array ul 3D matriciFibo
	static long[][][] calculeInitiale() {
		long[][] start = new long[2][2];
		start[0][0] = 1;
		start[0][1] = 1;
		start[1][0] = 1;

		long[][][] matriciFibo = new long[65][2][2];
		matriciFibo[0] = start;
		for (int i = 1; i < 64; i++) {
			matriciFibo[i] = inmultireMat(matriciFibo[i - 1], matriciFibo[i - 1]);
		}
		return matriciFibo;
	}

	// functia converteste numarul intr un string binar
	// si inmulteste matricile salvate conform
	// puterilor lui 2 prezente in numar
	static long calculFibonacci(long[][][] matriciFibo, long numar) {
		// biti va fi reprezentarea in baza 2 a numarului primit
		String biti = "";
		while (numar != 0) {
			if (numar % 2 == 0) {
				biti += "0";
			} else {
				biti += "1";
			}
			numar /= 2;
		}
		// rezultat reprezinta matricea finala obtinuta
		// din inmultirile cu matrici care sunt puteri ale
		// lui 2
		long[][] rezultat = new long[2][2];
		// prima este un switch pentru primul caz
		// cand fac doar atribuirea, nu si inmultire
		int prima = 0;
		for (int i = 0; i < biti.length(); i++) {
			// doar puterile lui 2 prezente in numar
			if (biti.charAt(i) == '1') {
				if (prima == 0) {
					rezultat = matriciFibo[i];
					prima = 1;
				} else {
					rezultat = inmultireMat(rezultat, matriciFibo[i]);
				}
			}
		}
		// rezultat[0][0] este intotdeauna valoarea fibo
		return rezultat[0][0] % MOD;
	}

	public static void main(String[] args) throws IOException {
		MyScanner obj;
		obj = new MyScanner(new FileReader("badgpt.in"));

		String sir = obj.nextLine();
		// un array 3D in care salvez cele 64 de matrici
		long[][][] valoriFibo;
		valoriFibo = calculeInitiale();
		long rezultat = 0;

		int cntParcurgere = 0;
		while (cntParcurgere < sir.length()) {
			String numar = "";
			// daca nu e 'n' sau 'u' ignoram
			if (sir.charAt(cntParcurgere) == 'n' || sir.charAt(cntParcurgere) == 'u') {
				cntParcurgere++;
				while (cntParcurgere < sir.length()
						&& (sir.charAt(cntParcurgere) >= '0' && sir.charAt(cntParcurgere) <= '9')) {
					numar += sir.charAt(cntParcurgere);
					cntParcurgere++;
				}
				// pentru primul numar doar atribui
				if (rezultat == 0) {
					rezultat = calculFibonacci(valoriFibo, Long.parseLong(numar)) % MOD;
				} else {
					// pentru celelalte numere inmultesc cu anterioarele
					rezultat = ((rezultat % MOD) * calculFibonacci(valoriFibo,
							Long.parseLong(numar)) % MOD) % MOD;
				}
				continue;
			}
			cntParcurgere++;
			// ignor cifrele literelor care nu sunt 'n' sau 'u'
			while (cntParcurgere < sir.length()
					&& (sir.charAt(cntParcurgere) >= '0' && sir.charAt(cntParcurgere) <= '9')) {
				cntParcurgere++;
			}
		}

		try (var printer = new PrintStream("badgpt.out")) {
			if (rezultat != 0) {
				printer.println(rezultat % MOD);
			} else {
				printer.println("1");
			}
		}

	}
}

