        #include <fstream>

#include <vector>

#include <iostream>

#include <string>

using namespace std;
const int MOD = 1000000007;

int64_t findnr(int64_t nr) {
    vector < int64_t > fib(nr + 1);
    fib[1] = 1;
    fib[2] = 2;
    for (int i = 3; i <= nr; i++) {
        fib[i] = (fib[i - 1] + fib[i - 2]) % MOD;
    }
    return fib[nr];
}

int64_t Solve(int n,
 const vector < int64_t > & numbers) {
    int possible = 1;
    for (int i = 0; i < n; i++) {
        if (numbers[i] > 0) {
            possible = (possible * findnr(numbers[i])) % MOD;
        } else {
            return 0;
        }
    }
    return possible;
}

int main() {
    ifstream fin("badgpt.in");
    ofstream fout("badgpt.out");

    string s;
    fin >> s;
    vector < int64_t > numbers;

    int i = 1;
    while (i <= (int64_t) s.size()) {
        if (s[i - 1] == 'n' || s[i - 1] == 'u') {
            int64_t nr = 0;
            while (s[i] >= '0' && s[i] <= '9') {
                nr = (nr * 10 + (s[i] - '0'));
                i++;
            }
            numbers.push_back(nr);
        } else {
            i++;
        }
    }
    int64_t n = numbers.size();
    int64_t rez = Solve(n, numbers);
    fout << rez << "\n";
    return 0;
}

