void multiply(unsigned long long a[2][2], unsigned long long b[2][2]) {
    unsigned long long c[2][2];
    c[0][0] = a[0][0] * b[0][0] + a[0][1] * b[1][0];
    if (c[0][0] > mod)
        c[0][0] %= mod;
    c[0][1] = a[0][0] * b[0][1] + a[0][1] * b[1][1];
