    if (c[1][0] > mod)
        c[1][0] %= mod;
    c[1][1] = a[1][0] * b[0][1] + a[1][1] * b[1][1];
    if (c[1][1] > mod)
        c[1][1] %= mod;
    a[0][0] = c[0][0];
    a[0][1] = c[0][1];
    a[1][0] = c[1][0];
    a[1][1] = c[1][1];
}

unsigned long long fibonacci(unsigned long long n) {
    // cazurile de baza
    if (n == 0)
        return 0;
    if (n == 1)
        return 1;

    // folosesc algoritmul de exponentiere binara
    unsigned long long result[2][2] = {{1, 1}, {1, 0}};
    unsigned long long fib[2][2] = {{1, 1}, {1, 0}};
    while (n > 0) {
        if (n % 2 == 1)
            multiply(result, fib);
        n = n / 2;
        multiply(fib, fib);
    }
    return result[0][1];
}


