	private static long fib(long n) {
		if (n == 0) {
			return 0;
		}

		if (n == 1 || n == 2) {
			return 1;
		}

		// memoizare pentru a evita recalcularea valorilor
		if (memo.containsKey(n)) {
			return memo.get(n);
		}

		long k = 0;
		if (n % 2 == 1) {
			k = (n + 1) / 2;
		} else {
