vector<vector<int64_t>> exp_by_squaring(vector<vector<int64_t>> x, int64_t n) {
    vector<vector<int64_t>> res(2, vector<int64_t>(2));
    res = identity_matrix();
    while (n) {
        if (n == 1) {
            return matrix_multiply(res, x);
        } else if (n % 2 == 0) {
            x = matrix_multiply(x, x);
            n = n / 2;
        } else {
            res = matrix_multiply(res, x);
            n--;
        }
    }

    return identity_matrix();
}

