        #include <iostream>
#include <algorithm>
#include <vector>

using namespace std;

#define MOD 1000000007

// functie ce identifica secventele ce contin litera n
long long find_strings_n(string s) {
    long long n = s.size();
	// se foloseste un vector unidimensional
    vector<long long> dp(n + 1, 0);
	// se trateaza cazul in care litera n ar fi pe prima pozitie
	if(s[0] == 'n') {
		dp[1] = 2;
		dp[0] = 1;
	} else {
		dp[0] = 1;
		dp[1] = 1;
	}
	// parcurgem vectorul si verificam aparitia consecutiva a literei n
    for (long long i = 2; i <= n; i++) {
        if (s[i] == 'n' && s[i - 1] == 'n') {
			// recurenta este una similara cu recurenta sirului lui Fibonacci
			dp[i] = dp[i - 1] + dp[i - 2];
			dp[i] %= MOD;
        } else {
            dp[i] = dp[i - 1];
			dp[i] %= MOD;
        }
    }
    return dp[n] % MOD;
}

// functie ce identifica aparitia literei u
long long find_strings_u(string s) {
    long long n = s.size();
    vector<long long> dp(n + 1, 0);
	// se trateaza cazul in care litera u este pe prima pozitie
    if (s[0] == 'u') {
		dp[1] = 2;
		dp[0] = 1;
	} else {
		dp[0] = 1;
		dp[1] = 1;
	}
	// se parcurge vectorul si se actualizeaza numarul de posibilitati
    for (long long i = 2; i <= n; i++) {
        if (s[i] == 'u' && s[i - 1] == 'u') {
			dp[i] = dp[i - 1] + dp[i - 2];
			dp[i] %= MOD;
        } else {
            dp[i] = dp[i - 1];
			dp[i] %= MOD;
        }
    }
    return dp[n] % MOD;
}

// functie ce creeaza sirul de litere extins, pornind de la input
string extended_string(string s) {
	string extended = "";
	for (long long i = 0; i < s.size(); i++) {
		if (isdigit(s[i])) {
			long long nr = s[i] - '0';
			long long j = i + 1;
			while(j < s.size() && isdigit(s[j])) {
				nr = (nr * 10) % MOD + (s[j] - '0');
				j++;
			}
            nr %= MOD;
			char letter = s[i - 1];
			// se adauga litera actuala la string ul extins
			extended.append(nr, letter);
			i = j - 1;
		}
	}
	return extended;
}

int main() {
    freopen("badgpt.in", "r", stdin);
	freopen("badgpt.out", "w", stdout);

    string s;
    cin >> s;
	string extended = extended_string(s);
	// posibilitatile sunt reprezentate de produsul dintre posibilitatile
	// pesntru litera n si cele pt litera u
    long long result = (find_strings_n(extended)
	* find_strings_u(extended)) % MOD;
    cout << result << endl;
    return 0;
}

