        #include <bits/stdc++.h>

using namespace std;

const long mod = 1000000007;

vector<vector<long long>> matrix_pow(vector<vector<long long>> A, long long n) {
    if (n == 1) {
        return A;
    }

    vector<vector<long long>> A1 = matrix_pow(A, n / 2);
    for (long long i = 0; i < A.size(); i++) {
        for (long long j = 0; j < A.size(); j++) {
            A1[i][j] %= mod;
        }
    }

    vector<vector<long long>> A2(A.size(), vector<long long>(A.size()));
    for (long long i = 0; i < A.size(); i++) {
        for (long long j = 0; j < A.size(); j++) {
            for (long long k = 0; k < A.size(); k++) {
                A2[i][j] += A1[i][k] * A1[k][j];
                A2[i][j] %= mod;
            }
        }
    }

    if (n % 2 == 0) {
        return A2;
    }

    vector<vector<long long>> A3(A.size(), vector<long long>(A.size()));
    for (long long i = 0; i < A.size(); i++) {
        for (long long j = 0; j < A.size(); j++) {
            for (long long k = 0; k < A.size(); k++) {
                A3[i][j] += A[i][k] * A2[k][j];
                A3[i][j] %= mod;
            }
        }
    }

    return A3;
}

long long fibo_quick(long long n) {
    if (0 <= n && n <= 1) {
        return n;
    }

    vector<vector<long long>> A = {{0, 1}, {1, 1}};
    vector<long long> x = {0, 1};
    vector<vector<long long>> An = matrix_pow(A, n - 1);

    long long res = 0;
    for (long long i = 0; i < An.size(); i++) {
        res += An[1][i] * x[i];
        res %= mod;
    }

    return res;
}

long SolveTask(char* str) {
    long long ret = 1;
    char* p = strchr(str, 'n');

    while (p != NULL) {
        char* q = p + 1;
        long number = 0;
        number = strtoul(q, NULL, 0);

        ret = ((ret % mod) * (fibo_quick(number + 1) % mod)) % mod;
        p = strchr(q, 'n');
    }

    char* a = strchr(str, 'u');

    while (a != NULL) {
        char* b = a + 1;
        long number = 0;
        number = strtoul(b, NULL, 0);

        ret = ((ret % mod) * (fibo_quick(number + 1) % mod)) % mod;
        a = strchr(b, 'u');
    }

    return ret;
}

int main() {
    ifstream fin("badgpt.in");
    ofstream fout("badgpt.out");

    string str;
    getline(fin, str);
    long long length = str.length();
    char* s = new char[length + 1];
    strcpy(s, str.c_str());

    auto res = SolveTask(s);
    fout << res << "\n";

    return 0;
}

