public class Criptat {
	int n;
	String[] words;
	HashMap<Character, ArrayList<String>> letters = new HashMap<Character, ArrayList<String>>();
	HashMap<Character, Integer> lettersCount = new HashMap<Character, Integer>();

	private void readInput() {
		try {
			File input = new File("criptat.in");
			Scanner scanner = new Scanner(input);
			n = Integer.parseInt(scanner.nextLine());
			words = new String[n];
			for (int i = 0; i < n; i++) {
