	private int numberOfAppearences(String word, char letter) {
		int nr = 0;
		for (int i = 0; i < word.length(); i++) {
			if (word.charAt(i) == letter) {
				nr++;
			}
		}
		return nr;
	}
	private int lenWithOtherLetters(int len, char letter) {
		HashMap<Integer, ArrayList<String>> words = new HashMap<Integer, ArrayList<String>>();
		for (Map.Entry<Character, ArrayList<String>> entry : letters.entrySet()) {
			char newLetter = entry.getKey();
			ArrayList<String> value = entry.getValue();
			if (newLetter != letter) {
				for (String word : value) {
					if (!words.containsKey(word.length())) {
						words.put(word.length(), new ArrayList<String>());
					}
					if (!words.get(word.length()).contains(word)) {
						words.get(word.length()).add(word);
					}
				}
			}
		}
		int found = 0;
		int remaining = len;
		boolean wordsAvailable = true;
		while (remaining > 0 && wordsAvailable) {
			int counter = remaining;
			boolean foundWord = false;
			while (counter > 0) {
				if (words.containsKey(counter)) {
					if (found + counter <= len) {
						found = found + counter;
						foundWord = true;
					}
					remaining = remaining - counter;
					words.get(counter).remove(0);
					if (words.get(counter).size() == 0) {
						words.remove(counter);
					}
				} else {
					counter--;
				}
			}
			if (!foundWord) {
				wordsAvailable = false;
			}
		}
		return found;
	}

	private int verifyEveryLetter(char letter) {

		class SortByApearrences implements Comparator<String> {
			public int compare(String word1, String word2) {
				double ratioWord1 = (double)numberOfAppearences(word1, letter) / word1.length();
				double ratioWord2 = (double)numberOfAppearences(word2, letter) / word2.length();
				if (ratioWord2 > ratioWord1) {
					return 1;
				} else if (ratioWord2 < ratioWord1) {
					return -1;
				} else {
					if (word2.length() > word1.length()) {
						return 1;
					} else if (word2.length() < word1.length()) {
						return -1;
					} else {
						return 0;
					}
				}
			}	
		}

		ArrayList<String> wordsContainLetter = letters.get(letter);
		Collections.sort(wordsContainLetter, new SortByApearrences());
		int len = 0;
		int numberLetter = 0;
		for (int i = 0; i < wordsContainLetter.size(); i++) {
			if ((len + wordsContainLetter.get(i).length()) / 2 < numberLetter 
				+ numberOfAppearences(wordsContainLetter.get(i), letter)) {
				len = len + wordsContainLetter.get(i).length();
				numberLetter = numberLetter
					+ numberOfAppearences(wordsContainLetter.get(i), letter);	
			}
		}
		int remainingLen = 2 * numberLetter - 1;
		remainingLen = remainingLen - len;
		return len + lenWithOtherLetters(remainingLen, letter);
	}
	private int getResult() {
		for (String word : words) {
			ArrayList<Character> added = new ArrayList<Character>();
			for (int i = 0; i < word.length(); i++) {
				char letter = word.charAt(i);
				if (!letters.containsKey(letter)) {
					letters.put(letter, new ArrayList<String>());
				}
				if (!lettersCount.containsKey(letter)) {
					lettersCount.put(letter, 0);
				}
				if (!added.contains(letter)) {
					letters.get(letter).add(word);
					added.add(letter);
				}
				int count = lettersCount.get(letter);
				lettersCount.put(letter, count + 1);
			}
		}
		int maximum = 0;
		for (Map.Entry<Character, Integer> entry : lettersCount.entrySet()) {
			char letter = entry.getKey();
			if (maximum < verifyEveryLetter(letter)) {
				maximum = verifyEveryLetter(letter);
			}
		}
		return maximum;
	}
