int maxLengthForChar(const vector<string>& words, char ch) {
    int maxLen = 0;
    vector<int> countByLen(10001, 0);
    for (const string& word : words) {
        int count = 0;
        int length = word.size();

        // In cazul acesta priceul de la problema rucsacului este numarul
        // de apariti al lui ch si greutatea obiectelor
        // e reprezentata de numarul de litere al cuvantului
        for (char c : word) {
            if (c == ch) count++;
        }
        // Actualizam vectorul de lungimi pentru fiecare cuvant
        for (int i = 10000; i >= length; --i) {
            countByLen[i] = max(countByLen[i], countByLen[i - length] + count);
        }
    }

    // Luam lungimea maxima a parolei din vector
    for (int len = 10000; len >= 1; len--) {
        if (countByLen[len] > len / 2) {  // verificam conditia pentru parola
            maxLen = max(maxLen, len);
            break;
        }
    }

    return maxLen;
}

