    set<char> distinctChars;
    char buffer[1000];
    for (int i = 0; i < N; i++) {
        fscanf(input, "%s", buffer);  // citim un cuvant folosind fscanf
        words[i] = string(buffer);
        for (char c : words[i]) {
            distinctChars.insert(c);
            if (distinctChars.size() == 8) {
                break;  // dacă sunt 8 litere, dăm break pentru a optimiza codul
            }
        }
    }

    int maxPasswordLength = 0;
    // Aflăm lungimea maximă pentru fiecare literă
    for (char ch : distinctChars) {
        int newMaxLength = maxLengthForChar(words, ch);
        if (maxPasswordLength < newMaxLength)
            maxPasswordLength = newMaxLength;
    }

    fprintf(output, "%d\n", maxPasswordLength);

    fclose(input);
    fclose(output);

    return 0;
}

