        import java.io.File;
import java.io.FileNotFoundException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Comparator;
import java.util.Scanner;

public class Criptat {
	// structura necesara procesarii unui cuvant din lista
	static class Word {
		int length;
		int[] letterCounts;

		Word(String word) {
			this.length = word.length();
			this.letterCounts = new int[26];
			for (char c : word.toCharArray()) {
				this.letterCounts[c - 'a']++;
			}
		}
	}

	public static void main(String[] args) {
		try {
			Scanner scanner = new Scanner(new File("criptat.in"));
			PrintWriter writer = new PrintWriter("criptat.out");
			int n = scanner.nextInt();
			scanner.nextLine();

			Word[] words = new Word[n];
			for (int i = 0; i < n; i++) {
				words[i] = new Word(scanner.nextLine().trim());
			}

			int maxResult = solve(words, n);
			writer.println(maxResult);
			writer.close();
			scanner.close();
		} catch (FileNotFoundException e) {
			System.out.println("File not found: " + e.getMessage());
		}
	}

	private static int solve(Word[] words, int n) {
		boolean[] letterPresent = new boolean[26];
		for (Word word : words) {
			for (int i = 0; i < 26; i++) {
				if (word.letterCounts[i] > 0) {
					letterPresent[i] = true;
				}
			}
		}

		int answer = 0;
		for (int k = 0; k < 26; k++) {
			if (!letterPresent[k]) {
				continue;
			}
			// pt fiecare litera din alfabet se sorteaza cuvintele
			int finalK = k;
			Arrays.sort(words, new Comparator<Word>() {
				@Override
				public int compare(Word w1, Word w2) {
					int ratio1 = w1.letterCounts[finalK] * w2.length;
					int ratio2 = w2.letterCounts[finalK] * w1.length;
					if (ratio1 != ratio2) {
						return ratio2 - ratio1;  // ratia mai mare
					}
					return w2.length - w1.length;  // Lungimea mai mare , pt ratie egala
				}
			});
			// se calculeaza lungimea max a parolei pt litera curenta dominanta
			int currentLetterCount = words[0].letterCounts[k];
			int currentLength = words[0].length;
			if (2 * currentLetterCount > currentLength) {
				for (int i = 1; i < n; i++) {
					//se verifica pastrarea proprietatii de litera dom.
					if ((currentLetterCount + words[i].letterCounts[k]) * 2
							> currentLength + words[i].length) {
						currentLength += words[i].length;
						currentLetterCount += words[i].letterCounts[k];
					}
				}
				answer = Math.max(answer, currentLength);
			}
		}

		return answer;
	}
}

