// Find all the used letters in the words (no duplicates, no more than 8)
vector<char> get_used_letters(vector<string> &words) {
    vector<char> res;
    for (int i = 0; i < words.size(); i++) {
        for (int j = 0; j < words[i].size(); j++) {
            bool found = false;
            for (int k = 0; k < res.size(); k++) {
                if (res[k] == words[i][j]) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                res.push_back(words[i][j]);
            }
        }
    }
    return res;
}

int get_letter_occurence(string word, char letter) {
    int count = 0;
    for (int i = 0; i < word.size(); i++) {
        if (word[i] == letter) {
            count++;
        }
    }
    return count;
}

int knapsackish(int n,
                int L,
                vector<string> &words,
                char letter,
                vector<int> &letter_in_words) {
    vector<vector<int>> dp(n + 1, vector<int>(L + 1, -1));
    // For length 0, we can't have any letters
    for (int i = 0; i <= n; i++) {
        dp[i][0] = 0;
    }

    for (int i = 1; i <= n; i++) {
        for (int len = 0; len <= L; len++) {
            int word_size = words[i - 1].size();
            // If we can't fit the word, we can't use it
            if (len < word_size) {
                dp[i][len] = dp[i - 1][len];
            } else {
                // If we can form a word with len - word_size letters,
                // decide if we should use the word or not
                if (dp[i - 1][len - word_size] != -1) {
                    dp[i][len] = max(dp[i - 1][len],
                                     dp[i - 1][len - word_size] +
                                     letter_in_words[i - 1]);
                } else {
                    // We can't form a word with len using the current word
                    // and the ones until it
                    dp[i][len] = -1;
                }
            }
            dp[i][len] = max(dp[i][len], dp[i - 1][len]);
        }
    }

    // Find the longest word which validates the condition
    for (int i = L; i >= 0; i--) {
        if ((float)dp[n][i] / i > 0.5 && dp[n][i] != -1) {
            return i;
        }
    }
    return 0;
}

unsigned int solve(int n, vector<string> &words, int L) {
    // Find the used letters in the words
    vector<char> letters = get_used_letters(words);
    // Initialize the result vector for all the letters
    vector<int> letters_res(letters.size(), 0);

    vector<vector<int>> let_occurences(letters.size(), vector<int>(n, 0));
    for (int let = 0; let < letters.size(); let++) {
        for (int i = 0; i < n; i++) {
            let_occurences[let][i] = get_letter_occurence(words[i],
                                                        letters[let]);
        }
    }
    for (int let = 0; let < letters.size(); let++) {
        // Do a DP for each letter
        letters_res[let] = knapsackish(n,
                                        L,
                                        words,
                                        letters[let],
                                        let_occurences[let]);
    }

    // Return the best result
    int max = 0;
    for (int i = 0; i < letters_res.size(); i++) {
        if (letters_res[i] > max) {
            max = letters_res[i];
        }
    }
    return max;
}

int main(void) {
	int N, total_len = 0;

	fin >> N;
	vector<string> words(N);
	for (int i = 0; i < N; i++) {
		fin >> words[i];
        total_len += words[i].size();
	}

	unsigned int res = solve(N, words, total_len);

	fout << res << "\n";
	return 0;
}

