        return v;
    }

    void get_sorted_by_character(vector<entry_t>& v, char c) {
        sort(v.begin(), v.end(), [&](entry_t &e1, entry_t &e2) {
            int e1_freq;
            int e2_freq;

            if (!e1.freq[c])
                e1_freq = 0;
            else
                e1_freq = e1.freq[c];


            if (!e2.freq[c])
                e2_freq = 0;
            else
                e2_freq = e2.freq[c];

            if (!e1_freq && !e2_freq)
                return e1.size > e2.size;

            double e1_ratio = (double)e1_freq / (double)e1.size;
            double e2_ratio = (double)e2_freq / (double)e2.size;

            if (e1_ratio == e2_ratio)
                return e1.size > e2.size;

            return e1_ratio > e2_ratio;
        });
    }

    void decompose_words() {
        unordered_map<char, int> total;

        for (int i = 0; i < n; i++)
            decomposed.push_back(unroll_word(words[i], total));


        globalFreq = get_sorted_characters(total);
    }

    bool testSolution(int character_occurences, int total_len) {
        return (double)character_occurences > (double)total_len / FACTOR;
    }

    int get_maxlen_string(vector<entry_t>& sorted, char c) {
        size_t character_occurences = 0;
        size_t total_len = 0;

        for (size_t i = 0; i < sorted.size(); i++) {
            int freq;
            if (!sorted[i].freq[c])
                freq = 0;
            else
                freq = sorted[i].freq[c];

            size_t size = sorted[i].size;

            bool ret = testSolution(character_occurences + freq,
