            if (ret) {
                character_occurences += freq;
                total_len += size;
            }
        }

        return total_len;
    }

    void find_solution() {
        int max = 0;
        for (size_t i = 0; i < globalFreq.size(); i++) {
            char c = globalFreq[i].first;

