        import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Arrays;
import java.util.Comparator;
import java.util.Scanner;

public class Criptat {
	//vector in care retin numarul de aparitii per total al fiecarei litere
	public static int[] alfabet = new int[26];
	//clasa in care retin cuvintele alaturi de aparitiile fiecarei litere ale sale
	public static class Cuvant {
		String info;

		int[] aparitii;
		//constructor in care populez vectorul de aparitii ale literelor
		public Cuvant(String info) {
			this.info = info;
			this.aparitii = new int[26];
			for (int i = 0; i < 26; i++) {
				this.aparitii[i] = 0;
			}
			for (int i = 0; i < info.length(); i++) {
				this.aparitii[info.charAt(i) - 'a']++;
				alfabet[info.charAt(i) - 'a']++;
			}
		}
	}
	//functie de comparator pentru a ordona cuvintele
	public static class AparitiiComparator implements Comparator<Cuvant> {
		//index este pozitia in vectorul de litere a literei pe care o consider dominanta
		private int index;
		public AparitiiComparator(int index) {
			this.index = index;
		}
		//sortez in functie de raportul dintre aparitiile literei pe care
		//o consider dominanta si lungimea cuvantului, iar, daca este egal, in functie
		//de numarul de aparitii ale literei dominante
		@Override
		public int compare(Cuvant Cuvantt1, Cuvant Cuvantt2) {
			double ratie1 = (double)Cuvantt1.aparitii[index] / Cuvantt1.info.length();
			double ratie2 = (double)Cuvantt2.aparitii[index] / Cuvantt2.info.length();
			double aparitii1 = Cuvantt1.aparitii[index];
			double aparitii2 = Cuvantt2.aparitii[index];

			if (ratie1 > ratie2) {
				return -1;
			} else if (ratie1 < ratie2) {
				return 1;
			} else if (aparitii1 > aparitii2) {
				return 1;
			} else if (aparitii1 < aparitii2) {
				return -1;
			} else {
				return 0;
			}
		}
	}
	//intoarce parola de lungime maxima in functie de litera pe care o consider dominanta
	public static int verificaLitera(int idx, Cuvant[] cuvinte) {
		Arrays.sort(cuvinte, new AparitiiComparator(idx));
		//lungime parola si numarul de aparitii ale literei dominante in parola
		int lungime = 0, i = 0, aparitiiParola = 0;
		while (i < cuvinte.length) {
			int aparitiiAux = (cuvinte[i].aparitii[idx] + aparitiiParola) * 2;
			int lungimeAux = lungime + cuvinte[i].info.length();
			//verific daca dupa adaugarea cuvantului curent inca mai este litera dominanta
			if (aparitiiAux <= lungimeAux) {
				break;
			} else {
				//adaug cuvantul curent la parola
				lungime += cuvinte[i].info.length();
				aparitiiParola += cuvinte[i].aparitii[idx];
				i++;
			}
		}
		return lungime;
	}
	public static void main(String[] args) throws IOException {
		Scanner scanner = new Scanner(new File("criptat.in"));
		int N = Integer.parseInt(scanner.nextLine());
		Cuvant[] cuvinte = new Cuvant[N];
		//citesc cuvintele si creez obiectele pentru vectorul de cuvinte
		for (int i = 0; i < N; i++) {
			String info = scanner.nextLine();
			cuvinte[i] = new Cuvant(info);
		}
		int maxim = -1;
		//verific fiecare litera daca apare in cuvintele primite si aflu lungimea maxima
		//a parolei considerand pe rand fiecare litera ca fiind dominanta
		for (int i = 0; i < 26; i++) {
			if (alfabet[i] != 0) {
				int verifica = verificaLitera(i,cuvinte);
				if (verifica > maxim) {
					maxim = verifica;
				}
			}
		}
		FileWriter writer = new FileWriter("criptat.out");
		writer.write(String.format("%d", maxim));
		writer.close();
	}
}

