const int MAX_CHAR = 26;


bool compareWords(const std::string& word1, const std::string& word2, char c) {
    int count1 = std::count(word1.begin(), word1.end(), c);
    int count2 = std::count(word2.begin(), word2.end(), c);
    int totalChars1 = word1.size();
    int totalChars2 = word2.size();

    // Compare the occurrence of character c relative to
    // the total number of characters in each word
    double ratio1 = count1 / static_cast<double>(totalChars1);
    double ratio2 = count2 / static_cast<double>(totalChars2);

    // Sort in descending order based on the ratio
    if (ratio1 != ratio2) {
        return ratio1 > ratio2;
    }

    // If the ratios are equal, sort by length
    if (word1.size() != word2.size()) {
        return word1.size() > word2.size();
    }

    // If lengths are also equal, sort lexicographically
    return word1 < word2;
}

int computeMaxLength(std::vector<std::string> words) {
    int numberOfWords = words.size();

    // dominant[i] means the maximal length of a password with i
    // as dominant character
    std::vector<int> dominant(MAX_CHAR, 0);

    for (int i = 'a'; i <= 'z'; ++i) {
        // Sort words based on the occurrence of character i
        // relative to the total number of characters
        std::sort(words.begin(), words.end(),
            [&](const std::string& word1, const std::string& word2) {
                return compareWords(word1, word2, i);
        });

        // Add words one by one to dominant[i]
        // keeping track of the total number
        // of i occurances over and the total number of characters
        int totalOccurrences = 0;
        int totalCharacters = 0;

        // Iterate over sorted words
        for (const std::string& word : words) {
            totalOccurrences += std::count(word.begin(), word.end(), i);
            totalCharacters += word.size();
            // Check if the condition is met for
            // the current dominant character
            if (totalOccurrences > totalCharacters / 2) {
                dominant[i - 'a'] = totalCharacters;
            }
        }
    }

    // Find and return the maximum length of the password
    int maxLength = 0;
    for (int len : dominant) {
        maxLength = std::max(maxLength, len);
    }
    return maxLength;
}

