std::vector<char> GetUniqueLetters(const std::vector<std::string>& words) {
    std::set<char> uniqueLetters;
    std::vector<char> result;
    for (const std::string& word : words) {
        for (int i=0; i<(int)word.size(); i++) {
            if (uniqueLetters.size() == MAX_UNIQUE_LETTERS) {
                for (auto letter : uniqueLetters)
                        result.push_back(letter);
                return result;
            } else {
                uniqueLetters.insert(word[i]);
            }
        }
    }
    for (auto letter : uniqueLetters)
        result.push_back(letter);
    return result;
}
/*computes letter frequencies in the word and other useful data*/
void ComputeData(const std::vector<std::string>& inWords,
                const std::vector<char>& letters,
                std::vector<WordData>& words,
                int& totalLetters ) {
    totalLetters = 0;
    std::unordered_map<char, int> totalLetterCount;
    for (auto letter : letters) {
        totalLetterCount[letter] = 0;
    }
    for (auto word : inWords) {
        WordData w;
        w.word = word;
        std::unordered_map<char, int> letterCount;
        for (auto letter : letters) {
            letterCount[letter] = 0;
        }
        // update letter counts
        for (int i=0; i<(int)word.size(); i++) {
            letterCount[word[i]] += 1;
            totalLetterCount[word[i]] += 1;
            totalLetters += 1;
        }
        // compute letter frequencies
        for (char letter : letters) {
            w.freq[letter] = letterCount[letter]/(float)word.size();
            w.lc[letter] = letterCount[letter];
        }
        words.push_back(w);
    }
}

/*builds the longest possible password for which the letter is dominant*/
std::string BuildPasswordWithLetter(char letter, std::vector<WordData>& data) {
    std::string result;
    std::sort(data.begin(), data.end(),
              [letter](const WordData& a, const WordData& b) {
                return a.freq.at(letter) > b.freq.at(letter);
            });
    int totalApparitions = 0;
    for (auto& wordData : data) {
        float totalAparitionsNew = totalApparitions + wordData.lc[letter];
        float totalSizeNew = result.size() + wordData.word.size();
        float freq = totalAparitionsNew / totalSizeNew;
        if (freq > 0.5) {
            totalApparitions += wordData.lc[letter];
            result += wordData.word;
        }
    }
    return result;
}
