// Structura pentru un cuvant
typedef struct {
  string word;
  int no_dominant_chars;
  float ratio;
} word_t;

// Functie de citire a cuvintelor din fisier
vector<string> readWords(string filename) {
  ifstream fin(filename);
  vector<string> words;
  int n;
  fin >> n;
  for (int i = 0; i < n; i++) {
    string word;
    fin >> word;
    words.push_back(word);
  }
  fin.close();
  return words;
}

// Functie de rezolvare a problemei
int solve(vector<string> words) {
  unordered_set<char> unique_characters;
  int answer = 0;
  // Parcurgem fiecare cuvant si calculam numarul de caractere dominante
  for (auto &word : words) {
    for (auto &c : word) {
      unique_characters.insert(c);
    }
  }
  for (auto &character : unique_characters) {
    vector<word_t> words_info;
    // Calculam numarul de caractere dominante pentru fiecare cuvant
    for (auto &word : words) {
      int dominant_chars = 0;
      for (auto &c : word) {
        if (c == character) {
          dominant_chars++;
        }
      }
      // Salvam informatiile
      word_t word_info;
      word_info.word = word;
      word_info.no_dominant_chars = dominant_chars;
      word_info.ratio = (float)dominant_chars / word.size();
      words_info.push_back(word_info);
    }
    // Sortam cuvintele in functie de raportul de caractere dominante
    sort(words_info.begin(), words_info.end(), [](word_t a, word_t b) {
      return a.ratio > b.ratio;
    });

    int actualLen = 0;
    int actualDominantChars = 0;
    // Alegem cuvintele in ordinea data de sortare
    for (auto &word_info : words_info) {
      if (word_info.no_dominant_chars + actualDominantChars
      > (actualLen + word_info.word.size()) / 2) {
        actualLen += word_info.word.size();
        actualDominantChars += word_info.no_dominant_chars;
      }
    }
    answer = max(answer, actualLen);
  }
  return answer;
}

