using namespace std;

#define NMAX 100001
#define INF (1LL << 60)

struct Dijkstra_Res {
	// vector pt distantele minime
	vector<long long> dist;
	// vector pentru parinti
	vector<int> parent;

	// constructor
	explicit Dijkstra_Res(int n)
    : dist(n + 1, INF), parent(n + 1, -1) {}
};

class Drumuri {
	public:
		void solve() {
			read();
			print(get_res());
		}

	private:
		int n, m;
		//  nodurile de start si destinatia
		int x, y, z;
		// folosesc un vector de perechi pentru a retine muchia si costul
		vector<pair<int, long long>> adj[NMAX];

		// functie pentru citirea datelor din fisier
		void read() {
			ifstream fin("drumuri.in");
			fin >> n >> m;
			for (int i = 1; i <= m; i++) {
				int a, b;
				long long cost;
				fin >> a >> b >> cost;
				adj[a].push_back({b, cost});
			}
			fin >> x >> y >> z;
			fin.close();
		}

		// functie care returneaza rezultatul
		long long get_res() {
			// aplic dijkstra pornind din fiecare sursa
			auto res_x = dijkstra(x);
			auto res_y = dijkstra(y);

			// daca raman distante infinite le fac -1
			if (res_x.dist[z] == INF || res_y.dist[z] == INF) {
				return -1;
			}

			// returnez costurile minim pentru fiecare sursa pana la destinatie adunate
			return res_x.dist[z] + res_y.dist[z];
		}

		// functie pentru algoritmul dijkstra
		Dijkstra_Res dijkstra(int start) {
			Dijkstra_Res result(n);

			// coada pt noduri vizitate
			set<pair<long long, int>> pq;
			// initializez cu 0 distanta de start si o adaug in coada
			result.dist[start] = 0;
			pq.insert({0, start});

			while (!pq.empty()) {
				// extrag nodul din coada
				pair<long long, int> top = *pq.begin();
				long long dist = top.first;
				int node = top.second;
				pq.erase(pq.begin());

				// parcurg vecinii
				for (size_t i = 0; i < adj[node].size(); ++i) {
					int neighbor = adj[node][i].first;
					long long weight = adj[node][i].second;
					// calculez distanta daca trecem prin nodul asta
					long long new_dist = dist + weight;
					// verific daca distanta e mai mica
					if (new_dist < result.dist[neighbor]) {
						pq.erase({result.dist[neighbor], neighbor});
						result.dist[neighbor] = new_dist;
						result.parent[neighbor] = node;
						pq.insert({new_dist, neighbor});
					}
				}
			}
			return result;
		}

		// functie care printeaza rezultatul
		void print(long long result) {
			ofstream fout("drumuri.out");
			fout << result;
			fout.close();
		}
};

int main() {
	auto *rez = new (nothrow) Drumuri();
	rez->solve();
	delete rez;
	return 0;
}

