        #include<stdio.h>
#include <bits/stdc++.h>
#include<iostream>
#include<fstream>

using namespace std;

// valoare maxima pt nodurile in care nu se poate ajunge

#define INF 10000000000

/*
    functia dijkstra pentru calcularea drumurilor
    minime dintr un nod sursa la cele la care poate ajunge
    preluata din rezolvarea oficiala a labului
*/

vector<long long> dijkstra(int source, int nodes,
                vector<pair<int, long long>> adj[]) {
    vector<long long> d(nodes + 1, INF);
    set<pair<int, long long>> pq;

    d[source] = 0;
    pq.insert({d[source], source});

    while (!pq.empty()) {
        auto top = pq.begin();
        auto [_, node] = *top;
        pq.erase(top);

        for (auto [neigh, w] : adj[node]) {
            if (d[node] + w < d[neigh]) {
                pq.erase({d[neigh], neigh});
                d[neigh] = d[node] + w;
                pq.insert({d[neigh], neigh});
            }
        }
    }

    return d;
}

int main() {
    ifstream fin("drumuri.in");
    ofstream fout("drumuri.out");

    int n, m, a, b, x, y, z;
    long long c, min_dist = 100000000000;
    fin >> n >> m;

    vector<pair<int, long long>> adj[n + 1];
    vector<pair<int, long long>> adj_reverse[n + 1];

    /*
        vom avea nevoie de lista de adiacenta a
        grafului initial, dar si de cea pt graful
        cu muchiile inversate
    */

    for (int i = 1; i <= m; i++) {
        fin >> a >> b >> c;
        adj[a].push_back({b, c});
        adj_reverse[b].push_back({a, c});
    }

    fin >> x >> y >> z;

    /*
        calculam dijkstra din toate cele 3 noduri,
        dar pt z din graful inversat
    */

    vector<long long> dist_x = dijkstra(x, n, adj);
    vector<long long> dist_y = dijkstra(y, n, adj);
    vector<long long> dist_z = dijkstra(z, n, adj_reverse);

    /*
        daca se poate ajunge intr un nod din cele 3 punte,
        calculam suma distantelor pana acolo, iar apoi
        vom lua minimul, iar acela este raspunsul cautat
    */

    for (int i = 1; i <= n; i++) {
        if (dist_x[i] != INF && dist_y[i] != INF && dist_z[i] != INF) {
            if (min_dist > dist_x[i] + dist_y[i] + dist_z[i]) {
                min_dist = dist_x[i] + dist_y[i] + dist_z[i];
            }
        }
    }

    fout << min_dist;

    fin.close();
    fout.close();
    return 0;
}

