	public static ReturnClass dijsktra(int source, int[] nodes, List<Integer>[] v,
										HashMap<Integer, Costs> costs) {
		long[] d = new long[nodes.length];
		int[] p = new int[nodes.length];
		for (int i = 1; i < nodes.length; i++) {
			d[i] = Long.MAX_VALUE;
			p[i] = -1;
		}

		PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> Long.compare(d[a], d[b]));

		d[source] = 0;
		p[source] = -1;
		pq.add(source);

		while (!pq.isEmpty()) {

			int node = pq.poll();

			for (int neigh : v[node]) {
				Costs cost = costs.get(node * 1000 + neigh);
				if (d[node] + cost.cost < d[neigh]) {
					d[neigh] = d[node] + cost.cost;
					p[neigh] = node;

					pq.add(neigh);
				}
			}
		}

		ReturnClass ret = new ReturnClass();
		ret.d = d;
		ret.p = p;
		return ret;
	}
