using namespace std;
#define MAX_NODES 100001

// Dijkstra algoritm to find minimal distance
vector<long long> dijkstra(int N, int source,
            vector<pair<int, int>> graph[MAX_NODES]) {
    vector<long long> dist(N + 1, LLONG_MAX);
    vector<int> parent(N + 1, -1);
    dist[source] = 0;

    set<pair<long long, int>> pq;

    pq.insert({dist[source], source});

    while (!pq.empty()) {
        auto top = pq.begin();
        const auto [_, node] = *top;
        pq.erase(top);

        for (const auto& [neigh, w] : graph[node]) {
            if (dist[node] + w < dist[neigh]) {
                pq.erase({dist[neigh], neigh});
                dist[neigh] = dist[node] + w;
                parent[neigh] = node;
                pq.insert({dist[neigh], neigh});
            }
        }
    }


    for (int i = 1; i <= N; i++) {
        if (dist[i] == LLONG_MAX) {
            dist[i] = -1;
        }
    }

    return dist;
}


int main() {
    ifstream fin("drumuri.in");
    ofstream fout("drumuri.out");

    int N, M, i;
    int a, b, c;
    int x, y, z;
    fin >> N >> M;

    vector<pair<int, int>> graph[MAX_NODES];
    vector<pair<int, int>> transpose_graph[MAX_NODES];

    // Create the graph and the transpose of the graph
    for (i = 1; i <= M; i++) {
        fin >> a >> b >> c;
        graph[a].push_back({b, c});
        transpose_graph[b].push_back({a, c});
    }
    fin >> x >> y >> z;

    // Calculate the distance of the shortest path for each node
    vector<long long> distances = dijkstra(N, x, graph);
    vector<long long> distances2 = dijkstra(N, y, graph);
    vector<long long> distances3 = dijkstra(N, z, transpose_graph);

    // If the path exist find the minimum distance between the 3 shortest paths
    long long min_dist = LLONG_MAX;
    for (i = 1; i <= N; i++) {
        if (distances[i] != -1 && distances2[i] != -1 && distances3[i] != -1) {
            min_dist = min(min_dist,
            distances[i] + distances2[i] + distances3[i]);
        }
    }

    fout << min_dist << "\n";

    fin.close();
    fout.close();
    return 0;
}

