using namespace std;

ifstream fin("drumuri.in");
ofstream fout("drumuri.out");

#define INF 0x3f3f3f3f


// Structura pentru un drum
typedef struct {
    int cost;  // costul drumului
    vector<pair<int, int>> path;  // drumul in sine
} path;

// Functie de Dijkstra
vector<path> djs(int node, vector<int> adj[],
                map<pair<int, int>, int> costs, int n) {
    vector<path> dist(n + 1, {INF, {}});  // vector de drumuri
    dist[node] = {0, {}};  // drumul de la nodul de start la el insusi

    set<pair<int, int>> pq;  // coada de prioritati
    pq.insert({0, node});  // adaugam nodul de start in coada

    while (!pq.empty()) {
        int u = pq.begin()->second; // nodul cu cel mai mic cost
        pq.erase(pq.begin());  // scoatem nodul din coada

        // pentru fiecare vecin al nodului
        for (int v : adj[u]) {
            /*
            daca drumul de start la v este mai putin costisitor
            prin u, actualizam costul si drumul
            */
            if (dist[v].cost > dist[u].cost + costs[{u, v}]) {
                pq.erase({dist[v].cost, v});
                dist[v].cost = dist[u].cost + costs[{u, v}];
                dist[v].path = dist[u].path;
                dist[v].path.push_back({u, v});
                pq.insert({dist[v].cost, v});
            }
        }
    }

    return dist;
}

int main() {
    int n;  // numarul de noduri
    fin >> n;

    int m;  // numarul de muchii
    fin >> m;

    vector<int> adj[n + 1];  // lista de adiacenta
    map<pair<int, int>, int> costs;  // costurile muchiilor

    for (int i = 0; i < m; i++) {
        int x, y, c;
        fin >> x >> y >> c;
        adj[y].push_back(x);
        costs[{y, x}] = c;
    }



    int x, y, z;
    fin >> x >> y >> z;


    // Drumurile de la z la celelalte noduri
    vector<path> dist = djs(z, adj, costs, n);

    int cost = 0;  // costul total
    // parcurgem drumul de la z la x
    for (auto p : dist[x].path) {
        // daca nu am adaugat deja muchia la costul total
        // ii adaugam costul
        if (costs[p] != 0) {
            cost += costs[p];
            costs[p] = 0;
        }
    }
    // parcurgem drumul de la z la y
    for (auto p : dist[y].path) {
        // daca nu am adaugat deja muchia la costul total
        // ii adaugam costul
        if (costs[p] != 0) {
            cost += costs[p];
            costs[p] = 0;
        }
    }



    fout << cost << "\n";


    return 0;
}

