void dijkstra(int start, int N, vector<Edge> graph[], long long dist[]) {
    priority_queue<pair<long long, int>, vector<pair<long long, int>>,
        greater<pair<long long, int>>> pq;
    fill(dist, dist + N + 1, INF);
    dist[start] = 0;
