	int y;
	int z;

	Drumuri(int n, int m, Graph graph, Graph graph2, int x, int y, int z) {
		this.n = n;
		this.m = m;
		this.graph = graph;
		this.graph2 = graph2;
		this.x = x;
		this.y = y;
		this.z = z;
	}
	/*
	Metoda care realizeaza algoritmul lui Dijkstra pentru a determina
	distanta minima de la nodul fst la nodul z
	 */
	public long dijkstra(int fst, Graph graph) {
		int n = graph.n;
		// initializam un vector de distante care va simboliza pentru fiecare nod distanta
		// minima de la sursa la nodul respectiv si un vector de parinti
		long[] distance = new long[n];
		long[] parent = new long[n];
		// initializam distantele cu infinit si parintii cu -3
		Arrays.fill(distance, Long.MAX_VALUE);
		Arrays.fill(parent, -3);
		// setam distanta de la sursa la ea insasi cu 0
		distance[fst] = 0;
		parent[fst] = -1;
		// initializam o coada de prioritati si adaugam nodul sursa
		PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[1], b[1]));
		pq.add(new long[]{fst, 0});
		// cat timp coada nu este goala extragem nodul cu distanta minima
		while (!pq.isEmpty()) {
			long[] current = pq.poll();
			int node = (int) current[0];
			long cost = current[1];
			// pentru fiecare vecin al nodului curent actualizam distanta
			if (graph.costs.containsKey(node)) {
				for (Map.Entry<Integer, Integer> entry : graph.costs.get(node).entrySet()) {
					int nextNode = entry.getKey();
					int nextCost = entry.getValue();
					if (distance[node] != Long.MAX_VALUE) {
						// daca distanta de la sursa la nodul curent + costul muchiei
						// este mai mica decat distanta de la sursa la vecin
						// actualizam distanta si parintele si adaugam vecinul in coada
						if (distance[nextNode] >= distance[node] + nextCost) {
							distance[nextNode] = distance[node] + nextCost;
							parent[nextNode] = node;
							pq.add(new long[]{nextNode, distance[nextNode]});
						}
					}
				}
			}
		}
		// reconstruim drumul de la sursa la destinatie
		int[] path = new int[n];

		int i = 0;
		int end = z;
		// cat timp nu am ajuns la sursa
		while (end != -1) {
			// actualizam costul muchiei de la parinte la nodul curent cu 0 si
			// adaugam nodul in drum
			if (graph.costs.containsKey((int)parent[end])) {
				if (graph.costs.get((int)parent[end]).containsKey(end)) {
					graph.costs.get((int)parent[end]).put(end, 0);
				}
			}
			path[i++] = end;
			end = (int) parent[end];
		}
		// returnam distanta de la sursa la destinatie
		return distance[z];
	}


	/*
	Metoda care intoarce suma distantei minime de la x la z si de la y la z
	 */
