import java.util.ArrayList;
import java.util.Comparator;
import java.util.PriorityQueue;
import java.util.Scanner;

public class Drumuri {
	public static void main(String[] args) {
		new SolutionDrumuri().solution();
	}
}

class SolutionDrumuri {

	public void solution() {
		// declar graful
		Graph graph = readGraph();
		if (graph == null) {
			return;
		}

		// folosind algoritmul lui Dijsktra adaptat, obtin vectorul de valori a drumurilor
		// raportate la nodul de finish
		int[] dist = graph.backwardsDijkstra(graph.z);

		// afisez rezultatul
		int sol = dist[graph.x] + dist[graph.y];
		try {
			Writer writer = new FileWriter("drumuri.out");
			writer.write(String.valueOf(sol));
			writer.close();
		} catch (Exception e) {
			e.printStackTrace();
		}
	}

	public Graph readGraph() {
		try {
			Scanner scanner = new Scanner(new File("drumuri.in"));
			int V = scanner.nextInt();
			Graph graph = new Graph(V);
			int n = scanner.nextInt();
			for (int i = 0; i < n; i++) {
				int src = scanner.nextInt();
				int dest = scanner.nextInt();
				int weight = scanner.nextInt();
				graph.addEdge(src, dest, weight);
			}
			int x = scanner.nextInt();
			int y = scanner.nextInt();
			int z = scanner.nextInt();
			graph.addSpecialElement(x, y, z);
			scanner.close();

			return graph;
		} catch (FileNotFoundException e) {
			e.printStackTrace();
		}
		return null;
	}
}

class Graph {
	final int inf = Integer.MAX_VALUE;
	int V, x, y, z;
	// implementez graful cu o matrice de adiacenta, pentru a putea folosi algoritmul lui Dijsktra
	// in sens invers
	ArrayList<int[]>[] adjList = new ArrayList[V + 1];

	public Graph(int V) {
		this.V = V;
		this.adjList = new ArrayList[V + 1];
		for (int i = 0; i < V + 1; i++) {
			adjList[i] = new ArrayList<>();
		}
	}

	public void addSpecialElement(int x, int y, int z) {
		this.x = x;
		this.y = y;
		this.z = z;
	}

	public void addEdge(int src, int dest, int weight) {
		int[] node = new int[2];
		node[0] = src;
		node[1] = weight;
		this.adjList[dest].add(node);
	}

	public int[] backwardsDijkstra(int finish) {
		int[] values = new int[V + 1];
		boolean[] visited = new boolean[V + 1];
		PriorityQueue<int[]> pQueue = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));

		// initializare vectori
		for (int i = 1; i <= V; i++) {
			values[i] = inf;
			visited[i] = false;
		}
		values[finish] = 0;

		// incep parcurferea grafului
		pQueue.add(new int[]{finish, 0});
		while (!pQueue.isEmpty()) {
			int node = pQueue.poll()[0];
			visited[node] = true;

			for (int i = 0; i < adjList[node].size(); i++) {
				int[] neighbour = adjList[node].get(i);
				if (neighbour[0] != 0 && !visited[neighbour[0]]) {
					if (values[neighbour[0]] > values[node] + neighbour[1]) {
						values[neighbour[0]] = values[node] + neighbour[1];
						pQueue.add(new int[]{neighbour[0], values[neighbour[0]]});
					}
				}
			}
		}
		return values;
	}
}

