        #include <bits/stdc++.h>

using namespace std;

// function for reading input data from file
void read_input(int& n, int& k, vector<double>& prices) {
    ifstream fin("oferta.in");
    fin >> n >> k;
    double x;
    for (int i = 0; i < n; i++) {
        fin >> x;
        prices.push_back(x);
    }
    fin.close();
}

// function for applying the discount on two products
double disc_2(double x, double y) {
    if (x < y)
        return x / 2.0 + y;
    else
        return x + y / 2.0;
}

// function for the min of three elements
double min_3(double x, double y, double z) {
    return (double) min(x, (double) min(y, z));
}

// function for applying the discount on three products
double disc_3(double x, double y, double z) {
    return x + y + z - min_3(x, y, z);
}

int main(void) {
    int n, k;
    vector<double> prices;

    // read input
    read_input(n, k, prices);

    ofstream fout("oferta.out");

    // invalid
    if (k > n) {
        fout << -1 << endl;
        return 0;
    }

    // array for solution (dynamic programming)
    vector<double> dp(n, 0.0);

    // best prices is the product's
    dp[0] = prices[0];

    // best price is obtained by applying the discount on the first 2
    if (n > 1)
        dp[1] = disc_2(prices[1], prices[0]);

    /* best price is obtained by getting the minimum of the discount on
       the first three, the discount on the current and the last one and
       the discount on the first two plus the current*/
    if (n > 2)
        dp[2] = min_3(disc_3(prices[2], prices[1], prices[0]),
                      disc_2(prices[2], prices[1]) + dp[0],
                      prices[2] + dp[1]);

    // general rule
    for (int i = 3; i < n; i++) {
        dp[i] = min_3(disc_3(prices[i], prices[i-1], prices[i-2]) + dp[i-3],
                      disc_2(prices[i], prices[i-1]) + dp[i-2],
                      prices[i] + dp[i-1]);
    }

    // print result
    fout << fixed << setprecision(1) << dp[n-k] << endl;
    fout.close();

    return 0;
}

