// Functie ce calculeaza discountul oferit daca grupez 2 produse
double pair2(double prod1, double prod2) {
    return max(prod1, prod2) + min(prod1, prod2) / 2;
}

// Functie ce calculeaza discountul oferit daca grupez 3 produse
double pair3(double prod1, double prod2, double prod3) {
    return prod1 + prod2 + prod3 - min({prod1, prod2, prod3});
