// Functie ce calculeaza cel mai mic pret posibil
double minCost(vector<double>& pret, int n) {
    // Initializez vectorul dp
    vector<double> dp(n + 1, 0);
    // Parcurg fiecare element
    for (int i = 1; i <= n; i++) {
        // Calculez pretul minim in functie de cum le grupez

        // Grupez 1
        dp[i] = dp[i - 1] + pret[i - 1];
        // Grupez 2
        if (i >= 2) {
            dp[i] = min(dp[i], dp[i - 2] +
            pair2(pret[i - 1], pret[i - 2]));
        }
        // Grupez 3
        if (i >= 3) {
            dp[i] = min(dp[i], dp[i - 3] +
            pair3(pret[i - 1], pret[i - 2], pret[i - 3]));
        }
    }

    // Returnez pretul minim ce se afla la dp[n]
    return dp[n];
}

