void merge(double a[], int n1, double b[], int n2, double c[], int n3, int k,
           double result[], int &idx) {
    priority_queue<tuple<double, int, int>, vector<tuple<double,
    int, int>>, Compare1> minHeap;

    if (n1 > 0)
        minHeap.push(make_tuple(a[1], 0, 2));
    if (n2 > 0)
        minHeap.push(make_tuple(b[1], 1, 2));
    if (n3 > 0)
        minHeap.push(make_tuple(c[1], 2, 2));

    idx = 0;

    while (!minHeap.empty() && idx < k) {
        tuple<double, int, int> top = minHeap.top();
        minHeap.pop();

