        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import static java.lang.Math.min;
import java.util.ArrayList;
import java.util.Scanner;

public class Oferta {
	public final String input_file = "oferta.in";
	public final String output_file = "oferta.out";

	int n, k;
	ArrayList<Integer> products = new ArrayList<Integer>();

	private double twoOffer(int first, int second) {
		return first + second  -  min(first, second) / 2.0;
	}

	private double threeOffer(int first, int second, int third) {
		return first + second + third  -  min(min(first, second), third);
	}

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void readInput() {
		try {
			Scanner sc = new Scanner(new File(input_file));

			n = sc.nextInt();
			k = sc.nextInt();
			for (int i = 0; i < n; i++) {
				products.add(sc.nextInt());
			}

			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(double result) {
		try {
			PrintWriter pw = new PrintWriter(new File(output_file));
			pw.printf("%.1f", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private double getResult() {
		ArrayList<Double> dp = new ArrayList<Double>();

		dp.add(Double.valueOf(products.getFirst()));
		if (products.size() > 1) {
			dp.add(
					// offer is best by default
					twoOffer(products.get(0), products.get(1))
			);
		}
		if (products.size() > 2) {
			dp.add(min(
					min(
						// second + alone
						dp.get(1) + products.get(2),
						// first + double offer
						dp.get(0) + twoOffer(products.get(1), products.get(2))
					),
					// triple offer
					threeOffer(products.get(0), products.get(1), products.get(2))
			));
		}
		for (int i = 3; i < n; i++) {
			// three-way min
			dp.add(min(
					min(
						dp.get(i - 1) + products.get(i),
						dp.get(i - 2) + twoOffer(products.get(i - 1), products.get(i))
					),
					dp.get(i - 3)
						+ threeOffer(products.get(i - 2), products.get(i - 1), products.get(i))
			));
		}

		double result = dp.getLast();

		return result;
	}

	public static void main(String[] args) {
		new Oferta().solve();
	}
}

