			return prices[0];
		} else if (length == 2) {
			return group50(prices[0], prices[1]);
		}

		double[] dp = new double[length + 1];
		dp[0] = prices[0];
		dp[1] = Math.min(dp[0] + prices[1], group50(prices[0], prices[1]));
		double min = Math.min(dp[1] + prices[2], (dp[0] + group50(prices[1], prices[2])));
		dp[2] = Math.min(min, (group100(prices[0], prices[1], prices[2])));

		for (int i = 3; i <= length; i++) {
			min = Math.min(dp[i - 1] + prices[i], (dp[i - 2] + group50(prices[i - 1], prices[i])));
			min = Math.min(min, (dp[i - 3] + group100(prices[i - 2], prices[i - 1], prices[i])));
			dp[i] = min;
		}

		return dp[length - 1];
	}

	public static void main(String[] args) throws FileNotFoundException {
		double[] prices = new double[100001];

		int length = readInput(prices);

		double minPrice = computeMinPrice(prices, length);

		writeOutput(minPrice);
	}

	private static int readInput(double[] prices) throws FileNotFoundException {
		File inputFile = new File("oferta.in");
		Scanner scanner = new Scanner(inputFile);

		int n = scanner.nextInt();
		int k = scanner.nextInt();
		for (int i = 0; i < n; i++) {
			prices[i] = scanner.nextInt();
		}

		scanner.close();
		return n;
	}

	private static void writeOutput(double minPrice) throws FileNotFoundException {
		PrintWriter writer = new PrintWriter("oferta.out");

		writer.write(Double.toString(minPrice));

		writer.close();
	}
}

