        #include <iostream>
#include <fstream>
#include <vector>
#include <iomanip>
#include <limits>
#include <algorithm>
#include <cmath>
#include <numeric>

using namespace std;

// functia calculeaza suma unui grup de elemente,
// scazand cel mai mic element din grup
double groupSum(vector<double>& nums, int start, int groupSize) {
    double minVal = numeric_limits<double>::max();
    double sum = 0;
    for (int j = 0; j < groupSize; ++j) {
        minVal = min(minVal, static_cast<double>(nums[start + j]));
        sum += nums[start + j];
    }
    return sum - minVal;
}

// calculeaza suma minima ajustata pentru un numar de grupuri
// posibile din vector
double calculateMinimumSum(vector<double>& nums, int n, int K) {
    if (n == 0) return 0;
    if (n == 1 && K == 1) return nums[0];
    if (n == 1 && K != 1) return -1;
    if (n == 2 && K != 1) return -1;
    // initializeaza vectorul cu valori maxime
    vector<double> dp(n + 1, numeric_limits<double>::max());
    // seteaza costul de start la 0
    dp[0] = 0;

    for (int i = 1; i <= n; ++i) {
        // grup de cate 1
        dp[i] = min(dp[i], dp[i - 1] + nums[i - 1]);

        // grup de cate 2
        if (i >= 2) {
            double sum = nums[i - 1] + nums[i - 2] - min(nums[i - 1],
                                                            nums[i - 2]) / 2.0;
            dp[i] = min(dp[i], dp[i - 2] + sum);
        }
        // grup de cate 3
        if (i >= 3) {
            double sum = groupSum(nums, i - 3, 3);
            dp[i] = min(dp[i], dp[i - 3] + sum);
        }
    }

    return dp[n];
}

int main() {
    ifstream input_file("oferta.in");
    if (!input_file.is_open()) {
        cerr << "Nu am putut deschide fișierul.";
        return 1;
    }

    int N, K;
    input_file >> N >> K;
    vector<double> prices(N);
    double price;
    for (int i = 0; i < N; ++i) {
        input_file >> price;
        prices[i] = price;
    }

    double minimal_sum = calculateMinimumSum(prices, N, K);
    ofstream output_file("oferta.out");
    output_file << fixed << setprecision(1) << minimal_sum << endl;
    output_file.close();
    return 0;
}

