        #include <bits/stdc++.h>
#include <iomanip>

using namespace std;

class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    int n, k;
    vector<int> v;

    void read_input() {
        ifstream fin("oferta.in");

        fin >> n >> k;

        int x;

        // push 3 redundant elements since we can group 3 products
        // helps with indexing during dp
        v.push_back(-1);
        v.push_back(-1);
        v.push_back(-1);
        for (int i = 0; i < n; ++i) {
            fin >> x;
            v.push_back(x);
        }

        fin.close();
    }

    double get_result() {
        vector<vector<double>> dp(k, vector<double>(n + 3, INFINITY));

        dp[0][2] = 0;

        for (int i = 3; i < n + 3; ++i) {
            set<double> prices;
            for (int j = 0; j < k; ++j) {
                double c;

                // individual product
                c = dp[j][i - 1] + v[i];
                prices.insert(c);

                // grouped 2 products
                c = dp[j][i - 2]
                    + v[i - 1] + v[i]
                    - min({ v[i - 1], v[i] }) * 0.5;
                prices.insert(c);

                // grouped 3 products
                c = dp[j][i - 3]
                    + v[i - 2] + v[i - 1] + v[i]
                    - min({ v[i - 2], v[i - 1], v[i] });
                prices.insert(c);
            }

            auto it = prices.begin();

            for (int j = 0; j < k && j < prices.size(); ++j) {
                dp[j][i] = *it;
                ++it;
            }
        }

        if (dp[k - 1][n + 2] != INFINITY)
            return dp[k - 1][n + 2];

        return -1;
    }

    void print_output(double result) {
        ofstream fout("oferta.out");
        fout << fixed << setprecision(1) << result << "\n";
        fout.close();
    }
};

int main() {
    Task* task = new Task();

    if (!task) {
        return -1;
    }

    task->solve();

    delete task;
    return 0;
}

