long double max_double(long double a1, long double a2) {
    if (a1 > a2) {
        return a1;
    }

    return a2;
}

int must_pay_max(const std::vector<int> &objects, const int k) {
    return max_double(objects[k - 1], objects[k - 0]);
}

double half_price(const std::vector<int> &objects, const int k) {
    return min_double(objects[k - 1], objects[k - 0]) / 2.0;
}

double solve(const std::vector<int> &objects, const int n) {
    std::vector<long double>dp(n + 1);
    long double current_value;
    dp[0] = 0;
    dp[1] = objects[0];
    dp[2] = min_double(dp[1] + objects[1], dp[0] + must_pay_max(objects, 1) + half_price(objects, 1));

    // std::cout << dp[1] << " " << dp[2] << " ";

    int k = 2;

    for (int i = 3; i < n + 1; i++) {
        dp[i] = dp[i - 1] + objects[k];

        current_value = dp[i - 2] + must_pay_max(objects, k) + half_price(objects, k);
        dp[i] = min_double(dp[i], current_value);

        current_value = dp[i - 3] + objects[k - 2] + objects[k - 1] + objects[k - 0]
                    - min_double(min_double(objects[k - 2], objects[k - 1]), objects[k - 0]);
        dp[i] = min_double(dp[i], current_value);

        // std::cout << dp[i] << " ";
        k++;
    }

    return dp[n];
}

int main() {
    int n, k;
    fin >> n >> k;
    std::vector<int> objects(n);
    for (int i = 0; i < n; i++) {
        fin >> objects[i];
    }

    fout << std::fixed << std::setprecision(1);
    fout << solve(objects, n) << "\n";

    fin.close();
    fout.close();

    return 0;
}
