private:
    // numarul maxim de noduri
    static constexpr int NMAX = 10005;
    int n, m, a;
    vector<int> adj[NMAX];

    // retine gradul intern pentru fiecare nod
    vector<int> in_degree;

    void read_input() {
        ifstream fin("curse.in");
        fin >> n >> m >> a;
        in_degree = vector<int>(m + 1, 0);
        int matrix[a + 1][n + 1];

        for (int i = 0; i < a; i++) {
            for (int j = 0; j < n; j++) {
                int x;
                fin >> x;
                matrix[i][j] = x;
            }
        }

        // transform datele de intare intr-un graf orientat pe care
        // se poate aplica sortarea topologica
        for (int i = 1; i < a; i++) {
            for (int j = 0; j < n; j++) {
                if (matrix[i][j] != matrix[i - 1][j]) {
                    int ok = 0;
                    for (int k = 0; k < j; k++) {
                        // daca exista 2 masini diferite in pistele precedente
                        if (matrix[i][k] != matrix[i - 1][k]) {
                            ok = 1;
                            break;
                        }
                    }

                    if (ok == 0) {
                        adj[matrix[i][j]].push_back(matrix[i - 1][j]);
                        ++in_degree[matrix[i - 1][j]];
                    }
                }
            }
        }
        fin.close();
    }

    vector<int> get_result() {
        return solve_bfs();
    }

    vector<int> solve_bfs() {
        vector<int> topsort;
        queue<int> q;
        int minimum = NMAX;
        bool visited[n];
        // calculez gradul intern minim si pun in coada nodurile
        // cu acest grad
        for (int i = 1; i <= m; i++) {
            if (in_degree[i] < minimum) {
                minimum = in_degree[i];
            }
        }
        for (int node = 1; node <= m; ++node) {
            if (in_degree[node] == minimum) {
                q.push(node);
                visited[node] = true;
            }
        }

        // BFS
        while (!q.empty()) {
            int node = q.front();
            q.pop();

            // adaug la solutie elementul scos
            topsort.push_back(node);
