        #include <bits/stdc++.h>
#define MAX_TRACKS 101  // numarul maxim de piste
#define MAX_CARS 20001  // numarul maxim de masini
#define MAX_TRAININGS 200001  // numarul maxim de antrenamente

using namespace std;

ifstream fin("curse.in");
ofstream fout("curse.out");

int tracks;  // numarul de piste
int cars;  // numarul de masini
int trainings;  // numarul de antrenamente

// usedTrainings[i] = true, daca antrenamentele i si j au generat deja o muchie
bool usedTrainings[MAX_TRAININGS];

// vector in care salvam cursele din input
vector<vector<int>> races(MAX_TRACKS, vector<int>(MAX_CARS, 0));

int n;  // numarul de noduri din graful rezultat
int inNodes[MAX_CARS];  // numarul de vecini interiori ai unui nod
vector<int> adj[MAX_CARS];  // lista de adiacenta a grafului rezultat

int main() {
    // citeste datele de intrare
    fin >> tracks >> cars >> trainings;
    for (int i = 1; i <= trainings; ++i) {
        for (int j = 1; j <= tracks; ++j) fin >> races[j][i];
    }

    // genereaza muchiile din graf pe baza comparatiilor dintre curse
    for (int t = 1; t <= tracks; ++t)
        for (int i = 1; i < trainings; ++i)
            if (races[t][i] != races[t][i + 1] && !usedTrainings[i]) {
                // marcheaza pereche de antrenamnete (i,i+1) ca folosita
                usedTrainings[i] = true;
                // adauga nodul interior nou adaugat
                inNodes[races[t][i + 1]]++;
                // adauga intrarea in lista de adiacenta
                adj[races[t][i]].push_back(races[t][i + 1]);
            }

    vector<int> ans;  // vectorul in care se va salva rezultatul
    n = cars;  // numarul de noduri este egal cu numarul de masini

    // sortare topologica
    for (int i = 1; i <= n; ++i) {
        int nod = 1;
        // cauta un nod care nu are noduri interioare
        while (inNodes[nod]) nod++;
        // marcheaza nodul nod ca fiind folosit
        inNodes[nod] = -1;
        // adauga nodul nod la solutie
        ans.push_back(nod);
        // actualizeaza gradul interior al nodurilor spre care are muchie nod
        for (auto it = adj[nod].begin(); it != adj[nod].end(); it++)
            --inNodes[*it];
    }

    // afiseaza solutia
    for (auto it = ans.begin(); it != ans.end(); it++) fout << (*it) << ' ';
    fout << "\n";
    return 0;
}

