using namespace std;

int task1(int n, int m, int x, const vector<int> &p,
		  const vector<int> &gradesSum) {
	x *= n;

	// knapsack
	vector<int> dp(x + 1, 0);
	for (int i = 0; i < m; i++) {
		for (int j = x; j >= p[i]; j--) {
			dp[j] = max(dp[j], dp[j - p[i]] + gradesSum[i]);
		}
	}

	return dp[x];
