			int x = sc.nextInt();
			b = n * x;

			prices = new int[m + 1];
			sumGrades = new int[m + 1];

			for (int i = 1; i <= m; ++i) {
				prices[i] = sc.nextInt();
			}

			for (int i = 0; i < n; i++) {
				for (int j = 0; j < m; j++) {
					/* Compute the sum of the grades */
					sumGrades[j + 1] += sc.nextInt();
				}
			}

