using namespace std;

int task1(int n, int m, int x, vector <pair <int, int>> rategrade) {
	int aux[m + 1][n * x + 1] = {0};

	/* Initializam prima linie cu 0 (nu a mers cu varianta de mai sus). */
	for (int j = 0; j <= n * x; j++) {
		aux[0][j] = 0;
	}

	for (int i = 1; i <= m; i++) {
		for (int j = 0; j <= n * x; j++) {
			/* Stocam solutia de la pasul anterior (i - 1) */
			aux[i][j] = aux[i - 1][j];
			/* Daca sunt bani suficienti pentru achizitionarea platoului,
			 atunci stochez maximul dintre pasul precedent si adaugand ratingul
			 platoului proaspat achizitionat. */
			if (j - rategrade[i - 1].second >= 0) {
				aux[i][j] = max(aux[i][j],
								(aux[i - 1][j - rategrade[i - 1].second] + rategrade[i - 1].first));
			}
		}
	}
	return aux[m][n * x];
}

int task2(int n, int m, int x, vector <pair <int, int>> rategrade) {
	int aux[2 * m + 3][n * x + 1] = {0};

	for (int j = 0; j <= n * x; j++) {
		aux[0][j] = 0;
	}
	/* i se dubleaza pentru a accesa de 2 ori fiecare platou. */
	for (int i = 1; i <= 2 * m + 2; i++) {
		for (int j = 0; j <= n * x; j++) {
			/* Stocam solutia de la pasul i - 1. */
			aux[i][j] = aux[i - 1][j];
			/* Daca sunt bani suficienti pentru achizitionarea platoului,
			 atunci stochez maximul dintre pasul precedent si adaugand ratingul
			 platoului proaspat achizitionat. */
			if (j - rategrade[(i - 1) / 2].second >= 0) {
				aux[i][j] = max(aux[i][j],
							   (aux[i - 1][j - rategrade[(i - 1) / 2].second] +
							   rategrade[(i - 1) / 2].first));
			}
		}
	}
	return aux[2 * m][n * x];
}

int task3(int n, int m, int x, vector <pair <int, int>> rategrade) {
	/* Sortam in ordine descrescatoare in functie de pret. */
	sort(rategrade.begin(), rategrade.end(), [](const pair<int, int>& elem1,
		 const pair<int, int>& elem2) {
		 return elem1.first > elem2.first;});
	/* Vector de perechi ce stocheaza valoarea sumei ratingului pana in acel
	 moment si cate platouri au fost cumparate. */
	vector<vector<pair <int, int>>> aux(2 * m + 4,
										vector<pair<int, int>>(n * x + 10));
	int maxim = 0;

	for (int j = 0; j <= n * x; j++) {
		aux[0][j].first = 0;
		aux[0][j].second = 0;
	}

	for (int i = 1; i <= 2 * m + 2; i++) {
		for (int j = 0; j <= n * x; j++) {
			/* Stocam solutia de la pasul i - 1. */
			aux[i][j].first = aux[i - 1][j].first;
			aux[i][j].second = aux[i - 1][j].second;
			/* Daca sunt bani suficienti pentru achizitionarea platoului,
			 atunci stochez maximul dintre pasul precedent si adaugand ratingul
			 platoului proaspat achizitionat. */
			if (aux[i][j].second < n && j - rategrade[(i - 1) / 2].second >= 0) {
				aux[i][j].first = max(aux[i][j].first, (aux[i - 1][j -
									  rategrade[(i - 1) / 2].second].first +
									  rategrade[(i - 1) / 2].first));
				/* Daca am ales platoul, crestem numarul de platouri alese. */
				if (aux[i][j].first != aux[i - 1][j].first) {
					aux[i][j].second++;
					/* Daca sunt sub n platouri, iar suma e mai mare decat ce
					 avea, inainte, salveaza noua valoare.*/
					if (maxim < aux[i][j].first) {
						maxim = aux[i][j].first;
					}
				}
			}
		}
	}
	return maxim;
}

