			if (i == 0) {
				rating[j] = grades[i][j];
			} else {
				rating[j] += grades[i][j];
			}
			/* Unim ratingul unui platou cu pretul sau. */
			if (i == n - 1) {
				rategrade.push_back(pair<int, int>(rating[j], prices[j]));
			}
		}
	}
