using namespace std;

// returnez un vector de vectori cu divizorii numerelor de la 1 la n
// Complexitatea temporala O(n * logn)
// Complexitatea spatiala O(n*n)
vector<vector<int>> get_divisors_interval(int n) {
    vector<vector<int>> numbers_divisors(n + 1);
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= n; j += i) {
            numbers_divisors[j].push_back(i);
        }
    }
    return numbers_divisors;
}

// construiesc vectorul cu numarul de operatii pentru fiecare numar
// Complexitatea temporala O(n*n)
vector<int> getOperations(int n, vector<vector<int>> divisors_interval) {
    vector<int> operations(n + 1, 100);
    operations[0] = -1;  // pe 0 nu il iau in considerare
    operations[1] = 0;  // pentru numarul 1 nu se face nicio operatie
    for (int i = 1; i <= n; i++) {
        vector<int> divisors_i = divisors_interval[i];
        for (int j = 0; j < divisors_interval[i].size(); j++) {  // O(n)
            if (i + divisors_i[j] <= n &&
                (operations[i + divisors_i[j]] > operations[i] + 1)) {
                operations[i + divisors_i[j]] = operations[i] + 1;
            }
        }
    }
    return operations;
}

// Calculez numarul maxim de puncte pe care il pot obtine
// Complexitatea temporala e O(n*k) timp
// Complexitatea spatiala O(k)
int rucsac(vector<int> operations, vector<int> points, int k,
            vector<int> target) {
    vector<int> maxim(k + 1, -1);
    maxim[0] = 0;
    int max = maxim[0];

    for (int i = 0; i < target.size(); i++) {
        int operation_i = operations[target[i]];
        for (int j = k; j >= operations[target[i]]; j--) {
            if (maxim[j - operation_i] != -1 &&
                (maxim[j - operation_i] + points[i] > maxim[j])) {
                maxim[j] = maxim[j - operation_i] + points[i];
                if (maxim[j] > max) {
                    max = maxim[j];
                }
            }
        }
    }
    return max;
}

int main(void) {
    ifstream fin;
    ofstream fout;
    int n, k;
    fin.open("prinel.in");
    fout.open("prinel.out");

    fin >> n >> k;

    vector<int> target(n), points(n);
    int max_number = 0;

    for (int i = 0; i < n; i++) {
        fin >> target[i];
        if (target[i] > max_number) {
            max_number = target[i];
        }
    }

    for (int i = 0; i < n; i++) {
        fin >> points[i];
    }

    vector<vector<int>> numbers_divisors = get_divisors_interval(max_number);
    vector<int> operations = getOperations(max_number, numbers_divisors);

    if (k > 25000) {
        k = 25000;
    }

    fout << rucsac(operations, points, k, target);

    fin.close();
    fout.close();
}

