int max_points(int n, int W, vector<int> &cost, vector<int> &p) {
    vector< vector<int> > dp(n + 1, vector<int>(W + 1, 0));

    for (int cap = 0; cap <= W; ++cap) {
        dp[0][cap] = 0;
    }

    for (int i = 1; i <= n; ++i) {
        for (int cap = 0; cap <= W; ++cap) {
            dp[i][cap] = dp[i-1][cap];

            if (cap - cost[i] >= 0) {
                int sol_aux = dp[i-1][cap - cost[i]] + p[i];
                dp[i][cap] = max(dp[i][cap], sol_aux);
            }
        }
    }
    return dp[n][W];
}

// Functie pentru calcului divizorilor
void get_divisors(int n, vector<int> &div) {
    for (int i = 1; i <= sqrt(n); i++) {
        if (n % i == 0) {
            if (n / i == i) {
                div.push_back(i);
            } else {
                div.push_back(i);
                div.push_back(n / i);
            }
        }
    }
    sort(div.begin(), div.end(), greater<int>());
}

// Functia care calculeaza toate costurile folosind BFS
void get_costs(int target, vector<int> &dist) {
    bool *visited = new bool[MAX_SIZE];
    for (int i = 0; i < MAX_SIZE; i++) {
        visited[i] = false;
    }

    queue<int> queue;
    int s = 1;  // incep de la 1
    visited[s] = true;  // 1 a fost vizitat
    queue.push(s);
    dist[s] = 0;  // costul lui 1 este 0

    while (!queue.empty()) {
        s = queue.front();
        queue.pop();
        if (s == target) {
            break;
        }
        // Pentru fiecare divizor al numarului curent calculez fiecare
        // divizor al lui.
        vector<int> div;
        get_divisors(s, div);
        for (auto const &el : div) {
            // Daca numarul obtinut prin adunarea numarului curent si
            // unul din divizorii lui nu a mai fost vizitat calculez
            // costul lui si il pun in coada.

            if (!visited[s + el] && (s + el) <= target) {
                visited[s + el] = true;
                dist[s + el] = dist[s] + 1;
                queue.push(s + el);
            }
            // Fac acelasi lucru si pentru s + s/el.
            if (!visited[s + el] && (s + s/el) <= target) {
                dist[s + s / el] = dist[s] + 1;
                visited[s + s/el] = true;
            }
        }
    }

    delete[] visited;
}




int main() {
    ifstream input;
    ofstream output;
    int N, K, n, c = 0;
    vector<int> cost, value, target;

    input.open("prinel.in");
    output.open("prinel.out");

    input >> N;
    input >> K;

    if (K == 0) {
        output << 0 << endl;
        return 0;
    }

    cost.push_back(-1);
    value.push_back(-1);

    vector<int> dist(MAX_SIZE, 0);
    // Calculez toate costurile pentru numere de la 1 la 10-e5
    get_costs(MAX_SIZE, dist);

    for (int i = 1; i <= N; i++) {
        input >> n;
        cost.push_back(dist[n]);
    }

    for (int i = 1; i <= N; i++) {
        input >> n;
        value.push_back(n);
    }

    output << max_points(N, K, cost, value) << endl;
    return 0;
}

