  void calculate_divisors(int num) {
    // If steps for num is different from INT_MAX, it means the steps are
    // already calculated.
    if (steps[num] != INT_MAX) {
      return;
    }
    for (int i = sqrt(num); i >= 1; i--) {
      if (num % i == 0) {
        // If i is a divisor for num, calculate the steps required for num-i
        calculate_divisors(num - i);

        // Decide wether the number of steps calculated is a more efficient
        // path than the actual one.
        steps[num] = min(steps[num], steps[num - i] + 1);

        // For if i is a divisor, num/i is a divisor for sure, so do the
        // the same for any i aside from 1, since num - num/i would be 0.
        if (i != 1) {
          calculate_divisors(num - num / i);
          steps[num] = min(steps[num], steps[num - num / i] + 1);
        }
      }
    }
  }

  int get_result() {
    vector<int> dp(k + 1);

    // Initialize steps
    steps.push_back(-1);
    for (int i = 1; i <= max_target; i++) {
      steps.push_back(INT_MAX);
    }
    steps[1] = 0;

    // Calculate the steps required for all targets
    for (int i = 0; i < n; i++) {
      calculate_divisors(targets[i].first);
    }

    // Do '1-0 backsack' problem with dynamic programming, where
    // the weights are represented by the number of steps required to
    // get to target and the price by the points awarded
    for (int i = 0; i < n; i++) {
      for (int j = k; j >= 0; j--) {
        if (j >= steps[targets[i].first])
          dp[j] = max(
            dp[j],
            dp[j - steps[targets[i].first]] + targets[i].second);
      }
    }

    return dp[k];
  }
};

