            fin.close();
        }

        int get_result() {
            int maximum = 0;

            for (int i = 1; i <= n; i++)
                if (target[i] > maximum)
                    maximum = target[i];

            vector < int > moves(maximum + 1);
            vector < pair < int, int >> pairs(n + 1);

            // precalculez numarul de operatii necesare
            // pentru a ajunge de la 1 la orice valoare din
            // intervalul [2, maximum]
            for (int i = 2; i <= maximum; i++)
                moves[i] = INT_MAX;
            for (int i = 1; i <= maximum; i++) {
                int j;
                for (j = 1; j * j < i; j++) {
                    if (i % j == 0) {
                        if (i + j <= maximum)
                            moves[i + j] = min(moves[i] + 1, moves[i + j]);
                        if (i + i / j <= maximum)
                            moves[i + i / j] = min(moves[i] + 1,
                                                   moves[i + i / j]);
                    }
                }
                if (j * j == i && i + j <= maximum)
                    moves[i + j] = min(moves[i] + 1, moves[i + j]);
            }

            // verific daca se pot obtine toate punctele
            int totalWeight = 0;
            long long totalPoints = 0;
            for (int i = 1; i <= n; i++) {
                pairs[i].first = p[i];
                pairs[i].second = moves[target[i]];
                totalWeight += moves[target[i]];
                totalPoints += p[i];
            }
            if (totalWeight <= k)
                return totalPoints;

            // agloritmul de programare dinamica
            // problema rucsacului
            vector < vector < int >> M(n + 1, vector < int > (totalWeight + 1));
            for (int i = 0; i <= n; i++) {
                for (int j = 0; j <= k; j++)
                    if (i == 0 || j == 0) {
                        M[i][j] = 0;
                    } else  {
                        if (pairs[i].second <= j)
                            M[i][j] = max(pairs[i].first
                                          + M[i - 1][j - pairs[i].second],
                                          M[i - 1][j]);
                        else
                            M[i][j] = M[i - 1][j];
                    }
            }

            return M[n][k];
        }

        void print_output(int result) {
            ofstream fout("prinel.out");
            fout << result;
            fout.close();
        }
};

