import java.io.FileWriter;
import java.io.IOException;
import java.io.Writer;
import java.util.ArrayList;
import java.util.Scanner;

public class Prinel {
	public static void main(String[] args) {
		int n, k;
		try {
			File myObj = new File("prinel.in");
			final String newLine = "\n";
			Scanner myReader = new Scanner(myObj);
			ArrayList<Integer> list = new ArrayList<Integer>();
			n = myReader.nextInt();
			k = myReader.nextInt();
			for (int i = 0; i < n; i++) {
				list.add(myReader.nextInt());
			}
			ArrayList<Integer> points = new ArrayList<>();
			for (int i = 0; i < n; i++) {
				points.add(myReader.nextInt());
			}
			//salvez in operationList numarul de operatii necesare ca sa
			//ajung la cel mai mare numar din lista data
			ArrayList<Integer> operationList = new ArrayList<Integer>();
			getBestOperations(list, operationList);
			Writer outputFile = new FileWriter("prinel.out");
			outputFile.write(getBestPoints(operationList, points, k) + newLine);
			myReader.close();
			outputFile.close();
		} catch (FileNotFoundException e) {
			System.out.println("An error occurred.");
			e.printStackTrace();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}

	//un soi de Problema Rucsacului
	private static int getBestPoints(ArrayList<Integer> operationList,
									ArrayList<Integer> points, int k) {
		ArrayList<ArrayList<Integer>> dp = new ArrayList<>();
		//Verific daca "greutatea rucsacului" este cumva mai mica sau egala cu
		//"greutatea tuturor obiectelor"
		int sumGreutati = 0;
		int sumPreturi = 0;
		for (int i = 0; i < operationList.size(); i++) {
			sumPreturi += points.get(i);
			sumGreutati += operationList.get(i);
		}
		//daca da, returnez "suma preturilor" (adica a punctelor date)
		if (sumGreutati <= k) {
			return sumPreturi;
		}
		//initializam o matrice de 0-uri
		for (int i = 0; i <= operationList.size(); i++) {
			dp.add(new ArrayList<>());
			for (int j = 0; j <= k; j++) {
				dp.get(i).add(0);
			}
		}
		//problema rucsacului
		for (int i = 1; i <= operationList.size(); i++) {
			for (int j = 0; j <= k; j++) {
				dp.get(i).set(j, dp.get(i - 1).get(j));
				if (j - operationList.get(i - 1) >= 0) {
					dp.get(i).set(j, Integer.max(dp.get(i).get(j),
							dp.get(i - 1).get(j - operationList.get(i - 1)) + points.get(i - 1)));
				}
			}
		}
		return dp.get(operationList.size() - 1).get(k);
	}

	private static void getBestOperations(ArrayList<Integer> list,
										ArrayList<Integer> operationList) {
		int max = Integer.MIN_VALUE;
		//gasim elementul maxim din vector
		for (Integer integer : list) {
			if (integer > max) {
				max = integer;
			}
		}
		//vom genera nr de operatii minime pentru fiecare element
		//de la 0 pana la max
		ArrayList<Integer> minimumOps = getMinimumOps(max);
		for (Integer integer : list) {
			//vom adauga in lista noastra de operatii minime
			//elementele din minimumOps
			operationList.add(minimumOps.get(integer));
		}
	}

	private static ArrayList<Integer> getMinimumOps(int target) {
		ArrayList<Integer> operations = new ArrayList<Integer>();
		//ideea e sa pornesc de la 2, iar cum ArrayList
		//incepe obligatoriu de la 0, am pus doua valori de 0
		//ca sa ocup acele pozitii de 0 si 1
		//plus ca pentru 1 am nevoie de 0 operatii
		operations.add(0);
		operations.add(0);
		for (int i = 2; i <= target; i++) {
			//luam un numar bun de comparat pentru gasit minimul
			operations.add(Integer.MAX_VALUE);
			//parcurgem divizorii
			for (int divizor = 1; divizor * divizor <= i; divizor++) {
				//daca este i este divizor atunci avem formula
				// operations[i]=min{operations[i], operations[i-div] +1}
				if (i % divizor == 0) {
					operations.set(i, Integer.min(operations.get(i),
							operations.get(i - divizor) + 1));
					//sa nu pun de 2 ori radical din i in cazul in care e patrat perfect
					if (divizor * divizor != i && divizor != 1) {
						//operations[i]=min{operations[i], operations[i-i/div]+1}
						operations.set(i, Integer.min(operations.get(i),
								operations.get(i - i / divizor) + 1));
					}
				}
			}
		}
		return operations;
	}
}

