/*
    Functie care intoarce minimul dintre dp[n - i],
    unde i este divizor al lui n.
*/
int minimum(unsigned int dp[], unsigned int n) {
    unsigned int min = 200000;

    for (unsigned int i = 1; i <= sqrt(n); i++) {
        if (n % i == 0) {
            // Daca divizorii sunt egali atunci ia doar unul
            if (n / i == i) {
                if (dp[n - i] < min) {
                    min = dp[n - i];
                }
            } else {
                // Altfel ii iei pe ambii
                if (dp[n - i] < min) {
                    min = dp[n - i];
                }
                if (dp[n - n/i] < min) {
                    min = dp[n - n/i];
                }
            }
        }
    }
    return min;
}

void calculate_nr_ops(element v[], unsigned int N,
                      unsigned int max_target) {
    unsigned int dp[max_target + 1];
    dp[0] = -1; dp[1] = 0; dp[2] = 1;

    /*  
        Completez vectorul dp care va contine numarul
        de operatii pt. fiecare target de la 1 la max_target.
    */

    for (unsigned int i = 3; i <= max_target; ++i) {
        dp[i] = 1 + minimum(dp, i);
    }

    for (unsigned int i = 0; i < N; ++i) {
        v[i].nr_ops = dp[v[i].target_i];
    }
}

