    ifstream inputFile;

    inputFile.open("prinel.in", ios::in);
    outputFile.open("prinel.out", ios::out);

    inputFile >> N >> K;
    element v[N];

    // Citesc primul vector (target)
    for (unsigned int i = 0; i < N; ++i) {
        inputFile >> v[i].target_i;
        if (v[i].target_i > max_target)
            max_target = v[i].target_i;
        v[i].nr_ops = 0;
    }

    // Citesc al doilea vector (p)
    for (unsigned int i = 0; i < N; ++i) {
        inputFile >> v[i].p_i;
