    // Calculez nr_ops pt. fiecare elemen.
    calculate_nr_ops(v, N, max_target);

    /*  
        Nu prea mai merge sa sortezi ca te lovesti de ceva similar
        cu problema rucsacului unde obiectele nu sunt divizibile.
        Am incercat sa sortez dupa criteriul p_i/nr_op  dar NU MERGE.
    */
    unsigned int dp[K+1];
    memset(dp, 0x00, sizeof(unsigned int) * (K+1));

    for (int i = 0; i < N; ++i) {
        for (int j = K; j >= 0; --j) {
            if (j - v[i].nr_ops >= 0) {
                unsigned int sol_aux = dp[j-v[i].nr_ops] + v[i].p_i;
                dp[j] = max2(dp[j], sol_aux);
            }
        }
    }
    outputFile << dp[K] << endl;

    inputFile.close();
    outputFile.close();
    return 0;
}

