using namespace std;
// Variabila necesara pentru memoizare, counters[i] stocheaz numarul de pasi
// necesar pentru a ajunge de la 1 la i
int counters[100001] = {-1};

int countMinOperations(int n) {
    // Instantez un vector de booleeni, setati initial pe 1, pentru a memora
    // nodurile vizitate
    vector<bool> visited(n + 1, false);
    // Instantiez o coada pentru a memora nodurile
    queue<int> coada;
    int count = 0;
    // Pun nodul 1 in coada si il vizitez
    coada.push(1);
    visited[1] = true;
    // cat timp coada nu este vida
    while (!coada.empty()) {
        // memorez lungimea cozii
        int lungime_coada = coada.size();
        while (lungime_coada--) {
            // nodul curent este primul din coada si il scot din coada
            int curent = coada.front();
            coada.pop();
            // caut divizorii lui curent
            for (int i = 1; i * i <= curent; i++) {
                // daca este divizor
                if (curent % i == 0) {
                    // daca curent+i <= n si nu este vizitat
                    if (curent + i <= n && !visited[curent + i]) {
                        // il pun in coada, vizitez, actualizez numarul de pasi
                        coada.push(curent + i);
                        visited[curent + i] = true;
                        counters[curent + i] = counters[curent] + 1;
                    }
                    // daca curent + curent / i <= n si nu este vizitat
                    if (curent + curent / i <= n &&
                            !visited[curent + curent / i]) {
                        // il pun in coada, vizitez, actualizez numarul de pasi
                        coada.push(curent + curent / i);
                        visited[curent + curent / i] = true;
                        counters[curent + curent / i] = counters[curent] + 1;
                    }
                }
            }
        }
    }
}

// Obiect ce contine punctele corespunzatoare si numarul de operatii 
// pentru a ajunge la target
struct Object {
    int puncte;
    int nr_operatii;

    explicit Object(int _puncte, int _nr_operatii)
        : puncte(_puncte), nr_operatii(_nr_operatii) {}
};

int knapSack(int W, vector<Object> lista, int n) {
    // varianta optimizata a rucsacului
    int i, j;
    // instantiez o matrice
    vector<vector<int>> matrice(n + 1, vector<int>(W + 1));

    // Parcurg si actualizez valorile
    for (i = 0; i <= n; i++)
        for (j = 0; j <= W; j++) {
            // cazul de baza
            if (i == 0 || j == 0)
                matrice[i][j] = 0;
            else 
                // folosesc obiectul i, deci trebuie sa rezerv w[i] unitati în
                // rucsac si trebuie sa ocup maxim cap - w[i] unitati inainte
                if (lista[i - 1].nr_operatii <= j)
                    matrice[i][j] = max(lista[i - 1].puncte +
                                    matrice[i - 1][j - lista[i - 1].nr_operatii],
                                matrice[i - 1][j]);
            else
                // daca nu folosesc obiectul i
                matrice[i][j] = matrice[i - 1][j];
        }
    return matrice[n][W];
}

bool compare(Object obj1, Object obj2) {
    return 1.0 * obj1.puncte / obj1.nr_operatii >
                1.0 * obj2.puncte / obj2.nr_operatii;
}

int main() {
    ifstream fin("prinel.in");
    ofstream fout("prinel.out");
    int n, k, i, aux, counter = 0, puncte = 0;
    int target[10001];
    vector<Object> lista;
    // Citesc datele de intrare
    fin >> n >> k;
    for (i = 0; i < n; i++)
        fin >> target[i];
    // Setez counters[i] pe -1 si counters[i] pe 0
    for (i = 0; i < 100001; i++)
        counters[i] = -1;
    counters[1] = 0;
    // Citesc si actualizez lista de obiecte
    for (i = 0; i < n; i++) {
        fin >> aux;
        if (counters[target[i]] == -1) {
            countMinOperations(target[i]);
            lista.push_back(Object(aux, counters[target[i]]));
        } else {
            lista.push_back(Object(aux, counters[target[i]]));
        }
    }
    // Calculez numarul total de operatii si punctele ce pot fi obitnute
    for (i = 0; i < n; i++) {
        counter = counter + lista[i].nr_operatii;
        puncte = puncte + lista[i].puncte;
    }
    // Verific daca numarul total de operatii este mai mic decat cel permis
    // Daca da, obtin numarul maxim de puncte, altfel folosesc problema
    // rucsacului pentru a afla numarul de puncte obtinute
    if (counter < k)
        fout << puncte;
    else
        fout << knapSack(k, lista, n);

    fin.close();
    fout.close();
    return 0;
}

