        vector< vector<int> > dp(n + 1, vector<int>(W + 1, 0));

        int maxi = 0;

        // cazul de bază
        for (int cap = 0; cap <= W; ++cap) {
            dp[0][cap] = 0;
        }

        // cazul general
        for (int i = 1; i <= n; ++i) {
            for (int cap = 0; cap <= W; ++cap) {
                // nu folosesc obiectul i => e soluția de la pasul i - 1
                dp[i][cap] = dp[i-1][cap];

                // folosesc obiectul i, deci trebuie să rezerv
                // w[i] unități în rucsac
                // înseamnă ca înainte trebuie să ocup maxim cap - w[i] unități
                if (cap - w[i] >= 0) {
                    int sol_aux = dp[i-1][cap - w[i]] + p[i];

                    dp[i][cap] = MAX(dp[i][cap], sol_aux);
                }
            }
        }
        return dp[n][W];
    }

    int get_result() {
        int dp[NMAX + NMAX];
        memset(dp, 1, sizeof(dp));
        vector<int> nr_steps(NMAX + 1);

        dp[1] = 0;
        for (int i = 1; i <= NMAX; ++i) {
            for (int d = 1; d * d <= i; ++d) {
                if (i % d == 0) {
                    if (i + d <= NMAX) {
                        dp[i + d] = MIN(dp[i + d], dp[i] + 1);
                    }
                    if (i + i / d <= NMAX) {
                        dp[i + i / d] = MIN(dp[i + i / d], dp[i] + 1);
                    }
                }
            }
        }

        for (int i = 1; i <= n; ++i) {
            nr_steps[i] = dp[target[i]];
        }

        return rucsac(n, k, nr_steps, pts);
    }

    void print_output(int result) {
        ofstream fout("prinel.out");
        fout << result;
        fout.close();
    }
};

