using namespace std;

vector<int> getDivizors(int x) {
    vector<int> divizors;
    for ( int i = 1; i*i <= x; i++ )
        if ( x % i == 0 ) {
            divizors.push_back(x/i);
            divizors.push_back(i);
        }
    return divizors;
}

int knapsack(vector<int> &weights, vector<int> &costs, int weight) {
    vector<int> previous(weight + 1, 0);
    vector<int> next(weight + 1, 0);
    for ( unsigned int i = 1; i <= weights.size(); i++ ) {
        for ( int j = 1; j <= weight; j++ )
            if ( j-weights[i-1] >= 0 )
                next[j] = max(previous[j],
							  costs[i-1] + previous[j-weights[i-1]]);
            else
                next[j] = previous[j];
        previous = next;
    }
    return next[weight];
}


int main() {
    ifstream in("prinel.in");
    ofstream out("prinel.out");
    int n, k, max_val;
    vector<int> v, points;


    in >> n >> k;
    for ( int i = 0; i < n; i++ ) {
        int x; in >> x;
        v.push_back(x);
        max_val = max(max_val, x);
    }
    for ( int i = 0; i < n; i++ ) {
        int x; in >> x;
        points.push_back(x);
    }

    vector<int> d(max_val + 1, 10000000);
    d[0] = 0;
    d[1] = 0;
    for ( int i = 1; i <= max_val; i++ ) {
        auto divizors = getDivizors(i);
        for ( auto divizor : divizors )
            if ( i + divizor <= max_val )
                d[i + divizor] = min(d[i + divizor], d[i] + 1);
    }

    int partialSolution = 0;
    vector<int> weights, costs;
    for ( unsigned int i = 0; i < v.size(); i++ )
        if ( v[i] == 1 ) {
            partialSolution += points[i];
		} else if ( d[v[i]] <= k ) {
            weights.push_back(d[v[i]]);
            costs.push_back(points[i]);
        }

    out << partialSolution + knapsack(weights, costs, k);

    in.close();
    out.close();

    return 0;
}

