        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;

public class Walsh {
	static class Task {
		int n, k;

		private void getSolution() {
			try {
				BufferedReader reader = new BufferedReader(new FileReader("walsh.in"));
				PrintWriter writer = new PrintWriter(new File("walsh.out"));

				String[] line;
				line = reader.readLine().split(" ");
				n = Integer.parseInt(line[0]);
				k = Integer.parseInt(line[1]);

				for (int i = 0; i < k; i++) {
					line = reader.readLine().split(" ");
					int x = Integer.parseInt(line[0]);
					int y = Integer.parseInt(line[1]);
					int result = solve(x, y);
					writer.printf("%d\n", result);
				}

				writer.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		// Abodare Divide et Impera
		// Se imparte recursiv tabelul in 4 cadrane pana cand dimensiunea tabelei
		// devine unitara si se construieste solutie pe revenire din recursivitate
		private Boolean helperWalsh(int n, int x, int y, int leftx, int lefty) {
			if (n == 1) {
				if (x != leftx && y != lefty) {
					return true;  // se afla in cadranul IV
				} else {
					return false;
				}
			} else {
				Boolean res = false;
				int rightx = leftx + n - 1;
				int righty = lefty + n - 1;
				int midx = (leftx + rightx) / 2;
				int midy = (lefty + righty) / 2;

				if (x >= leftx && x <= midx && y >= lefty && y <= midy) {        // cadran I
					res = helperWalsh(n >> 1, x, y, leftx, lefty);
				} else if (x >= leftx && x <= midx && y > midy && y <= righty) { // cadran II
					res = helperWalsh(n >> 1, x, y, leftx, midy + 1);
				} else if (x > midx && x <= rightx && y >= lefty && y <= midy) { // cadran III
					res = helperWalsh(n >> 1, x, y, midx + 1, lefty);
				} else if (x > midx && x <= rightx && y > midy && y <= righty) { // cadran IV
					res = !helperWalsh(n >> 1, x, y, midx + 1, midy + 1);
				}

				return res;
			}
		}

		private int solve(int x, int y) {
			if (helperWalsh(n, x, y, 1, 1)) {
				return 1;
			}

			return 0;
		}
	}

	public static void main(String[] args) {
		new Task().getSolution();
	}
}
