		if (size == 1) {

			// set output stream
			System.setOut(o);
			System.out.println(acc);
			return;
		}

		if (i < mid && j < mid) {
			// is in 1st square
			getElem(i, j, size / 2, acc);
		} else if (i < mid && j >= mid) {
			// is in 2nd square
			getElem(i, j - mid, size / 2, acc);
		} else if (i >= mid && j < mid) {
			// is in 3rd square
			getElem(i - mid, j, size / 2, acc);
		} else if (i >= mid && j >= mid) {
			// is in 4th square
			getElem(i - mid, j - mid, size / 2, negate(acc));
		}

	}

	private static int negate(int x) {
		if (x == 1) {
			return 0;
		} else {
