using namespace std;

int computeValue(unsigned long long int linie,
                 unsigned long long int coloana,
                 int n) {
    --n;
    unsigned long long int linieNV = 1, coloanaNV = 1;
    unsigned long long int step = pow(2, n);
    bool ok = true;
    int value;

    while (n >= 1) {
        unsigned long long linie1 = linieNV + step;
        unsigned long long coloana1 = coloanaNV + step;
        if (linie < linie1 && coloana < coloana1) {
            // cadran Nord-Vest
        } else if (linie >= linie1 && coloana < coloana1) {
            // cadran Sud-Vest
            linieNV = linie1;
        } else if (linie < linie1 && coloana >= coloana1) {
            // cadran Nord-Est
            coloanaNV = coloana1;
        } else if (linie >= linie1 && coloana >= coloana1) {
            // cadran Sud-Est
            linieNV = linie1;
            coloanaNV = coloana1;
            if (ok == true)
                ok = false;
            else
                ok = true;
        }

        step /= 2;
        --n;
    }

    /*
        Tiparul este :
        -----
        0 0
        0 1
        -----
    */
    if (ok == true) {
        if (linieNV == linie && coloanaNV == coloana) {
            value = 0;
        }
        if (linieNV + 1 == linie && coloanaNV == coloana) {
            value = 0;
        }
        if (linieNV == linie && coloanaNV + 1 == coloana) {
            value = 0;
        }
        if (linieNV + 1 == linie && coloanaNV + 1 == coloana) {
            value = 1;
        }
    }

    /*
        Tiparul este :
        -----
        1 1
        1 0
        -----
    */
    if (ok == false) {
        if (linieNV == linie && coloanaNV == coloana) {
            value = 1;
        }
        if (linieNV + 1 == linie && coloanaNV == coloana) {
            value = 1;
        }
        if (linieNV == linie && coloanaNV + 1 == coloana) {
            value = 1;
        }
        if (linieNV + 1 == linie && coloanaNV + 1 == coloana) {
           value = 0;
        }
    }

    return value;
}

int main() {
    ofstream outputFile;
    ifstream inputFile;
    unsigned long long int N, linie, coloana;
    unsigned long long int c_N;
    unsigned int K, n = 0;

    inputFile.open("walsh.in", ios::in);
    outputFile.open("walsh.out", ios::out);

    inputFile >> N >> K;

    c_N = N;
    while (c_N != 1) {
        c_N >>= 1;
        ++n;
    }

    for (int i = 0; i < K; ++i) {
        inputFile >> linie >> coloana;
        outputFile << computeValue(linie, coloana, n) << endl;
    }

    inputFile.close();
    outputFile.close();

    return 0;
}

