class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    int n, k, x, y;
    vector<Pair> pairs;

    void read_input() {
        ifstream fin("walsh.in");
        fin >> n >> k;
        for (int i = 0; i < k; i++) {
            Pair p;
            fin >> p.x >> p.y;
            pairs.push_back(p);
        }
        fin.close();
    }

    int get_cadran(int middle, int &x, int &y) {
        int c3 = x > middle;
        int c2 = y > middle;

        x-= c3 ? middle : 0;
        y-= c2 ? middle : 0;

        return (c2 && c3) ? 4 : c3 ? 3 : c2 ? 2 : 1;
    }

    int get_value(int n, int x, int y) {
        if (n == 1)
            return 0;

        n >>= 1;
        if (get_cadran(n, x, y) == 4)
            return 1 ^ get_value(n, x, y);

        return get_value(n, x, y);
    }

    vector<int> get_result() {
        vector<int> sol;
        for (int i = 0; i < k; i++)
            sol.push_back(get_value(n, pairs[i].x, pairs[i].y));

        return sol;
    }

    void print_output(vector<int> sol) {
        ofstream fout("walsh.out");
        for (int i = 0; i < k; i++)
            fout << sol[i] <<'\n';
        fout.close();
    }
};

