        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.StringTokenizer;

public class Walsh {

	static class Pair {
		public int x;
		public int y;

		public Pair() {
			this.x = 0;
			this.y = 0;
		}
	};

	static class Task {

		public final String input = "walsh.in";
		public final String output = "walsh.out";

		int n, k;
		Pair[] pairs;

		public void solve() {
			readInput();
			writeOutput(getResults(n, k, pairs));
		}

		private void readInput() {
			try (BufferedReader br = new BufferedReader(new FileReader(input))) {
				StringTokenizer st = new StringTokenizer(br.readLine()," ");
				n = Integer.parseInt(st.nextToken());
				k = Integer.parseInt(st.nextToken());
				pairs = new Pair[k];
				for (int i = 0; i < k; i++) {
					pairs[i] = new Pair();
					st = new StringTokenizer(br.readLine()," ");
					pairs[i].x = Integer.parseInt(st.nextToken());
					pairs[i].y = Integer.parseInt(st.nextToken());
				}
			} catch (Exception e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int[] res) {
			try {
				PrintWriter pw = new PrintWriter(new File(output));
				for (int i = 0; i < k; i++) {
					pw.printf("%d\n", res[i]);
				}
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private int[] getResults(int n, int k, Pair[] pairs) {
			int[] res = new int[k];

			for (int i = 0; i < k; i++) {
				res[i] = getResult(n, pairs[i].x, pairs[i].y);
			}

			return res;
		}

		private int getResult(int n, int x, int y) {
			if (n == 1 || x <= 1 || y <= 1) {
				return 0;
			}

			//daca n == 2
			if (n == 2) {
				if (x == 2 && y == 2) {
					return 1;
				} else { 
					return 0; 
				}
			} 

			int mid = n / 2;
			// Verificam cadranul I x <= n/2, y <= n/2
			if ((x <= mid) && (y <= mid)) {
				return getResult(mid, x, y);
			}
			// Verificam cadranul II x <= n/2, y > n/2
			if ((x <= mid) && (y > mid)) {
				return getResult(n, x, y - mid);
			}
			// Verificam cadranul III x > n/2, y <= n/2
			if ((x > mid) && (y <= mid)) {
				return getResult(n, x - mid, y);
			}

			// Verificam cadranul IV x > n/2, y > n/2
			if ((x > mid) && (y > mid)) {
				return negate(getResult(n, x - mid, y - mid));
			}

			return 0;
		}

		private int negate(int x) {
			return x == 0 ? 1 : 0;
		}
	};

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		new Task().solve();
	}
}

