int findQuadrant(int tlx, int tly, int drx, int dry, int x, int y) {
	// Dreapta Sus
	if (x <= tlx - 1 + (drx - tlx + 1) / 2 && y > tly - 1 + (dry - tly + 1) / 2) {
		return 1;
	}
	// Stanga Sus
	if (x <= tlx - 1 + (drx - tlx + 1) / 2 &&
			y <= tly - 1 + (dry - tly + 1) / 2) {
		return 2;
	}
	// Stanga Jos
	if (x > tlx - 1 + (drx - tlx + 1) / 2 && y <= tly - 1 + (dry - tly + 1) / 2) {
		return 3;
	}
	// Dreapta Jos
	if (x > tlx - 1 + (drx - tlx + 1) / 2 && y > tly - 1 + (dry - tly + 1) / 2) {
		return 4;
	}
	return -1;  // Error out of bounds, neimplementata
}

void findSol(int N, int x, int y) {
	int tlx, tly, drx, dry, sol;
	tlx = 1;
	tly = 1;
	drx = N;
	dry = N;
	sol = -1;
	while (tlx != drx) {
		// cautam in care quadrant se afla (x.y)
		switch (findQuadrant(tlx, tly, drx, dry, x, y)) {
		case 1:
			drx = drx - (drx - tlx + 1) / 2;
			tly = dry - (dry - tly + 1) / 2 + 1;
			break;
		case 2:
			drx = drx - (drx - tlx + 1) / 2;
			dry = dry - (dry - tly + 1) / 2;
			break;
		case 3:
			tlx = drx - (drx - tlx + 1) / 2 + 1;
			dry = dry - (dry - tly + 1) / 2;
			break;
		case 4:
			tlx = drx - (drx - tlx + 1) / 2 + 1;
			tly = dry - (dry - tly + 1) / 2 + 1;
			sol = -sol;
			break;
		default:
			return;
			break;
		}
	}

	if (sol == -1) {
		fout << 0 << endl;
		return;
	}
	fout << 1 << endl;
}

int main() {
	int N, K, x, y;
	fin >> N >> K;

	int sol = 0;
	for (int i = 0; i < K; i++) {
		fin >> x >> y;
		findSol(N, x, y);
	}

	return 0;
}

