        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Scanner;

public class Walsh {
	int n, k;
	ArrayList<Integer> answers = new ArrayList<>();
	private void readInput() {
		try {
			Scanner sc = new Scanner(new File("walsh.in"));
			n = sc.nextInt();
			k = sc.nextInt();
			for (int i = 0; i < k; i++) {
				int x = sc.nextInt();
				int y = sc.nextInt();
				int count = walsh(n, x, y, true);
			}
			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(ArrayList<Integer> n_ai_tu_treaba) {
		try {
			PrintWriter pw = new PrintWriter(new File("walsh.out"));
			for (int i = 0; i < n_ai_tu_treaba.size(); i++) {
				pw.printf("%d\n", n_ai_tu_treaba.get(i));
			}
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private int walsh(int dim, int x, int y, boolean bool) {
		if (dim == 1) {
			if (!bool) {
				answers.add(1);
				return 1;
			} else {
				answers.add(0);
				return 0;
			}
		}
		//x,y are in down right(~Wn)
		if (x > dim / 2 && y > dim / 2) {
			bool = !bool;
			walsh(dim / 2, x - dim / 2, y - dim / 2, bool);
		//x,y are in Wn(down left)
		} else if (x > dim / 2 && y <= dim / 2) {
			walsh(dim / 2, x - dim / 2, y, bool);
		//x,y are in Wn(top right)
		} else if (x <= dim / 2 && y > dim / 2) {
			walsh(dim / 2, x , y - dim / 2, bool);
		//x,y are in Wn(top left)
		} else {
			walsh(dim / 2, x , y, bool);
		}
		return -1;
	}

	public static void main(String[] args) {
		Walsh walsh = new Walsh();
		walsh.readInput();
		walsh.writeOutput(walsh.answers);
	}
}

