void concat_to_array(vector<string>& dest, vector<string> source) {
	bool duplicate;
	for (auto mail : source) {
		// Search for duplicate
		duplicate = false;
		for (auto dest_mail : dest) {
			if (mail.compare(dest_mail) == 0) {
				duplicate = true;
				break;
			}
		}

		if (!duplicate)
			dest.push_back(mail);
	}
}

void solver() {
