		Person new_person, *old_person;
		vector <string> temp_mails;
		in >> new_person.name >> no_mails;

		// Reading mails
		int person_index = NOT_FOUND;
		for (int j = 0; j < no_mails; ++j) {
			string mail;
			in >> mail;
			temp_mails.push_back(mail);

			// Try to find if a new_person exists for those mails
			if (person_index == NOT_FOUND) {
				person_index = find_new_person(mail);
			}
		}

		// Check if new_person already exists
		if (person_index != NOT_FOUND) {
			old_person = &persons[person_index];
			concat_to_array(old_person->mails, temp_mails);

			// Check which name is good lexicograph
			if (new_person.name.compare(old_person->name) < 0)
				old_person->name = new_person.name;
		} else {
			// Create a new new_person
			new_person.mails = temp_mails;
			persons.push_back(new_person);
		}
	}

	sort(persons.begin(), persons.end(), cmp_persons);

