        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Vector;

public class Adrese {
	static HashMap<String, Vector<Person>> links = new HashMap<String, Vector<Person>>();
	static HashSet<Person> not_visited = new HashSet<Person>();
	static List<Person> not_vis;

	static String name;
	static HashSet<String> emails;

	static ArrayList<Person> rez = new ArrayList<>();

	private void writeOutputRez(ArrayList<Person> rez) throws IOException {
		PrintWriter pw = new PrintWriter(new File("adrese.out"));
		pw.printf("%d\n", rez.size());
		for (Person p : rez) {
			pw.printf("%s\n", p.name + " " + p.emails.size());
			for (String str : p.emails) {
				pw.printf("%s\n", str);
			}
		}
		pw.close();
	}

	public void dfs(Person person) {
		for (Person p : person.adj) {
			if (not_vis.contains(p)) {
				//if this person hasn't been visited yet
				//update name
				if (name.compareTo(p.name) > 0) {
					name = p.name;
				}
				//add all the emails to the set
				emails.addAll(p.emails);
				//mark it as visited
				not_vis.remove(p);
				//call DFS for this person
				dfs(p);
			}
		}
	}

	public static void main(String[] args) {
		try {
			Adrese a = new Adrese();
			MyScanner sc = new MyScanner("adrese.in");
			int N = sc.nextInt();
			for (int i = 0; i < N; i++) {
				Person this_p = new Person(sc.next());
				int no_of_emails = sc.nextInt();
				for (int j = 0; j < no_of_emails; j++) {
					String new_mail = sc.next();
					this_p.emails.add(new_mail);
					Vector<Person> same_people = links.get(new_mail);
					if (same_people == null) {
						//nu am entry in hashmap
						Vector<Person> new_same_people = new Vector<Person>();
						new_same_people.add(this_p);
						links.put(new_mail, new_same_people);
					} else {
						//am entry in hashmap
						for (Person pers : same_people) {
							//imi creez lista de adiacenta
							pers.adj.add(this_p);
							this_p.adj.add(pers);
						}
						same_people.add(this_p);
					}
				}
				not_visited.add(this_p);
			}

			//start DFS
			not_vis = new ArrayList<Person>(not_visited);

			while (!not_vis.isEmpty()) {
				//get the current person
				Person pers = not_vis.get(0);
				//init emails and name for the current person
				emails = new HashSet<String>();
				emails.addAll(pers.emails);
				name = pers.name;
				//remove it form the "not visited" list
				not_vis.remove(pers);
				//begin dfs with start node pers;
				a.dfs(pers);
				//at the end print result
				List<String> sorted_emails = new ArrayList<>(emails);
				Collections.sort(sorted_emails);
				Person real_person = new Person(name);
				real_person.emails.addAll(sorted_emails);
				rez.add(real_person);
			}
			//at the end, print result
			Collections.sort(rez);
			a.writeOutputRez(rez);
		} catch (Exception e) {
			e.printStackTrace();
		}
	}
}

class Person implements Comparable<Person> {
	String name;
	Vector<String> emails;
	Vector<Person> adj;

	public Person() {
		emails = new Vector<String>();
		adj = new Vector<Person>();
	}

	public Person(String name) {
		this.name = name;
		emails = new Vector<String>();
		adj = new Vector<Person>();
	}

	public String toString() {
		String s = "" + "(" + name + ")" + emails;
		s = s + "{";
		for (Person p : adj) {
			s = s + " " + p.name;
		}
		s = s + " }";
		return s;
	}

	@Override
	public int compareTo(Person person) {
		if (person.emails.size() == emails.size()) {
			return name.compareTo(person.name);
		} else {
			return emails.size() - person.emails.size();
		}
	}
}
