        #include <bits/stdc++.h>
using namespace std;

struct Person {
    string name;
    set<string> emails;
};

bool person_compare(Person a, Person b) {
    if (a.emails.size() == b.emails.size()) {
        return a.name < b.name;
    }
    return a.emails.size() < b.emails.size();
}

class Task {
 public:
    void solve() {
        read_input();
        set<Person, decltype(person_compare)*> sol(person_compare);
        get_result(sol);
        print_output(sol);
    }

 private:
    int n;
    vector<Person> persons;
    unordered_map<int, vector<int>> adj;


    void read_input() {
        ifstream fin("adrese.in");
        fin >> n;
        unordered_map <string, int> emails;
        adj.rehash(n);
        for (int i = 0, k; i < n; i++) {
            Person newPerson;
            fin >> newPerson.name >> k;
            for (int j = 0; j < k; j++) {
                string newEmail;
                fin >> newEmail;
                // Adauagam email-urile la noua persoana
                newPerson.emails.emplace(newEmail);
                // Cautam daca a mai fost introdus acest email
                auto email = emails.find(newEmail);
                if (email != emails.end()) {
                    // Adaugam legatura intre cele doua persoane
                    adj[email->second].push_back(i);
                    adj[i].push_back(email->second);
                    emails[newEmail] = i;
                } else {
                    // Daca nu a mai fost introdus il introducem
                    emails.emplace(newEmail, i);
                }
            }
            // Adaugam persoana in vector
            persons.push_back(newPerson);
        }
        fin.close();
    }

    void check_peers(Person& solPers, vector<bool>& visited, int i) {
        Person person = persons[i];
        // Updatam numele cu cel mai mic lexicografic
        solPers.name = min(person.name, solPers.name);
        // Adaugam email-urile la persoana solutie
        for (auto email : person.emails) {
            solPers.emails.emplace(email);
        }
        // Parcurgem legaturile persoanei pentru a o adauga
        for (auto index : adj[i]) {
            // Verificam daca persoana a fost vizitata
            if (visited[index] == true) {
                continue;
            }
            visited[index] = true;
            check_peers(solPers, visited, index);
        }
    }

    void get_result(set<Person, decltype(person_compare)*>& sol) {
        vector<bool> visited(n, false);
        // Parcurgem lista de persoane
        for (int i = 0; i < n; i++) {
            // Verificam daca au fost vizitati
            if (visited[i]) {
                continue;
            }
            // Ii setam ca vizitati
            visited[i] = true;
            // Adaugam noua persoana
            Person solPers;
            solPers.name = persons[i].name;
