        #include <bits/stdc++.h>

using namespace std;

#define NMAX 1005

ifstream fin("adrese.in");
ofstream fout("adrese.out");

struct Comp {
    string name;
    vector<string> emails;
};
vector<Comp> components;

/**
 * adj[i] <- people with whom person(i) 
 *           has at least one address in common with
 */
vector<int> adj[NMAX];

/**
 * addr[i] <- emails_person(i)
 */
vector<string> addr[NMAX];

/**
 * id[i] = person_name(i)
 */
string id[NMAX];

int vis[NMAX];

/**
 * mails[email] = id
 *   -- id - index of one person that has address <email>
 */
unordered_map<string, int> mails;

void add_emails(Comp& curr, int ind) {
    for (auto m : addr[ind]) {
        curr.emails.push_back(m);
    }
}

void dfs(int node, Comp& curr) {
    vis[node] = 1;

    for (auto neigh : adj[node]) {
        if (!vis[neigh]) {
            if (curr.name > id[neigh]) {
                curr.name = id[neigh];
            }

            add_emails(curr, neigh);

            dfs(neigh, curr);
        }
    }
}

int main() {
    int N;
    int K, i, j;
    string s;
    string a;

    fin >> N;

    for (i = 1; i <= N; ++i) {
        fin >> s >> K;

        // i-th person
        //  --> id == i
        id[i] = s;

        for (j = 1; j <= K; ++j) {
            fin >> a;

            if (mails.find(a) != mails.end()) {
                int ind = mails[a];

                adj[i].push_back(ind);
                adj[ind].push_back(i);
            } else {
                addr[i].push_back(a);
                mails[a] = i;
            }
        }
    }

    for (i = 1; i <= N; ++i) {
        if (!vis[i]) {
            Comp new_comp;

            new_comp.name = id[i];
            add_emails(new_comp, i);

            dfs(i, new_comp);

            components.push_back(new_comp);
        }
    }

    /**
     * sort the components accordingly
     */
    sort(components.begin(), components.end(),
            [&](const Comp a, const Comp b) {
                if (a.emails.size() == b.emails.size()) {
                    return a.name < b.name;
                }

                return a.emails.size() < b.emails.size();
            });

    fout << components.size() << "\n";
    for (auto c : components) {
        fout << c.name << " " << c.emails.size() << "\n";

        sort(c.emails.begin(), c.emails.end());

        for (auto m : c.emails) {
            fout << m << "\n";
        }
    }

    return 0;
}

