        import java.io.BufferedReader;
import java.io.File;
import java.io.FileInputStream;
import java.io.FileReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.Comparator;
import java.util.HashSet;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.StringTokenizer;

public class Adrese {

	static class Task {
		public final String inputfile = "adrese.in";
		public final String outputfile = "adrese.out";

		int n;
		ArrayList<Person> people = new ArrayList<>();

		class MyScanner {
			BufferedReader br;
			StringTokenizer st;

			public MyScanner() {
				try {
					br = new BufferedReader(new InputStreamReader(
						new FileInputStream(inputfile)));
				} catch (IOException e) {
					throw new RuntimeException(e);
				}
			}

			String next() {
				while (st == null || !st.hasMoreElements()) {
					try {
						st = new StringTokenizer(br.readLine());
					} catch (IOException e) {
						e.printStackTrace();
					}
				}
				return st.nextToken();
			}

			int nextInt() {
				return Integer.parseInt(next());
			}

			long nextLong() {
				return Long.parseLong(next());
			}

			double nextDouble() {
				return Double.parseDouble(next());
			}

			String nextLine() {
				String str = "";
				try {
					str = br.readLine();
				} catch (IOException e) {
					e.printStackTrace();
				}
				return str;
			}
		}
		// Metoda care cauta in lista de persoane o persoana cu acelasi email cu
		// persoana de la indicele dat ca parametru
		public static Person containsEmail(int index, ArrayList<Person> people) {
			for (int i = 0; i < people.size(); i++) {
				if (i == index) {
					continue;
				}
				for (String email : people.get(index).emails) {
					if (people.get(i).emails.contains(email) == true) {
						return people.get(i);
					}
				}
			}
			return null;
		}
		// Clasa folosita pentru a retine presoanele citite de la tastatura
		public class Person implements Comparable<Person> {
			String name;
			int nrEmails;
			HashSet<String> emails;

			public Person(String name, int nrEmails, HashSet<String> emails) {
				this.name = name;
				this.nrEmails = nrEmails;
				this.emails = emails;
			}
			// metoda de comparare, se compara dupa numarul de emailui si apoi
			// dupa nume
			public int compareTo(Person person) {
				if (this.nrEmails - person.nrEmails == 0) {
					return this.name.compareTo(person.name);
				}
				return this.nrEmails - person.nrEmails;

			}
		}

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			MyScanner msc = new MyScanner();
			n = msc.nextInt();
			String name = new String();
			int nrEmails;
			for (int i = 1; i <= n; i++) {
				String[] temp = msc.nextLine().split(" ");
				name = temp[0];
				nrEmails = Integer.parseInt(temp[1]);
				// stochez emailurile intr-un hashset pentru a evita duplicate
				HashSet<String> emails = new HashSet<>();
				for (int j = 1; j <= nrEmails; j++) {
					emails.add(msc.nextLine());
				}
				// adaug persoana abia citita in lista de persoane
				people.add(new Person(name, nrEmails, emails));
			}
		}

		private void writeOutput(int result) {
			try {
				PrintWriter pw = new PrintWriter(new File(outputfile));
				pw.printf("%d\n", result);
				for (int i = 0; i < result; i++) {
					ArrayList<String> sorted = new ArrayList<String>(people.get(i).emails);
					// sortez emailurile lexicografic
					Collections.sort(sorted);
					pw.printf("%s %d\n", people.get(i).name, people.get(i).nrEmails);
					for (String curr : sorted) {
						pw.printf("%s\n", curr);
					}
				}
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private int getResult() {
			Person p;
			// parcurg lista de persoane si caut emailuri duplicate intre persoane
			for (int i = 0; i < people.size(); i++) {
				if (Task.containsEmail(i, people) != null) {
					p = Task.containsEmail(i, people);
					// daca se gaseste un duplicat, fac operatiile necesare
					if (people.get(i).name.compareTo(p.name) > 0) {
						people.get(i).name = p.name;
					}
					people.get(i).emails.addAll(p.emails);
					people.get(i).nrEmails = people.get(i).emails.size();
					people.remove(p);
					i--;
				}
			}
			// sortez persoanele dupa metoda compareTo din clasa Person
			Collections.sort(people);
			return people.size();
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

