	ifstream fin("adrese.in");
	fin >> M;
	for (int i = 0; i < M; i++) {
		struct person pers = person();
		fin >> pers.name >> T;
		for (int j = 0; j < T; j++) {
			fin >> email;
				pers.emails.push_back(email);
		}
		sort(pers.emails.begin(), pers.emails.end());
		users.push_back(pers);
	}
	fin.close();
}

/*Function which finds duplicate emails, namely emails which are found
both in the vector of emails and in the vector of emails of any user
and returns the indexes of users where duplicate emails ere found*/
vector<int> find_duplicates(size_t idx, vector<person> users,
										vector<string> emails) {
	vector<int> duplicate;
	size_t i = idx + 1;

	/*Traverses only users after idx because the previous one were
	already traversed and merged if there were duplicates*/
	while (i < users.size()) {
		size_t j = 0, c = 0;
		while (c < users[i].emails.size() && j < emails.size()) {
			if (emails[j] >= users[i].emails[c]) {
					if (emails[j] == users[i].emails[c]) {
						duplicate.push_back(i);
						break;
					}
					c++;
			} else {
					j++;
			}
		}
		i++;
	}

	return duplicate;
}

/*Function which removes duplicates by merging the emails of
the current users with the emails of the users found which at least
one similar email to the emails of the current user and removing
the duplicate users from the vector of users*/
void remove_duplicates(vector<person> &users) {
	size_t i = 0;
	/*At first the vector of emails is equal to the emails
	of the first user*/
	vector<string> emails = users[0].emails;

	while (i < users.size()) {
		vector<int> duplicate = find_duplicates(i, users, emails);
		emails.clear();

		/*If duplicates were found, the emails of the duplicate users
		are added into the vector of emails, so that the next time 
		find_duplicate will be called on these emails and the duplicate
		users are removed*/
		if (!duplicate.empty()) {
			for (size_t j = 0; j < duplicate.size(); j++) {
				if (users[i].name > users[duplicate[j]].name) {
					users[i].name = users[duplicate[j]].name;
				}
				emails.insert(emails.end(), users[duplicate[j]].emails.begin(),
											users[duplicate[j]].emails.end());
			}
			sort(emails.begin(), emails.end());

			/*Duplicates are erased*/
			for(size_t j = 0; j < duplicate.size(); j++) {
				users.erase(users.begin() + duplicate[j] - j);
			}

			/*The other emails are added to the user number i*/
			users[i].emails.insert(users[i].emails.end(),
						emails.begin(), emails.end());
		} else {
			i++;
			/*Emails will be equal to the emails of the next user*/
			if(i < users.size())
				emails = users[i].emails;
		}
	}
}

