        #include <bits/stdc++.h>

using namespace std;

vector<string> bfs(string &root,
	unordered_map<string, vector<string>> &graph,
	unordered_set<string> &visited) {
	queue<string> q;

	// all nodes covered
	vector<string> sol;

	q.push(root);

	while(!q.empty()) {
		string curr;

		curr = q.front();
		q.pop();

		// already visited
		if (visited.find(curr) != visited.end()) {
			continue;
		}

		// mark node visited
		visited.insert(curr);
		sol.push_back(curr);

		for (int i = 0; i < graph[curr].size(); ++i) {
			q.push(graph[curr][i]);
		}
	}

	sort(sol.begin(), sol.end());

	return sol;
}

inline bool solution_sort(const pair<string, vector<string>> &p1,
	const pair<string, vector<string>> &p2) {
	return (p1.second.size() == p2.second.size()) ?
		(p1.first < p2.first) : p1.second.size() < p2.second.size();
}

void solve(vector<pair<string, string>> &users,
	unordered_map<string, vector<string>> &graph) {
	ofstream out("adrese.out");

	unordered_set<string> visited;
	vector<pair<string, vector<string>>> solution;

	for (auto &e : users) {
		vector<string> v;

		v = bfs(e.second, graph, visited);

		if (v.size() != 0) {
			solution.push_back(make_pair(e.first, v));
		}
	}

	sort(solution.begin(), solution.end(), solution_sort);

	out << solution.size() << endl;

	for (int i = 0; i < solution.size(); ++i) {
		out << solution[i].first << " ";
		out << solution[i].second.size() << endl;

		for (int j = 0; j < solution[i].second.size(); ++j) {
			out << solution[i].second[j] << endl;
		}
	}

	out.close();
}

inline bool users_sort(const pair<string, string> &p1,
	const pair<string, string> &p2) {
	return p1.first < p2.first;
}

int main() {
	ifstream in("adrese.in");

	int n;
	in >> n;

	// map user-name to root node (first email)
	vector<pair<string, string>> users;

	unordered_map<string, vector<string>> graph;

	for (int i = 0; i < n; ++i) {
		string name;
		string first_email;
		int t;

		in >> name >> t;

		in >> first_email;

		users.push_back(make_pair(name, first_email));

		for (int j = 1; j < t; ++j) {
			string email;

			in >> email;

			graph[first_email].push_back(email);
			graph[email].push_back(first_email);
		}
	}

	in.close();

	sort(users.begin(), users.end(), users_sort);

	solve(users, graph);

	return 0;
}

