public class Adrese {

	public class Person{
		String name;
		int num_mails;
		List<String> mails_list = new ArrayList<String>();
		Set<String> mails_set = new HashSet<String>();

		Person(String name, int num_mails)
		{
			this.name = name;
			this.num_mails = num_mails;
		}

		public void add_mail(String mail){
			this.mails_list.add(new String(mail));
			this.mails_set.add(new String(mail));
		}
	}

	// Comparator for 2 persons
	public class SortPerson implements Comparator<Person>
	{
		@Override
		public int compare(Person o1, Person o2) {
			if(o1.mails_list.size() == o2.mails_list.size())
				return o1.name.compareTo(o2.name);

			return o1.mails_list.size() - o2.mails_list.size();
		}
	}

	int N, vis[];
	Person persons[];

	// Adjacency lists for the bidirectional graph
	List< List<Integer> > l = new ArrayList< List<Integer> >();

	void read_input()
	{
		Scanner scanner = null;

		try {
			scanner = new Scanner(new File("adrese.in"));
		} catch (FileNotFoundException e) {
			// TODO Auto-generated catch block
			e.printStackTrace();
		}

		// Read the map size and the coordinates (x,y)
		N = scanner.nextInt();

		persons = new Person[N];
		vis = new int[N];
		for(int i=0; i < N; i++)
		{
			vis[i] = 0;
			String name = scanner.next();
			int num_mails = scanner.nextInt();

			persons[i] = new Person(name, num_mails);
			for(int j=0; j < num_mails; j++)
			{
				String mail = scanner.next();
				persons[i].add_mail(mail);
			}
		}

		for(int i=0; i < N; i++)
			l.add(new ArrayList<Integer>());
	}


	void dfs(int node)
	{
		vis[node] = 1;
		for(int i=0; i < l.get(node).size(); i++)
			if(vis[l.get(node).get(i)] == 0)
			{
				int next_node = l.get(node).get(i);
				// Compute the minimum name for the son of the node and also all the emails
				dfs(next_node);

				// Add to the current node(parent) all his sons mails and update the name if necessary
				persons[node].mails_set.addAll(persons[next_node].mails_set);
				if(persons[node].name.compareTo(persons[next_node].name) >= 0)
					persons[node].name = persons[next_node].name;
			}
	}

	void sort_mails()
	{
		Map<String, Set<Integer>> map = new HashMap<>();

		// Map each mail to a list of indices of the person that has that specific mail
		for(int i=0; i < N; i++)
		{
			String name = persons[i].name;
			List<String> mails = persons[i].mails_list;

			for(int j=0; j < mails.size(); j++)
			{
				String mail = mails.get(j);
				if(map.containsKey(mail))
					map.get(mail).add(i);
				else
				{
					Set<Integer> set = new HashSet<Integer>();
					set.add(i);

					map.put(mail, set);
				}
			}
		}

		// Build a bidirectional graph by connecting each person indices common to a specific mail
		for (Map.Entry<String, Set<Integer>> entry : map.entrySet())
		{
			List<Integer> values = new ArrayList<Integer>(entry.getValue());
			for(int i=0; i < values.size() - 1; i++)
			{
				l.get(values.get(i)).add(values.get(i+1));
				l.get(values.get(i+1)).add(values.get(i));
			}
		}

		// Create a new list of persons with a size equal to the number of connected components
		// Traverse with a DFS the connected components (each connected component contains different aliases of a person)
		List<Person> persons_list = new ArrayList<Person>();
		for(int i=0; i < N; i++)
			if(vis[i] == 0)
			{
				dfs(i);

				// Sort the mails by order
				List<String> sorted_mails = new ArrayList<String>(persons[i].mails_set);
				sorted_mails.sort(null);
				persons[i].mails_list = sorted_mails;

				// Add the person with the minimum name and all emails to the final person list
				persons_list.add(persons[i]);
			}

		// Sort the persons by number of emails and then by name order
		persons_list.sort(new SortPerson());

		// Write down the results
		try {
			FileWriter writer = new FileWriter("adrese.out");
			writer.write(persons_list.size() + "\n");

			for(int i=0; i < persons_list.size(); i++)
			{	
				writer.write(persons_list.get(i).name + " " + persons_list.get(i).mails_list.size() + "\n"); 

				for(int j=0; j < persons_list.get(i).mails_list.size(); j++)
					writer.write(persons_list.get(i).mails_list.get(j) + "\n");

			}
			writer.close();

		} catch (IOException e) {
			// TODO Auto-generated catch block
			e.printStackTrace();
		}

	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		Adrese adrese = new Adrese();
		adrese.read_input();
		System.out.println();
		adrese.sort_mails();

	}

