/// Saves a user and all of it's emails in the result. The insertion will be
/// based on the number of emails each users has. If 2 users have the same
/// amount of emails, then the insertion will be based on the user name
/// (lexicographically sorted).
void insert_user_and_emails(vector<string> user_and_emails,
                            vector<vector<string>>* result) {
    // guard so we don't add the fake users
    if (user_and_emails.size() == 1) {
        return;
    }

    unsigned long int vector_size = (*result).size();

    if (vector_size == 0) {
        // it is the first user found
        (*result).push_back(user_and_emails);

        return;
    }

    // search for the correct position to insert the new user
    for (vector<vector<string>>::iterator it = (*result).begin();
            it != (*result).end(); ++it) {
        if (user_and_emails.size() < (*it).size()) {
            // the new user has fewer emails than the current one
            (*result).emplace(it, user_and_emails);

            return;
        } else if (user_and_emails.size() == (*it).size()) {
            string new_user = user_and_emails[0];
            string current_user = (*it)[0];

            if (new_user < current_user) {
                // the new user has the same amount of emails as the current one
                // but it's user name is smaller by the lexicographically value
                (*result).emplace(it, user_and_emails);

                return;
            }
        }
    }

    // add at the end
    (*result).emplace_back(user_and_emails);
}

void explore(string start,
             unordered_map<string, list<string>>* graph,
             unordered_map<string, int>* visited,
             vector<string>* user_and_emails) {
    // mark the current node as visited
    (*visited)[start] = 1;

    while (!(*graph)[start].empty()) {
        // extract each neighbour of the current node
        string neighbour = (*graph)[start].front();

        (*graph)[start].pop_front();

        if ((*visited)[neighbour] == 0) {
            if (is_user_name(neighbour)) {
                // The node doesn't contains @, it is a name.
                // Compare it with the current user name:
                if (neighbour < (*user_and_emails)[0]) {
                    (*user_and_emails)[0] = neighbour;
                }
            } else {
                // The node contains @, it is an email.
                (*user_and_emails).emplace_back(neighbour);
            }

            // explore the neighbour now
            explore(neighbour, graph, visited, user_and_emails);
        }
    }
}

