        user_nodes.pop_front();

        if (visited[current_node] == 0) {
            // Vector which contains information about a user and it's emails.
            // v[0] = user name
            // v[1...n] = user's emails
            vector<string> user_and_emails;

            user_and_emails.push_back(current_node);

            // start exploring the current node
            explore(current_node, graph, &visited, &user_and_emails);

            // sort only the emails from the vector
            sort(user_and_emails.begin() + 1, user_and_emails.end());

            // add the user and it's emails in the result
            insert_user_and_emails(user_and_emails, &result);
        }
    }

    return result;
