        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Scanner;

public class Feribot {

	Feribot() {
	}

	static long task(int n, int k, int[] cars) {
		// caut maximul si suma tuturor greutatilor
		long maxWeight = 0;
		long sumWeight = 0;
		for (int i = 0; i < n; i++) {
			maxWeight = Math.max(maxWeight, cars[i]);
			sumWeight += cars[i];
		}

		// Execut cautare binara pe intervalul posibil de costuri
		long lo = maxWeight, hi = sumWeight, ans = -1;
		while (lo <= hi) {
			long mid = lo + (hi - lo) / 2;

			// Incerc sa atribui masinile la feriboturi
			long numFerries = 0;
			long ferryWeight = 0;
			for (int i = 0; i < n; i++) {
				if (cars[i] > mid) {
					// Daca o masina e prea grea pentru orice feribot, nu putem transporta
					// toate masinile
					numFerries = k + 1;
					break;
				}
				if (ferryWeight + cars[i] > mid) {
					// Daca adaug o masina la feribotul curent ar face ca acesta sa fie prea greu,
					// trebuie sa folosim un alt feribot
					numFerries++;
					ferryWeight = cars[i];
				} else {
					ferryWeight += cars[i];
				}
			}
			if (ferryWeight > 0) {
				// Daca mai sunt masini pe ultimul feribot, trebuie sa folosim un alt feribot
				numFerries++;
			}

			// Updatez limitele cautarii binare
			if (numFerries <= k) {
				ans = mid;
				hi = mid - 1;
			} else {
				lo = mid + 1;
			}
		}

		return ans;
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("feribot.in"));

			int n = sc.nextInt(); // number of cars
			int k = sc.nextInt(); // number of ferries

			int[] cars = new int[n];

			// read cars
			for (int i = 0; i < n; ++i) {
				cars[i] = sc.nextInt();
			}

			try {
				FileWriter fw = new FileWriter("feribot.out");
				fw.write(Feribot.task(n, k, cars) + "\n");
				fw.close();
			} catch (IOException e) {
				System.out.println(e.getMessage());
			}

			sc.close();
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}
