        import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Feribot {

    /* starting from the lowest and highest supposed solutions, this functions returns
    the optimal solution for the problem using binarySearch algorithm
     */
    public static long binarySearch(int nrCars, int nrFerries, long[] cars, long low, long high) {
        while (low <= high) {
            long mid = (low + high) / 2;

            // the optimal solution is the number for which getSolution (..., number) = 1, but getSolution(..., number-1) = 0
            if (getSolution(nrCars, nrFerries, cars, mid) == 1) {
                if (getSolution(nrCars, nrFerries, cars, mid-1) == 0) {
                    return mid;
                } else {
                    high = mid - 1;
                }
            } else {
                low = mid + 1;
            }
        }
        return 0;
    }

    /* returns 1 if all the cars are transported and every ferry carries a weight lighter or equal than maxAllowedWeight
    and 0 otherwise
     */
    public static int getSolution(int nrCars, int nrFerries, long[] cars, long maxAllowedWeight) {

        /* when carIndex reaches the total number of cars => all the cars have been transported */
        int carIndex = 0;

        for (int i = 0; i < nrFerries; i++) {

            long ferryWeight = 0;  // Let's start loading this ferry

            for ( ; carIndex < nrCars; carIndex++) {
                // Check if we have enough space for the next car
                if (ferryWeight + cars[carIndex] <= maxAllowedWeight) {
                    ferryWeight += cars[carIndex];
                } else break;
            }
            if (carIndex == nrCars) {
                // all the cars have been loaded
                return 1;
            }
        }
        // we ran out of ferries => the supposed maximum allowed weight per ferry is too low
        return 0;
    }

    public static void main(String args[]) throws IOException {

        Scanner scanner = new Scanner(new File("feribot.in"));
        int nrCars, nrFerries;
        nrCars = scanner.nextInt();
        nrFerries = scanner.nextInt();

        long[] cars = new long[nrCars];
        long maxCarWeight = 0;
        long allCarsOnAFerry = 0;

        /* Parsing the file and adding the weight of the cars in the array
        Also calculating the maximum weight a car can have
        It should be clear that minimum possible solution should be the maxCarWeight,
        since a single car cannot be split on to different ferries
        The maximum possible solution would be if all the cars would be on a single ferry */

        for (int i = 0; i < nrCars; i++) {
            cars[i] = scanner.nextLong();
            allCarsOnAFerry += cars[i];
            if (cars[i] > maxCarWeight)
                maxCarWeight = cars[i];
        }

        /* Now that we have a low (maxCarWeight) and a high (allCarsOnAFerry), we can binary search
        the lowest cost solution
         */

        long solution = Feribot.binarySearch(nrCars, nrFerries, cars, maxCarWeight, allCarsOnAFerry);

        FileWriter fWriter = new FileWriter("feribot.out");
        fWriter.write(String.valueOf(solution));
        fWriter.close();

    }
}
