using namespace std;


long long SolveTask(const vector<long long>& vehicles,
                  long long nr_vehicles, long long nr_ferry_boats) {
    long long lower = -1, upper = 0;

    /*
        lower = greutatea maxima cand nr_ferry_boats = nr_vehicles
        upper = greutatea maxima cand nr_ferry_boats = 1
    */
    for (long long i = 0; i < nr_vehicles; i++) {
        upper += vehicles[i];

        if (lower < vehicles[i]) {
            lower = vehicles[i];
        }
    }

    while (lower < upper) {
        /*
            gasesc de cate feriboturi am nevoie pentru a
            incarca cat mai multe masini

            nr_ferry_boats_needed = numarul de feriboturi
            necesare pentru incarca toate masinile
            weight = greutatea pe un feribot
        */
        long double middle = (lower + upper) / 2;
        long long nr_ferry_boats_needed = 1;
        long long weight = 0;

        /*
            aflu de cate feriboturi am nev a.i. fiecare
            feribot sa aiba greutate mai mica decat middle

            daca greutate feribot curent + greutate
            vehicul curent > middle, mai am nev de
            un feribot, care va fi incarcat cu greutate
            vehicul curent
        */
        for (long long i = 0; i < nr_vehicles; i++) {
            if (weight + vehicles[i] > middle) {
                nr_ferry_boats_needed ++;
                weight = vehicles[i];
            } else {
                weight += vehicles[i];
            }
        }

        /*
            gasesc jumatatea in care ma aflu

            nr_ferry_boats_needed < nr_ferry_boats => prima jum
            nr_ferry_boats_needed > nr_ferry_boats => a doua jum
        */
        if (nr_ferry_boats_needed < nr_ferry_boats) {
            upper = (long long)middle - 1;
        } else if (nr_ferry_boats_needed > nr_ferry_boats) {
            lower = (long long)middle + 1;
        } else {
            upper = (long long)middle;
        }
    }

    return lower;
}

