int solvetask (vector<int> a, int n, int k) {
    int cost = 0;
    int left = *max_element(a.begin(), a.end()); //costul minim posibil
    int right = accumulate(a.begin(), a.end(), 0); //costul maxim posibil
    while (left <= right) { //efectuz cautare binara
        int mid = left + (right - left) / 2;
        int nr = k - 1; //o barca am folosit
        int sum = 0;
        for (int i = 0; i < n; i++) {
            if (sum + a[i] > mid) {//inseamna ca mai fol o barca
                nr--;
                sum = a[i];
            } else sum = sum + a[i];//costul de transport
        }

        if (nr >= 0) {//inseamna ca nu am fol toate barcile, caut cost mai mic
            cost = mid;
            right = mid - 1;
        } else left = mid + 1;//am fol toate barci, caut cost mai mare

    }

    return cost;
}


