class Feribot {
	static int n, k;
	static long[] weights;

	Feribot(){}

	static boolean carsFit(long maxWeight) {
		long currentFerries = 1;
		long currentWeight = 0;
		for (int i = 0; i < n; i++) {
			// keep adding if there's room for more cars
			if (currentWeight + weights[i] <= maxWeight) {
				currentWeight += weights[i];
			} else {
				// move on to next ferry
				currentFerries++;
				currentWeight = weights[i];
			}
			// if we don't have enough ferries to transport all cars
			if (currentFerries > k) {
				return false;
			}
		}
		return true;
	}

	static long task() {
		// left is the maximum weight of a car
		long left = Integer.MIN_VALUE;
		// right is the sum of all weights
		long right = 0;
		for (int i = 0; i < n; i++) {
			if (weights[i] > left) {
				left = weights[i];
			}
			right += weights[i];
		}
		long ans = 0, mid;
		// search for best answer
		while (left <= right) {
			mid = (left + right) / 2;
			if (carsFit(mid)) {
				ans = mid;
