  public static int minimumCostPerBasket(int[] cars, int totalFeribots) {
    // Gasirea limitei minime in stanga (cea mai mare greutate)
    // si limita din dreapta (greutatea tuturor masinilor)
    int left = 0, right = 0, totalCost, mid, feribots;

    for (var i = 0; i < cars.length; i++) {
      if (left < cars[i]) {
        left = cars[i];
      }
      right += cars[i];
    }

    // Gasirea solutiei
    while (left < right) {
      mid = (left + right) / 2;
      totalCost = 0;
      feribots = 1;

      for (int car : cars) {
        if (totalCost + car > mid) {
          totalCost = car;
          feribots++;
          if (feribots > totalFeribots) {
            break;
          }
        } else {
          totalCost += car;
        }
      }

      if (feribots > totalFeribots) {
        left = mid + 1;
      } else {
        right = mid;
      }
    }

    return left;
  }

