int main()
{
    // Open the input and output files
    ifstream fin("feribot.in");
    ofstream fout("feribot.out");

    // Read the values of N and K from the input file
    int n, k;
    fin >> n >> k;

    // Create a vector to store the weights of the cars
    vector<long long> a(n);
    for (int i = 0; i < n; i++)
    {
        // Read the weight of each car from the input file
        fin >> a[i];
    }

    // Initialize the lower and upper bounds for the binary search
    long long lo = 0, hi = 1e15, mid;

    // Perform the binary search to find the minimum cost
    while (lo < hi)
    {
        // Calculate the middle value
        mid = lo + (hi - lo) / 2;

        // Count the number of trips and calculate the cost for the current mid value
        int cnt = 0;
        long long sum = 0;
        for (int i = 0; i < n; i++)
        {
            if (sum + a[i] > mid)
            {
                // If adding the current car's weight exceeds the mid value,
                // increment the trip count and reset the sum for the next trip
                cnt++;
                sum = 0;
            }
            sum += a[i];
        }
        if (sum > 0)
            cnt++;

        // Adjust the bounds based on the trip count
        if (cnt <= k)
        {
            // If the number of trips is less than or equal to K,
            // update the upper bound to mid
            hi = mid;
        }
        else
        {
            // If the number of trips is greater than K,
            // update the lower bound to mid + 1
            lo = mid + 1;
        }
    }

    // Output the minimum cost to the output file
    fout << lo << endl;

    return 0;
