		int N = sc.nextInt();
		int K = sc.nextInt();

		long[] v = new long[N];

		for (int i = 0; i < N; i++) {
			v[i] = sc.nextLong();
		}

		long left = 0;
		long right = 0;

		// Initilizare left si right
		for (int i = 0; i < N; i++) {
			left = Math.max(left, v[i]);
			right += v[i];
		}

		while (left < right) {
			long mid = left + (right - left) / 2;
			long sum = 0;

			// numarul de partiții
			int used_partition = 1;
			for (int i = 0; i < N; i++) {
				if (sum + v[i] > mid) {
					// daca nu mai pot pune elementul curent in partitia curenta
					used_partition++;
					sum = v[i];
				} else {
					// daca mai pot pune elementul curent in partitia curenta
					sum += v[i];
				}
			}

			// daca am folosit mai putine partiții decât K
			if (used_partition <= K) {
				right = mid;
			} else {
				left = mid + 1;
			}
		}

		PrintWriter pw = new PrintWriter(new FileOutputStream("feribot.out"));
		pw.println(left);
		pw.close();

		sc.close();
	}
}

