        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;

public class Numarare {
	public final String input_file = "numarare.in";
	public final String output_file = "numarare.out";

	private final int modulo = 1000000007;

	int n, m; // nodes and edges
	ArrayList<LinkedList<Integer>> adj1, adj2;

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void readInput() {
		try {
			Scanner sc = new Scanner(new File(input_file));

			n = sc.nextInt();
			m = sc.nextInt();

			adj1 = new ArrayList<>();
			adj2 = new ArrayList<>();
			for (int i = 0; i < n + 1; i++) {
				adj1.add(new LinkedList<>());
				adj2.add(new LinkedList<>());
			}

			int src, dst;
			for (int i = 0; i < m; i++) { // first graph
				src = sc.nextInt();
				dst = sc.nextInt();
				adj1.get(src).add(dst);
			}
			for (int i = 0; i < m; i++) { // second graph
				src = sc.nextInt();
				dst = sc.nextInt();
				if (adj1.get(src).contains(dst)) {
					// only formed of common roads, from the get-go
					adj2.get(src).add(dst);
				}
			}

			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(final int result) {
		try {
			PrintWriter pw = new PrintWriter(new File(output_file));
			pw.printf("%d", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private ArrayList<Integer> topSort(final ArrayList<LinkedList<Integer>> adjList, final int n) {
		int[] incoming = new int[n];

		// find how many incoming roads each node has
		for (int i = 0; i < n; i++) {
			for (int v : adjList.get(i)) {
				incoming[v]++;
			}
		}

		Queue<Integer> q = new LinkedList<>();

		// first process all that have no incoming roads
		for (int i = 0; i < n; i++) {
			if (incoming[i] == 0) {
				q.add(i);
			}
		}

		ArrayList<Integer> result = new ArrayList<>();

		// kahn moment
		while (!q.isEmpty()) {
			int u = q.poll();
			result.add(u);

			// update incoming road count
			for (int v : adjList.get(u)) {
				incoming[v]--;

				// no more roads means viable candidate
				if (incoming[v] == 0) {
					q.add(v);
				}
			}
		}

		return result;
	}

	private int getResult() {
		int result = 0;

		ArrayList<Integer> s = topSort(adj2, n + 1);

		int[] dp = new int[n + 1];

		dp[n] = 1;

		// traverse in reverse order
		for (int i = s.size() - 1; i > 0; i--) {
			int curr = s.get(i);
			for (int v : adj2.get(curr)) {
				dp[curr] += dp[v];
				dp[curr] %= modulo;
			}
		}

		result = dp[1];

		return result;
	}

	public static void main(final String[] args) {
		new Numarare().solve();
	}
}

