        #include <iostream>
#include <fstream>
#include <vector>
#include <unordered_set>
#include <algorithm>

using namespace std;

ifstream fin("numarare.in");
ofstream fout("numarare.out");

const long MOD = 1e9 + 7;

void dfs(int source_node, int dest_node, const vector<unordered_set<int>>& adj,
        vector<int>& visited) {
    if (dest_node == source_node) {
        // Am ajuns la destinație, deci am mai găsit o cale
        visited[dest_node]++;
        return;
    }

    // Parcurgem toți vecinii nodului curent
    for (int neighbor : adj[source_node]) {
        if (!visited[neighbor]) {
            dfs(neighbor, dest_node, adj, visited);
        }

        // Actualizăm numărul de căi pentru nodul curent
        visited[source_node] = (visited[source_node] + visited[neighbor]) % MOD;
    }
}

int main() {
    int N, M, x, y;
    fin >> N >> M;

    // Graful inițial și graful cu muchii comune
    vector<unordered_set<int>> graph(N + 1);
    vector<unordered_set<int>> common(N + 1);
    vector<int> visited(N + 1, 0);

    for (int i = 0; i < M; i ++) {
        fin >> x >> y;
        graph[x].insert(y);
    }

    for (int i = 0; i < M; i ++) {
        fin >> x >> y;
        // Dacă muchia (x, y) este comună, o adăugăm în lista de adiacență
        // a grafului cu muchii comune
        if (graph[x].find(y) != graph[x].end())
            common[x].insert(y);
    }

    visited[N] = 1;

    // Apelăm funcția DFS pentru a calcula toate căile de la nodul 1 la nodul N
    dfs(1, N, common, visited);

    fout << visited[1];

    return 0;
}

