        import java.io.File;
import java.io.FileNotFoundException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.Scanner;

public class Numarare {
	public static final String INPUT_FILE = "numarare.in";
	public static final String OUTPUT_FILE = "numarare.out";
	public static final int MOD = 1000000007;

	public static int N, M;
	public static List<Integer>[] graph1, commonGraph;
	public static long[] dp;

	@SuppressWarnings("unchecked")
	public static void solve() throws FileNotFoundException {
		Scanner sc = new Scanner(new File(INPUT_FILE));

		N = sc.nextInt();
		M = sc.nextInt();
		graph1 = new ArrayList[N + 1];
		commonGraph = new ArrayList[N + 1];

		for (int i = 1; i <= N; i++) {
			graph1[i] = new ArrayList<>();
			commonGraph[i] = new ArrayList<>();
		}

		for (int i = 0; i < M; i++) {
			int x = sc.nextInt();
			int y = sc.nextInt();
			graph1[x].add(y);
		}

		for (int i = 0; i < M; i++) {
			int x = sc.nextInt();
			int y = sc.nextInt();
			if (graph1[x].contains(y)) {
				commonGraph[x].add(y);
			}
		}

		dp = new long[N + 1];
		Arrays.fill(dp, 0);
		dp[1] = 1;

		List<Integer> sortedNodes = topologicalSort(commonGraph);
		for (int node : sortedNodes) {
			for (int neighbor : commonGraph[node]) {
				dp[neighbor] = (dp[neighbor] + dp[node]) % MOD;
			}
		}

		long result = dp[N];

		PrintWriter pw = new PrintWriter(new File(OUTPUT_FILE));
		pw.printf("%d\n", result);

		sc.close();
		pw.close();
	}

	public static List<Integer> topologicalSort(List<Integer>[] graph) {
		List<Integer> result = new ArrayList<>();
		Queue<Integer> queue = new LinkedList<>();
		int[] inDegree = new int[N + 1];

		for (int i = 1; i <= N; i++) {
			for (int neighbor : graph[i]) {
				inDegree[neighbor]++;
			}
		}

		for (int i = 1; i <= N; i++) {
			if (inDegree[i] == 0) {
				queue.offer(i);
			}
		}

		while (!queue.isEmpty()) {
			int current = queue.poll();
			result.add(current);
			for (int neighbor : graph[current]) {
				inDegree[neighbor]--;
				if (inDegree[neighbor] == 0) {
					queue.offer(neighbor);
				}
			}
		}

		return result;
	}

	public static void main(String[] args) throws FileNotFoundException {
		solve();
	}
}

