                    = destination;
                break;
            }
        }
    }
}

long solve() {
    for (int i = 0; i <= n; ++i) {
        dp[i] = 0;
    }
    dp[1] = 1;

    for (int i = 1; i <= n; ++i) {
        for (int j = 0; j < graph[i].neighbor_count; ++j) {
            int neighbor = graph[i].neighbors[j];
            dp[neighbor] = (dp[neighbor] + dp[i]) % MOD;
        }
    }
    return dp[n];
}

int main() {
    init();
    fout << solve();
    return 0;
}

