	static long MOD = (long) (1e9 + 7);

	// logarithmic time complexity pow (used solution from lab 1)
	private static long pow(long base, int exponent) {
		if (exponent <= 0) {
			return 1;
		}

		long aux = 1;
		while (exponent != 1) {
			if (exponent % 2 == 0) {
				base = (base * base) % MOD;
				exponent /= 2;
			} else {
				aux = (aux * base) % MOD;
				exponent--;
			}
		}
		return (aux * base) % MOD;
	}

	private static long solve(int N, Integer[] count, Character[] type) {
		ArrayList<Integer> zoneCount = new ArrayList<>();
		ArrayList<Character> zoneType = new ArrayList<>();
		combineZones(N, count, type, zoneCount, zoneType);

		long ans;
		// first zone is a special case, there are more possible combinations
		if (zoneType.getFirst() == 'H') {
			ans = (6 * pow(3, zoneCount.getFirst() - 1)) % MOD;
		} else {
			ans = (3 * pow(2, zoneCount.getFirst() - 1)) % MOD;
		}

		for (int i = 1; i < zoneCount.size(); i++) {
			if (zoneType.get(i) == 'H') {
				// last zone was V, current one is H, update combinations
				ans = (ans * 2) % MOD;
				ans = (ans * pow(3, zoneCount.get(i) - 1)) % MOD;
			} else {
				// last zone was H, current one is V, update combinations
				ans = (ans * pow(2, zoneCount.get(i) - 1)) % MOD;
			}
		}

		return ans % MOD;
	}

	private static void combineZones(int N, Integer[] count, Character[] type,
									ArrayList<Integer> zoneCount, ArrayList<Character> zoneType) {
		// combine zones that have the same type
		for (int i = 0; i < N; i++) {
			int j = i + 1;
			zoneCount.add(count[i]);
			zoneType.add(type[i]);
			int indexCopy = i;
			while (j < N && type[indexCopy] == type[j]) {
				zoneCount.set(zoneCount.size() - 1, zoneCount.getLast() + count[j]);
				j++;
				i++;
			}
		}
	}

