		int N = myScanner.nextInt();
		Integer[] count = new Integer[N];
		Character[] type = new Character[N];

		for (int i = 0; i < N; i++) {
			count[i] = myScanner.nextInt();
			type[i] = myScanner.next().charAt(0);
		}

		File outputFile = new File("colorare.out");
		FileWriter fileWriter;
		try {
			fileWriter = new FileWriter(outputFile);
			fileWriter.write(Long.toString(solve(N, count, type)));
			fileWriter.close();
		} catch (IOException e) {
			System.out.println(e.getMessage());
		}
	}
}

