        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Scanner;

public class Colorare {
	public static final String INPUT_FILE = "colorare.in";
	public static final String OUTPUT_FILE = "colorare.out";
	public static final long MOD = 1000000007;

	int k;  // numarul de perechi
	int[] x;  // numarul de zone de un anumit tip
	String[] position;  // tipul, vertical sau orizontal

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void readInput() {
		try (Scanner sc = new Scanner(new BufferedReader(
				new FileReader(INPUT_FILE)))) {
			k = sc.nextInt();
			x = new int[k];
			position = new String[k];
			for (int i = 0; i < k; i++) {
				x[i] = sc.nextInt();
				position[i] = sc.next();
			}
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(long result) {
		try {
			PrintWriter pw = new PrintWriter(new BufferedWriter(
					new FileWriter(OUTPUT_FILE)));
			pw.printf("%d\n", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private long getResult() {
		long result = 0;

		if (position[0].equals("H")) {
			/* prima zona orizontala => aranjamente de 3 luate cate 2,
			* iar urmatoarele zone orizontale pot fi colorate in 3 moduri distincte */
			result = 6 * pow(3, x[0] - 1);
		} else if (position[0].equals("V")) {
			/* prima zona verticala => aranjamente de 3 luate cate 1,
			* iar urmatoarele zone verticale pot fi colorate in 2 moduri distincte */
			result = 3 * pow(2, x[0] - 1);
		}

		for (int i = 1; i < k; i++) {
			if (position[i - 1].equals("V")) {  // daca zona precedenta este verticala
				if (position[i].equals("H")) { // iar actuala zona este orizontala
					// vom avea 2 moduri de colorare pentru prima zona orizontala si 3 in continuare
					result = multiplyMod(result, multiplyMod(2, pow(3, x[i] - 1)));
				} else {  // actuala zona verticala
					// vom avea 1 mod de a colora prima zona verticala si 2 in continuare
					result = multiplyMod(result, pow(2, x[i]));
				}
			} else {  // daca zona precedenta este orizontala
				if (position[i].equals("H")) {  // iar actuala zona este orizontala
					// vom avea 1 mod de colorare pentru prima zona orizontala si 3 in continuare
					result = multiplyMod(result, pow(3, x[i]));
				} else {  // actuala zona verticala
					// vom avea 1 mod de colorare pentru prima zona verticala si 2 in continuare
					result = multiplyMod(result, pow(2, x[i] - 1));
				}
			}
		}
		return result;
	}

	// https://stackoverflow.com/questions/30694842/exponentiation-by-squaring
	private long pow(long base, long exponent) {
		long result = 1;
		base %= MOD;
		while (exponent > 0) {
			if (exponent % 2 == 1) {
				result = multiplyMod(result, base);
			}
			base = multiplyMod(base, base);
			exponent /= 2;
		}
		return result;
	}

	private long multiplyMod(long a, long b) {
		return (a * b) % MOD;
	}


	public static void main(String[] args) {
		new Colorare().solve();
	}
}

