int MODULO = 1000000007;
typedef unsigned long long ull;
#define f "colorare.in"
#define g "colorare.out"

ull multiplication(ull a, ull b, ull mod = MODULO) {
	ull res = 0;
	a %= mod;

	while (b) {
		if (b & 1)
			res = (res + a) % mod;
		a = (2 * a) % mod;
		b >>= 1;
	}

	return res;
}

ull power(ull x, ull y) {
	ull res = 1;
	while (y > 0) {
		if (y % 2 == 1)
			res = multiplication(res, x);
		y = y >> 1;

		x = multiplication(x, x);
	}
	return res;
}

int read_and_count(ull &count) {
    std::ifstream fin(f);
    int K;
    fin >> K;

    ull X;
    char T, oldT = ' ';
    int oldX = 0;
    for (int i = 0; i < K; i++) {
        fin >> X >> T;
        if (oldX == 0 && T == 'H') {
            count *= 6;
            if (X > 1) {
                count = multiplication(count, power(3, X - 1));
            }
        } else if (oldX == 0 && T == 'V') {
            count *= 3;
            if (X > 1) {
                count = multiplication(count, power(2, X - 1));
            }
        } else if (oldX != 0 && T == 'H' && oldT == 'H') {
            count = multiplication(count, power(3, X));
        } else if (oldX != 0 && T == 'V' && oldT == 'V') {
            count = multiplication(count, power(2, X));
        } else if (oldX != 0 && T == 'H' && oldT == 'V') {
            count *= 2;
            if (X > 1) {
                count = multiplication(count, power(3, X - 1));
            }
        } else if (oldX != 0 && T == 'V' && oldT == 'H') {
            if (X > 1) {
                count = multiplication(count, power(2, X - 1));
            }
        }

        oldX = X;
        oldT = T;
    }

    fin.close();
    return K;
}

void write_output(ull count ) {
