        if (!exponent) {
            return 1;
        }

        int aux = 1;
        while (exponent != 1) {
            if (exponent % 2 == 0) {
                base = (1LL * base * base) % mod;
                exponent /= 2;
            } else {
                aux = (1LL * aux * base) % mod;
                exponent--;
            }
        }

        return (1LL * aux * base) % mod;
    }

