					numarModuri = (numarModuri * 3 * 2) % 1000000007;
				} else if (perechi.get(i - 1).getOrientare().equals('V')) {
					/* Daca urmeaza dupa un bloc vertical -> 2 moduri de colorare */
					numarModuri = (numarModuri * 2) % 1000000007;
