		} else {
			// avem 3 posibilitati de a colora primele 2 patratele
			nr = 3;
			// restul au 2 posibilitati
			nr = ((nr % Mod) * (pow(2, num[0] - 1) % Mod)) % Mod;
		}

		// procesam restul elementelor
		for (int i = 1; i < n; i++) {
