				FileReader fr = new FileReader(INPUT_FILE);
				BufferedReader br = new BufferedReader(fr);
				K = Integer.parseInt(br.readLine());
				input = br.readLine().split(" ");
				br.close();
				fr.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
