using namespace std;

#define MOD ((int)1e9 + 7)

struct Zone {
    int nr;
    char type;
};

long long power(long long base, long long exponent, long long modulus) {
    long long result = 1;
    base = base % modulus;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % modulus;
        }
        exponent = exponent >> 1;
        base = (base * base) % modulus;
    }
    return result;
}

int main() {
    ifstream FileInput("colorare.in");
    ofstream FileOutput("colorare.out");

    long long k;
    FileInput >> k;
    vector<struct Zone> zone(k);

    for (long long i = 0; i < k; i++) {
        FileInput >> zone[i].nr;
        FileInput >> zone[i].type;
    }

    long long distinct_nr = 0;

    switch (zone[0].type)
    {
    case 'H':
        distinct_nr = (6 * power(3, zone[0].nr - 1, MOD)) % MOD;
        break;
    case 'V':
        distinct_nr = (3 * power(2, zone[0].nr - 1, MOD)) % MOD;
        break;

    default:
        break;
    }

    for (long long i = 1; i < k; i ++) {
        if (zone[i].type == 'H') {
            if (zone[i - 1].type == 'H') {
                distinct_nr = (distinct_nr * power(3, zone[i].nr, MOD)) % MOD;
            } else {
                distinct_nr = (distinct_nr * 2 * power(3, zone[i].nr - 1, MOD)) % MOD;
            }
        } else {
            if (zone[i - 1].type == 'V') {
                distinct_nr = (distinct_nr * power(2, zone[i].nr, MOD)) % MOD;
            } else {
                distinct_nr = (distinct_nr * power(2, zone[i].nr - 1, MOD)) % MOD;
            }
        }
    }

    FileOutput << distinct_nr;


    FileInput.close();
    FileOutput.close();
}

