        #include <fstream>
#include <string>
#include <vector>
#include <set>
#include <unordered_map>
#include <stack>


typedef std::unordered_map<int, std::set<int>> Edges;
typedef std::vector<int> SubGraph;
class ImplicationGraph {
 public:
    ImplicationGraph(): mVariablesCount(0) {}

    void SetVariablesCount(int variablesCount) {
        mVariablesCount = variablesCount;
        for (int i=1; i<variablesCount+1; i++) {
            mEdges[i] = {};
            mEdges[-i] = {};

            mReverseEdges[i] = {};
            mReverseEdges[-i] = {};
        }
    }

    /*
        adds relation x or y in graph
        if x < 0, x is considered to be: not x
        if y < 0, y is considered to be: not y
    */
    void AddOr(int x, int y) {
        mEdges[-x].insert(y);
        mEdges[-y].insert(x);

        // add edges for the reverse graph
        mReverseEdges[y].insert(-x);
        mReverseEdges[x].insert(-y);
    }

    /*
        adds x implies y
        if x < 0, x is considered to be not x
        if y < 0, y is considered to be: not y
    */
    void AddImplication(int x, int y) {
        mEdges[x].insert(y);
        mEdges[-y].insert(-x);

        // add edges for the reverse graph
        mReverseEdges[y].insert(x);
        mReverseEdges[-x].insert(-y);
    }

    int VariablesCount() const {
        return mVariablesCount;
    }
    /* Implementation of the two-sat problem solution*/
    std::unordered_map<int, bool> ComputeSolution() {
        std::stack<int> stack;
        // maps visited value for each node
        std::unordered_map<int, bool> visited;
        std::vector<SubGraph> stronglyConnectedComponents;
        // maps the id of the SCC the node is part of
        std::unordered_map<int, int> node2SCCID;

        const Edges& edges = mEdges;
        const Edges& reverseEdges = mReverseEdges;
        int variablesCount = mVariablesCount;
        auto VisitedSet = [&visited, variablesCount](bool isVisited) {
            for (int i=1; i<variablesCount+1; i++) {
                visited[i] = isVisited;
                visited[-i] = isVisited;
            }
        };
        auto DFS1 = [&visited, &edges, &stack](auto&& DFS1, int node) {
            if (visited[node]) {
                 return;
            }
            visited[node] = true;
		    for (int neighbour : edges.at(node)) {
			    DFS1(DFS1, neighbour);
		    }
		    stack.push(node);
        };

        auto DFS2 = [&visited, &reverseEdges, &stack, &node2SCCID](auto&& DFS2,
                        SubGraph& scc, int sccid, int node) {
            if (visited[node]) {
                return;
            }
            visited[node] = true;
            node2SCCID[node] = sccid;
            scc.push_back(node);
		    for (int neighbour : reverseEdges.at(node)) {
			    DFS2(DFS2, scc, sccid, neighbour);
		    }
		    stack.push(node);
        };

        // mark all nodes as not visited
        VisitedSet(false);

        // perform the first dfs on the graph
        for (const auto& edgesIt : edges) {
            int node = edgesIt.first;
            DFS1(DFS1, node);
        }

        VisitedSet(false);
        // perform second dfs on the inverted graph to find the SCCs
        while (!stack.empty()) {
			int node = stack.top();
            stack.pop();
			if (!visited[node]) {
                SubGraph scc;
                DFS2(DFS2, scc, stronglyConnectedComponents.size(), node);
				stronglyConnectedComponents.push_back(scc);
			}
		}
        // check if the solution exists by checking if the variable and
        // its negation are in the same strongly connected component
        for (int i = 1; i < variablesCount+1; i++) {
			if (node2SCCID[i] == node2SCCID[-i]) {
                return {};
            }
		}
        std::unordered_map<int, bool> result;
		for (SubGraph& scc : stronglyConnectedComponents) {
			for (int node : scc) {
                // only check variable (not negations)
                if (node > 0) {
                    if (node2SCCID[node] < node2SCCID[-node]) {
                        result[node] = false;
                    } else {
                        result[node] = true;
                    }
                }
			}
		}
        return result;
    }

 private:
    Edges mEdges;
    Edges mReverseEdges;
    int mVariablesCount;
};

void Read(const std::string& inputFile, ImplicationGraph& graph) {
    int N, M;
    std::ifstream ifile(inputFile);
    ifile >> N >> M;
    graph.SetVariablesCount(N);
    for (int i=0; i<M; i++)  {
        int x, y, c;
        ifile >> x >> y >> c;
        switch (c) {
        case 0:
            graph.AddOr(x, y);
            break;
        case 1:
            graph.AddImplication(-x, -y);
            break;
        case 2:
            graph.AddImplication(-y, -x);
            break;
        case 3:
            graph.AddOr(-x, -y);
            break;
        default:
            break;
        }
    }
}

