        #include <iostream>
#include <fstream>
#include <vector>
#include <queue>

using namespace std;
ifstream fin("scandal.in");
ofstream fout("scandal.out");

int main() {
    int N, M;
    fin >> N >> M;
    vector<vector<int>> adj(2 * N + 2);
    // pentru nodurile simple si nodurile negate
    // nodul negat se afla cu n pozitii mai la dreapta fata de nodul simplu
    for (int i = 1; i <= M; i++) {
        int x, y, c;
        fin >> x >> y >> c;
        if (c == 0) {
            adj[x + N].push_back(y);
            adj[y + N].push_back(x);
        } else if (c == 1) {
            adj[x + N].push_back(y + N);
            adj[y].push_back(x);
        } else if (c == 2) {
            adj[y + N].push_back(x + N);
            adj[x].push_back(y);
        } else if (c == 3) {
            adj[x].push_back(y + N);
            adj[y].push_back(x + N);
        }
    }

    // facem un BFS pentru a decide pentru fiecare nod
    // daca il luam in considerare ca fiind invitat sau neinvitat
    vector<int> viz(N + 1, 0);
    // 0 - nu a fost vizitat, 1 - invitat, 2 - neinvitat'
    queue<int> q;
    int restart = 0;
    for (int i = 1; i <= N; i++) {
        if (viz[i] == 0) {
            q.push(i);
            if (restart == 1) {
                viz[i] = 2;
                restart = 0;
            } else {
                viz[i] = 1;
            }
            while (q.empty() == false) {
                int node = q.front();
                q.pop();
                if (restart == 0) {
                    for (int j = 0; j < adj[node].size(); j++) {
                        int neigh = adj[node][j];
                        if (neigh > N) {
                            if (viz[neigh - N] == 0) {
                                viz[neigh - N] = 2;
                                q.push(neigh);
                            } else if (viz[neigh - N] == 1) {
                                // daca un nod este invitat si el trebuie sa fie
                                // neinvitat trebuie sa reluam parcurgerea de la
                                // inceput cu nodul neinvitat
                                restart = 1;
                            }
                        } else {
                            if (viz[neigh] == 0) {
                                viz[neigh] = 1;
                                q.push(neigh);
                            } else if (viz[neigh] == 2) {
                                // daca un nod este neinvitat si el trebuie sa
                                // fie invitat trebuie sa reluam parcurgerea
                                // de la inceput cu nodul invitat
                                restart = 1;
                            }
                        }
                    }
                }
            }
            if (restart == 1) {
                i--;
            }
        }
    }

    int ct = 0;
    for (int i = 1; i <= N; i++) {
        if (viz[i] == 1) {
            ct++;
        }
    }
    fout << ct << '\n';
    for (int i = 1; i <= N; i++) {
        if (viz[i] == 1) {
            fout << i << '\n';
        }
    }
    return 0;
}

