        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

public class Scandal {
	static final int Limit = 200002; // NMAX
	static List<List<Integer>> graf = new ArrayList<>();
	static List<List<Integer>> grafT = new ArrayList<>();
	static int[] ord = new int[Limit + 5]; // vector de postordine
	static ArrayList<Integer> result = new ArrayList<>(); // rezultat
	static int[] comp_tari_conexe = new int[Limit + 5];
	static boolean[] visited = new boolean[Limit + 5]; // vector de vizitati
	static int n, M, nr_prieteni;
	static int contor = -1;

	public static void main(String[] args) throws IOException {
		BufferedReader input = new BufferedReader(new FileReader("scandal.in"));
		String[] line = input.readLine().split(" ");
		n = Integer.parseInt(line[0]);
		for (int i = 1; i <= 2 * Limit; i++) { // initializez grafurile
			graf.add(new ArrayList<>());
			grafT.add(new ArrayList<>());
		}
		M = Integer.parseInt(line[1]); // citesc nr de muchii
		while (M > 0) {
			line = input.readLine().split(" ");
			int a = Integer.parseInt(line[0]);
			int b = Integer.parseInt(line[1]);
			int rule = Integer.parseInt(line[2]);
			M--;
			switch (rule) { // fac un switch pe cazuri
				case 0:
					grafT.get(n + b).add(n - a);
					grafT.get(n + a).add(n - b);
					graf.get(n - a).add(n + b);
					graf.get(n - b).add(n + a); // adaug muchii grafului
					break;
				case 1:
					grafT.get(n + a).add(n + b);
					grafT.get(n - b).add(n - a);
					graf.get(n + b).add(n + a);
					graf.get(n - a).add(n - b); // la fel si aici
					break;
				case 2:
					graf.get(n + a).add(n + b); // leg cele 2 afirmate si negate
					grafT.get(n + b).add(n + a);
					grafT.get(n - a).add(n - b);
					graf.get(n - b).add(n - a);
					break;
				case 3:
					grafT.get(n - b).add(n + a);
					// leg primul afirmat cu al doilea negat
					grafT.get(n - a).add(n + b);
					graf.get(n + a).add(n - b);
					graf.get(n + b).add(n - a);
					break;
				default:
					// Tratare caz neacoperit
					break;
			}
		}

		for (int i = 1; i <= n; i++) {
			if (!visited[n - i]) {
				functie_dfs(n - i); // fac dfs
			}
			if (!visited[n + i]) {
				functie_dfs(n + i); // fac dfs pe negate
			}
		}

		for (int i = ord.length - 1; i >= 0; i--) {
			if (visited[ord[i]]) {
				nr_prieteni++;
			}
			functie_dfs2(ord[i]);
		}

		for (int i = 1; i <= n; i++) {
			if (comp_tari_conexe[n + i] > comp_tari_conexe[n - i]) { // daca este bun
				result.add(i); // il adaug
			}
		}
		BufferedWriter output = new BufferedWriter(new FileWriter("scandal.out"));
		output.write(result.size() + "\n");
		for (int i = 0; i < result.size(); i++) {
			output.write(result.get(i) + "\n");
		}
		output.write("\n");

		input.close();
		output.close();
	}

	static void functie_dfs(int start) {
		visited[start] = true; // dfs pe graf
		for (int i : graf.get(start)) {
			if (!visited[i]) {
				visited[i] = true;
				functie_dfs(i);
			}
		}
		contor++;
		ord[contor] = start; // salvez in vect de postordine
	}

	static void functie_dfs2(int start) {
		// lucrez pe graf transpus
		visited[start] = false;
		comp_tari_conexe[start] = nr_prieteni;
		for (int i : grafT.get(start)) {
			if (visited[i]) {
				visited[i] = false;
				functie_dfs2(i);
			}
		}
	}
}

