#include "graf.h"

using namespace std;


int n, m;
Graf graf;
Graf grafinv;
int* stari;
int* valori;

int cod = 1;
void tarzan(int idx) {
    stari[idx] = 1;
    valori[idx] = cod++;

    Nod nod = graf->noduri[idx];
    for (; nod != NULL; nod = nod->next) {
        if (stari[nod->d] == 0) {
            stari[nod->d] = 1;
            tarzan(nod->d);
        }
        if (stari[nod->d == 1])
            valori[idx] = min(valori[idx], valori[nod->d]);
    }
}

int* topsort;
int start;

void sortareTopologica(int idx) {
    stari[idx] = 1;
    Nod nod = graf->noduri[idx];
    for (; nod != NULL; nod = nod->next) {
        if (!stari[nod->d]) {
            sortareTopologica(nod->d);
        }
    }
    topsort[start++] = idx;
}

void tare_conex(int idx) {
    valori[idx] = cod;
    Nod nod = grafinv->noduri[idx];
    for (; nod != NULL; nod = nod->next) {
        if (!stari[nod->d]) {
            tare_conex(nod->d);
        }
    }
}



