            adaugaNod(graf, n + d, s);
            adaugaNod(grafinv, d, n + s);
            adaugaNod(grafinv, s, n + d);
        } else if (c == 1) {
            adaugaNod(graf, n + s, n + d);
            adaugaNod(graf, d, s);
            adaugaNod(grafinv, n + d, n + s);
            adaugaNod(grafinv, s, d);
        } else if (c == 2) {
            adaugaNod(graf, n + d, n + s);
            adaugaNod(graf, s, d);
            adaugaNod(grafinv, n + s, n + d);
            adaugaNod(grafinv, d, s);
        } else {
            adaugaNod(graf, s, n + d);
            adaugaNod(graf, d, n + s);
            adaugaNod(grafinv, n + d, s);
            adaugaNod(grafinv, n + s, d);
        }
    }
    stari = (int*)calloc(2 * n + 2, sizeof(int));
    valori = (int*)calloc(2 * n + 2, sizeof(int));
    topsort = (int*)calloc(2 * n + 2, sizeof(int));


    for (int i = 1; i <= 2 * n; i++) {
        if (stari[i] == 0)
