import java.math.BigInteger;
import java.util.ArrayList;
import java.util.Scanner;

public class Crypto {
	//in aceasta pb este nevoie de numere foarte mari, iar BigInteger >> long
	static final BigInteger constant = BigInteger.valueOf(10).pow(9).add(BigInteger.valueOf(7));

	public static void main(String[] args) {
		try {
			File myObj = new File("crypto.in");
			final String newLine = "\n";
			Writer outputFile = new FileWriter("crypto.out");
			Scanner myReader = new Scanner(myObj);
			long sizeOfA = myReader.nextInt();
			long sizeOfB = myReader.nextInt();
			String a = myReader.next();
			String b = myReader.next();
			//functie care imi intoarce cate elemente distincte am in sirul mic
			int uniqueCharactersInB = uniqueCharacters(b);
			outputFile.write(findOccurences(a, b, sizeOfA, sizeOfB, uniqueCharactersInB) + newLine);
			myReader.close();
			outputFile.close();
		} catch (FileNotFoundException e) {
			System.out.println("An error occurred.");
			e.printStackTrace();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}

	private static int uniqueCharacters(String b) {
		int count = 0;
		for (char a = 'a'; a <= 'z'; a++) {
			//daca nu exista in b, indexOf intoarce -1
			if (b.indexOf(a) != -1) {
				count++;
			}
		}
		return count;
	}

	private static BigInteger findOccurences(String a, String b, long m, long n,
											int uniqueCharactersInB) {
		ArrayList<ArrayList<BigInteger>> dp = new ArrayList<>();
		BigInteger k = new BigInteger(String.valueOf(1));
		//Initializez matricea mea cu 0 uri pe toate liniile
		for (int i = 0; i <= m; i++) {
			dp.add(new ArrayList<>());
			for (int j = 0; j <= n; j++) {
				if (j == 0) {
					//insa pe coloana 0 pun k
					dp.get(i).add(k.mod(constant));
					if (i < m && a.charAt(i) == '?') {
						//mereu cand dau de un semn al intrebarii, k devine multiplu mai
						//mare de numarul de caractere unice
