        #include <bits/stdc++.h>

#define MODULO 1000000007

using namespace std;

class Task {
 public:
  void solve() {
    ifstream fin("crypto.in");
    ofstream fout("crypto.out");

    fin >> n >> l;
    fin >> K;
    fin >> S;
    fout << get_result() << '\n';
    fin.close();
    fout.close();
  }

 private:
  int n, l;
  string K, S;

  /**
   * Returns the power of base to p modulo 10^9+7
   */
  long pow(long base, long p) {
    long result = 1;
    while (p > 0) {
      if (p % 2 == 1) {
        p--;
        result = result * base % MODULO;
      }

      p = p / 2;
      base = base * base % MODULO;
    }
    return result;
  }

  int get_result() {
    vector<char> unique_chars;
    vector<long> dp(l);
    int qmarks;
    qmarks = 0;

    // Put all characters used in S in unique_chars, without repeating them.
    for (int i = 0; i < l; i++) {
      int j;
      for (j = 0; j < unique_chars.size(); j++) {
        if (unique_chars[j] == S[i]) {
          break;
        }
      }
      if (j == unique_chars.size()) {
        unique_chars.push_back(S[i]);
      }
    }

    // Remember the number of different characters used in the string
    int n_unique = unique_chars.size();

    for (int i = 0; i < n; i++) {
      // If the letter is represented by a question mark, update the values
      // for all letters, while accounting how they would have changed for
      // each letter that could take the place of the question mark.
      if (K[i] == '?') {
        for (int j = l; j >= 1; j--) {
          dp[j] = ((dp[j] * n_unique) % MODULO + dp[j - 1]) % MODULO;
        }

        dp[0] = ((dp[0] * n_unique) % MODULO + pow(n_unique, qmarks)) % MODULO;

        qmarks++;
        continue;
      }

      // Find the matching letter in S and update it's coresponding value
      for (int j = l; j >= 1; j--) {
        if (K[i] == S[j]) {
          dp[j] = (dp[j] + dp[j - 1]) % MODULO;
        }
      }

      if (K[i] == S[0]) {
        dp[0] = (dp[0] + pow(n_unique, qmarks)) % MODULO;
      }
    }

    long result = dp[l - 1];

    dp.clear();

    return dp[l - 1];
  }
};

int main() {
  Task* task = new (nothrow) Task();
  if (!task) {
    return -1;
  }
  task->solve();
  delete task;
  return 0;
