	int count_char(string my_key) {
		int count = 0;
		for (int i = 0; i < my_key.length(); i++) {
			if (my_key[i] == '?') {
				count++;
			}
		}
		return count;
	}

	// intoarce un sir care contine literele o singura data dintr-un sir dat,
	// fara sa le pastreze ordinea
	// sir ordonat alfabetic
	string remove_same_chars(string my_string) {
		string new_string;
		for (int i = 0; i < 26; i++) {
			if (my_string.find(static_cast<char>(i + 97)) < my_string.length()) {
				char c = static_cast<char>(i + 97);
				new_string += c;
			}
		}
		return new_string;
	}

	// ce numar trebuie sa inmultesc cu MOD pentru ca
	// impartirea sa fie numar intreg
	int find_number(int dp_number, int len, int mod) {
		int i = 0;
		while (1) {
			if ((dp_number + mod * i) % len == 0) {
				break;
			} else {
				i++;
			}
		}
		return i;
	}
	// ridicare la putere pentru numere mari, folosind modulo
	long long int power(long long int a, long long int b) {
		long long int sol = 1;
		while (b) {
			if (b & 1) {
				sol = (sol * a) % MOD;
			}
			a = (a * a) % MOD;
			b = b / 2;
		}
		return sol;
	}

	int solve_dp(int n, int l, string my_string, string my_key) {
		vector<vector<int>> dp(n + 1, vector<int>(l + 1, 0));
		long long int special_char = count_char(my_key);
		string my_string_without_duplicates = remove_same_chars(my_string);
		int len = my_string_without_duplicates.length();
