			dp[0][j] = 0;
		}
		for (int i = 1; i < n + 1; i++) {
			if (my_key[i - 1] != '?') {
				for (int j = 1; j < l + 1; j++) {
					if (my_key[i - 1] == my_string[j - 1]) {
						dp[i][j] = (dp[i - 1][j - 1] + dp[i - 1][j]) % MOD;
					} else {
						dp[i][j] = dp[i - 1][j];
					}
				}
			} else {
				for (int j = 1; j < l + 1; j++) {
					int multiply = find_number(dp[i - 1][j - 1], len, MOD);
					dp[i][j] = (dp[i - 1][j] + (int)((long double)((double)MOD
					/ (double)len) * (double)multiply + (double)(((double)
					(dp[i - 1][j - 1])) / (double)len))) % MOD;
				}
			}
		}
		return dp[n][l];
	}
	void print_output(int result) {
		ofstream fout("crypto.out");
		fout << result << endl;
		fout.close();
	}
};

int main() {
	auto *crypto = new (nothrow) Crypto();
	if (!crypto) {
		cerr << ":(";
		return -1;
	}
	crypto->solve();
	delete crypto;
	return 0;
}

