        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Set;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

public class Crypto {
	private static final String INPUT_FILE = "crypto.in";
	private static final String OUTPUT_FILE = "crypto.out";

	private static final long MODULO = 1000000007;
	private static final char JOKER = '?';

	private static String k;

	private static String s;

	private static int count; /* number of unique letters in "s" */

	private static long[][] dp;

	/**
	 * reads input and writes answer in output file by solving the current problem.
	 * @throws IOException input-output exception
	 */
	private static void read() throws IOException {
		BufferedReader reader = new BufferedReader(new FileReader(INPUT_FILE));
		String[] line = reader.readLine().split(" ");
		int n = Integer.parseInt(line[0]);
		int l = Integer.parseInt(line[1]);
		dp = new long[n + 1][l + 1];

		for (int i = 0; i < n + 1; i++) {
			for (int j = 0; j < l + 1; j++) {
				dp[i][j] = -1;
			}
		}
		k = reader.readLine();
		s = reader.readLine();
		count = count();
		PrintWriter writer = new PrintWriter(OUTPUT_FILE);
		writer.println(solve(n, l));
		reader.close();
		writer.close();
	}

	/**
	 * counts the total number of unique letters found in "s".
	 * @return total
	 */
	private static int count() {
		Set<Character> set = IntStream.range(
				0, s.length()).mapToObj(i -> s.charAt(i)).collect(Collectors.toSet());
		return set.size();
	}

	/**
	 * solves the current problem.
	 * @param n "k" length
	 * @param l "s" length
	 * @return result
	 */
	private static long solve(int n, int l) {
		if (l == 0 && n == 0) {
			return 1;
		}
		if (l == 0) {
			if (k.charAt(n - 1) == JOKER) {
				return count * solve(n - 1, l) % MODULO;
			}
			return solve(n - 1, l) % MODULO;
		}
		if (n == 0) {
			return 0;
		}
		if (dp[n][l] != -1) {
			return dp[n][l];
		}
		if (k.charAt(n - 1) == JOKER) {
			dp[n][l] = (solve(n - 1, l - 1) + count * solve(n - 1, l)) % MODULO;
			return dp[n][l];
		}
		if (k.charAt(n - 1) == s.charAt(l - 1)) {
			dp[n][l] = (solve(n - 1, l - 1) + solve(n - 1, l)) % MODULO;
			return dp[n][l];
		}
		dp[n][l] = solve(n - 1, l) % MODULO;
		return dp[n][l];
	}

	public static void main(String[] args) throws IOException {
		read();
	}
}

