import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.regex.Pattern;

public class Servere {

    static class Task {
        int numberOfServers;
        double[] powers;
        double[] currents;

        public void solve() {
            readInput();
            writeOutput(computeMaximumPower());
        }

        private void readInput() {
            BufferedReader reader = null;
            Pattern pattern = Pattern.compile("\\s");

            try {
                reader = new BufferedReader(new FileReader("servere.in"));
                String numberOfServersLine;
                String powersLine;
                String currentsLine;

                if ((numberOfServersLine = reader.readLine()) != null) {
                    numberOfServers = Integer.parseInt(numberOfServersLine);
                }

                powers = new double[numberOfServers];
                currents = new double[numberOfServers];

                powersLine = reader.readLine();
                currentsLine = reader.readLine();

                if (powersLine != null || currentsLine != null) {
                    String[] powerStrings = pattern.split(powersLine);
                    String[] currentStrings = pattern.split(currentsLine);
                    for (int i = 0; i < numberOfServers; i++) {
                        powers[i] = Double.parseDouble(powerStrings[i]);
                        currents[i] = Double.parseDouble(currentStrings[i]);
                    }
                }

            } catch (IOException e) {
                throw new RuntimeException(e);
            } finally {
                try {
                    if (reader != null) {
                        reader.close();
                    }
                } catch (IOException ex) {
                    throw new RuntimeException(ex);
                }
            }
        }

        private double computeMaximumPower() {
            double[] sortedCurrents = Arrays.copyOf(currents, currents.length);
            Arrays.sort(sortedCurrents);
            double maxMinPower = computeMinimumAdjustedPower(sortedCurrents[0]);

            for (int i = 0; i < numberOfServers - 1; i++) {
                double currentLeft = sortedCurrents[i];
                double currentRight = sortedCurrents[i + 1];
                double intervalDelta = 0.01;

                double minPowerRightEdge = computeMinimumAdjustedPower(currentRight);
                if (minPowerRightEdge > maxMinPower) {
                    maxMinPower = minPowerRightEdge;
                }

                while (currentRight - currentLeft > intervalDelta) {
                    double currentMiddle = (currentLeft + currentRight) / 2;
                    double minPowerMid = computeMinimumAdjustedPower(currentMiddle);
                    double minPowerLeft = computeMinimumAdjustedPower(currentMiddle - intervalDelta);
                    double minPowerRight = computeMinimumAdjustedPower(currentMiddle + intervalDelta);

                    if (minPowerLeft <= minPowerMid && minPowerRight <= minPowerMid) {
                        if (minPowerMid > maxMinPower) {
                            maxMinPower = minPowerMid;
                        }
                        break;
                    } else if (minPowerLeft > minPowerMid) {
                        currentRight = currentMiddle;
                    } else {
                        currentLeft = currentMiddle;
                    }
                }
            }

            return maxMinPower;
        }

        private double computeMinimumAdjustedPower(double current) {
            double minAdjustedPower = Double.POSITIVE_INFINITY;
            for (int i = 0; i < numberOfServers; i++) {
                double adjustedPower = powers[i] - Math.abs(current - currents[i]);
                minAdjustedPower = Math.min(minAdjustedPower, adjustedPower);
            }
            return minAdjustedPower;
        }

        private void writeOutput(double result) {
            BufferedWriter bufferedWriter = null;
            try {
                bufferedWriter = new BufferedWriter(new FileWriter("servere.out"));
                bufferedWriter.write(String.format("%.1f", result));
                bufferedWriter.close();
            } catch (IOException e) {
                throw new RuntimeException(e);
            } finally {
                try {
                    if (bufferedWriter != null) {
                        bufferedWriter.close();
                    }
                } catch (IOException ex) {
                    throw new RuntimeException(ex);
                }
            }
        }

    }

    public static void main(String[] args) {
        new Task().solve();
    }

}

