// Functia care calculeaza puterea unui server
double computePower(int n, vector<int>& puteri_server,
vector<int>& limite_alimentare, double c) {
    // Initializam puterea minima cu o valoare foarte mare
    double minPower = numeric_limits<double>::max();
    // Pentru fiecare server
    for (int i = 0; i < n; i++) {
        // Calculam puterea efectiva
        double power = puteri_server[i] - abs(c - limite_alimentare[i]);
        // Actualizam puterea minima
        minPower = min(minPower, power);
    }
    return minPower;
}


int main() {
    // Citirea datelor din fisierul de intrare
    ifstream fin("servere.in");
    if (!fin) {
        cerr << "Nu s-a putut deschide fisierul.";
        return 1;
    }

    // Citim numarul de servere
    int n;
    fin >> n;

    // Citim puterile si limitele de alimentare pentru fiecare server
    vector<int> puteri_server(n), limite_alimentare(n);
    for (int i = 0; i < n; ++i) {
        fin >> puteri_server[i];
    }
    for (int i = 0; i < n; ++i) {
        fin >> limite_alimentare[i];
    }
    fin.close();

    // Initializam limitele pentru cautare binara
    double low = 0.0;
    double high = 1e9;

    // Cautare binara pentru valoarea optima a curentului de alimentare
    while (high - low > 0.1) {
        double mid1 = low + (high - low) / 5;
        double mid2 = high - (high - low) / 5;

        double f1 = computePower(n, puteri_server, limite_alimentare, mid1);
        double f2 = computePower(n, puteri_server, limite_alimentare, mid2);

        if (f1 < f2) {
            low = mid1;
        } else {
            high = mid2;
        }
    }

    // Afisam puterea totala pentru valoarea curentului de alimentare optima
    ofstream fout("servere.out");
    fout << fixed << computePower(n, puteri_server, limite_alimentare,
    low)<< endl;
    fout.close();

    return 0;
}

