// Libraria care include toate librariile necesare
#include <bits/stdc++.h>

// Folosesc namespace std ca sa nu mai scriu std:: in fata functiilor standard
using namespace std;

// Definesc rescrictiile din enuntul temei
#define MAX_LIMIT pow(10, 9)
#define MIN_LIMIT 1

// Functie care calculeaza puterea minima a serverelor pentru un prag
double calc_P_min(int N, vector<int> P, vector<int> C, double prag) {
    // Initializez puterea minima cu limita din enunt
    double P_minim = MAX_LIMIT;

    // Calculez cea mai mica putere a serverelor pentru pragul dat
    for (int i = 0; i < N; i++) {
        P_minim = min(P_minim, P[i] - abs(prag - C[i]));
    }

    // Returnez puterea minima
    return P_minim;
}

int main() {
    // Deschid fisierele de intrare si iesire
    ifstream fin("servere.in");
    ofstream fout("servere.out");

    // Citesc numarul de servere
    int N;
    fin >> N;

    // Citesc puterile de calcul si limitele de alimentare ale serverelor
    vector <int> P(N), C(N);
    for (int i = 0; i < N; ++i) {
        fin >> P[i];
    }
    for (int i = 0; i < N; ++i) {
        fin >> C[i];
    }

    // Calculez limitele de alimentare minima si maxima a serverelor
    double minim = MAX_LIMIT, maxim = MIN_LIMIT;
    for (int i = 0; i < N; ++i) {
        minim = min(minim, (double)C[i]);
        maxim = max(maxim, (double)C[i]);
    }

    // Initializez rezultatul cu limita minima din enunt
    double result = MIN_LIMIT;

    // Cat timp diferenta intre limita maxima si minima este mai mare decat 0.1
    // verific daca exista un result mai bun decat cel curent
    while (maxim - minim > 0.1) {
        // Calculez pragul intervalului, care este mijlocul
        double prag = (maxim + minim) / 2;

        // Result va fi maximul dintre result si puterea maxima pentru prag
        result = max(result, calc_P_min(N, P, C, prag));

        // Verific daca puterea minima pentru prag + 0.1 este mai mica
        // decat cea pentru prag si fac schimbarile necesare la maxim si minim
        double P_min = calc_P_min(N, P, C, prag);
        double P_min_new = calc_P_min(N, P, C, prag + 0.1);
        if (P_min_new < P_min) {
            maxim = prag;
        } else {
            minim = prag;
        }
    }

    // Scriu rezultatul in fisierul de iesire
    fout << fixed << setprecision(1) << result << "\n";

    // Inchid fisierele
    fin.close();
    fout.close();

    return 0;
}

