        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;

public class Servere {
	public static int[] computingPower;
	public static int[] powerConsumption;
	public static int length;

	public static final String INPUT_FILE = "servere.in";
	public static final String OUTPUT_FILE = "servere.out";

	private static Map<String, Double> readInput() {
		try {
			Scanner sc = new Scanner(new File(INPUT_FILE));
			length = sc.nextInt();
			computingPower = new int[length];
			powerConsumption = new int[length];
			int left = Integer.MAX_VALUE, right = Integer.MIN_VALUE;

			for (int i = 0; i < length; i++) {
				computingPower[i] = sc.nextInt();
			}
			for (int i = 0; i < length; i++) {
				powerConsumption[i] = sc.nextInt();
				if (powerConsumption[i] < left) { // determinam limita inferioara
					left = powerConsumption[i];
				}
				if (powerConsumption[i] > right) { // determinam limita superioara
					right = powerConsumption[i];
				}
			}
			sc.close();
			Map<String, Double> interval = new HashMap<>();
			interval.put("left", (double) left);
			interval.put("right", (double) right);
			return interval; // le returnam ca un tuplu

		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	public static double optimalPower(double middle) {
		double optimalPower = Double.MAX_VALUE;
		for (int i = 0; i < length; i++) { // parcurgem fiecare server si aplicam formula
			double individualPower = computingPower[i] - Math.abs(powerConsumption[i] - middle);
			optimalPower = Math.min(optimalPower, individualPower);
		}
		return optimalPower;
	}

	public static double maxVicinity(double middle, double idealpower) { // gasim maximul vecin
		double maxLeft = Math.max(optimalPower(middle - 0.5), optimalPower(middle - 1));
		double maxRight = Math.max(optimalPower(middle + 0.5), optimalPower(middle + 1));
		double maxNeighbors = Math.max(maxLeft, maxRight);
		return Math.max(Math.max(maxNeighbors, optimalPower(middle)), idealpower);
	}

	public static double solve(double left, double right) {
		double idealPower = -(Double.MAX_VALUE);
		while (left < right) {
			double middle = (left + right) / 2; // determinam mijlocul
			double midPower = optimalPower(middle);
			idealPower = maxVicinity(middle, idealPower);

			if (Math.floor(middle) != middle) { // verificam daca mijlocul nu e intreg
				if (optimalPower(middle - 0.5) >= midPower) { //actualizam capetele
					right = middle - 0.5;
				} else if (optimalPower(middle + 0.5) >= midPower) {
					left = middle + 0.5;
				} else {
					return idealPower;
				}
			} else { // mijlocul este intreg
				if (optimalPower(middle - 1) >= midPower) { // actualizam capetele
					right = middle - 1;
				} else if (optimalPower(middle + 1) >= midPower) {
					left = middle + 1;
				} else {
					return idealPower;
				}
			}
		}
		return idealPower;
	}

	private static void writeOutput(double result) {
		try {
			PrintWriter pw = new PrintWriter(OUTPUT_FILE);
			pw.printf("%f", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	public static void main(String[] args) {
		Map<String, Double> interval = readInput();
		writeOutput(solve(interval.get("left"), interval.get("right")));
	}
}

