        #include <iostream>
#include <fstream>
#include <vector>
#include <iomanip>

#define stop 100

using namespace std;

struct server {
    int power, current;
};

// Custom abs function
float my_abs(double x) {
    if (x < 0)
        return -x;
    return x;
}

int main() {
    int n;
    double left, right, mid = 0, min_mid = 0;

    ifstream in("servere.in");
	if (!in)
		exit(-1);
	ofstream out("servere.out");
	if (!out)
		exit(-1);

    in >> n;
    vector<server> servers(n);

    for (int i = 0; i < n; i++)
        in >> servers[i].power;

    in >> servers[0].current;
    left = right = servers[0].current;

    for (int i = 1; i < n; i++) {
        in >> servers[i].current;
        if (servers[i].current > right)
            right = servers[i].current;
        if (servers[i].current < left)
            left = servers[i].current;
    }

    in.close();

    int step = 1;
    while (step < stop) {
        mid = (left + right) / 2;
        double third = (right - left) / 3;
        double third_left = left + third, third_right = left + 2 * third;
        double min_left , min_right;   // The power of the system
        double curr_left, curr_right, curr_mid;

        // Initialize minimum values
        min_left = servers[0].power - my_abs(servers[0].current - third_left);
        min_right = servers[0].power - my_abs(servers[0].current - third_right);
        min_mid = servers[0].power - my_abs(servers[0].current - mid);

        for (int i = 1; i < n; i++) {
            curr_left = servers[i].power -
                        my_abs(servers[i].current - third_left);
            curr_right = servers[i].power -
                        my_abs(servers[i].current - third_right);
            curr_mid = servers[i].power - my_abs(servers[i].current - mid);

            // Update the power of the system for each current
            if (curr_left < min_left)
                min_left = curr_left;
            if (curr_right < min_right)
                min_right = curr_right;
            if (curr_mid < min_mid)
                min_mid = curr_mid;
        }

        if (min_left > min_right)
            right = mid;
        else
            left = mid;

        step++;
    }

    out << fixed << setprecision(1) << min_mid;

    return 0;
}

