using namespace std;

class Task {
	public:
		void solve() {
			read_input();
			print_output(get_result());
		}

	private:
		// Number of servers
		int n;

		// Servers : first -> current required; second -> power
		vector <pair<int, int>> servers;

		void read_input() {
			ifstream fin("servere.in");

			fin >> n;

			// Powers and currents required (given as input)
			vector <int> powers(n), supplies(n);

			for (int i = 0; i < n; ++i) {
				fin >> powers[i];
			}

			for (int i = 0; i < n; ++i) {
				fin >> supplies[i];
			}

			// Generating the server list using the input
			for (int i = 0; i < n; ++i) {
				servers.push_back(make_pair(supplies[i], powers[i]));
			}

			fin.close();
		}

		double get_result() {
			// Sort the servers by the current required in ascending order
			sort(servers.begin(), servers.end());

			// Precompute the minimum value [0 ... i] and [i ... n]
			vector <int> min_left(n), min_right(n);

			min_left[0] = servers[0].second + servers[0].first;
			for (int i = 1; i < n - 1; ++i) {
				min_left[i] = min(min_left[i - 1], servers[i].second + servers[i].first);
			}

			min_right[n - 1] = servers[n - 1].second - servers[n - 1].first;
			for (int i = n - 2; i > 0; --i) {
				min_right[i] = min(min_right[i + 1], servers[i].second - servers[i].first);
			}

			// Consider each interval where the common current (sol) can be chosen
			// All the servers with the current required that are:
			// - to the left => power + current required - sol = power output
			// - to the right => power' - current required' + sol = power output
			// => for minimum value in the left and in the right:
			// sol = (power + current required - power' + current required') / 2
			for (int i = 0; i < n - 1; ++i) {
				double sol = 1.0 * (min_left[i] - min_right[i + 1]) / 2;
				if (sol >= servers[i].first && sol <= servers[i + 1].first) {
					return 1.0 * min_left[i] - sol;
				}
			}

			return -1;
		}

		void print_output(double result) {
			ofstream fout("servere.out");

			fout << fixed << setprecision(1) << result;

			fout.close();
		}
};

