        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Scanner;

public class Servere {
	private static int numberOfServers;
	private static ArrayList<Long> powers = new ArrayList<>();
	private static ArrayList<Long> thresholds = new ArrayList<>();
	private static long minThreshold = -1, maxThreshold = -1, maxPower = -1;

	private static void readInput() {
		try {
			// read from file
			File input = new File("servere.in");
			Scanner reader = new Scanner(input);
			numberOfServers = Integer.parseInt(reader.nextLine());
			String[] aux0 = reader.nextLine().split(" ");
			String[] aux1 = reader.nextLine().split(" ");
			reader.close();
			for (int i = 0; i < numberOfServers; i ++) {
				long powerAux = Integer.parseInt(aux0[i]);
				powers.add(powerAux);
				// get max power
				if (maxPower < powerAux || maxPower == -1) {
					maxPower = powerAux;
				}
				long thresholdAux = Integer.parseInt(aux1[i]);
				thresholds.add(thresholdAux);
				// get min threshold
				if (minThreshold > thresholdAux || minThreshold == -1) {
					minThreshold = thresholdAux;
				}
				// get max threshold
				if (maxThreshold < thresholdAux || maxThreshold == -1) {
					maxThreshold = thresholdAux;
				}
			}
		} catch (FileNotFoundException e) {
			System.err.println(e);
		}
	}

	public static void main(String[] args) {
		readInput();
		// unity to determinate local maximum
		double epsilon = 0.1;
		// the most "left" position
		double low = minThreshold;
		// the most "right" position
		double high = maxThreshold;
		double mid = 0;
		while (low <= high) {
			// get mid posititon
			mid = low + (high - low) / 2;
			double leftMin = maxPower;
			double rightMin = maxPower;
			double midMin = maxPower;
			// get minimum value of mid, left and right
			for (int i = 0; i < numberOfServers; i ++) {
				double auxMid = powers.get(i) 
					- Math.abs(mid - thresholds.get(i));
				double auxLeft = powers.get(i) 
					- Math.abs((mid - epsilon) - thresholds.get(i));
				double auxRight = powers.get(i) 
					- Math.abs((mid + epsilon) - thresholds.get(i));
				if (leftMin > auxLeft) {
					leftMin = auxLeft;
				}
				if (rightMin > auxRight) {
					rightMin = auxRight;
				}
				if (midMin > auxMid) {
					midMin = auxMid;
				}
			}
			// check if we find a local maximum
			if (leftMin < midMin && rightMin < midMin) {
				try {
					FileWriter writer = new FileWriter("servere.out");
					writer.write(String.format("%.1f", midMin));
					writer.close();
				} catch (IOException e) {
					System.err.println(e);
				}
				break;
			}
			// move to the "upper" position
			if (leftMin < midMin) {
				low = mid + epsilon;
			}
			if (rightMin < midMin) {
				high = mid - epsilon;
			}
		}
	}
}
