vector<tuple<int, int>> read_file(string filename){
	ifstream file(filename);
	vector<tuple<int, int>> servere;
	int N;
	file >> N;
	int power[N], consumption[N];
	for (int i = 0; i< N; i++){
		file >> power[i];
	}
	for (int i = 0; i< N; i++){
		file >> consumption[i];
		servere.push_back(make_tuple(power[i], consumption[i]));
	}
	file.close();
	return servere;
}


float calculateMinPower(vector<tuple<int, int>> servere, float cmid){
	float min_power = 999999999.0f;

	int server_index = 0;
	int mid_inf = -1, mid_sup = -1;
	for (int i = 0; i< servere.size(); i++){
		int cons = get<1>(servere[i]);
		float adjusted_pow = get<0>(servere[i]) - abs(cons - cmid);
		if (adjusted_pow < min_power){
			min_power = adjusted_pow;
		}
	}
	return min_power;
}


int main(){
	vector<tuple<int, int>> servere;

	servere = read_file("servere.in");
	// We need to find the min and the max value of Consumption
	// in order to perform binary search
	int min_consumption = 999999999;
	int max_consumption = -1;
	for (int i = 0; i< servere.size(); i++){
		if (get<1>(servere[i]) < min_consumption){
			min_consumption = get<1>(servere[i]);
		}
		if (get<1>(servere[i]) > max_consumption){
			max_consumption = get<1>(servere[i]);
		}
	}
