	// We need a vector to perform binary search for finding the optimal c value
	vector<int> c_values;

	float min_power = 999999999.0f;

	float cmid = 0;
	int left = 0 , right = max_consumption - min_consumption;
	int c = 0;
	while (1){
		cmid = (float)(min_consumption + left + min_consumption + right)/2;

		min_power = calculateMinPower(servere, cmid);
		float min_power_left = calculateMinPower(servere, cmid - 0.5);
		float min_power_right = calculateMinPower(servere, cmid + 0.5);
		cout << "left: " << left << " right: " << right << endl;
		cout << "min_power: " << min_power << " min_power_left: " << min_power_left << " min_power_right: " << min_power_right << endl;
		cout << "cmid: " << cmid << endl;
		if (min_power >= min_power_left && min_power >= min_power_right){
			break;
		}
		if (left == right - 1 && min_power_left < min_power_right){
			right += 1;
		} else if (left == right - 1 && min_power_left > min_power_right){
			left -= 1;
		}else if (min_power < min_power_right && min_power_right > min_power_left){
			left = (left + right)/2;
		}else if (min_power < min_power_left && min_power_left > min_power_right){
			right = (left + right)/2;
		}
		c++;
	}
	cout << "c: " << c << endl;
	// We write the result in the output file

	ofstream out("servere.out");
	out << fixed << setprecision(1) << min_power;
}
