using namespace std;
#include <iomanip>

class Servere {
	public:
		void solve() {
			read();
			print(get_rez());
		}

	private:
		int n;
		// vector de servere cu perechi de tip(putere, limita)
		vector<pair<int, int>> servere;

		void read() {
			ifstream fin("servere.in");
			fin >> n;

			servere.resize(n);
			int putere;
			int limita;

			// citesc toate puterile de calcul
			for (int i = 0; i < n; i++) {
				fin >> putere;
				servere[i].first = putere;
			}

			// citesc toate limitele de alimentare
			for (int i = 0; i < n; i++) {
				fin >> limita;
				servere[i].second = limita;
			}

			fin.close();
		}

		// functie de comparare pt sortare crescatoare in functie de limite
		static bool comp(const pair<int, int> &a, const pair<int, int> &b) {
			return a.second < b.second;
		}

		// functie pentru cautare binara
		double cautare_bin(vector<pair<int, int>> servere) {
			double left = servere[0].second;
			double right = servere[n - 1].second;
			double rez = -servere[n - 1].second;
			while (left <= right) {
				double mid = (left + right) / 2;
				double min = calcul(servere, mid);
				rez = max(rez, min);
				// calculez si pentru o eroare de 0.01
				double min_down = calcul(servere, mid - 0.01);
				double min_up = calcul(servere, mid + 0.01);

				if (min_down >= min) {
					right = mid - 0.01;
				} else if (min_up >= min) {
					left = mid + 0.01;
				} else {
					break;
				}
			}

			return rez;
		}

		// functie pentru calculul formulei
		double calcul(vector<pair<int, int>> servere, double mid) {
			double min = -1;
			double formula;
			for (int i = 0; i < n; i++) {
				formula = servere[i].first - abs(mid - servere[i].second);
				if (min == -1)
					min = formula;
				else if (min > formula)
					min = formula;
			}

			return min;
		}

		// functie care returneaza rezultatul
		double get_rez() {
			// sortez vectorul de perechi
			sort(servere.begin(), servere.end(), comp);
			double rez = cautare_bin(servere);
			return rez;
		}

		void print(int result) {
			ofstream fout("servere.out");
			fout << fixed << setprecision(1) << get_rez();
			fout.close();
		}
};

int main() {
