#include <queue>
#include <stack>
#include <vector>

using std::cout;
using std::endl;
using std::list;
using std::pair;
using std::priority_queue;
using std::sort;
using std::stack;
using std::vector;

struct Node {
  int n;
  int conn;
  bool visited;
};

int connections = 0;
int *conns;

void dfsDirect(int start, list<int> *graph, bool *direct) {
  list<int> stack;

  // push start node
  stack.push_back(start);

  while (!stack.empty()) {
    // get top node
    int node = stack.back();
    stack.pop_back();

    // if not visited
    if (!direct[node]) {
      direct[node] = true;
    }

    // push all adjacent nodes
    for (auto it = graph[node].begin(); it != graph[node].end(); it++) {
      if (!direct[*it]) {
        stack.push_back(*it);
      }
    }
  }
}

void dfsRec(int start, list<int> *graph, bool *visited, bool *direct) {
  visited[start] = true;
  if (!direct[start]) {
    connections++;
  }
  for (auto it = graph[start].begin(); it != graph[start].end(); it++) {
    if (!visited[*it] && !direct[*it]) {
      dfsRec(*it, graph, visited, direct);
    }
  }
}

// dfs iterative
void dfsIter(int start, list<int> *graph, bool *visited, bool *direct) {
  list<int> stack;

  // push start node
  stack.push_back(start);
  while (!stack.empty()) {
    // get top node
    int node = stack.back();
    stack.pop_back();

    // if not visited
    if (!visited[node]) {
      visited[node] = true;
      connections++;
    }

    // push all adjacent nodes
    for (auto it = graph[node].begin(); it != graph[node].end(); it++) {
      if (!visited[*it] && !direct[*it]) {
        stack.push_back(*it);
      }
    }
  }
}

struct CompareNode {
  bool operator()(const Node &a, const Node &b) { return a.conn < b.conn; }
};

int main() {
  FILE *f = fopen("ferate.in", "r");
  FILE *out = fopen("ferate.out", "w");

  int m, n = 0, x;
  fscanf(f, "%d %d %d", &n, &m, &x);
  int *in_degree = new int[n + 1];
  memset(in_degree, 0, sizeof(int) * (n + 1));

  list<int> *graph = new list<int>[n + 1];
  for (int i = 0; i < m; i++) {
    int x, y;
    fscanf(f, "%d %d", &x, &y);
    graph[x].push_back(y);
    in_degree[y]++;
  }
  bool *direct = new bool[n + 1];
  memset(direct, false, sizeof(bool) * (n + 1));
  priority_queue<Node, vector<Node>, CompareNode> pq;
  bool *visited = new bool[n + 1];
  dfsDirect(x, graph, direct);
  for (int i = 1; i <= n; i++) {
    if (!direct[i]) {
      connections = 0;

      memset(visited, false, sizeof(bool) * (n + 1));
      dfsRec(i, graph, visited, direct);
      // dfsIter(i, n, graph, visited, direct);
      connections--;
      Node node;
      node.n = i;
      node.conn = connections;
      pq.push(node);
    }
  }

  int min = 0;
  while (!pq.empty()) {
    Node node = pq.top();
    pq.pop();
    if (!direct[node.n]) {
      min++;
      dfsDirect(node.n, graph, direct);
    }
  }
  // print
  fprintf(out, "%d", min);
  return 0;
}

