// pt fiecare nod o sa am in scc[node] scc-ul caruia apartine
vector<int> sccs(100001, false), order;
vector<bool> seen(100001);  // nodurile in care am fost

int sccCount;  // counter pt componentele tari conexe

// dfs ca sa vedem care i ordinea nodurilor
void dfs(int v, vector<int>& order) {
    seen[v] = true;

    for (int i = 0; i < graph[v].size(); i++)
        if (seen[graph[v][i]] == false)
            dfs(graph[v][i], order);

    order.push_back(v);
}

// dfs invers ca sa punem numere de scc pe fiecare nod
void dfsRev(int v) {
    sccs[v] = sccCount;
    seen[v] = true;

    for (int i = 0; i < graphRev[v].size(); i++)
        if (seen[graphRev[v][i]] == false)
            dfsRev(graphRev[v][i]);
}

// functie care creaza componente tare conexe (scc)
void findTareConexa(int n) {
    sccCount = 0;
    seen.assign(n + 1, false);  // dau unsee la vector

    for (int i = 1; i <= n; i++)  // iau toate nodurile si fac dfs pentru ele
        if (!seen[i])
            dfs(i, order);

    seen.assign(n + 1, false);  // dau iar unsee la vector

    // si acum merg invers pentru ca fac dfsRev
    for (int i = order.size() - 1; i >= 0; i--) {
        if (!seen[order[i]]) {
            dfsRev(order[i]);
            sccCount++;
        }
    }
}

int main() {
    ifstream fin("ferate.in");
    ofstream fout("ferate.out");

    int x, y, N, M, S;
    int sccProst = 0;
    fin >> N >> M >> S;

    for (int i = 1; i <= M; i++) {  // creez graful si graful invers
        fin >> x >> y;
        graph[x].push_back(y);
        graphRev[y].push_back(x);
    }

    // stabilesc cate bucati din graf sunt elemente tari conexe
    findTareConexa(N);

    vector<int> rank(sccCount, 0);

    // vad in cate dintre componentele tari conexe nu intra nimic
    for (int v = 1; v <= N; v++) {
        // for (int u : graph[v]) {
        for (int i = 0 ; i < graph[v].size() ; i++) {
            // verific daca nodul vecin apartine altui scc
            if (sccs[graph[v][i]] != sccs[v])
                rank[sccs[graph[v][i]]]++;  // si daca da, cresc rankul scc-ulu
        }
    }

    for (int i = 0; i < sccCount; i++) {
        // verific daca rank-ul este zero
        // si daca componenta curenta nu are nodul S
        if (rank[i] == 0 &&
                find(graph[i + 1].begin(),
                    graph[i + 1].end(),
                    S) == graph[i + 1].end())
            // imi pare rau pentru abominatia de mai sus,
            // nu ma lasa cu coding style-ul
            sccProst++;
            // inseamna ca aceasta componenta este izolata
            // si are nevoie de sina pana aici
    }

    fout << sccProst;  // afisez rezultatul

    fin.close();
    fout.close();

    return 0;
}

