// Funcția DFS care explorează graful și găsește componentele conexe tari
void dfs(int node, int &timestamp, vector<vector<int>> &all_sccs) {
    // Marchează nodul ca fiind vizitat și inițializează low_link
    // și found cu timestamp-ul curent
    found[node] = ++timestamp;
    low_link[node] = found[node];
    nodes_stack.push(node);
    in_stack[node] = true;

    // Parcurge vecinii nodului
    for (auto neigh : adj[node]) {
        if (parent[neigh] != -1) {
            // Verifică dacă vecinul este în stivă
            if (in_stack[neigh]) {
                low_link[node] = min(low_link[node], found[neigh]);
            }
            continue;
        }
        // salveaza parintele
        parent[neigh] = node;
        dfs(neigh, timestamp, all_sccs);
        // actualizați low_link[node] cu informațiile obținute prin neigh
        low_link[node] = min(low_link[node], low_link[neigh]);
    }

    // Verifică dacă nodul este rădăcina unei componente tare conexe
    if (low_link[node] == found[node]) {
        // Se găsește o nouă componentă tare conexă
        vector<int> scc;
        do {
            auto x = nodes_stack.top();
            nodes_stack.pop();
            in_stack[x] = false;

            scc.push_back(x);
        }while (scc.back() != node);
            all_sccs.push_back(scc);
    }
}
// Funcția care aplică algoritmul lui Tarjan pentru a găsi toate componentele
// tari conexe din graf
vector<vector<int>> tarjan_scc() {
    parent = vector<int>(n + 1, -1);
    found = vector<int>(n + 1, -1);
    low_link = vector<int>(n + 1, -1);
    in_stack = vector<bool>(n + 1, false);

    // vizitați toate nodurile
    vector<vector<int>> all_sccs;
    int timestamp = 0;

    for (int node = 1; node <= n; ++node) {
        if (parent[node] == -1) {
            parent[node] = node;
            // începe un nou DFS traversează acest subarbore
            dfs(node, timestamp, all_sccs);
        }
    }
    return all_sccs;
}

int main() {
