    ofstream fout("ferate.out");

    fin >> n >> m >> s;
    // Citirea muchiilor grafului
    for (int i = 1, x, y; i <= m; i++) {
        fin >> x >> y;
        adj[x].push_back(y);
    }
    // Determină toate componente tare conexe folosind algoritmul lui Tarjan
    const vector<vector<int>> all_sccs = tarjan_scc();
    vector<int> indegree(n + 1, 0);
    int sursa = 0;

    // Calculează gradul intern al fiecărei componente tare conexe
    for (size_t i = 0; i < all_sccs.size(); i++) {
        const vector<int> &scc = all_sccs[i];
        for (size_t j = 0; j < scc.size(); j++) {
            int node = scc[j];

            for (size_t k = 0; k < adj[node].size(); k++) {
                int neighbor = adj[node][k];
                bool found = false;
                for (size_t l = 0; l < scc.size(); l++) {
                    if (scc[l] == neighbor) {
                        found = true;
                        break;
                    }
                }

                if (!found) {
                    indegree[neighbor]++;
                }
            }
        }
    }
    // Calculează gradul intern al CTC și verifică dacă nodul s este prezent
    // și gradul intern este 0
    int ctr = 0;
    for (const auto &scc : all_sccs) {
        int internal_degree = 0;
        bool is_s_node_present = false;

        for (auto node : scc) {
            internal_degree += indegree[node];

            if (node == s) {
                is_s_node_present = true;
            }
        }

        if (is_s_node_present && internal_degree == 0) {
            sursa++;
        }

        if (internal_degree == 0) {
            ctr++;
        }
    }

    // Calculează și afișează rezultatul final
    fout << ctr - sursa << endl;
    return 0;
}

