					if (dfsSimplu == 0 && gariBune.get(matrice.get(gara).get(i)) == 0) {
						dfs(matrice, gariVizitate, gariBune, matrice.get(gara).get(i),
								gariVizitateDfs, dfsSimplu);
					}
				}
			}
		}
	}

	public static void main(String[] args) throws IOException {
		MyScanner in;
		in = new MyScanner(new FileReader("ferate.in"));

		int nrGari = in.nextInt();
		int nrLinii = in.nextInt();
		int garaStart = in.nextInt();
		/// salvez listele de adiacenta
		ArrayList<ArrayList<Integer>> matrice = new ArrayList<ArrayList<Integer>>();
		/// vizitateLocal este un vector bidimensional pentru
		/// a rula dfs avand drept start fiecare nod care nu
		/// a fost conectat initial cu garaStart
		List<List<Integer>> vizitateLocal = new ArrayList<List<Integer>>();
		/// in gariVizitate salvez parcurgerea dfs din gara start
		/// si il folosesc ca reper pentru a vedea nodurile
		/// inaccesibile din gara start
		ArrayList<Integer> gariVizitate = new ArrayList<Integer>();
		/// in gariVizitateDfs salvez nodurile parcurse in dfs
		/// pentru a determina numarul acestora
		/// deci vom folosi doar size ul lor
		ArrayList<Integer> gariVizitateDfs = new ArrayList<Integer>();
		for (int i = 0; i < nrGari + 1; i++) {
			ArrayList<Integer> linie = new ArrayList<Integer>();
			matrice.add(linie);
			vizitateLocal.add(linie);

			gariVizitate.add(0);
			gariVizitateDfs.add(0);
		}
		for (int i = 0; i < nrLinii; i++) {
			int x = in.nextInt();
			int y = in.nextInt();
			matrice.get(x).add(y);
		}

		/// aplic un simplu dfs initial
		dfs(matrice, gariVizitate, null, garaStart, gariVizitateDfs, 1);

		/// pentru fiecare nod neaccesibil din sursa aplic dfs
		/// si vreau sa vad cate noduri am putut accesa din acesta
		PriorityQueue<Corespondenta> coada = new PriorityQueue<>(new CorespondentaComparator());

		for (int i = 1; i < nrGari + 1; i++) {
			if (gariVizitate.get(i) == 0) {
				/// trebuie initializat si setat cu 0
				vizitateLocal.set(i, new ArrayList<Integer>(Collections.nCopies(nrGari + 1, 0)));
				dfs(matrice, vizitateLocal.get(i), gariVizitate, i, gariVizitateDfs, 0);

				int nrGariAccesibile = gariVizitateDfs.size();
				/// resetez garile vizitate din dfs
				/// ma ajuta pentru a afla cate am parcurs
				gariVizitateDfs.clear();
				coada.add(new Corespondenta(nrGariAccesibile, i));
			}
		}

		int muchii = 0;

		while (!coada.isEmpty()) {
			Corespondenta elem = coada.poll();
			/// daca nu pot ajunge din acest nod
			/// rulez un dfs
			if (gariVizitate.get(elem.nodStart) == 0) {
				dfs(matrice, gariVizitate, null, elem.nodStart, gariVizitateDfs, 1);
				/// deoarece am conectat prin rularea unui dfs
				/// incrementez numarul de muchii
				muchii++;
			}
		}

		try (var printer = new PrintStream("ferate.out")) {
			printer.println(muchii);
		}

	}

