		}
	}

	static class Corespondenta {
		int count;
		int nodStart;

		Corespondenta(int count, int nodStart) {
			this.count = count;
			this.nodStart = nodStart;
		}
	}

	static class CorespondentaComparator implements Comparator<Corespondenta> {
		public int compare(Corespondenta a, Corespondenta b) {
			if (a.count > b.count) {
				return -1;
			} else if (a.count < b.count) {
				return 1;
			} else {
				return 0;
			}
		}
	}
}

