        #include <bits/stdc++.h>
using namespace std;

#define MAX_N 999999

struct Node {
    vector<int> adj;
    vector<int> rev_adj;
};

Node graph[MAX_N];
stack<int> S;
bool visited[MAX_N];

int component[MAX_N];
vector<int> components[MAX_N];
int numComponents;
int n, m, val;

unordered_set<int> inDegree[MAX_N];

// functia de cititre
void read_input() {
    ifstream fin("ferate.in");

    fin >> n >> m >> val;

    for (int i = 0, x, y; i < m; i++) {
        fin >> x >> y;
        graph[x].adj.push_back(y);
        graph[y].rev_adj.push_back(x);
    }

    fin.close();
}

// dfs
void DFS1(int x) {
    visited[x] = true;
    for (int i = 0; i < graph[x].adj.size(); i++)
        if (!visited[graph[x].adj[i]])
            DFS1(graph[x].adj[i]);

    S.push(x);
}

// dfs
void DFS2(int x) {
    component[x] = numComponents;
    components[numComponents].push_back(x);
    visited[x] = true;
    for (int i = 0; i < graph[x].rev_adj.size(); i++)
        if (!visited[graph[x].rev_adj[i]])
            DFS2(graph[x].rev_adj[i]);
}

// kosaraju luat de pe linkul din README
void Kosaraju() {
    for (int i = 1; i <= n; i++)
        if (!visited[i])
            DFS1(i);

    for (int i = 1; i <= n; i++)
        visited[i] = false;

    while (!S.empty()) {
        int v = S.top();
        S.pop();
        if (!visited[v]) {
            DFS2(v);
            numComponents++;
        }
    }
}

// calcularea gradului intern al unei componente tari conexe
void get_result() {
    for (int i = 1; i <= n; i++)
        for (int j = 0; j < graph[i].adj.size(); j++) {
            int u = graph[i].adj[j];
            if (component[i] != component[u])
                inDegree[component[u]].insert(component[i]);
        }
}

// elementele ce vor fi afisate
int output() {
    int sum = 0;

    for (int i = 0; i < numComponents; i++) {
        bool containsVal = false;
        for (int j = 0; j < components[i].size(); j++)
            if (components[i][j] == val) {
                containsVal = true;
                break;
            }

        if (!containsVal && inDegree[i].empty())
            sum++;
    }

    return sum;
}

// apelarea functiilor si afisarea
int main() {
    ofstream fout("ferate.out");

    read_input();
    Kosaraju();
    get_result();

    fout << output();

    fout.close();
    return 0;
}

