		if (!good[i]) {
			cnt = 0;
			memset(vis, false, sizeof(vis));

			// gaseste cnt-ul acestui nod
			dfs2(i);
			val.push_back(make_pair(cnt, i));
		}
	}

	// sorteaza in ordine descrescatoare
	sort(val.begin(), val.end());
	reverse(val.begin(), val.end());

	// gaseste numarul minim de muchii necesare
	int ans = 0;
	for (auto it : val) {
		if (!good[it.second]) {
			++ans;
			dfs1(it.second);
		}
	}
    if ( n == 1)
        return 1;
	else
		return ans-1;
}

