import java.util.Collections;
import java.util.PriorityQueue;
import java.util.StringTokenizer;

class Ferate {
	int count = 0;
	int nr;
	boolean[] reached;

	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("ferate.in"));

		// numarul de gari
		var N = scanner.nextInt();
		// numarul de linii ferate existente
		int M;
		M = scanner.nextInt();
		// gara ce reprezinta depozitul principal
		int S;
		S = scanner.nextInt();

		// lista de adiacenta
		ArrayList<Integer>[] adj = new ArrayList[N + 1];
		for (var i = 1; i <= N; i += 1) {
			adj[i] = new ArrayList<>();
		}

		// vector ce retine gradul intern al nodurilor
		var in_degree = new int[N + 1];
		Arrays.fill(in_degree, 0);

		for (var i = 1; i <= M; i += 1) {
			var x = scanner.nextInt();
			var y = scanner.nextInt();
			adj[x].add(y);
			++in_degree[y];
		}


		FileWriter writer = new FileWriter("ferate.out");

		BufferedWriter output = new BufferedWriter(writer);

		output.write(String.valueOf(new Ferate().getResult(N, M, S, adj, in_degree)));

		output.close();
	}

	public class Pair implements Comparable<Pair> {
		public int node;
		public int priority;

		Pair(int _node, int _priority) {
			node = _node;
			priority = _priority;
		}

		public int compareTo(Pair p) {
			return Integer.compare(priority, p.priority);
		}

	}

	private int getResult(int N, int M, int S, ArrayList<Integer>[] adj, int[] in_degree) {
		// adaug arc de la S la nod cu in_degree 0
		for (var i = 1; i <= N; i++) {
			if (i != S && in_degree[i]++ == 0) {
				adj[S].add(i);
				count++;
			}
		}

		// vector care indica daca se poate ajunge la un nod de la sursa
		reached = new boolean[N + 1];
		Arrays.fill(reached, false);

		dfs(S, reached, adj, 0);

		// coada de prioritati in care pun nodurile nevizitate 
		PriorityQueue<Pair> pq = new PriorityQueue<>(Collections.reverseOrder());

		// pentru fiecare nod la care nu pot ajunge numar la cate noduri nevizitate poate ajunge
		for (int i = 1; i <= N; i++) {
			if (reached[i] == false) {
				nr = 0;
				boolean[] reachable = new boolean[N + 1];
				Arrays.fill(reachable, false);
				dfs(i, reachable, adj, 1);
				pq.add(new Pair(i, nr));
			}
		}

		int oprire = 1;
		// atata timp cat nu s-a ajuns la toate nodurile
		while (oprire != 0 && pq.size() > 0) {
			if (pq.size() == 1) {
				count++;
				oprire = 0;
				break;
			}
			int node = pq.poll().node;
			if (reached[node] == false) {
				// adaug muchie catre primul nod din coada de prioritati
				count++;
				// parcurg graful si marchez noile noduri la care se poate ajunge
				dfs(node, reached, adj, 0);
			}

			// verific daca s-a ajuns la toate nodurile
			int ok = 0;
			for (int i = 1; i <= N; i++) {
				if (reached[i] == false) {
					ok = 1;
					break;
				}
			}
			if (ok == 0) {
				oprire = 0;
			}
		}

		return count;
	}

	void dfs(int node, boolean[] visited, ArrayList<Integer>[] adj, int ok) {
		visited[node] = true;

		// daca ok = 1 numar cate noduri nevizitate pot fi vizitate 
		if (ok == 1) {
			for (int v : adj[node]) {
				if (!visited[v] && !reached[v]) {
					nr++;
					dfs(v, visited, adj, ok);
				}
			}
		} else {
			for (int v : adj[node]) {
				if (!visited[v]) {
					dfs(v, visited, adj, ok);
				}
			}
		}

	}

