        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Stack;
import java.util.TreeSet;


public class Ferate {

	static int n;
	static int m;
	static int s;
	static int time = 0;
	static int ans = 0;
	static ArrayList<ArrayList<Integer>> graph = new ArrayList<>();
	static ArrayList<ArrayList<Integer>> invertedGraph = new ArrayList<>();
	static int[] indegree;
	static int[] outdegree;
	static TreeSet<Integer> accessible = new TreeSet<>();
	static ArrayList<ArrayList<Integer>> cycles = new ArrayList<>();


	public static void main(String[] args) {
		parse();
		tarjan();

		for (ArrayList<Integer> cycle : cycles) {
			if (cycle.size() == 1) {
				if (indegree[cycle.get(0)] == 0) {
					if (!accessible.contains(cycle.get(0))) {
						ans++;
						updateAccess(cycle.get(0));

					}

				}
			} else {

				boolean outside = false;
				for (Integer i : cycle) {
					for (Integer i2 : invertedGraph.get(i)) {
						if (!cycle.contains(i2 - 1)) {
							outside = true;
							break;
						}
					}
					if (outside) {
						break;
					}
				}

				if (!outside) {
					boolean found = false;
					for (Integer in : cycle) {
						if (accessible.contains(in)) {
							found = true;
							break;
						}
					}
					if (!found) {
						for (Integer in : cycle) {
							updateAccess(in);
						}
						ans++;
					}
				}
			}

		}

		try (PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter("ferate.out")))) {
			System.out.println(ans);
			pw.println(ans);
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	static void parse() {
		try (BufferedReader br = new BufferedReader(new FileReader("ferate.in"))) {
			String str = br.readLine();
			String[] split = str.split(" ");

			n = Integer.parseInt(split[0]);
			m = Integer.parseInt(split[1]);
			s = Integer.parseInt(split[2]);

			indegree = new int[n];
			outdegree = new int[n];
			for (int i = 0; i < n; i++) {
				graph.add(new ArrayList<>());
				invertedGraph.add(new ArrayList<>());
				indegree[i] = 0;
				outdegree[i] = 0;
			}

			for (int i = 0; i < m; i++) {
				str = br.readLine();
				split = str.split(" ");

				int x = Integer.parseInt(split[0]);
				int y = Integer.parseInt(split[1]);

				graph.get(x - 1).add(y);
				invertedGraph.get(y - 1).add(x);
				outdegree[x - 1]++;
				indegree[y - 1]++;
			}

			updateAccess(s - 1);
		} catch (FileNotFoundException e) {
			throw new RuntimeException(e);
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	static void tarjanUtil(int i, int[] low, int[] disc, boolean[] member, Stack<Integer> stack) {
		disc[i] = time;
		low[i] = time;
		time++;
		member[i] = true;
		stack.push(i);

		for (Integer in : graph.get(i)) {
			if (disc[in - 1] == -1) {
				tarjanUtil(in - 1, low, disc, member, stack);
				low[i] = Math.min(low[i], low[in - 1]);
			} else if (member[in - 1]) {
				low[i] = Math.min(low[i], disc[in - 1]);
			}
		}

		int w = -1;
		if (low[i] == disc[i]) {
			int count = 0;
			ArrayList<Integer> cycle = new ArrayList<>();
			while (w != i) {
				w = stack.pop();
				cycle.add(w);
				member[w] = false;
				count++;
			}
			cycles.add(cycle);
		}
	}

	static void tarjan() {
		int[] disc = new int[n];
		int[] low = new int[n];
		for (int i = 0; i < n; i++) {
			disc[i] = -1;
			low[i] = -1;
		}

		boolean[] member = new boolean[n];
		Stack<Integer> stack = new Stack<>();

		for (int i = 0; i < n; i++) {
			if (disc[i] == -1) {
				tarjanUtil(i, low, disc, member, stack);
			}
		}
	}

	static void updateAccess(int node) {
		if (!accessible.contains(node)) {
			accessible.add(node);
			for (Integer i : graph.get(node)) {
				updateAccess(i - 1);
			}
		}
	}
}


