using namespace std;


int minCompressedLength(vector<int> &A, vector<int> &B) {
    int m = A.size();
    int n = B.size();

    int length = 0, i = 0, j = 0;
    int sumA = 0, sumB = 0;

    // Parcurgem ambii vectori până când ajungem la finalul lor
    while (i != m || j != n) {
        // Adăugăm la suma parțială doar dacă nu am depășit limitele vectorului
        if (i != m || j != n) {
            // Adăugăm doar la suma parțială a vectorului cu suma mai mică
            if (sumA < sumB) {
                sumA += A[i++];
            } else {
                sumB += B[j++];
            }
        }

         // Dacă sumele parțiale sunt egale, creștem lungimea compresiei
         if (sumA == sumB) {
            length++;
            sumA = 0;
            sumB = 0;
        }
    }

    // Verificăm dacă am parcurs toți elementele din ambele vectori
    if (i != m || j != n) {
        length = -1;
    }

    return length;
}


int main() {
    ifstream in("compresie.in");
    ofstream out("compresie.out");

    int m, n;

    // Citim vectorul A
    in >> m;

    vector<int> A(m);

    for (int i = 0; i<m; i++) {
        in >> A[i];
    }

    // Citim vectorul B
    in >> n;

    vector<int> B(n);

    for (int i = 0; i<n; i++) {
        in >> B[i];
    }

    // Calculăm lungimea compresiei
    int result = minCompressedLength(A, B);
    out << result << endl;

    in.close();
    out.close();

    return 0;
}

