void compress(unsigned long long* A, unsigned long long* B,
unsigned long long& elements,
unsigned long long N, unsigned long long M) {
    unsigned long long i = 1, j = 1;

    unsigned long long sum_A = A[0], sum_B = B[0];

    while (i < N && j < M) {
        if (sum_A > sum_B) {
            sum_B += B[j++];
        } else if (sum_A < sum_B) {
            sum_A += A[i++];
        } else {
            elements++;
            sum_A = A[i];
            sum_B = B[j];
            ++i;
            ++j;
        }
    }

    // Check the remaining elements
    while (i < N) {
        sum_A += A[i++];
    }

    while (j < M) {
