			exception.printStackTrace();
		}
	}

	private void writeOutput(double result) {
		try (BufferedWriter bufferedWriter = new BufferedWriter(new FileWriter(OUTPUT_FILE_NAME))) {
			bufferedWriter.write(String.format("%.1f\n", result));

		} catch (IOException exception) {
			exception.printStackTrace();
		}
	}

	private void solve() {
		readInput();
		try {
			writeOutput(getResult());
		} catch (IOException exception) {
			exception.printStackTrace();
		}
	}

	public double getResult() throws IOException {
		Scanner scanner = new Scanner(new FileReader("compresie.in"));

		scanner.nextLine();
		scanner.nextLine();
		scanner.nextLine();

		int debt = 0;

		int res = 0;

		int currentB = scanner.nextInt();
		int cumul = currentB;
		boolean exit = false;

		for (int i = 1; i <= n; i++) {
			int currentA = A.get(i);

			while (debt != 0) {
				while (debt + currentA < cumul) {
					debt += currentA;

					i++;
					if (i > n) {
						return -1;
					}

					currentA = A.get(i);
				}

				if (debt + currentA == cumul) {
					res += 1;
					debt = 0;

					if (i != n) {
						currentB = scanner.nextInt();
						cumul = currentB;
					}

					exit = true;
					continue;
				}

				if (!scanner.hasNextInt()) {
					return -1;
				}
				cumul += scanner.nextInt();
			}

			if (exit) {
				exit = false;
				continue;
			}

			/* Debt == 0 */
			while (currentA > cumul) {
				if (!scanner.hasNextInt()) {
					return -1;
				}

				currentB = scanner.nextInt();
				cumul += currentB;
			}

			if (currentA == cumul) {
				res += 1;

				if (i != n) {
					currentB = scanner.nextInt();
					cumul = currentB;
				} else if (scanner.hasNextInt()) {
					return -1;
				}
			} else if (currentA < cumul) {
				debt += currentA;
			}
		}

		if (scanner.hasNextInt()) {
			return -1;
		}

		return res;
	}

	public static void main(String[] args) {
		Compresie compresie = new Compresie();
		compresie.solve();
	}
}

