        import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

public class Compresie {

    private static int compresie(int n, int m, List<Double> A, List<Double> B) {

        int ida = 0;
        int idb = 0;

        while (ida < A.size() && idb < B.size()) {
            if (Objects.equals(A.get(ida), B.get(idb))) {
                ida++;
                idb++;
            } else if (A.get(ida) > B.get(idb)) {
                if (idb + 1 < B.size()) {
                    B.set(idb + 1, B.get(idb) + B.get(idb + 1));
                }
                B.remove(idb);
            } else {
                if (ida + 1 < A.size()) {
                    A.set(ida + 1, A.get(ida) + A.get(ida + 1));
                }
                A.remove(ida);
            }
        }

        if (A.size() == B.size()) {
            return A.size();
        } else {
            return -1;
        }
    }

    public static void main(String[] args) throws IOException {
        var scanner = new MyScanner(new FileReader("compresie.in"));
        var n = scanner.nextInt();

        List<Double> A = new ArrayList<>();
        List<Double> B = new ArrayList<>();

        for (int i = 0; i < n; i++) {
            A.add(scanner.nextDouble());
        }

        var m = scanner.nextInt();

        for (int i = 0; i < m; i++) {
            B.add(scanner.nextDouble());
        }

        var answer = compresie(n, m, A, B);

        try (var writer = new BufferedWriter(new FileWriter("compresie.out"))) {
            writer.write(Integer.toString(answer) + "\n");
        }
    }
}

