        #include <iostream>
#include <fstream>
#include <vector>

using namespace std;

int subsequence(int n, vector<int> A, int m, vector<int> B) {
    vector<int> result;  // pastrez rezultatul gasit
    int suma = 0;  // pastrez suma la fiecare pas
    int i = 0;
    int j = 0;
    while (i < n && j < m) {  // iterez  prin vector
        if (A[i] == B[j]) {  // elemente egale, pastrez doar unul
            result.push_back(A[i]);
            suma = 0;
            i++;
            j++;
        } else if (A[i] > B[j]) {  // calculez suma in B pina e egal
            while (suma < A[i] && j < m) {
                suma += B[j];
                j++;
            }
            j--;
            if (j != m - 1 && suma != A[i]) {  // suma diferita de A[i]
                B[j] = suma;  // inlocuiesc B[j] cu suma calculata
                suma = 0;
            }
            if (suma == A[i]) {  // suma egala cu A[i]
                    result.push_back(suma);  // pastrez rezultatul
                    i++;
                    j++;
                    suma = 0;
                }
        } else {
            while (suma < B[j] && i < n) {  // calculez suma in B pina e egal
                suma += A[i];
                i++;
            }
            i--;
            if (i != n - 1 && suma != B[j]) {  // suma diferita de A[i]
                    A[i] = suma;  // inlocuiesc B[j] cu suma calculata
                    suma = 0;
            }
            if (suma == B[j]) {  // suma egala cu B[j]
                    result.push_back(suma);  // pastrez rezultatul
                    i++;
                    j++;
                    suma = 0;
                }
        }
    }
    if (i == n && j == m - 1) {
        j++;  // schimb indicii daca am parcurs tot vectorul A
    }
    if (j == m && i == n - 1) {
        i++;  // schimb indicii daca am parcurs tot vectorul B
    }
    if (n != i || m != j) {  // se depaseste lungimea
        return -1;
    }
    return result.size();  // returnez lungimea maxima a sirului
}

int main() {
    ifstream input("compresie.in");
    ofstream output("compresie.out");
    int n;
    input >> n;
    vector<int> A(n);
    for (int i = 0; i < n; i++) {
        input >> A[i];
