using namespace std;

int main() {
    ifstream fin("compresie.in");
    ofstream fout("compresie.out");

    int n, m;
    fin >> n;

    // citesc elementele vectorilor
    vector<int> a(n), aux1(1000000);
    for (int i = 0; i < n; ++i) {
        fin >> a[i];
    }
    fin >> m;
    vector<int> b(m), aux2(1000000);
    for (int i = 0; i < m; ++i) {
        fin >> b[i];
    }

    // count1 si count2 reprezinta indecsii care imi arata unde am ajuns in
    // vectorii originali, distance-urile sunt ca sa stiu cate numere am adunat
    // count_aux sunt ca sa vad unde am ajuns in noii vectori formati
    int count1 = 0, count2 = 0, count_aux1 = 0, count_aux2 = 0;
    int distance1 = 0, distance2 = 0;

    // cat timp mai pot sa adun si trebuie sa verific
    while (n >= (count1 + distance1) && m >= (count2 + distance2)) {
        // trec la urmatoarele numere
        if (a[count1] == b[count2]) {
            // adaug numerele in vectori
            aux1[count_aux1] = a[count1];
            aux2[count_aux2] = b[count2];

            // mut indexul dupa numerele adunate
            count1 += distance1 + 1;
            count2 += distance2 + 1;

            // cresc indecsii vectorilor si reinitializez distantele
            count_aux1++;
            count_aux2++;
            distance1 = 0;
            distance2 = 0;
        } else if (a[count1] < b[count2]) {
            // cresc distanta pentru a sti de unde iau urmatorul numar
            distance1++;

            // adun numarul urmator la cel curent
            a[count1] += a[count1 + distance1];
        } else if (a[count1] > b[count2]) {
            distance2++;
            b[count2] += b[count2 + distance2];
        }
    }

    if (aux1 == aux2) {
        // scot 0-urile de la final
        auto it = find(aux1.begin(), aux1.end(), 0);
        if (it != aux1.end()) {
            aux1.resize(it - aux1.begin());
        }

        fout << size(aux1);
    } else {
        fout << -1;
    }

    fin.close();
    fout.close();

    return 0;
}

