#include <algorithm>

using namespace std;
ifstream fin("compresie.in");
ofstream fout("compresie.out");

void binary_search(vector<int> &v, int x, int &commonElements) {
    int left = 0;
    int right = v.size() - 1;

    while (left <= right) {
        int middle = left + (right - left) / 2;

        if (v[middle] == x) {
            commonElements++;
            return;
        }

        if (v[middle] < x) {
            left = middle + 1;
        } else {
            right = middle - 1;
        }
    }
}

int main() {
    int n, m;
    vector<int> a;
    vector<int> b;

    if (!fin) {
        cerr << "Unable to open file";
        return 1;
    }

    fin >> n;
    a.resize(n);
    for (int i = 0; i < n; i++) {
        fin >> a[i];
    }

    fin >> m;
    b.resize(m);
    for (int i = 0; i < m; i++) {
        fin >> b[i];
    }

    // Fac vector de sume partiale pt cei doi vectori
    vector<int> sumA(n, 0);
    vector<int> sumB(m, 0);

    sumA[0] = a[0];
    for (int i = 1; i < n; i++) {
        sumA[i] = sumA[i - 1] + a[i];
    }

    sumB[0] = b[0];
    for (int i = 1; i < m; i++) {
        sumB[i] = sumB[i - 1] + b[i];
    }

    // Vad elementele comune din cei doi vectori de sume partiale
    int commonElements = 0;
    for (int i = 0; i < n; i++) {
        binary_search(sumB, sumA[i], commonElements);
    }

    if (commonElements == 0) {
        fout << "-1";
    } else {
        fout << commonElements << "\n";
    }

    return 0;
}

