    while (equal(A.begin(), A.end(), B.begin()) == false) {
        // check if index is out of bounds
        if (A[index] == B[index]) {
            // increment index
            index++;
            continue;
        }
        // index for keeping track of the shifting instead of erasing every time
        int shiftingIndex = 1;
        if (A[index] < B[index]) {
            while (A[index] < B[index]) {
                // add A[index + 1] to A[index] and remove A[index + 1]
                A[index] += A[index + shiftingIndex];
                shiftingIndex++;
                // check again
            }
            // erase the elements that were added to A[index]
            A.erase(A.begin() + index + 1, A.begin() + index + shiftingIndex);
        } else {
            while (A[index] > B[index]) {
                // add A[index] to A[index + 1] and remove A[index]
                B[index] += B[index + shiftingIndex];
                shiftingIndex++;
                // check again
            }
            // erase the elements that were added to A[index + 1]
            B.erase(B.begin() + index + 1, B.begin() + index + shiftingIndex);
        }
    }
    fout << A.size() << "\n";
    fin.close();
    fout.close();
    return 0;
}

