    for (int i = 1; i <= n; i++) {
        int current_max = activare[i];

        for (int j = i + 1; j <= n; j++) {
            if (activare[j] > current_max) {
                current_max = activare[j];
            }
        }

        max_activ[i] = current_max;
    }

    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    vector<int> last_line_max(n + 1, 0);
    vector<int> current_line_max(n + 1, 0);

    for (int i = 1; i <= n; i++) {
        int line_max = INT_MIN;

        for (int j = 1; j <= n; j++) {
            if (i == 1) {
                dp[i][j] = max_activ[j];
            } else if (i + j > n + 1) {
                dp[i][j] = 0;
            } else if (i + j == n + 1) {
                dp[i][j] = orase[n] - orase[j];
                if (j != 1) {
                    dp[i][j] += orase[j] - orase[j - 1];
                }
            } else {
                dp[i][j] = activare[j] + last_line_max[j];
            }

            if (dp[i][j] > line_max) {
                line_max = dp[i][j];
            }
        }

        for (int r = 1; r <= n; r++) {
            last_line_max[r] = 0;
        }
        for (int r = n - 2; r >= 1; r--) {
            last_line_max[r] = max(dp[i][r + 2], 
            max(last_line_max[r + 1], last_line_max[r + 2]));
        }

        current_line_max[i] = line_max;
    }

    for (int i = 0; i < q; i++) {
        int answer = 0;
        for (int j = n; j >= 1; j--) {
            if (intrebari[i] >= current_line_max[j]) {
                answer = j;
                break;
            }
        }
        out << answer << endl;
