        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.IntSummaryStatistics;
import java.util.Scanner;

/* clasa care retine maximul de value negustori pentru index orase */
class MaximCities {
	int index;
	int value;
}

public class Regele {
	public String inputFile = "regele.in";
	public String outputFile = "regele.out";
	public int n;
	public int[] cities;
	public int numberQuestions;
	public int[] questions;
	public int[] res;
	public int[][] dp;
	public MaximCities[] max;

	public void solve() {
		readInput();
		getResult();
		writeOutput();
	}

	private void readInput() {
		try {
			Scanner sc = new Scanner(new File(inputFile));
			n = sc.nextInt();

			cities = new int[n];
			for (int i = 0; i < n; i++) {
				cities[i] = Integer.parseInt(sc.next());
			}

			numberQuestions = sc.nextInt();
			questions = new int[numberQuestions];
			for (int i = 0; i < numberQuestions; i++) {
				questions[i] = Integer.parseInt(sc.next());
			}

			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput() {
		try {
			PrintWriter pw = new PrintWriter(new File(outputFile));
			for (int i = 0; i < numberQuestions; i++) {
				pw.printf("%d\n", res[i]);
			}
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	public void completeDp() {
		/* sunt suficiente n/2 linii, daca numarul de negustori se incadreaza
		pentru a activa n/2 orase => se incadreaza pentru a activa n orase */
		dp = new int[n / 2][n];

		/* pe prima linie se salveaza numarul de negustori pentru a activa doar orasul i */
		dp[0][0] = cities[1] - cities[0];
		dp[0][n - 1] = cities[n - 1] - cities[n - 2];

		for (int i = 1; i < n - 1; i++) {
			dp[0][i] = cities[i + 1] - cities[i - 1];
		}

		/* dp[i][j] se refera la numarul de negustori necesari pentru a 
		activa i orase din primele j*/
		for (int i = 1; i < n / 2; i++) {
			int max = dp[0][0]; 
			dp[i][0] = max;
			dp[i][1] = dp[0][1];

			/* la fiecare pas, se compara numarul de negustori necesari pentru 
			a lua i - 1 orase cu suma dintre numarul de negustori pentru orasul curent, 
			adica do[0][j] si max, care reprezinta cel mai mare numar de negustori pentru 
			a lua i - 1 orase */

			/* maximul se poate actualiza la o diferenta de 2 pozitii anterioare 
			fata de pozitia curenta pentru a fi evitata suprapunerea unui numar 
			de negustori dintre 2 orase */
			for (int j = i + 1; j < n; j++) {
				if (j > 2 && dp[i - 1][j - 2] > max) {
					max = dp[i - 1][j - 2];
				}
				dp[i][j] = Math.max(dp[0][j] + max, dp[i][j - 1]);
			}
		}
	}

	/* cautarea liniara a numarului de negustori in vectorul de maxime */
	public int searchMaximNumberCities(int target) {
		/*nu se poate activa niciun oras */
		if (target < max[0].value) {
			return 0;
		}

		/* pentru a activa toate cele n orase, este necesar sa activam n/2 orase */ 
		if (target >= max[n / 2 - 1].value) {
			return n;
		}

		if (target == max[0].value) {
			return max[0].index;
		}

		for (int i = 0; i < max.length - 1; i++) {
			/* daca target se incadreaza intre primele 2 orase */
			if (i == 0) {
				if (max[i + 1].value >= target && max[i + 1].value > target) {
					return max[0].index;
				}

			} else if (target < max[i + 1].value && target >= max[i - 1].value) {
				return max[i].index;
			}
		}
		return 0;
	}

	public void getResult() {
		res = new int[numberQuestions];
		completeDp();

		/* se initializeaza in vectoru ce retine maximul de negustori 
		pentru fiecare oras, prima pozitie */
		max = new MaximCities[n / 2];
		IntSummaryStatistics stat = Arrays.stream(dp[0]).summaryStatistics();
		max[0] = new MaximCities();
		max[0].value = stat.getMax();
		max[0].index = 1;

		/* pe ultima coloana din dp se va afla mereu maximul de negustori pentru 
		numarul i de orase */
		for (int i = 1; i < n / 2; i++) {
			max[i] = new MaximCities();
			max[i].value = dp[i][n - 1];
			max[i].index = i + 1;
		}

		for (int i = 0; i < numberQuestions; i++) {
			res[i] = searchMaximNumberCities(questions[i]);
		}
	}

	public static void main(String[] args) {
		new Regele().solve();
	}
}

