struct data1 {
	int nro;     // orase
	int nrm;     // negustori

	data1(int o, int m) : nro(o), nrm(m) {}
};


inline int max(int a, int b) {
	return a < b ? b : a;
}

int binarySearch(const vector<data1>& vec, int nrm) {
	int size = vec.size();
	int pos = -1;
	if (nrm > vec[size - 1].nrm) {
		pos = -size - 1;
	} else {
		int l = 0;    // left
		int r = size - 1;    // right
		int m = 0;    // middle
		// right - left
		while (r - l > 1) {
			m = (l + r) / 2;    // indicele din mijloc
			if (nrm == vec[m].nrm)
				return m;
			else if (nrm < vec[m].nrm)
				r = m;
			else
				l = m;
		}
		// o ultima comparatie
		if (nrm == vec[l].nrm)
			pos = l;
		else if (nrm == vec[r].nrm)
			pos = r;
		else
			pos = -r - 1;     // = -insertion point - 1
	}
	return pos;
}

// mer[i] - numarul de negustori (merchants) intre orasele i si i + 1
int mer[2002];     // 0
// maxmer[i] - numarul maxim de negustori pentru oricare i orase
int maxmer[2002];    // 0
// Dynamic Programming multiarray
// DP[i][j][0] - costul maxim pentru activarea a
// j orase din primele i, si orasul i este inactiv
// DP[i][j][1] - costul maxim pentru activarea a j orase
// din primele i, si orasul i este activ
int DP[2002][2001][2];    // 0

int main() {
	int N, i, j, pos = 0, poso;
	fin >> N;
	fin >> poso;    // pozitia anterioara
	int pos0 = poso;    // prima pozitie
	for (i = 1; i < N; i++) {
		fin >> pos;
		mer[i] = pos - poso;
		poso = pos;    // actualizare pozitia anterioara
	}
	// numarul total minim  de vanzatori pentru a acoperi toate orasele
	int merTotal = pos - pos0;
	DP[1][0][0] = 0;
	DP[1][1][1] = mer[1];
	for (i = 2; i <= N; i++) {
		for (j = 1; j <= i; j++) {
			DP[i][j][0] = max(DP[i - 1][j][0], DP[i - 1][j][1]);
			DP[i][j][1] = max(DP[i - 1][j - 1][0] +
							mer[i - 1] + mer[i], DP[i - 1][j - 1][1] + mer[i]);
		}
		if (max(DP[i][i][0], DP[i][i][1]) == merTotal)
			break;
	}
	int N1 = i;
	for (i = 1; i <= N1; i++) {
		maxmer[i - 1] = max(DP[N1][i][0], DP[N1][i][1]);
	}
	// maxmer este gata sortat
	vector<data1> vdata;
	vdata.push_back(data1(0, 0));
	for (i = 0; i < N1; i++) {
		if (maxmer[i] == merTotal) {
			vdata.push_back(data1(N1, merTotal));
			break;
		}
		vdata.push_back(data1(i + 1, maxmer[i]));
	}
	int Q, M, ip, ix1;
	fin >> Q;
	// mapa de memorizare pentru solutiile anterioare
	map<int, int> mp;
	map<int, int>::iterator it;
	for (i = 0; i < Q; i++) {
		fin >> M;
		if (M >= merTotal) {
			fout << N << endl;
			continue;
		}
		it = mp.find(M);
		if (it != mp.end()) {
			fout << it->second << endl;
		} else {
			ix1 = binarySearch(vdata, M);
			if (ix1 >= 0) {
				fout << vdata[ix1].nro << endl;
				mp[M] = vdata[ix1].nro;
			} else {
				ip = -ix1 - 1;
				fout << vdata[ip - 1].nro << endl;
				mp[M] = vdata[ip - 1].nro;
			}
		}
	}
	return 0;
}

