int main() {
    std::ifstream input_file("crypto.in");
    std::ofstream output_file("crypto.out");

    // use long long to enlarge the range of values and avoid integer overflows
    long long N, B;
    std::vector < std::pair <long long, long long> > pu;
    input_file >> N >> B;

    // read as pairs
    long long p, u;
    for (int i = 0; i < N; i++) {
        input_file >> p >> u;
        pu.push_back(std::make_pair(p, u));  // push as pair
    }

    // sort by pu.first
    sort(pu.begin(), pu.end());

    // the greedy algorithm itself
    long long level = pu[0].first, temp, sum_till_now = pu[0].second;
    // iterate through the computers untill we have no more money
    for (unsigned int i = 1; i < pu.size() && (B - sum_till_now) > 0; i++) {
        // if we find a computer with a higher capacity than the one before it
        if (pu[i].first > pu[i - 1].first) {
            /*
             * money required to update all the computers until this point to
             * the new found highest capacity
             */
            temp = sum_till_now * (pu[i].first - pu[i - 1].first);
            // if we afford to pay for the entire upgrade
            if (B - temp > 0) {
                level = pu[i].first;
                B -= temp;
            } else {  // else just upgrade to the maximum capcity possible
                level += B / sum_till_now;
                B = -1;
                break;
            }
        }
        sum_till_now += pu[i].second;  // upgrade required sum up to this point
    }

    /*
     * if we are still too rich, just throw the rest of the money into this
     * hopefully profitable cryptocurrency
     */
    if (B > 0) {
        level += (B / sum_till_now);
    }

    output_file << level << std::endl;

    input_file.close();
    output_file.close();

    return 0;
}

