import java.util.ArrayList;
import java.util.Comparator;
import java.util.StringTokenizer;


public class Crypto {

	static class MyScanner {
		BufferedReader br;
		StringTokenizer st;

		public MyScanner() throws FileNotFoundException {
			br = new BufferedReader(new FileReader("crypto.in"));
		}

		String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		int nextInt() {
			return Integer.parseInt(next());
		}

		long nextLong() {
			return Long.parseLong(next());
		}

		double nextDouble() {
			return Double.parseDouble(next());
		}

		String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}

	static class Pc {
		int power;
		int upgrade;

		public Pc(int power, int upgrade) {
			this.power = power;
			this.upgrade = upgrade;
		}

		public Pc() {
			this(0, 0);
		}

		void setPower(int power) {
			this.power = power;
		}

		void setUpgrade(int upgrade) {
			this.upgrade = upgrade;
		}

		public String toString() {
			return "(" + this.power + " , " + this.upgrade + ")";
		}
	}


	public static void main(String[] args) throws FileNotFoundException {

		MyScanner sc = new MyScanner();

		int N = sc.nextInt();
		int B = sc.nextInt();
		ArrayList<Pc> PCs = new ArrayList<>();
		for (int i = 0; i < N; i++) {
			Pc aux = new Pc(sc.nextInt(), sc.nextInt());
			PCs.add(aux);
		}
		//sortez PC-urile dupa puterea curenta
		PCs.sort(Comparator.comparingInt(o -> o.power));
		int index = 0;
		//selectez puterea minima curenta
		int minPower = PCs.get(0).power;
		while (index < N && B > 0) {
			//daca gasesc un pc ce are puterea minima
			if (PCs.get(index).power == minPower) {
				//si daca nu s-au terminat banii
				if (B - PCs.get(index).upgrade < 0) {
