import java.util.stream.Collectors;

public class Crypto {

	public static int min(int[] t) {
		int min = t[0];
		for (int i = 1; i < t.length; i++) {
			if (t[i] < min) {
				min = t[i];
			}
		}
		return min;
	}

	public static void quickSort(int[] arr, int[] arr2, int begin, int end) {
		if (begin < end) {
			int partitionIndex = partition(arr, arr2, begin, end);

			quickSort(arr, arr2, begin, partitionIndex - 1);
			quickSort(arr, arr2, partitionIndex + 1, end);
		}
	}

	private static int partition(int[] arr, int[] arr2, int begin, int end) {
		int pivot = arr[end];
		int i = begin - 1;

		for (int j = begin; j < end; j++) {
			if (arr[j] <= pivot) {
				i++;

				int swapTemp = arr[i];

				arr[i] = arr[j];
				arr[j] = swapTemp;

				int swapTemp2 = arr2[i];

				arr2[i] = arr2[j];
				arr2[j] = swapTemp2;
			}
		}
		int swapTemp = arr[i + 1];
		final int swapTemp2 = arr2[i + 1];

		arr[i + 1] = arr[end];
		arr[end] = swapTemp;

		arr2[i + 1] = arr2[end];
		arr2[end] = swapTemp2;

		return i + 1;
	}

	public static int crypto(int[] perfromance, int[] upgradeCost, int numberOfpc, int budget) {
		int i = 0;
		int result;
		int costs = 0;
		int min = perfromance[0];
		while (1 == 1) {
			if (perfromance[i] == min) {
				costs += upgradeCost[i];
				if (costs < budget) {
					perfromance[i]++;
				}
			}
			i++;

			if (i == numberOfpc && costs < budget) {
				i = 0;
				budget -= costs;
				costs = 0;
				min = perfromance[0];
			}


			if (costs > budget) {
				break;
			}
		}
		result = min(perfromance);
		return result;

	}

