struct pc {
	long p;  // Putere calcul
	long u;  // Pret upgrade
};

int compare(const void *a, const void *b) {
	struct pc pc1 = *(struct pc*)a;
	struct pc pc2 = *(struct pc*)b;

	if (pc1.p == pc2.p) return (pc2.u - pc1.u);
	else
		return pc1.p - pc2.p;
}

int main() {
	ifstream fin("crypto.in");

	long N, B;
	fin >> N >> B;

	struct pc *calculatoare = (struct pc*) malloc(N*sizeof(struct pc));

	long i;
	for (i = 0; i < N; i++) {
		fin >> calculatoare[i].p >> calculatoare[i].u;
	}

	fin.close();

	qsort(calculatoare, N, sizeof(struct pc), compare);

	struct pc rez = calculatoare[0];
	long cost_to_upgrade = 0;

	rez.u = 0;
	int ok1 = 0;

	if (calculatoare[0].u > B) {
		ofstream fout("crypto.out");
		fout << rez.p;
		fout.close();
		return 0;
	}

	cost_to_upgrade = calculatoare[0].u;

	for (i = 1; i < N; i++) {
		if (rez.p == calculatoare[i].p) {
			if (rez.u + calculatoare[i].u > B) break;
		} else {
			ok1 = 0;
			while (rez.p < calculatoare[i].p) {
				if (rez.u + cost_to_upgrade > B) {
					ok1 = 1;
					break;
				} else {
					rez.u += cost_to_upgrade;
					rez.p++;
				}
			}
			if (ok1 == 1) break;
		}
		cost_to_upgrade += calculatoare[i].u;
	}

	while (rez.u + cost_to_upgrade <= B) {
		rez.u += cost_to_upgrade;
		rez.p++;
	}

	ofstream fout("crypto.out");

	fout << rez.p;

	fout.close();

	return 0;
}

