int main() {
    int N, i, c, max, diff;
    long B, upgrade_cost;
    vector<pair<int, int>> v;
    pair<int, int> input;

    upgrade_cost = 0;
    i = 0;

    // opening the input file
    ifstream in;
    in.open("crypto.in");

    // creating & opening the output file
    ofstream out;
