    in >> B;

    // first element from the pair is P_i
    // second element from the pair is U_i
    while (in >> input.first >> input.second) {
        v.push_back(input);
    }

    // sorting the vector by the number of coins made by every computer
    sort(v.begin(), v.end());

    // maximum number of elements that can be mined on the network
    max = v[0].first;

    // upgrading while the total cost of the upgrade is lower than the budget
    while (B > upgrade_cost) {
        // difference between the number of coins produced
        // by two adjacent computers from the sorted vector of computers
        diff = v[i+1].first - v[i].first;

        upgrade_cost += v[i].second;
        i++;

        // if the upgrade cost for this computer does not
        // overcome the budget
        if (B > diff * upgrade_cost) {
            B -= diff * upgrade_cost;
            max +=  diff;
        } else {
            // there cannot be made any more upgrades
            max += B / upgrade_cost;
            break;
        }

        if (i == N) {
            max += B / upgrade_cost;
            break;
        }
    }

    out << max;

    in.close();
    out.close();
}

