        import java.io.*;
import java.util.*;


public class Crypto {

    private static void sortInput(int[][] input){
        Arrays.sort(input, new Comparator<int[]>() {
            @Override
            // Compare values according to columns
            public int compare(final int[] el1, final int[] el2) {
                if (el1[0] > el2[0])
                    return 1;
                if (el1[0] < el2[0])
                    return -1;
                else
                    return 0;
            }
        });
    }

    private static int areAllTheSame(int[] weights, int[] values, int budget) {
        boolean areAllTheSame = true;
        int firstValue = values[0];
        int sum = 0;
        for (int i = 1; i < values.length; i++) {
            if (firstValue != values[i]) {
                areAllTheSame = false;
                break;
            }
            sum += weights[i];
        }
        if (areAllTheSame) {
            int y = (int) budget / sum;
            return (firstValue + y);
        }
        return 0;
    }

    public static int computeSolution(int[] weights, int[] values, int budget) {

        //in case all capacities are equal
        int solution = areAllTheSame(weights, values, budget);
        if (solution != 0) {
            return solution;
        } else {
            int minIndex = 0;
            int minValue = values[minIndex];

            while (weights[minIndex] <= budget && budget > 0) {
                budget -= weights[minIndex];
                values[minIndex]++;
                if ((minIndex + 1) < values.length) {
                    if (minValue == values[minIndex + 1]) {
                        minIndex += 1;
                        continue;
                    }
                }
                minIndex = findMinIndex(values);
                minValue = values[minIndex];
            }
            return minValue;
        }
    }

    public static int findMinIndex(int[] values) {
        if (values.length == 0) {
            return -1;
        }

        int minIndex = 0;
        int minValue = values[0];

        for (int idx = 1; idx < values.length; idx++) {
            if (values[idx] < minValue) {
                minValue = values[idx];
                minIndex = idx;
            }
        }

        return minIndex;
    }

    public static void write(int result) throws IOException {
        FileWriter writer = new FileWriter("crypto.out");
        BufferedWriter buffer = new BufferedWriter(writer);
        buffer.write(String.valueOf(result));
        buffer.close();
    }

    public static String read() throws IOException {
        BufferedReader reader = new BufferedReader(new FileReader("crypto.in"));
        StringBuilder content = new StringBuilder();
        String line;

        while ((line = reader.readLine()) != null) {
            content.append(line);
            content.append(System.lineSeparator());
        }

        return content.toString();
    }

    public static int doCrypto(String fileInput){
        String[] lines = fileInput.split("\\r?\\n");


        int numOfItems = Integer.parseInt(lines[0].split(" ")[0]);
        int budget = Integer.parseInt(lines[0].split(" ")[1]);

        int[][] input = new int[numOfItems][2];

        int[] weights = new int[numOfItems];
        int[] values = new int[numOfItems];

        int currentIndex = 0;

        for(int i = 1; i <= numOfItems; i++){
            String[] lineItems = lines[i].split(" ");
            input[currentIndex][0] = Integer.parseInt(lineItems[0]);
            input[currentIndex][1] = Integer.parseInt(lineItems[1]);
            currentIndex++;
        }

        sortInput(input);
        for (int i = 0; i < numOfItems; i++) {
            values[i] = input[i][0];
            weights[i] = input[i][1];
        }
        return computeSolution(weights, values, budget);


    }

    public static void main(String[] args) throws IOException {
        write(doCrypto(read()));

    }
}
