class Pair implements Comparable<Object> {
	int i; // puterea de minare
	int j; // pretul de upgrade

	public Pair(int i, int j) {
		this.i = i;
		this.j = j;
	}

	public int compareTo(Object o) {
		if (o == null) {
			return 0;
		}

